UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے حدیث بیان کی، ان کو شعیب نے، ان کو ابولزناد نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے نقل کی کہ بیشک رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، قسم ہے اس ذات کی جس کے ہاتھ میں میری جان ہے۔ تم میں سے کوئی بھی ایماندار نہ ہو گا جب تک میں اس کے والد اور اولاد سے بھی زیادہ اس کا محبوب نہ بن جاؤں۔' WHERE id = 15;
UPDATE hadiths SET urdu = 'عبداللہ بن یوسف نے ہم سے بیان کیا، وہ کہتے ہیں کہ ہمیں مالک بن انس نے ابن شہاب سے خبر دی، وہ سالم بن عبداللہ سے نقل کرتے ہیں، وہ اپنے باپ (عبداللہ بن عمر رضی اللہ عنہما) سے کہ ایک دفعہ رسول اللہ صلی اللہ علیہ وسلم ایک انصاری شخص کے پاس سے گزرے اس حال میں کہ وہ اپنے ایک بھائی سے کہہ رہے تھے کہ تم اتنی شرم کیوں کرتے ہو۔ آپ صلی اللہ علیہ وسلم نے اس انصاری سے فرمایا کہ اس کو اس کے حال پر رہنے دو کیونکہ حیاء بھی ایمان ہی کا ایک حصہ ہے۔' WHERE id = 25;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے یہ حدیث بیان کی، ان سے سفیان نے، وہ اعمش بن عبیداللہ بن مرہ سے نقل کرتے ہیں، وہ مسروق سے، وہ عبداللہ بن عمر رضی اللہ عنہما سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ چار عادتیں جس کسی میں ہوں تو وہ خالص منافق ہے اور جس کسی میں ان چاروں میں سے ایک عادت ہو تو وہ ( بھی ) نفاق ہی ہے، جب تک اسے نہ چھوڑ دے۔ ( وہ یہ ہیں ) جب اسے امین بنایا جائے تو ( امانت میں ) خیانت کرے اور بات کرتے وقت جھوٹ بولے اور جب ( کسی سے ) عہد کرے تو اسے پورا نہ کرے اور جب ( کسی سے ) لڑے تو گالیوں پر اتر آئے۔ اس حدیث کو شعبہ نے ( بھی ) سفیان کے ساتھ اعمش سے روایت کیا ہے۔' WHERE id = 35;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، ان سے ہشام نے، ان سے قتادہ نے انس کے واسطے سے نقل کیا، وہ رسول اللہ صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ آپ صلی اللہ علیہ وسلم نے فرمایا جس شخص نے «لا إله إلا الله» کہہ لیا اور اس کے دل میں جو برابر بھی ( ایمان ) ہے تو وہ ( ایک نہ ایک دن ) دوزخ سے ضرور نکلے گا اور دوزخ سے وہ شخص ( بھی ) ضرور نکلے گا جس نے کلمہ پڑھا اور اس کے دل میں گیہوں کے دانہ برابر خیر ہے اور دوزخ سے وہ ( بھی ) نکلے گا جس نے کلمہ پڑھا اور اس کے دل میں اک ذرہ برابر بھی خیر ہے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) فرماتے ہیں کہ ابان نے بروایت قتادہ بواسطہ انس رضی اللہ عنہ رسول صلی اللہ علیہ وسلم سے «خير» کی جگہ «ايمان» کا لفظ نقل کیا ہے۔' WHERE id = 45;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم کو امام مالک رحمہ اللہ نے خبر دی، انہوں نے یحییٰ بن سعید سے، انہوں نے محمد بن ابراہیم سے، انہوں نے علقمہ بن وقاص سے، انہوں نے عمر رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا عمل نیت ہی سے صحیح ہوتے ہیں ( یا نیت ہی کے مطابق ان کا بدلا ملتا ہے ) اور ہر آدمی کو وہی ملے گا جو نیت کرے گا۔ پس جو کوئی اللہ اور اس کے رسول کی رضا کے لیے ہجرت کرے اس کی ہجرت اللہ اور اس کے رسول کی طرف ہو گی اور جو کوئی دنیا کمانے کے لیے یا کسی عورت سے شادی کرنے کے لیے ہجرت کرے گا تو اس کی ہجرت ان ہی کاموں کے لیے ہو گی۔' WHERE id = 55;
UPDATE hadiths SET urdu = 'اسماعیل بن عبداللہ نے ہم سے بیان کیا، ان سے ابراہیم بن سعد نے صالح کے واسطے سے روایت کی، انہوں نے ابن شہاب سے، انہوں نے عبیداللہ بن عبداللہ بن عتبہ بن مسعود رضی اللہ عنہ سے نقل کیا کہ ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک شخص کو اپنا ایک خط دے کر بھیجا اور اسے یہ حکم دیا کہ اسے حاکم بحرین کے پاس لے جائے۔ بحرین کے حاکم نے وہ خط کسریٰ ( شاہ ایران ) کے پاس بھیج دیا۔ جس وقت اس نے وہ خط پڑھا تو چاک کر ڈالا ( راوی کہتے ہیں ) اور میرا خیال ہے کہ ابن مسیب نے ( اس کے بعد ) مجھ سے کہا کہ ( اس واقعہ کو سن کر ) رسول اللہ صلی اللہ علیہ وسلم نے اہل ایران کے لیے بددعا کی کہ وہ ( بھی چاک شدہ خط کی طرح ) ٹکڑے ٹکڑے ہو جائیں۔' WHERE id = 65;
UPDATE hadiths SET urdu = 'ہم سے محمد بن غریر زہری نے بیان کیا، ان سے یعقوب بن ابراہیم نے، ان سے ان کے باپ (ابراہیم) نے، انہوں نے صالح سے سنا، انہوں نے ابن شہاب سے، وہ بیان کرتے ہیں کہ انہیں عبیداللہ بن عبداللہ نے ابن عباس رضی اللہ عنہما کے واسطے سے خبر دی کہ وہ اور حر بن قیس بن حصن فزاری موسیٰ علیہ السلام کے ساتھی کے بارے میں بحثے۔ ابن عباس رضی اللہ عنہما نے فرمایا کہ وہ خضر علیہ السلام تھے۔ پھر ان کے پاس سے ابی بن کعب گزرے تو عبداللہ بن عباس رضی اللہ عنہما نے انہیں بلایا اور کہا کہ میں اور میرے یہ رفیق موسیٰ علیہ السلام کے اس ساتھی کے بارے میں بحث کر رہے ہیں جس سے انہوں نے ملاقات چاہی تھی۔ کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم سے اس کے بارے میں کچھ ذکر سنا ہے۔ انہوں نے کہا، ہاں میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا ہے۔ ایک دن موسیٰ بنی اسرائیل کی ایک جماعت میں بیٹھے ہوئے تھے کہ اتنے میں ایک شخص آیا اور اس نے آپ سے پوچھا کیا آپ جانتے ہیں کہ ( دنیا میں ) کوئی آپ سے بھی بڑھ کر عالم موجود ہے؟ موسیٰ علیہ السلام نے فرمایا نہیں۔ اس پر اللہ تعالیٰ نے موسیٰ علیہ اسلام کے پاس وحی بھیجی کہ ہاں ہمارا بندہ خضر ہے ( جس کا علم تم سے زیادہ ہے ) موسیٰ علیہ السلام نے اللہ سے دریافت کیا کہ خضر علیہ السلام سے ملنے کی کیا صورت ہے؟ اللہ تعالیٰ نے ایک مچھلی کو ان سے ملاقات کی علامت قرار دیا اور ان سے کہہ دیا کہ جب تم اس مچھلی کو گم کر دو تو ( واپس ) لوٹ جاؤ، تب خضر سے تمہاری ملاقات ہو گی۔ تب موسیٰ ( چلے اور ) دریا میں مچھلی کی علامت تلاش کرتے رہے۔ اس وقت ان کے ساتھی نے کہا جب ہم پتھر کے پاس تھے، کیا آپ نے دیکھا تھا، میں اس وقت مچھلی کا کہنا بھول گیا اور شیطان ہی نے مجھے اس کا ذکر بھلا دیا۔ موسیٰ علیہ السلام نے کہا، اسی مقام کی ہمیں تلاش تھی۔ تب وہ اپنے نشانات قدم پر ( پچھلے پاؤں ) باتیں کرتے ہوئے لوٹے ( وہاں ) انہوں نے خضر علیہ السلام کو پایا۔ پھر ان کا وہی قصہ ہے جو اللہ نے اپنی کتاب قرآن میں بیان کیا ہے۔' WHERE id = 75;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ان سے وہیب نے، ان سے ایوب نے عکرمہ کے واسطے سے نقل کیا، وہ ابن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم سے آپ کے ( آخری ) حج میں کسی نے پوچھا کہ میں نے رمی کرنے ( یعنی کنکر پھینکنے ) سے پہلے ذبح کر لیا، آپ صلی اللہ علیہ وسلم نے ہاتھ سے اشارہ کیا ( اور ) فرمایا کچھ حرج نہیں۔ کسی نے کہا کہ میں نے ذبح سے پہلے حلق کرا لیا۔ آپ صلی اللہ علیہ وسلم نے سر سے اشارہ فرما دیا کہ کچھ حرج نہیں۔' WHERE id = 85;
UPDATE hadiths SET urdu = 'ہم سے عبدہ نے بیان کیا، ان سے عبدالصمد نے، ان سے عبداللہ بن مثنی نے، ان سے ثمامہ بن عبداللہ بن انس نے، ان سے انس رضی اللہ عنہ نے بیان کیا، وہ نبی اکرم صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ جب آپ صلی اللہ علیہ وسلم سلام کرتے تو تین بار سلام کرتے اور جب کوئی کلمہ ارشاد فرماتے تو اسے تین بار دہراتے یہاں تک کہ خوب سمجھ لیا جاتا۔' WHERE id = 95;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، ان سے لیث نے، ان سے سعید بن ابی سعید نے، وہ ابوشریح سے روایت کرتے ہیں کہ انہوں نے عمرو بن سعید ( والی مدینہ ) سے جب وہ مکہ میں ( ابن زبیر سے لڑنے کے لیے ) فوجیں بھیج رہے تھے کہا کہ اے امیر! مجھے آپ اجازت دیں تو میں وہ حدیث آپ سے بیان کر دوں، جو رسول اللہ صلی اللہ علیہ وسلم نے فتح مکہ کے دوسرے دن ارشاد فرمائی تھی، اس ( حدیث ) کو میرے دونوں کانوں نے سنا اور میرے دل نے اسے یاد رکھا ہے اور جب رسول اللہ صلی اللہ علیہ وسلم یہ حدیث فرما رہے تھے تو میری آنکھیں آپ صلی اللہ علیہ وسلم کو دیکھ رہی تھیں۔ آپ صلی اللہ علیہ وسلم نے ( پہلے ) اللہ کی حمد و ثنا بیان کی، پھر فرمایا کہ مکہ کو اللہ نے حرام کیا ہے، آدمیوں نے حرام نہیں کیا۔ تو ( سن لو ) کہ کسی شخص کے لیے جو اللہ پر اور یوم آخرت پر ایمان رکھتا ہو جائز نہیں ہے کہ مکہ میں خون ریزی کرے، یا اس کا کوئی پیڑ کاٹے، پھر اگر کوئی اللہ کے رسول ( کے لڑنے ) کی وجہ سے اس کا جواز نکالے تو اس سے کہہ دو اللہ نے اپنے رسول صلی اللہ علیہ وسلم کے لیے اجازت دی تھی، تمہارے لیے نہیں دی اور مجھے بھی دن کے کچھ لمحوں کے لیے اجازت ملی تھی۔ آج اس کی حرمت لوٹ آئی، جیسی کل تھی۔ اور حاضر غائب کو ( یہ بات ) پہنچا دے۔ ( یہ حدیث سننے کے بعد راوی حدیث ) ابوشریح سے پوچھا گیا کہ ( آپ کی یہ بات سن کر ) عمرو نے کیا جواب دیا؟ کہا یوں کہ اے ( ابوشریح! ) حدیث کو میں تم سے زیادہ جانتا ہوں۔ مگر حرم ( مکہ ) کسی خطاکار کو یا خون کر کے اور فتنہ پھیلا کر بھاگ آنے والے کو پناہ نہیں دیتا۔' WHERE id = 105;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، ان سے ابن وہب نے، انہیں یونس نے ابن شہاب سے خبر دی، وہ عبیداللہ بن عبداللہ سے، وہ ابن عباس سے روایت کرتے ہیں کہ جب نبی کریم صلی اللہ علیہ وسلم کے مرض میں شدت ہو گئی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے پاس سامان کتابت لاؤ تاکہ تمہارے لیے ایک تحریر لکھ دوں، تاکہ بعد میں تم گمراہ نہ ہو سکو، اس پر عمر رضی اللہ عنہ نے ( لوگوں سے ) کہا کہ اس وقت آپ صلی اللہ علیہ وسلم پر تکلیف کا غلبہ ہے اور ہمارے پاس اللہ کی کتاب قرآن موجود ہے جو ہمیں ( ہدایت کے لیے ) کافی ہے۔ اس پر لوگوں کی رائے مختلف ہو گئی اور شور و غل زیادہ ہونے لگا۔ آپ صلی اللہ علیہ وسلم نے فرمایا میرے پاس سے اٹھ کھڑے ہو، میرے پاس جھگڑنا ٹھیک نہیں، اس پر ابن عباس رضی اللہ عنہما یہ کہتے ہوئے نکل آئے کہ بیشک مصیبت بڑی سخت مصیبت ہے ( وہ چیز جو ) ہمارے اور رسول اللہ صلی اللہ علیہ وسلم کے اور آپ کی تحریر کے درمیان حائل ہو گئی۔' WHERE id = 115;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالعزیز بن ابی سلمہ نے زہری کے واسطے سے روایت کیا، انہوں نے عیسیٰ بن طلحہ سے، انہوں نے عبداللہ بن عمرو سے، وہ کہتے ہیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو رمی جمار کے وقت دیکھا آپ صلی اللہ علیہ وسلم سے پوچھا جا رہا تھا تو ایک شخص نے عرض کیا، یا رسول اللہ! میں نے رمی سے قبل قربانی کر لی؟ آپ صلی اللہ علیہ وسلم نے فرمایا ( اب ) رمی کر لو کچھ حرج نہیں ہوا۔ دوسرے نے کہا، یا رسول اللہ! میں نے قربانی سے پہلے سر منڈا لیا؟ آپ صلی اللہ علیہ وسلم نے فرمایا ( اب ) قربانی کر لو کچھ حرج نہیں۔ ( اس وقت ) جس چیز کے بارے میں جو آگے پیچھے ہو گئی تھی، آپ سے پوچھا گیا، آپ صلی اللہ علیہ وسلم نے یہ ہی جواب دیا ( اب ) کر لو کچھ حرج نہیں۔' WHERE id = 125;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ان کو ابن ابی ذئب نے نافع کے واسطے سے خبر دی، وہ عبداللہ بن عمر رضی اللہ عنہما سے روایت کرتے ہیں، وہ رسول اللہ صلی اللہ علیہ وسلم سے اور (دوسری سند میں) زہری سالم سے، کہا وہ ابن عمر رضی اللہ عنہما سے، وہ نبی کریم صلی اللہ علیہ وسلم سے روایت کرتے ہیں کہ ایک شخص نے آپ صلی اللہ علیہ وسلم سے پوچھا کہ احرام باندھنے والے کو کیا پہننا چاہیے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہ قمیص پہنے نہ صافہ باندھے اور نہ پاجامہ اور نہ کوئی سرپوش اوڑھے اور نہ کوئی زعفران اور ورس سے رنگا ہوا کپڑا پہنے اور اگر جوتے نہ ملیں تو موزے پہن لے اور انہیں ( اس طرح ) کاٹ دے کہ ٹخنوں سے نیچے ہو جائیں۔' WHERE id = 135;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا کہ ہم سے ابن ابی ذئب نے، کہا کہ ہم سے زہری نے عطاء بن یزید اللیثی کے واسطے سے نقل کیا، وہ ابوایوب انصاری رضی اللہ عنہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں سے کوئی بیت الخلاء میں جائے تو قبلہ کی طرف منہ کرے نہ اس کی طرف پشت کرے ( بلکہ ) مشرق کی طرف منہ کر لو یا مغرب کی طرف۔' WHERE id = 145;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے اوزاعی نے یحییٰ بن کثیر کے واسطے سے بیان کیا، وہ عبداللہ بن ابی قتادہ کے واسطے سے بیان کرتے ہیں، وہ اپنے باپ سے روایت کرتے ہیں، وہ نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا جب تم میں سے کوئی پیشاب کرے تو اپنا عضو اپنے داہنے ہاتھ سے نہ پکڑے، نہ داہنے ہاتھ سے طہارت کرے، نہ ( پانی پیتے وقت ) برتن میں سانس لے۔' WHERE id = 155;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے زہری کے واسطے سے خبر دی، کہا ہم کو عطاء بن یزید نے حمران مولیٰ عثمان بن عفان رضی اللہ عنہ کے واسطے سے خبر دی، انہوں نے عثمان رضی اللہ عنہ کو دیکھا کہ انہوں نے وضو کا پانی منگوایا اور اپنے دونوں ہاتھوں پر برتن سے پانی ( لے کر ) ڈالا۔ پھر دونوں ہاتھوں کو تین دفعہ دھویا۔ پھر اپنا داہنا ہاتھ وضو کر کے پانی میں ڈالا۔ پھر کلی کی، پھر ناک میں پانی دیا، پھر ناک صاف کی۔ پھر تین دفعہ اپنا منہ دھویا اور کہنیوں تک تین دفعہ ہاتھ دھوئے، پھر اپنے سر کا مسح کیا۔ پھر ہر ایک پاؤں تین دفعہ دھویا۔ پھر فرمایا میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ آپ میرے اس وضو جیسا وضو فرمایا کرتے تھے اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص میرے اس وضو جیسا وضو کرے اور ( حضور قلب سے ) دو رکعت پڑھے جس میں اپنے دل سے باتیں نہ کرے۔ تو اللہ تعالیٰ اس کے پچھلے گناہ معاف کر دیتا ہے۔' WHERE id = 165;
UPDATE hadiths SET urdu = 'احمد بن شبیب نے کہا کہ ہم سے میرے والد نے یونس کے واسطے سے بیان کیا، وہ ابن شہاب سے نقل کرتے ہیں، انہوں نے کہا مجھ سے حمزہ بن عبداللہ نے اپنے باپ (یعنی عبداللہ بن عمر رضی اللہ عنہما) کے واسطے سے بیان کیا۔ وہ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں کتے مسجد میں آتے جاتے تھے لیکن لوگ ان جگہوں پر پانی نہیں چھڑکتے تھے۔' WHERE id = 175;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے مالک نے ہشام بن عروہ کے واسطے سے نقل کیا، وہ اپنی بیوی فاطمہ سے، وہ اپنی دادی اسماء بنت ابی بکر سے روایت کرتی ہیں، وہ کہتی ہیں کہ میں رسول اللہ صلی اللہ علیہ وسلم کی زوجہ محترمہ عائشہ رضی اللہ عنہا کے پاس ایسے وقت آئی جب کہ سورج کو گہن لگ رہا تھا اور لوگ کھڑے ہو کر نماز پڑھ رہے تھے، کیا دیکھتی ہوں وہ بھی کھڑے ہو کر نماز پڑھ رہی ہیں۔ میں نے کہا کہ لوگوں کو کیا ہو گیا ہے؟ تو انہوں نے اپنے ہاتھ سے آسمان کی طرف اشارہ کر کے کہا، سبحان اللہ! میں نے کہا ( کیا یہ ) کوئی ( خاص ) نشانی ہے؟ تو انہوں نے اشارے سے کہا کہ ہاں۔ تو میں بھی آپ کے ساتھ نماز کے لیے کھڑی ہو گئی۔ ( آپ نے اتنا فرمایا کہ ) مجھ پر غشی طاری ہونے لگی اور میں اپنے سر پر پانی ڈالنے لگی۔ جب رسول اللہ صلی اللہ علیہ وسلم نماز سے فارغ ہوئے تو آپ نے اللہ کی حمد و ثنا بیان کی اور فرمایا، آج کوئی چیز ایسی نہیں رہی جس کو میں نے اپنی اسی جگہ نہ دیکھ لیا ہو حتیٰ کہ جنت اور دوزخ کو بھی دیکھ لیا۔ اور مجھ پر یہ وحی کی گئی ہے کہ تم لوگوں کو قبروں میں آزمایا جائے گا۔ دجال جیسی آزمائش یا اس کے قریب قریب۔ ( راوی کا بیان ہے کہ ) میں نہیں جانتی کہ اسماء نے کون سا لفظ کہا۔ تم میں سے ہر ایک کے پاس ( اللہ کے فرشتے ) بھیجے جائیں گے اور اس سے کہا جائے گا کہ تمہارا اس شخص ( یعنی محمد صلی اللہ علیہ وسلم ) کے بارے میں کیا خیال ہے؟ پھر اسماء نے لفظ ایماندار کہا یا یقین رکھنے والا کہا۔ مجھے یاد نہیں۔ ( بہرحال وہ شخص ) کہے گا کہ محمد صلی اللہ علیہ وسلم اللہ کے سچے رسول ہیں۔ وہ ہمارے پاس نشانیاں اور ہدایت کی روشنی لے کر آئے۔ ہم نے ( اسے ) قبول کیا، ایمان لائے، اور ( آپ کا ) اتباع کیا۔ پھر ( اس سے ) کہہ دیا جائے گا تو سو جا درحالیکہ تو مرد صالح ہے اور ہم جانتے تھے کہ تو مومن ہے۔ اور بہرحال منافق یا شکی آدمی، اسماء نے کون سا لفظ کہا مجھے یاد نہیں۔ ( جب اس سے پوچھا جائے گا ) کہے گا کہ میں ( کچھ ) نہیں جانتا، میں نے لوگوں کو جو کہتے سنا، وہی میں نے بھی کہہ دیا۔' WHERE id = 185;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے محمد بن المنکدر کے واسطے سے، انہوں نے جابر رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم میری مزاج پرسی کے لیے تشریف لائے۔ میں بیمار تھا ایسا کہ مجھے ہوش تک نہیں تھا۔ آپ صلی اللہ علیہ وسلم نے وضو کیا اور اپنے وضو کا پانی مجھ پر چھڑکا، تو مجھے ہوش آ گیا۔ میں نے عرض کیا، یا رسول اللہ! میرا وارث کون ہو گا؟ میرا تو صرف ایک کلالہ وارث ہے۔ اس پر آیت میراث نازل ہوئی۔' WHERE id = 195;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے شیبان نے یحییٰ کے واسطے سے نقل کیا، وہ ابوسلمہ سے، انہوں نے جعفر بن عمرو بن امیہ الضمری سے نقل کیا، انہیں ان کے باپ نے خبر دی کہ انھوں نے رسول اللہ صلی اللہ علیہ وسلم کو موزوں پر مسح کرتے ہوئے دیکھا۔ اس حدیث کی متابعت میں حرب اور ابان نے یحییٰ سے حدیث نقل کی ہے۔' WHERE id = 205;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے عمرو بن عامر کے واسطے سے بیان کیا، کہا میں نے انس رضی اللہ عنہ سے سنا۔ (دوسری سند سے) ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے، وہ سفیان سے روایت کرتے ہیں، ان سے عمرو بن عامر نے بیان کیا، وہ انس رضی اللہ عنہ سے روایت کرتے ہیں۔ انہوں نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم ہر نماز کے لیے نیا وضو فرمایا کرتے تھے۔ میں نے کہا تم لوگ کس طرح کرتے تھے، کہنے لگے ہم میں سے ہر ایک کو اس کا وضو اس وقت تک کافی ہوتا، جب تک کوئی وضو توڑنے والی چیز پیش نہ آ جاتی۔ ( یعنی پیشاب، پاخانہ، یا نیند وغیرہ ) ۔' WHERE id = 215;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے اعمش کے واسطے سے نقل کیا، وہ ابووائل سے، وہ حذیفہ رضی اللہ عنہ سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم کسی قوم کی کوڑی پر تشریف لائے ( پس ) آپ صلی اللہ علیہ وسلم نے وہاں کھڑے ہو کر پیشاب کیا۔ پھر پانی منگایا۔ میں آپ صلی اللہ علیہ وسلم کے پاس پانی لے کر آیا تو آپ صلی اللہ علیہ وسلم نے وضو فرمایا۔' WHERE id = 225;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے، کہا مجھے ابوالتیاح یزید بن حمید نے انس رضی اللہ عنہ سے خبر دی، وہ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم مسجد کی تعمیر سے پہلے نماز بکریوں کے باڑے میں پڑھ لیا کرتے تھے۔ ( معلوم ہوا کہ بکریوں وغیرہ کے باڑے میں بوقت ضرورت نماز پڑھی جا سکتی ہے ) ۔' WHERE id = 235;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے غیلان بن جریر کے واسطے سے نقل کیا، وہ ابوبردہ سے وہ اپنے باپ سے نقل کرتے ہیں کہ میں ( ایک مرتبہ ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو میں نے آپ کو اپنے ہاتھ سے مسواک کرتے ہوئے پایا اور آپ صلی اللہ علیہ وسلم کے منہ سے اع اع کی آواز نکل رہی تھی اور مسواک آپ صلی اللہ علیہ وسلم کے منہ میں تھی جس طرح آپ صلی اللہ علیہ وسلم قے کر رہے ہوں۔' WHERE id = 245;
UPDATE hadiths SET urdu = 'ابونعیم نے ہم سے بیان کیا، انہوں نے کہا کہ ہم سے زہیر نے روایت کی ابواسحاق سے، انہوں نے کہا کہ ہم سے جبیر بن مطعم رضی اللہ عنہ نے روایت کی۔ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا میں تو اپنے سر پر تین مرتبہ پانی بہاتا ہوں اور آپ صلی اللہ علیہ وسلم نے اپنے دونوں ہاتھوں سے اشارہ کیا۔' WHERE id = 255;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے عبداللہ بن عبداللہ بن جبیر سے انہوں نے کہا کہ میں نے انس بن مالک سے سنا کہ نبی کریم صلی اللہ علیہ وسلم اور آپ کی کوئی زوجہ مطہرہ ایک برتن میں غسل کرتے تھے۔ اس حدیث میں مسلم بن ابراہیم اور وہب بن جریر کی روایت میں شعبہ سے «من الجنابة‏» کا لفظ ( زیادہ ) ہے۔ ( یعنی یہ جنابت کا غسل ہوتا تھا ) ۔' WHERE id = 265;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے ابوحمزہ (محمد بن میمون) نے، کہا میں نے اعمش سے سنا، انہوں نے سالم بن ابی الجعد سے، انہوں نے کریب سے، انہوں نے ابن عباس سے، آپ نے کہا کہ میمونہ رضی اللہ عنہا نے فرمایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے لیے غسل کا پانی رکھا اور ایک کپڑے سے پردہ کر دیا۔ پہلے آپ صلی اللہ علیہ وسلم نے اپنے دونوں ہاتھوں پر پانی ڈالا اور انہیں دھویا۔ پھر اپنے داہنے ہاتھ سے بائیں ہاتھ میں پانی لیا اور شرمگاہ دھوئی۔ پھر ہاتھ کو زمین پر مارا اور دھویا۔ پھر کلی کی اور ناک میں پانی ڈالا اور چہرے اور بازو دھوئے۔ پھر سر پر پانی بہایا اور سارے بدن کا غسل کیا۔ اس کے بعد آپ صلی اللہ علیہ وسلم مقام غسل سے ایک طرف ہو گئے۔ پھر دونوں پاؤں دھوئے۔ اس کے بعد میں نے آپ صلی اللہ علیہ وسلم کو ایک کپڑا دینا چاہا۔ تو آپ صلی اللہ علیہ وسلم نے اسے نہیں لیا اور آپ صلی اللہ علیہ وسلم ہاتھوں سے پانی جھاڑنے لگے۔' WHERE id = 276;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے ہشام اور شیبان نے، وہ یحییٰ سے، وہ ابوسلمہ سے کہا میں نے عائشہ رضی اللہ عنہا سے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم جنابت کی حالت میں گھر میں سوتے تھے؟ کہا ہاں لیکن وضو کر لیتے تھے۔' WHERE id = 286;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا ابن جریج نے انہیں خبر دی، انہوں نے کہا مجھے ہشام بن عروہ نے عروہ کے واسطے سے بتایا کہ ان سے سوال کیا گیا، کیا حائضہ بیوی میری خدمت کر سکتی ہے، یا ناپاکی کی حالت میں عورت مجھ سے نزدیک ہو سکتی ہے؟ عروہ نے فرمایا میرے نزدیک تو اس میں کوئی حرج نہیں ہے۔ اس طرح کہ عورتیں میری بھی خدمت کرتی ہیں اور اس میں کسی کے لیے بھی کوئی حرج نہیں۔ اس لیے کہ مجھے عائشہ رضی اللہ عنہا نے خبر دی کہ وہ رسول اللہ صلی اللہ علیہ وسلم کو حائضہ ہونے کی حالت میں کنگھا کیا کرتی تھیں اور رسول اللہ صلی اللہ علیہ وسلم اس وقت مسجد میں معتکف ہوتے۔ آپ اپنا سر مبارک قریب کر دیتے اور عائشہ رضی اللہ عنہا اپنے حجرہ ہی سے کنگھا کر دیتیں، حالانکہ وہ حائضہ ہوتیں۔' WHERE id = 296;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین ابوبشر واسطی نے بیان کیا، انہوں نے کہا ہم سے خالد بن عبداللہ نے بیان کیا، انہوں نے خالد بن مہران سے، انہوں نے عکرمہ سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ آپ صلی اللہ علیہ وسلم کی بعض ازواج نے اعتکاف کیا، حالانکہ وہ مستحاضہ تھیں اور انہیں خون آتا تھا۔ اس لیے خون کی وجہ سے طشت اکثر اپنے نیچے رکھ لیتیں۔ اور عکرمہ نے کہا کہ عائشہ رضی اللہ عنہا نے کسم کا پانی دیکھا تو فرمایا یہ تو ایسا ہی معلوم ہوتا ہے جیسے فلاں صاحبہ کو استحاضہ کا خون آتا تھا۔' WHERE id = 307;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے عقیل بن خالد سے، انہوں نے ابن شہاب سے، انہوں نے عروہ بن زبیر سے، انہوں نے عائشہ رضی اللہ عنہا سے، انہوں نے کہا ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ حجۃ الوداع کے سفر میں نکلے، ہم میں سے بعض نے عمرہ کا احرام باندھا اور بعض نے حج کا، پھر ہم مکہ آئے اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے عمرہ کا احرام باندھا ہو اور ہدی ساتھ نہ لایا ہو تو وہ حلال ہو جائے اور جس نے عمرہ کا احرام باندھا ہو اور وہ ہدی بھی ساتھ لایا ہو تو وہ ہدی کی قربانی سے پہلے حلال نہ ہو گا۔ اور جس نے حج کا احرام باندھا ہو تو اسے حج پورا کرنا چاہیے۔ عائشہ رضی اللہ عنہا نے کہا کہ میں حائضہ ہو گئی اور عرفہ کا دن آ گیا۔ میں نے صرف عمرہ کا احرام باندھا تھا مجھے نبی کریم صلی اللہ علیہ وسلم نے حکم دیا کہ میں اپنا سر کھول لوں، کنگھا کر لوں اور حج کا احرام باندھ لوں اور عمرہ چھوڑ دوں، میں نے ایسا ہی کیا اور اپنا حج پورا کر لیا۔ پھر میرے ساتھ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن بن ابی بکر کو بھیجا اور مجھ سے فرمایا کہ میں اپنے چھوٹے ہوئے عمرہ کے عوض تنعیم سے دوسرا عمرہ کروں۔' WHERE id = 317;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے زہیر بن معاویہ نے بیان کیا، انہوں نے کہا ہم سے ہشام بن عروہ نے عائشہ رضی اللہ عنہا سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب حیض کا زمانہ آئے تو نماز چھوڑ دے اور جب یہ زمانہ گزر جائے تو خون کو دھو اور نماز پڑھ۔' WHERE id = 328;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم سے شعبہ نے حکم سے، وہ ذر بن عبداللہ سے، وہ سعید بن عبدالرحمٰن بن ابزیٰ سے، وہ اپنے والد عبدالرحمٰن بن ابزیٰ سے، انہوں نے بیان کیا کہ عمار رضی اللہ عنہ نے عمر رضی اللہ عنہ سے کہا کہ میں تو زمین میں لوٹ پوٹ ہو گیا پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تیرے لیے صرف چہرے اور پہنچوں پر مسح کرنا کافی تھا ( زمین پر لیٹنے کی ضرورت نہ تھی ) ۔' WHERE id = 338;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے یزید بن ابراہیم نے بیان کیا، وہ محمد سے، وہ ام عطیہ سے، انہوں نے فرمایا کہ ہمیں حکم ہوا کہ ہم عیدین کے دن حائضہ اور پردہ نشین عورتوں کو بھی باہر لے جائیں۔ تاکہ وہ مسلمانوں کے اجتماع اور ان کی دعاؤں میں شریک ہو سکیں۔ البتہ حائضہ عورتوں کو نماز پڑھنے کی جگہ سے دور رکھیں۔ ایک عورت نے کہا یا رسول اللہ! ہم میں بعض عورتیں ایسی بھی ہوتی ہیں جن کے پاس ( پردہ کرنے کے لیے ) چادر نہیں ہوتی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی ساتھی عورت اپنی چادر کا ایک حصہ اسے اڑھا دے۔ اور عبداللہ بن رجاء نے کہا ہم سے عمران قطان نے بیان کیا، کہا ہم سے محمد بن سیرین نے، کہا ہم سے ام عطیہ نے، میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا اور یہی حدیث بیان کی۔' WHERE id = 348;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن صالح نے بیان کیا، کہا ہم سے فلیح بن سلیمان نے، وہ سعید بن حارث سے، کہا ہم نے جابر بن عبداللہ سے ایک کپڑے میں نماز پڑھنے کے بارے میں پوچھا۔ تو آپ نے فرمایا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر ( غزوہ بواط ) میں گیا۔ ایک رات میں کسی ضرورت کی وجہ سے آپ کے پاس آیا۔ میں نے دیکھا کہ آپ صلی اللہ علیہ وسلم نماز میں مشغول ہیں، اس وقت میرے بدن پر صرف ایک ہی کپڑا تھا۔ اس لیے میں نے اسے لپیٹ لیا اور آپ کے بازو میں ہو کر میں بھی نماز میں شریک ہو گیا۔ جب آپ نماز سے فارغ ہوئے تو دریافت فرمایا جابر اس رات کے وقت کیسے آئے؟ میں نے آپ صلی اللہ علیہ وسلم سے اپنی ضرورت کے متعلق کہا۔ میں جب فارغ ہو گیا تو آپ صلی اللہ علیہ وسلم نے پوچھا کہ یہ تم نے کیا لپیٹ رکھا تھا جسے میں نے دیکھا۔ میں نے عرض کی کہ ( ایک ہی ) کپڑا تھا ( اس طرح نہ لپیٹتا تو کیا کرتا ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر وہ کشادہ ہو تو اسے اچھی طرح لپیٹ لیا کر اور اگر تنگ ہو تو اس کو تہبند کے طور پر باندھ لیا کر۔' WHERE id = 358;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے اسماعیل بن علیہ نے کہ کہا ہمیں عبدالعزیز بن صہیب نے انس بن مالک رضی اللہ عنہ سے روایت کر کے کہ نبی کریم صلی اللہ علیہ وسلم غزوہ خیبر میں تشریف لے گئے۔ ہم نے وہاں فجر کی نماز اندھیرے ہی میں پڑھی۔ پھر نبی کریم صلی اللہ علیہ وسلم سوار ہوئے۔ اور ابوطلحہ بھی سوار ہوئے۔ میں ابوطلحہ کے پیچھے بیٹھا ہوا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اپنی سواری کا رخ خیبر کی گلیوں کی طرف کر دیا۔ میرا گھٹنا نبی کریم صلی اللہ علیہ وسلم کی ران سے چھو جاتا تھا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے اپنی ران سے تہبند کو ہٹایا۔ یہاں تک کہ میں نبی کریم صلی اللہ علیہ وسلم کی شفاف اور سفید رانوں کی سفیدی اور چمک دیکھنے لگا۔ جب آپ خیبر کی بستی میں داخل ہوئے، تو آپ صلی اللہ علیہ وسلم نے فرمایا «الله اكبر» اللہ سب سے بڑا ہے، خیبر برباد ہو گیا، جب ہم کسی قوم کے آنگن میں اتر جائیں تو ڈرائے ہوئے لوگوں کی صبح منحوس ہو جاتی ہے۔ آپ نے یہ تین مرتبہ فرمایا، اس نے کہا کہ خیبر کے یہودی لوگ اپنے کاموں کے لیے باہر نکلے ہی تھے کہ وہ چلا اٹھے محمد ( صلی اللہ علیہ وسلم ) آن پہنچے۔ اور عبدالعزیز راوی نے کہا کہ بعض انس رضی اللہ عنہ سے روایت کرنے والے ہمارے ساتھیوں نے «والخميس‏» کا لفظ بھی نقل کیا ہے ( یعنی وہ چلا اٹھے کہ محمد صلی اللہ علیہ وسلم لشکر لے کر پہنچ گئے ) پس ہم نے خیبر لڑ کر فتح کر لیا اور قیدی جمع کئے گئے۔ پھر دحیہ رضی اللہ عنہ آئے اور عرض کی کہ یا رسول اللہ! قیدیوں میں سے کوئی باندی مجھے عنایت کیجیئے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جاؤ کوئی باندی لے لو۔ انہوں نے صفیہ بنت حیی کو لے لیا۔ پھر ایک شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کی یا رسول اللہ! صفیہ جو قریظہ اور نضیر کے سردار کی بیٹی ہیں، انہیں آپ نے دحیہ کو دے دیا۔ وہ تو صرف آپ ہی کے لیے مناسب تھیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ دحیہ کو صفیہ کے ساتھ بلاؤ، وہ لائے گئے۔ جب نبی کریم صلی اللہ علیہ وسلم نے انہیں دیکھا تو فرمایا کہ قیدیوں میں سے کوئی اور باندی لے لو۔ راوی نے کہا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے صفیہ کو آزاد کر دیا اور انہیں اپنے نکاح میں لے لیا۔ ثابت بنانی نے انس رضی اللہ عنہ سے پوچھا کہ ابوحمزہ! ان کا مہر نبی کریم صلی اللہ علیہ وسلم نے کیا رکھا تھا؟ انس رضی اللہ عنہ نے فرمایا کہ خود انہیں کی آزادی ان کا مہر تھا اور اسی پر آپ نے نکاح کیا۔ پھر راستے ہی میں ام سلیم رضی اللہ عنہا ( انس رضی اللہ عنہ کی والدہ ) نے انہیں دلہن بنایا اور نبی کریم صلی اللہ علیہ وسلم کے پاس رات کے وقت بھیجا۔ اب نبی کریم صلی اللہ علیہ وسلم دولہا تھے، اس لیے آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس کے پاس بھی کچھ کھانے کی چیز ہو تو یہاں لائے۔ آپ نے ایک چمڑے کا دستر خوان بچھایا۔ بعض صحابہ کھجور لائے، بعض گھی، عبدالعزیز نے کہا کہ میرا خیال ہے انس رضی اللہ عنہ نے ستو کا بھی ذکر کیا۔ پھر لوگوں نے ان کا حلوہ بنا لیا۔ یہ رسول اللہ صلی اللہ علیہ وسلم کا ولیمہ تھا۔' WHERE id = 368;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہ کہا ہم سے شعبہ نے، کہا ہم سے سلیمان شیبانی نے عبداللہ بن شداد کے واسطے سے، انہوں نے ام المؤمنین میمونہ رضی اللہ عنہا سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم سجدہ گاہ ( یعنی چھوٹے مصلے ) پر نماز پڑھا کرتے تھے۔' WHERE id = 378;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عباس نے بیان کیا، انہوں نے کہا ہم سے ابن مہدی نے بیان کیا، انہوں نے کہا ہم سے منصور بن سعد نے میمون بن سیاہ کے واسطہ سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، جس نے ہماری طرح نماز پڑھی اور ہماری طرح قبلہ کی طرف منہ کیا اور ہمارے ذبیحہ کو کھایا تو وہ مسلمان ہے جس کے لیے اللہ اور اس کے رسول کی پناہ ہے۔ پس تم اللہ کے ساتھ اس کی دی ہوئی پناہ میں خیانت نہ کرو۔' WHERE id = 388;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے عبداللہ بن دینار کے واسطہ سے، انہوں نے عبداللہ بن عمر سے، آپ نے فرمایا کہ لوگ قباء میں فجر کی نماز پڑھ رہے تھے کہ اتنے میں ایک آنے والا آیا۔ اس نے بتایا کہ رسول اللہ صلی اللہ علیہ وسلم پر کل وحی نازل ہوئی ہے اور انہیں کعبہ کی طرف ( نماز میں ) منہ کرنے کا حکم ہو گیا ہے۔ چنانچہ ان لوگوں نے بھی کعبہ کی جانب منہ کر لیے جب کہ اس وقت وہ شام کی جانب منہ کئے ہوئے تھے، اس لیے وہ سب کعبہ کی جانب گھوم گئے۔' WHERE id = 400;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا کہ ہم سے زہیر بن معاویہ نے، کہا ہم سے حمید نے انس بن مالک سے کہ نبی کریم صلی اللہ علیہ وسلم نے قبلہ کی طرف ( دیوار پر ) بلغم دیکھا تو آپ صلی اللہ علیہ وسلم نے خود اسے کھرچ ڈالا اور آپ صلی اللہ علیہ وسلم کی ناخوشی کو محسوس کیا گیا یا ( راوی نے اس طرح بیان کیا کہ ) اس کی وجہ سے آپ صلی اللہ علیہ وسلم کی شدید ناگواری کو محسوس کیا گیا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب کوئی شخص نماز کے لیے کھڑا ہوتا ہے تو وہ اپنے رب سے سرگوشی کرتا ہے، یا یہ کہ اس کا رب اس کے اور قبلہ کے درمیان ہوتا ہے۔ اس لیے قبلہ کی طرف نہ تھوکا کرو، البتہ بائیں طرف یا قدم کے نیچے تھوک لیا کرو۔ پھر آپ صلی اللہ علیہ وسلم نے اپنی چادر کا ایک کونا ( کنارہ ) لیا، اس میں تھوکا اور چادر کی ایک تہہ کو دوسری تہہ پر پھیر لیا اور فرمایا، یا اس طرح کر لیا کرے۔' WHERE id = 412;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے ہشام بن عروہ کے واسطہ سے بیان کیا، کہا کہ مجھے میرے باپ نے عائشہ رضی اللہ عنہا سے یہ خبر پہنچائی کہ ام حبیبہ اور ام سلمہ رضی اللہ عنہما دونوں نے ایک کلیسا کا ذکر کیا جسے انہوں نے حبشہ میں دیکھا تو اس میں مورتیں ( تصویریں ) تھیں۔ انہوں نے اس کا تذکرہ نبی کریم صلی اللہ علیہ وسلم سے بھی کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان کا یہ قاعدہ تھا کہ اگر ان میں کوئی نیکوکار ( نیک ) شخص مر جاتا تو وہ لوگ اس کی قبر پر مسجد بناتے اور اس میں یہی مورتیں ( تصویریں ) بنا دیتے پس یہ لوگ اللہ کی درگاہ میں قیامت کے دن تمام مخلوق میں برے ہوں گے۔' WHERE id = 422;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے ہشام کے واسطہ سے، انہوں نے اپنے باپ سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ عرب کے کسی قبیلہ کی ایک کالی لونڈی تھی۔ انہوں نے اسے آزاد کر دیا تھا اور وہ انہیں کے ساتھ رہتی تھی۔ اس نے بیان کیا کہ ایک دفعہ ان کی ایک لڑکی ( جو دلہن تھی ) نہانے کو نکلی، اس کا کمر بند سرخ تسموں کا تھا اس نے وہ کمر بند اتار کر رکھ دیا یا اس کے بدن سے گر گیا۔ پھر اس طرف سے ایک چیل گزری جہاں کمر بند پڑا تھا۔ چیل اسے ( سرخ رنگ کی وجہ سے ) گوشت سمجھ کر جھپٹ لے گئی۔ بعد میں قبیلہ والوں نے اسے بہت تلاش کیا، لیکن کہیں نہ ملا۔ ان لوگوں نے اس کی تہمت مجھ پر لگا دی اور میری تلاشی لینی شروع کر دی، یہاں تک کہ انہوں نے اس کی شرمگاہ تک کی تلاشی لی۔ اس نے بیان کیا کہ اللہ کی قسم میں ان کے ساتھ اسی حالت میں کھڑی تھی کہ وہی چیل آئی اور اس نے ان کا وہ کمر بند گرا دیا۔ وہ ان کے سامنے ہی گرا۔ میں نے ( اسے دیکھ کر ) کہا یہی تو تھا جس کی تم مجھ پر تہمت لگاتے تھے۔ تم لوگوں نے مجھ پر اس کا الزام لگایا تھا حالانکہ میں اس سے پاک تھی۔ یہی تو ہے وہ کمر بند! اس ( لونڈی ) نے کہا کہ اس کے بعد میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور اسلام لائی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ اس کے لیے مسجد نبوی میں ایک بڑا خیمہ لگا دیا گیا۔ ( یا یہ کہا کہ ) چھوٹا سا خیمہ لگا دیا گیا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ وہ لونڈی میرے پاس آتی اور مجھ سے باتیں کیا کرتی تھی۔ جب بھی وہ میرے پاس آتی تو یہ ضرور کہتی کہ کمر بند کا دن ہمارے رب کی عجیب نشانیوں میں سے ہے۔ اسی نے مجھے کفر کے ملک سے نجات دی۔ عائشہ رضی اللہ عنہا فرماتی ہیں کہ میں نے اس سے کہا، آخر بات کیا ہے؟ جب بھی تم میرے پاس بیٹھتی ہو تو یہ بات ضرور کہتی ہو۔ آپ نے بیان کیا کہ پھر اس نے مجھے یہ قصہ سنایا۔' WHERE id = 433;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد بن ایمن نے اپنے والد کے واسطے سے بیان کیا، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے کہ ایک عورت نے کہا یا رسول اللہ صلی اللہ علیہ وسلم ! کیا میں آپ کے لیے کوئی ایسی چیز نہ بنا دوں جس پر آپ صلی اللہ علیہ وسلم بیٹھا کریں۔ میرا ایک بڑھئی غلام بھی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا اگر تو چاہے تو منبر بنوا دے۔' WHERE id = 443;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے روح بن عبادہ اور محمد بن جعفر نے شعبہ کے واسطہ سے بیان کیا، انہوں نے محمد بن زیاد سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے انہوں نے نبی کریم صلی اللہ علیہ وسلم سے آپ صلی اللہ علیہ وسلم نے فرمایا کہ گذشتہ رات ایک سرکش جن اچانک میرے پاس آیا۔ یا اسی طرح کی کوئی بات آپ نے فرمائی، وہ میری نماز میں خلل ڈالنا چاہتا تھا۔ لیکن اللہ تبارک و تعالیٰ نے مجھے اس پر قابو دے دیا اور میں نے سوچا کہ مسجد کے کسی ستون کے ساتھ اسے باندھ دوں تاکہ صبح کو تم سب بھی اسے دیکھو۔ پھر مجھے اپنے بھائی سلیمان کی یہ دعا یاد آ گئی ( جو سورۃ ص میں ہے ) ”اے میرے رب! مجھے ایسا ملک عطا کرنا جو میرے بعد کسی کو حاصل نہ ہو“۔ راوی حدیث روح نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اس شیطان کو ذلیل کر کے دھتکار دیا۔' WHERE id = 454;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، انہوں نے کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا مجھے یونس بن یزید نے خبر دی، انہوں نے ابن شہاب زہری کے واسطہ سے بیان کیا، انہوں نے کہا کہ مجھ سے عبداللہ بن کعب بن مالک نے بیان کیا، ان کو ان کے باپ کعب بن مالک رضی اللہ عنہ نے خبر دی کہ انھوں نے عبداللہ ابن ابی حدرد رضی اللہ عنہ سے اپنے ایک قرض کے سلسلے میں رسول اللہ صلی اللہ علیہ وسلم کے دور میں مسجد نبوی کے اندر تقاضا کیا۔ دونوں کی آواز کچھ اونچی ہو گئی یہاں تک کہ رسول اللہ صلی اللہ علیہ وسلم نے بھی اپنے حجرہ سے سن لیا۔ آپ اٹھے اور حجرہ پر پڑے ہوئے پردہ کو ہٹایا۔ آپ نے کعب بن مالک کو آواز دی، اے کعب! کعب بولے۔ یا رسول اللہ! حاضر ہوں۔ آپ نے اپنے ہاتھ کے اشارے سے بتایا کہ وہ اپنا آدھا قرض معاف کر دے۔ کعب نے عرض کی یا رسول اللہ! میں نے معاف کر دیا۔ آپ نے ابن ابی حدرد سے فرمایا اچھا اب چل اٹھ اس کا قرض ادا کر۔' WHERE id = 464;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی نے بیان کیا کہا ہم سے فضیل بن سلیمان نے، کہا ہم سے موسیٰ بن عقبہ نے، کہا میں نے سالم بن عبداللہ بن عمر رضی اللہ عنہما کو دیکھا کہ وہ ( مدینہ سے مکہ تک ) راستے میں کئی جگہوں کو ڈھونڈھ کر وہاں نماز پڑھتے اور کہتے کہ ان کے باپ عبداللہ بن عمر رضی اللہ عنہما بھی ان مقامات پر نماز پڑھا کرتے تھے۔ اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو ان مقامات پر نماز پڑھتے ہوئے دیکھا ہے اور موسیٰ بن عقبہ نے کہا کہ مجھ سے نافع نے ابن عمر رضی اللہ عنہما کے متعلق بیان کیا کہ وہ ان مقامات پر نماز پڑھا کرتے تھے۔ اور میں نے سالم سے پوچھا تو مجھے خوب یاد ہے کہ انہوں نے بھی نافع کے بیان کے مطابق ہی تمام مقامات کا ذکر کیا۔ فقط مقام شرف روحاء کی مسجد کے متعلق دونوں نے اختلاف کیا۔' WHERE id = 475;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہم سے امام مالک نے ابن شہاب کے واسطے سے بیان کیا، انہوں نے عبیداللہ بن عبداللہ بن عتبہ سے کہ عبداللہ بن عباس رضی اللہ عنہما نے فرمایا کہ میں ایک گدھی پر سوار ہو کر آیا۔ اس زمانہ میں بالغ ہونے والا تھا۔ رسول اللہ صلی اللہ علیہ وسلم منیٰ میں لوگوں کو نماز پڑھا رہے تھے۔ لیکن دیوار آپ صلی اللہ علیہ وسلم کے سامنے نہ تھی۔ میں صف کے بعض حصے سے گزر کر سواری سے اترا اور میں نے گدھی کو چرنے کے لیے چھوڑ دیا اور صف میں داخل ہو گیا۔ پس کسی نے مجھ پر اعتراض نہیں کیا۔' WHERE id = 485;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے عمرو بن عامر سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے بڑے بڑے صحابہ رضوان اللہ علیہم اجمعین کو دیکھا کہ وہ مغرب ( کی اذان ) کے وقت ستونوں کی طرف لپکتے۔ اور شعبہ نے عمرو بن عامر سے انہوں نے انس رضی اللہ عنہ سے ( اس حدیث میں ) یہ زیادتی کی ہے۔ ”یہاں تک کہ نبی کریم صلی اللہ علیہ وسلم حجرے سے باہر تشریف لاتے۔“' WHERE id = 495;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا کہ ہمیں امام مالک نے خبر دی عمر بن عبیداللہ کے غلام ابوالنضر سے، انہوں نے ابوسلمہ عبداللہ بن عبدالرحمٰن سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا سے کہ آپ رضی اللہ عنہا نے فرمایا، میں رسول اللہ صلی اللہ علیہ وسلم کے سامنے سو جایا کرتی تھی۔ میرے پاؤں آپ صلی اللہ علیہ وسلم کے سامنے ( پھیلے ہوئے ) ہوتے۔ جب آپ صلی اللہ علیہ وسلم سجدہ کرتے تو پاؤں کو ہلکے سے دبا دیتے اور میں انہیں سکیڑ لیتی پھر جب قیام فرماتے تو میں انہیں پھیلا لیتی تھی اس زمانہ میں گھروں کے اندر چراغ نہیں ہوتے تھے۔ ( معلوم ہوا کہ ایسا کرنا بھی جائز ہے ) ۔' WHERE id = 505;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید قطان نے اعمش کی روایت سے بیان کیا، اعمش (سلیمان بن مہران) نے کہا کہ مجھ سے شقیق بن مسلمہ نے بیان کیا، شقیق نے کہا کہ میں نے حذیفہ بن یمان رضی اللہ عنہ سے سنا۔ حذیفہ رضی اللہ عنہ نے فرمایا کہ ہم عمر رضی اللہ عنہ کی خدمت میں بیٹھے ہوئے تھے کہ آپ نے پوچھا کہ فتنہ سے متعلق رسول اللہ صلی اللہ علیہ وسلم کی کوئی حدیث تم میں سے کسی کو یاد ہے؟ میں بولا، میں نے اسے ( اسی طرح یاد رکھا ہے ) جیسے نبی کریم صلی اللہ علیہ وسلم نے اس حدیث کو بیان فرمایا تھا۔ عمر رضی اللہ عنہ بولے، کہ تم رسول اللہ صلی اللہ علیہ وسلم سے فتن کو معلوم کرنے میں بہت بےباک تھے۔ میں نے کہا کہ انسان کے گھر والے، مال اولاد اور پڑوسی سب فتنہ ( کی چیز ) ہیں۔ اور نماز، روزہ، صدقہ، اچھی بات کے لیے لوگوں کو حکم کرنا اور بری باتوں سے روکنا ان فتنوں کا کفارہ ہیں۔ عمر رضی اللہ عنہ نے فرمایا کہ میں تم سے اس کے متعلق نہیں پوچھتا، مجھے تم اس فتنہ کے بارے میں بتلاؤ جو سمندر کی موج کی طرح ٹھاٹھیں مارتا ہوا بڑھے گا۔ اس پر میں نے کہا کہ یا امیرالمؤمنین! آپ اس سے خوف نہ کھائیے۔ آپ کے اور فتنہ کے درمیان ایک بند دروازہ ہے۔ پوچھا کیا وہ دروازہ توڑ دیا جائے گا یا ( صرف ) کھولا جائے گا۔ میں نے کہا کہ توڑ دیا جائے گا۔ عمر رضی اللہ عنہ بول اٹھے، کہ پھر تو وہ کبھی بند نہیں ہو سکے گا۔ شقیق نے کہا کہ ہم نے حذیفہ رضی اللہ عنہ سے پوچھا، کیا عمر رضی اللہ عنہ اس دروازہ کے متعلق کچھ علم رکھتے تھے تو انہوں نے کہا کہ ہاں! بالکل اسی طرح جیسے دن کے بعد رات کے آنے کا۔ میں نے تم سے ایک ایسی حدیث بیان کی ہے جو قطعاً غلط نہیں ہے۔ ہمیں اس کے متعلق حذیفہ رضی اللہ عنہ سے پوچھنے میں ڈر ہوتا تھا ( کہ دروازہ سے کیا مراد ہے ) اس لیے ہم نے مسروق سے کہا ( کہ وہ پوچھیں ) انہوں نے دریافت کیا تو آپ نے بتایا کہ وہ دروازہ خود عمر رضی اللہ عنہ ہی تھے۔' WHERE id = 516;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے بنی تیم اللہ کے غلام مہاجر ابوالحسن نے بیان کیا، کہا کہ میں نے زید بن وہب جہنی سے سنا، وہ ابوذر غفاری رضی اللہ عنہ سے نقل کرتے تھے کہ انہوں نے کہا کہ ہم ایک سفر میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ مؤذن نے چاہا کہ ظہر کی اذان دے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ وقت کو ٹھنڈا ہونے دو، مؤذن نے ( تھوڑی دیر بعد ) پھر چاہا کہ اذان دے، لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ ٹھنڈا ہونے دو۔ جب ہم نے ٹیلے کا سایہ ڈھلا ہوا دیکھ لیا۔ ( تب اذان کہی گئی ) پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ گرمی کی تیزی جہنم کی بھاپ کی تیزی سے ہے۔ اس لیے جب گرمی سخت ہو جایا کرے تو ظہر کی نماز ٹھنڈے وقت میں پڑھا کرو۔ ابن عباس رضی اللہ عنہما نے فرمایا «يتفيئو» ( کا لفظ جو سورۃ النحل میں ہے ) کے معنے «تتميل‏» ( جھکنا، مائل ہونا ) ہیں۔' WHERE id = 528;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، انہوں نے کہا ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہمیں ابوبکر بن عثمان بن سہل بن حنیف نے خبر دی، انہوں نے کہا میں نے ابوامامہ (سعد بن سہل) سے سنا، وہ کہتے تھے کہ ہم نے عمر بن عبدالعزیز رحمہ اللہ علیہ کے ساتھ ظہر کی نماز پڑھی۔ پھر ہم نکل کر انس بن مالک رضی اللہ عنہ کی خدمت میں حاضر ہوئے تو دیکھا آپ نماز پڑھ رہے ہیں۔ میں نے عرض کی کہ اے مکرم چچا! یہ کون سی نماز آپ نے پڑھی ہے۔ فرمایا کہ عصر کی اور اسی وقت ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ بھی یہ نماز پڑھتے تھے۔' WHERE id = 538;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مہران نے بیان کیا، کہا ہم سے ولید بن مسلمہ نے، انہوں نے کہا کہ ہم سے عبدالرحمٰن بن عمرو اوزاعی نے بیان کیا، کہا مجھ سے ابوالنجاشی نے بیان کیا، ان کا نام عطاء بن صہیب تھا اور یہ رافع بن خدیج رضی اللہ عنہ کے غلام ہیں۔ انہوں نے کہا کہ میں نے رافع بن خدیج سے سنا آپ نے فرمایا کہ ہم مغرب کی نماز نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھ کر جب واپس ہوتے اور تیر اندازی کرتے ( تو اتنا اجالا باقی رہتا تھا کہ ) ایک شخص اپنے تیر گرنے کی جگہ کو دیکھتا تھا۔' WHERE id = 548;
UPDATE hadiths SET urdu = 'ہم سے ایوب بن سلیمان نے بیان کیا، کہا ہم سے ابوبکر نے سلیمان سے، ان سے صالح بن کیسان نے بیان کیا کہ مجھے ابن شہاب نے عروہ سے خبر دی کہ عائشہ رضی اللہ عنہا نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک دفعہ عشاء کی نماز میں دیر فرمائی۔ یہاں تک کہ عمر رضی اللہ عنہ نے پکارا، نماز! عورتیں اور بچے سب سو گئے۔ تب آپ صلی اللہ علیہ وسلم گھر سے باہر تشریف لائے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ روئے زمین پر تمہارے علاوہ اور کوئی اس نماز کا انتظار نہیں کرتا۔ راوی نے کہا، اس وقت یہ نماز ( باجماعت ) مدینہ کے سوا اور کہیں نہیں پڑھی جاتی تھی۔ صحابہ اس نماز کو شام کی سرخی کے غائب ہونے کے بعد رات کے پہلے تہائی حصہ تک ( کسی وقت بھی ) پڑھتے تھے۔' WHERE id = 558;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، انہوں نے کہا ہم سے ہشام دستوائی نے بیان کیا، انہوں نے قتادہ بن دعامہ سے، انہوں نے ابوالعالیہ رفیع سے، انہوں نے ابن عباس رضی اللہ عنہما سے فرمایا کہ میرے سامنے چند معتبر حضرات نے گواہی دی، جن میں سب سے زیادہ معتبر میرے نزدیک عمر رضی اللہ عنہ تھے، کہ نبی کریم صلی اللہ علیہ وسلم نے فجر کی نماز کے بعد سورج بلند ہونے تک اور عصر کی نماز کے بعد سورج ڈوبنے تک نماز پڑھنے سے منع فرمایا۔ ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے شعبہ سے، انہوں نے قتادہ سے کہ میں نے ابوالعالیہ سے سنا، وہ ابن عباس رضی اللہ عنہما سے بیان کرتے تھے کہ انہوں نے فرمایا کہ مجھ سے چند لوگوں نے یہ حدیث بیان کی۔ ( جو پہلے ذکر ہوئی ) ۔' WHERE id = 569;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے ابواسحاق سے بیان کیا، کہا کہ ہم نے اسود بن یزید اور مسروق بن اجدع کو دیکھا کہ انھوں نے عائشہ رضی اللہ عنہا کے اس کہنے پر گواہی دی کہ نبی کریم صلی اللہ علیہ وسلم جب بھی میرے گھر میں عصر کے بعد تشریف لائے تو دو رکعت ضرور پڑھتے۔' WHERE id = 580;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ نے بیان کیا، کہا کہ ہم سے عبدالوارث بن سعید نے بیان کیا، کہا کہ ہم سے خالد حذاء نے ابوقلابہ عبداللہ بن زید سے، انہوں نے انس رضی اللہ عنہ سے کہ ( نماز کے وقت کے اعلان کے لیے ) لوگوں نے آگ اور ناقوس کا ذکر کیا۔ پھر یہود و نصاریٰ کا ذکر آ گیا۔ پھر بلال رضی اللہ عنہ کو یہ حکم ہوا کہ اذان کے کلمات دو دو مرتبہ کہیں اور اقامت میں ایک ایک مرتبہ۔' WHERE id = 590;
UPDATE hadiths SET urdu = 'یحییٰ نے کہا کہ مجھ سے میرے بعض بھائیوں نے حدیث بیان کی کہ جب مؤذن نے «حى على الصلاة‏» کہا تو معاویہ رضی اللہ عنہ نے «لا حول ولا قوة إلا بالله‏» کہا اور کہنے لگے کہ ہم نے نبی کریم صلی اللہ علیہ وسلم سے ایسا ہی کہتے سنا ہے۔' WHERE id = 600;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا کہ ہم سے محمد بن جعفر غندر نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ بن حجاج نے بیان کیا، کہا کہ میں نے عمرو بن عامر انصاری سے سنا، وہ انس بن مالک رضی اللہ عنہ سے بیان کرتے تھے کہ آپ نے فرمایا کہ ( عہدرسالت میں ) جب مؤذن اذان دیتا تو نبی کریم صلی اللہ علیہ وسلم کے صحابہ ستونوں کی طرف لپکتے۔ جب نبی کریم صلی اللہ علیہ وسلم اپنے حجرہ سے باہر تشریف لاتے تو لوگ اسی طرح نماز پڑھتے ہوئے ملتے۔ یہ جماعت مغرب سے پہلے کی دو رکعتیں تھیں۔ اور ( مغرب میں ) اذان اور تکبیر میں کوئی زیادہ فاصلہ نہیں ہوتا تھا۔ اور عثمان بن جبلہ اور ابوداؤد طیالسی نے شعبہ سے اس ( حدیث میں یوں نقل کیا ہے کہ ) اذان اور تکبیر میں بہت تھوڑا سا فاصلہ ہوتا تھا۔' WHERE id = 611;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا کہ ہم سے شیبان بن عبدالرحمٰن نے یحییٰ بن ابی کثیر سے بیان کیا، انہوں نے عبداللہ بن ابی قتادہ سے، انہوں نے اپنے والد ابوقتادہ رضی اللہ عنہ سے، انہوں نے کہا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز میں تھے۔ آپ صلی اللہ علیہ وسلم نے کچھ لوگوں کے چلنے پھرنے اور بولنے کی آواز سنی۔ نماز کے بعد آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا قصہ ہے لوگوں نے کہا کہ ہم نماز کے لیے جلدی کر رہے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایسا نہ کرو۔ بلکہ جب تم نماز کے لیے آؤ تو وقار اور سکون کو ملحوظ رکھو، نماز کا جو حصہ پاؤ اسے پڑھو اور اور جو رہ جائے اسے ( بعد ) میں پورا کر لو۔' WHERE id = 621;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے خبر دی، انہوں نے نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جماعت کے ساتھ نماز اکیلے نماز پڑھنے سے ستائیس درجہ زیادہ فضیلت رکھتی ہے۔' WHERE id = 631;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یزید بن زریع نے بیان کیا، کہا کہ ہم سے خالد حذاء نے ابوقلابہ عبداللہ بن زید سے، انہوں نے مالک بن حویرث سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا جب نماز کا وقت آ جائے تو تم دونوں اذان دو اور اقامت کہو، پھر جو تم میں بڑا ہے وہ امام بنے۔' WHERE id = 641;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب بصریٰ نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، کہا کہ ہم سے عبدالحمید صاحب الزیادی نے بیان کیا کہ کہا میں نے عبداللہ بن حارث بن نوفل سے سنا، انہوں نے کہا کہ ہمیں ایک دن ابن عباس رضی اللہ عنہما نے جب کہ بارش کی وجہ سے کیچڑ ہو رہی تھی خطبہ سنایا۔ پھر مؤذن کو حکم دیا اور جب وہ «حى على الصلاة‏» پر پہنچا تو آپ نے فرمایا کہ آج یوں پکار دو «الصلاة في الرحال» کہ نماز اپنی قیام گاہوں پر پڑھ لو۔ لوگ ایک دوسرے کو ( حیرت کی وجہ سے ) دیکھنے لگے۔ جیسے اس کو انہوں نے ناجائز سمجھا۔ ابن عباس رضی اللہ عنہما نے فرمایا کہ ایسا معلوم ہوتا ہے کہ تم نے شاید اس کو برا جانا ہے۔ ایسا تو مجھ سے بہتر ذات یعنی رسول اللہ صلی اللہ علیہ وسلم نے بھی کیا تھا۔ بیشک جمعہ واجب ہے مگر میں نے یہ پسند نہیں کیا کہ «حى على الصلاة‏» کہہ کر تمہیں باہر نکالوں ( اور تکلیف میں مبتلا کروں ) اور حماد عاصم سے، وہ عبداللہ بن حارث سے، وہ ابن عباس رضی اللہ عنہما سے، اسی طرح روایت کرتے ہیں۔ البتہ انہوں نے اتنا اور کہا کہ ابن عباس رضی اللہ عنہما نے فرمایا کہ مجھے اچھا معلوم نہیں ہوا کہ تمہیں گنہگار کروں اور تم اس حالت میں آؤ کہ تم مٹی میں گھٹنوں تک آلودہ ہو گئے ہو۔' WHERE id = 651;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، کہا کہ ہم سے حسین بن علی بن ولید نے زائدہ بن قدامہ سے بیان کیا، انہوں نے عبدالملک بن عمیر سے، کہا کہ مجھ سے ابوبردہ عامر نے بیان کیا، انہوں نے ابوموسیٰ اشعری رضی اللہ عنہ سے، آپ نے فرمایا کہ آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم بیمار ہوئے اور جب بیماری شدت اختیار کر گئی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ابوبکر ( رضی اللہ عنہ ) سے کہو کہ وہ لوگوں کو نماز پڑھائیں۔ اس پر عائشہ رضی اللہ عنہا بولیں کہ وہ نرم دل ہیں جب آپ کی جگہ کھڑے ہوں گے تو ان کے لیے نماز پڑھانا مشکل ہو گا۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ ابوبکر سے کہو کہ وہ نماز پڑھائیں۔ عائشہ رضی اللہ عنہا نے پھر وہی بات کہی۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ ابوبکر سے کہو کہ نماز پڑھائیں، تم لوگ صواحب یوسف ( زلیخا ) کی طرح ( باتیں بناتی ) ہو۔ آخر ابوبکر صدیق رضی اللہ عنہ کے پاس آدمی بلانے آیا اور آپ نے لوگوں کو نبی کریم صلی اللہ علیہ وسلم کی زندگی میں ہی نماز پڑھائی۔' WHERE id = 661;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا کہا کہ ہم سے امام مالک رحمہ اللہ نے ہشام بن عروہ سے بیان کیا۔ انہوں نے اپنے باپ عروہ سے انہوں نے ام المؤمنین عائشہ رضی اللہ عنہا سے کہ آپ نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک مرتبہ بیماری کی حالت میں میرے ہی گھر میں نماز پڑھی۔ آپ صلی اللہ علیہ وسلم بیٹھ کر نماز پڑھ رہے تھے اور لوگ آپ صلی اللہ علیہ وسلم کے پیچھے کھڑے ہو کر پڑھ رہے تھے۔ آپ صلی اللہ علیہ وسلم نے ان کو بیٹھنے کا اشارہ کیا اور نماز سے فارغ ہونے کے بعد فرمایا کہ امام اس لیے ہے کہ اس کی پیروی کی جائے۔ اس لیے جب وہ رکوع میں جائے تو تم بھی رکوع میں جاؤ اور جب وہ سر اٹھائے تو تم بھی سر اٹھاؤ اور جب وہ «سمع الله لمن حمده‏» کہے تو تم «ربنا ولك الحمد‏» کہو اور جب وہ بیٹھ کر نماز پڑھے تو تم بھی بیٹھ کر نماز پڑھو۔' WHERE id = 671;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا، کہا کہ ہم سے عمرو بن حارث مصری نے عبد ربہ بن سعید سے بیان کیا، انہوں نے مخرمہ بن سلیمان سے، انہوں نے ابن عباس رضی اللہ عنہما کے غلام کریب سے انہوں نے ابن عباس رضی اللہ عنہما سے۔ آپ نے بتلایا کہ میں ایک رات ام المؤمنین میمونہ کے ہاں سو گیا۔ اس رات نبی کریم صلی اللہ علیہ وسلم کی بھی وہیں سونے کی باری تھی۔ آپ صلی اللہ علیہ وسلم نے وضو کیا اور نماز پڑھنے کے لیے کھڑے ہو گئے۔ میں آپ صلی اللہ علیہ وسلم کے بائیں طرف کھڑا ہو گیا۔ اس لیے آپ صلی اللہ علیہ وسلم نے مجھے پکڑ کر دائیں طرف کر دیا۔ پھر تیرہ رکعت ( وتر سمیت ) نماز پڑھی اور سو گئے۔ یہاں تک کہ خراٹے لینے لگے اور نبی کریم صلی اللہ علیہ وسلم جب سوتے تو خراٹے لیتے تھے۔ پھر مؤذن آیا تو آپ صلی اللہ علیہ وسلم باہر تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم نے اس کے بعد ( فجر کی ) نماز پڑھی اور وضو نہیں کیا۔ عمرو نے بیان کیا میں نے یہ حدیث بکیر بن عبداللہ کے سامنے بیان کی تو انہوں نے فرمایا کہ یہ حدیث مجھ سے کریب نے بھی بیان کی تھی۔' WHERE id = 682;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا کہ ہم سے سلیمان بن بلال نے بیان کیا، کہا کہ ہم سے شریک بن عبداللہ بن ابی نمر قریشی نے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم سے زیادہ ہلکی لیکن کامل نماز میں نے کسی امام کے پیچھے کبھی نہیں پڑھی۔ آپ صلی اللہ علیہ وسلم کا یہ حال تھا کہ اگر آپ صلی اللہ علیہ وسلم بچے کے رونے کی آواز سن لیتے تو اس خیال سے کہ اس کی ماں کہیں پریشانی میں نہ مبتلا ہو جائے نماز مختصر کر دیتے۔' WHERE id = 692;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا کہ ہم سے عبدالوارث نے عبدالعزیز بن صہیب سے بیان کیا، انہوں نے انس رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ صفیں سیدھی کر لو۔ میں تمہیں اپنی پیٹھ کے پیچھے سے دیکھ رہا ہوں۔' WHERE id = 702;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، کہا کہ ہم سے محمد بن اسماعیل بن ابی فدیک نے بیان کیا، کہا کہ ہم سے محمد بن عبدالرحمٰن بن ابی ذئب نے بیان کیا، مقبری کے واسطہ سے، انہوں نے ابوسلمہ بن عبدالرحمٰن سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ نبی کریم صلی اللہ علیہ وسلم کے پاس ایک چٹائی تھی۔ جسے آپ صلی اللہ علیہ وسلم دن میں بچھاتے تھے اور رات میں اس کا پردہ کر لیتے تھے۔ پھر چند لوگ آپ صلی اللہ علیہ وسلم کے پاس کھڑے ہوئے یا آپ صلی اللہ علیہ وسلم کی طرف جھکے اور آپ صلی اللہ علیہ وسلم کے پیچھے نماز پڑھنے لگے۔' WHERE id = 713;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا امام مالک رحمہ اللہ سے، انہوں نے ابوحازم بن دینار سے، انہوں نے سہل بن سعد رضی اللہ عنہ سے کہ لوگوں کو حکم دیا جاتا تھا کہ نماز میں دایاں ہاتھ بائیں کلائی پر رکھیں، ابوحازم بن دینار نے بیان کیا کہ مجھے اچھی طرح یاد ہے کہ آپ اسے رسول اللہ صلی اللہ علیہ وسلم تک پہنچاتے تھے۔ اسماعیل بن ابی اویس نے کہا کہ یہ بات نبی کریم صلی اللہ علیہ وسلم تک پہنچائی جاتی تھی یوں نہیں کہا کہ پہنچاتے تھے۔' WHERE id = 723;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، انہوں نے کہا کہ ہم سے سعید بن مہران ابن ابی عروبہ نے بیان کیا، انہوں نے کہا کہ ہم سے قتادہ نے بیان کیا کہ انس بن مالک رضی اللہ عنہ نے ان سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا۔ لوگوں کا کیا حال ہے جو نماز میں اپنی نظریں آسمان کی طرف اٹھاتے ہیں۔ آپ صلی اللہ علیہ وسلم نے اس سے نہایت سختی سے روکا۔ یہاں تک آپ صلی اللہ علیہ وسلم نے فرمایا کہ لوگ اس حرکت سے باز آ جائیں ورنہ ان کی بینائی اچک لی جائے گی۔' WHERE id = 733;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا کہ کہا ہم سے میرے والد نے، انہوں نے کہا کہ ہم سے سلیمان بن مہران اعمش نے بیان کیا، کہا کہ مجھ سے عمارہ بن عمیر نے بیان کیا ابومعمر عبداللہ بن مخبرہ سے، کہا کہ ہم نے خباب بن ارت سے پوچھا کیا نبی کریم صلی اللہ علیہ وسلم ظہر اور عصر میں قرآت کیا کرتے تھے؟ تو انہوں نے بتلایا کہ ہاں، ہم نے پوچھا کہ آپ لوگوں کو کس طرح معلوم ہوتا تھا؟ فرمایا کہ آپ صلی اللہ علیہ وسلم کی داڑھی مبارک کے ہلنے سے۔' WHERE id = 743;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے ابوعون محمد بن عبداللہ ثقفی سے بیان کیا، انہوں نے کہا کہ میں نے جابر بن سمرہ سے سنا، انہوں نے بیان کیا کہ امیرالمؤمنین عمر رضی اللہ عنہ نے سعد بن ابی وقاص رضی اللہ عنہ سے کہا کہ آپ کی شکایت کوفہ والوں نے تمام ہی باتوں میں کی ہے، یہاں تک کہ نماز میں بھی۔ انہوں نے کہا کہ میرا عمل تو یہ ہے کہ پہلی دو رکعات میں قرآت لمبی کرتا ہوں اور دوسری دو میں مختصر جس طرح میں نے نبی کریم صلی اللہ علیہ وسلم کے پیچھے نماز پڑھی تھی اس میں کسی قسم کی کمی نہیں کرتا۔ عمر رضی اللہ عنہ نے فرمایا کہ سچ کہتے ہو۔ تم سے امید بھی اسی کی ہے۔' WHERE id = 753;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے خبر دی انہوں نے ابن شہاب سے، انہوں نے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن کے واسطے سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب امام «آمين» کہے تو تم بھی «آمين» کہو۔ کیونکہ جس کی «آمين» ملائکہ کے آمین کے ساتھ ہو گئی اس کے پچھلے تمام گناہ معاف کر دئیے جائیں گے۔ ابن شہاب نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم «آمين» کہتے تھے۔' WHERE id = 764;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ابویعفور اکبر سے، انہوں نے بیان کیا کہ میں نے مصعب بن سعد سے سنا، انہوں نے کہا کہ میں نے اپنے والد کے پہلو میں نماز پڑھی اور اپنی دونوں ہتھیلیوں کو ملا کر رانوں کے درمیان رکھ لیا۔ اس پر میرے باپ نے مجھے ٹوکا اور فرمایا کہ ہم بھی پہلے اسی طرح کرتے تھے۔ لیکن بعد میں اس سے روک دئیے گئے اور حکم ہوا کہ ہم اپنے ہاتھوں کو گھٹنوں پر رکھیں۔' WHERE id = 774;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے شعبہ نے ثابت بنانی سے بیان کیا، انہوں نے کہا کہ انس رضی اللہ عنہ ہمیں نبی کریم صلی اللہ علیہ وسلم کی نماز کا طریقہ بتلاتے تھے۔ چنانچہ آپ صلی اللہ علیہ وسلم نماز پڑھتے اور جب اپنا سر رکوع سے اٹھاتے تو اتنی دیر تک کھڑے رہتے کہ ہم سوچنے لگتے کہ آپ صلی اللہ علیہ وسلم بھول گئے ہیں۔' WHERE id = 784;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے، انہوں نے عمرو سے، انہوں نے طاؤس سے، انہوں نے ابن عباس رضی اللہ عنہما سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہمیں سات اعضاء پر اس طرح سجدہ کا حکم ہوا ہے کہ ہم نہ بال سمیٹیں نہ کپڑے۔' WHERE id = 794;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے محمد بن جعفر نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ میں نے قتادہ سے سنا، انہوں نے انس بن مالک رضی اللہ عنہ سے انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سجدہ میں اعتدال کو ملحوظ رکھو اور اپنے بازو کتوں کی طرح نہ پھیلایا کرو۔' WHERE id = 805;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے یزید بن ابی حبیب سے بیان کیا، ان سے ابوالخیر مرثد بن عبداللہ نے ان سے عبداللہ بن عمرو رضی اللہ عنہما نے، ان سے ابوبکر صدیق رضی اللہ عنہ نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا کہ آپ صلی اللہ علیہ وسلم مجھے کوئی ایسی دعا سکھا دیجئیے جسے میں نماز میں پڑھا کروں۔ آپ نے فرمایا کہ یہ دعا پڑھا کرو «اللهم إني ظلمت نفسي ظلما كثيرا ولا يغفر الذنوب إلا أنت،‏‏‏‏ فاغفر لي مغفرة من عندك،‏‏‏‏ وارحمني إنك أنت الغفور الرحيم» اے اللہ! میں نے اپنی جان پر ( گناہ کر کے ) بہت زیادہ ظلم کیا پس گناہوں کو تیرے سوا کوئی دوسرا معاف کرنے والا نہیں۔ مجھے اپنے پاس سے بھرپور مغفرت عطا فرما اور مجھ پر رحم کر کہ مغفرت کرنے والا اور رحم کرنے والا بیشک وشبہ تو ہی ہے۔' WHERE id = 816;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے جریر بن حازم نے بیان کیا، انہوں نے کہا کہ ہم سے ابورجاء عمران بن تمیم نے سمرہ بن جندب رضی اللہ عنہ سے نقل کیا، انہوں نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم جب نماز ( فرض ) پڑھا چکتے تو ہماری طرف منہ کرتے۔' WHERE id = 826;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، انہوں نے سلیمان شیبانی سے سنا، انہوں نے شعبی سے، انہوں نے بیان کیا کہ مجھے ایک ایسے شخص نے خبر دی جو ( ایک مرتبہ ) نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک اکیلی الگ تھلگ ٹوٹی ہوئی قبر پر سے گزر رہے تھے وہاں نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھائی اور لوگ آپ صلی اللہ علیہ وسلم کے پیچھے صف باندھے ہوئے تھے۔ سلیمان نے کہا کہ میں نے شعبی سے پوچھا کہ ابوعمرو آپ سے یہ کس نے بیان کیا تو انہوں نے کہا کہ ابن عباس رضی اللہ عنہما نے۔' WHERE id = 837;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، انہوں نے امام مالک رحمہ اللہ سے بیان کیا، (دوسری سند) اور ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہیں امام مالک رحمہ اللہ نے یحییٰ بن سعید انصاری سے خبر دی، انہیں عمرہ بنت عبدالرحمٰن نے، ان سے عائشہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم صبح کی نماز پڑھ لیتے پھر عورتیں چادریں لپیٹ کر ( اپنے گھروں کو ) واپس ہو جاتی تھیں۔ اندھیرے سے ان کی پہچان نہ ہو سکتی۔' WHERE id = 847;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے حدیث بیان کی، انہوں نے کہا کہ ہمیں مالک نے صفوان بن سلیم کے واسطہ سے خبر دی، انہیں عطاء بن یسار نے، انہیں ابو سعید خدری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جمعہ کے دن ہر بالغ کے لیے غسل ضروری ہے۔' WHERE id = 859;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہ ہمیں سفیان ثوری نے منصور بن معمر اور حصین بن عبدالرحمٰن سے خبر دی، انہیں ابووائل نے، انہیں حذیفہ بن یمان رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم جب رات کو اٹھتے تو منہ کو مسواک سے خوب صاف کرتے۔' WHERE id = 869;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا کہ ہم سے ابواسامہ نے بیان کیا کہا کہ ہم سے عبیداللہ ابن عمر نے بیان کیا، ان سے نافع نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے، انہوں نے کہا کہ عمر رضی اللہ عنہ کی ایک بیوی تھیں جو صبح اور عشاء کی نماز جماعت سے پڑھنے کے لیے مسجد میں آیا کرتی تھیں۔ ان سے کہا گیا کہ باوجود اس علم کے کہ عمر رضی اللہ عنہ اس بات کو مکروہ جانتے ہیں اور وہ غیرت محسوس کرتے ہیں پھر آپ مسجد میں کیوں جاتی ہیں۔ اس پر انہوں نے جواب دیا کہ پھر وہ مجھے منع کیوں نہیں کر دیتے۔ لوگوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کی اس حدیث کی وجہ سے کہ اللہ کی بندیوں کو اللہ کی مسجدوں میں آنے سے مت روکو۔' WHERE id = 879;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہوں نے کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی انہوں نے کہا کہ ہمیں ابن ابی ذئب نے خبر دی، انہیں سعید مقبری نے، انہیں ان کے باپ ابوسعید نے، انہیں عبداللہ بن ودیعہ نے، انہیں سلمان فارسی رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس نے جمعہ کے دن غسل کیا اور خوب پاکی حاصل کی اور تیل یا خوشبو استعمال کی، پھر جمعہ کے لیے چلا اور دو آدمیوں کے بیچ میں نہ گھسا اور جتنی اس کی قسمت میں تھی، نماز پڑھی، پھر جب امام باہر آیا اور خطبہ شروع کیا تو خاموش ہو گیا، اس کے اس جمعہ سے دوسرے جمعہ تک کے تمام گناہ بخش دیئے جائیں گے۔' WHERE id = 889;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن عمر قواریری نے بیان کیا، انہوں نے کہا کہ ہم سے خالد بن حارث نے بیان کیا، انہوں نے کہا کہ ہم سے عبیداللہ بن عمر نے نافع سے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کھڑے ہو کر خطبہ دیتے تھے۔ پھر بیٹھ جاتے اور پھر کھڑے ہوتے جیسے تم لوگ بھی آج کل کرتے ہو۔' WHERE id = 899;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے عمرو بن دینار نے، ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ ایک شخص آیا نبی کریم صلی اللہ علیہ وسلم جمعہ کا خطبہ دے رہے تھے۔ آپ صلی اللہ علیہ وسلم نے پوچھا کہ اے فلاں! کیا تم نے ( تحیۃ المسجد کی ) نماز پڑھ لی۔ اس نے کہا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا اچھا اٹھ اور دو رکعت نماز پڑھ لے۔' WHERE id = 909;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عقبہ شیبانی نے بیان کیا، کہا کہ ہم سے ابواسحاق فزاری ابراہیم بن محمد نے بیان کیا، ان سے حمید طویل نے، انہوں نے انس رضی اللہ عنہ سے سنا۔ آپ فرماتے تھے کہ ہم جمعہ سویرے پڑھتے، اس کے بعد دوپہر کی نیند لیتے تھے۔' WHERE id = 919;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے باپ (عروہ بن زبیر) نے، ان سے عائشہ رضی اللہ عنہا نے، آپ نے بتلایا کہ ابوبکر رضی اللہ عنہ تشریف لائے تو میرے پاس انصار کی دو لڑکیاں وہ اشعار گا رہی تھیں جو انصار نے بعاث کی جنگ کے موقع پر کہے تھے۔ عائشہ رضی اللہ عنہا نے کہا کہ یہ گانے والیاں نہیں تھیں، ابوبکر رضی اللہ عنہ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم کے گھر میں یہ شیطانی باجے اور یہ عید کا دن تھا آخر رسول اللہ صلی اللہ علیہ وسلم نے ابوبکر رضی اللہ عنہ سے فرمایا اے ابوبکر! ہر قوم کی عید ہوتی ہے اور آج یہ ہماری عید ہے۔' WHERE id = 930;
UPDATE hadiths SET urdu = 'ہم سے زکریا بن یحییٰ ابوالسکین نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالرحمٰن محاربی نے بیان کیا، کہا کہ ہم سے محمد بن سوقہ نے سعید بن جبیر سے بیان کیا، انہوں نے کہا کہ میں ( حج کے دن ) ابن عمر رضی اللہ عنہما کے ساتھ تھا جب نیزے کی انی آپ کے تلوے میں چبھ گئی جس کی وجہ سے آپ کا پاؤں رکاب سے چپک گیا۔ تب میں نے اتر کر اسے نکالا۔ یہ واقعہ منیٰ میں پیش آیا تھا۔ جب حجاج کو معلوم ہوا جو اس زمانہ میں ابن زبیر رضی اللہ عنہما کے قتل کے بعد حجاج کا امیر تھا تو وہ بیمار پرسی کے لیے آیا۔ حجاج نے کہا کہ کاش ہمیں معلوم ہو جاتا کہ کس نے آپ کو زخمی کیا ہے۔ اس پر ابن عمر رضی اللہ عنہما نے فرمایا کہ تو نے ہی تو مجھ کو نیزہ مارا ہے۔ حجاج نے پوچھا کہ وہ کیسے؟ آپ نے فرمایا کہ تم اس دن ہتھیار اپنے ساتھ لائے جس دن پہلے کبھی ہتھیار ساتھ نہیں لایا جاتا تھا ( عیدین کے دن ) تم ہتھیار حرم میں لائے حالانکہ حرم میں ہتھیار نہیں لایا جاتا تھا۔' WHERE id = 941;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا کہ ہم سے محمد بن طلحہ نے بیان کیا، ان سے زبید نے، ان سے شعبی نے، ان سے براء بن عازب رضی اللہ عنہ نے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم عید الاضحی کے دن بقیع کی طرف تشریف لے گئے اور دو رکعت عید کی نماز پڑھائی۔ پھر ہماری طرف چہرہ مبارک کر کے فرمایا کہ سب سے مقدم عبادت ہمارے اس دن کی یہ ہے کہ پہلے ہم نماز پڑھیں پھر ( نماز اور خطبے سے ) لوٹ کر قربانی کریں۔ اس لیے جس نے اس طرح کیا اس نے ہماری سنت کے مطابق کیا اور جس نے نماز سے پہلے ذبح کر دیا تو وہ ایسی چیز ہے جسے اس نے اپنے گھر والوں کے کھلانے کے لیے جلدی سے مہیا کر دیا ہے اور اس کا قربانی سے کوئی تعلق نہیں۔ اس پر ایک شخص نے کھڑے ہو کر عرض کیا کہ یا رسول اللہ! میں نے تو پہلے ہی ذبح کر دیا۔ لیکن میرے پاس ایک سال کی پٹھیا ہے اور وہ دوندی بکری سے زیادہ بہتر ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ خیر تم اسی کو ذبح کر لو لیکن تمہارے بعد کسی کی طرف سے ایسی پٹھیا جائز نہ ہو گی۔' WHERE id = 951;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، انہوں نے کہا کہ ہمیں ابوتمیلہ یحییٰ بن واضح نے خبر دی، انہیں فلیح بن سلیمان نے، انہیں سعید بن حارث نے، انہیں جابر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم عید کے دن ایک راستہ سے جاتے پھر دوسرا راستہ بدل کر آتے۔ اس روایت کی متابعت یونس بن محمد نے فلیح سے کی، ان سے سعید نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا لیکن جابر کی روایت زیادہ صحیح ہے۔' WHERE id = 961;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے ہشام بن عروہ نے بیان کیا، کہا کہ مجھ سے میرے باپ نے عائشہ رضی اللہ عنہا سے بیان کیا کہ آپ نے فرمایا نبی کریم صلی اللہ علیہ وسلم ( تہجد کی ) نماز پڑھتے رہتے اور میں آپ صلی اللہ علیہ وسلم کے بستر پر عرض میں لیٹی رہتی۔ جب وتر پڑھنے لگتے تو مجھے بھی جگا دیتے اور میں بھی وتر پڑھ لیتی۔' WHERE id = 971;
UPDATE hadiths SET urdu = 'ہم سے امام حمیدی نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے سلیمان اعمش نے، ان سے ابوالضحی نے، ان سے مسروق نے، ان سے عبداللہ بن مسعود نے (دوسری سند) ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا کہ ہم سے جریر بن عبدالحمید نے منصور بن مسعود بن معتمر سے بیان کیا، اور ان سے ابوالضحی نے، ان سے مسروق نے، انہوں نے بیان کیا کہ ہم عبداللہ بن مسعود رضی اللہ عنہ کی خدمت میں بیٹھے ہوئے تھے۔ آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے جب کفار قریش کی سرکشی دیکھی تو آپ صلی اللہ علیہ وسلم نے بددعا کی «اللهم سبع كسبع يوسف» کہ اے اللہ! سات برس کا قحط ان پر بھیج جیسے یوسف علیہ السلام کے وقت میں بھیجا تھا چنانچہ ایسا قحط پڑا کہ ہر چیز تباہ ہو گئی اور لوگوں نے چمڑے اور مردار تک کھا لیے۔ بھوک کی شدت کا یہ عالم تھا کہ آسمان کی طرف نظر اٹھائی جاتی تو دھویں کی طرح معلوم ہوتا تھا آخر مجبور ہو کر ابوسفیان حاضر خدمت ہوئے اور عرض کیا کہ اے محمد ( صلی اللہ علیہ وسلم ) ! آپ لوگوں کو اللہ کی اطاعت اور صلہ رحمی کا حکم دیتے ہیں۔ اب تو آپ ہی کی قوم برباد ہو رہی ہے، اس لیے آپ اللہ سے ان کے حق میں دعا کیجئے۔ اللہ تعالیٰ نے فرمایا کہ اس دن کا انتظار کر جب آسمان صاف دھواں نظر آئے گا آیت «انکم عائدون» تک ( نیز ) جب ہم سختی سے ان کی گرفت کریں گے ( کفار کی ) سخت گرفت بدر کی لڑائی میں ہوئی۔ دھویں کا بھی معاملہ گزر چکا ( جب سخت قحط پڑا تھا ) جس میں پکڑ اور قید کا ذکر ہے وہ سب ہو چکے اسی طرح سورۃ الروم کی آیت میں جو ذکر ہے وہ بھی ہو چکا۔' WHERE id = 981;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک رحمہ اللہ نے شریک بن عبداللہ بن ابی نمر کے واسطے سے خبر دی اور انہیں انس بن مالک رضی اللہ عنہ نے کہ ایک شخص رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ عرض کیا یا رسول اللہ! ( قحط سے ) جانور ہلاک ہو گئے اور راستے بند، اللہ سے دعا کیجئے۔ چنانچہ آپ صلی اللہ علیہ وسلم نے دعا کی اور ایک جمعہ سے اگلے جمعہ تک ایک ہفتہ بارش ہوتی رہی۔ پھر ایک شخص نے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر عرض کیا کہ یا رسول اللہ! ( بارش کی کثرت سے ) راستے بند ہو گئے اور مویشی ہلاک ہو گئے۔ اب رسول اللہ صلی اللہ علیہ وسلم نے یہ دعا کی «اللهم على ظهور الجبال والآكام وبطون الأودية ومنابت الشجر» کہ اے اللہ! بارش کا رخ پہاڑوں، ٹیلوں، وادیوں اور باغات کی طرف موڑ دے، چنانچہ بادل مدینہ سے اس طرح چھٹ گیا جیسے کپڑا پھٹ جایا کرتا ہے۔' WHERE id = 992;
UPDATE hadiths SET urdu = 'ایوب بن سلیمان نے کہا کہ مجھ سے ابوبکر بن ابی اویس نے بیان کیا، انہوں نے سلیمان بن بلال سے بیان کیا کہ یحییٰ بن سعید نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا انہوں نے کہا کہ ایک بدوی ( گاؤں کا رہنے والا ) جمعہ کے دن رسول اللہ صلی اللہ علیہ وسلم کے پاس آیا اور عرض کیا یا رسول اللہ! بھوک سے مویشی تباہ ہو گئے، اہل و عیال اور تمام لوگ مر رہے ہیں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے ہاتھ اٹھائے، اور لوگوں نے بھی آپ صلی اللہ علیہ وسلم کے ساتھ اپنے ہاتھ اٹھائے، دعا کرنے لگے، انس رضی اللہ عنہ نے بیان کیا کہ ابھی ہم مسجد سے باہر نکلے بھی نہ تھے کہ بارش شروع ہو گئی اور ایک ہفتہ برابر بارش ہوتی رہی۔ دوسرے جمعہ میں پھر وہی شخص آیا اور عرض کی کہ یا رسول اللہ! ( بارش بہت ہونے سے ) مسافر گھبرا گئے اور راستے بند ہو گئے۔' WHERE id = 1002;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان ثوری نے بیان کیا، انہوں نے کہا کہ ہم سے عبداللہ بن دینار نے بیان کیا، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ غیب کی پانچ کنجیاں ہیں جنہیں اللہ تعالیٰ کے سوا اور کوئی نہیں جانتا۔ کسی کو نہیں معلوم کہ کل کیا ہونے والا ہے، کوئی نہیں جانتا کہ ماں کے پیٹ میں کیا ہے، کل کیا کرنا ہو گا، اس کا کسی کو علم نہیں۔ نہ کوئی یہ جانتا ہے کہ اسے موت کس جگہ آئے گی اور نہ کسی کو یہ معلوم کہ بارش کب ہو گی۔' WHERE id = 1012;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین کوفی نے بیان کیا، انہوں نے کہا کہ ہم سے شیبان بن عبدالرحمٰن نے یحییٰ بن ابن ابی کثیر سے بیان کیا، ان سے ابوسلمہ بن عبدالرحمٰن بن عوف نے، ان سے عبداللہ بن عمرو رضی اللہ عنہما نے کہ جب نبی کریم صلی اللہ علیہ وسلم کے زمانے میں سورج کو گرہن لگا تو اعلان ہوا کہ نماز ہونے والی ہے ( اس نماز میں ) نبی کریم صلی اللہ علیہ وسلم نے ایک رکعت میں دو رکوع کئے اور پھر دوسری رکعت میں بھی دو رکوع کئے، اس کے بعد آپ صلی اللہ علیہ وسلم بیٹھے رہے ( قعدہ میں ) یہاں تک کہ سورج صاف ہو گیا۔ عبداللہ نے کہا عائشہ رضی اللہ عنہا نے فرمایا کہ میں نے اس سے زیادہ لمبا سجدہ اور کبھی نہیں کیا۔' WHERE id = 1023;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا کہ ہم سے عبدالوارث نے بیان کیا، کہا کہ ہم سے یونس نے بیان کیا، ان سے امام حسن بصری نے، ان سے ابوبکرہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں سورج گرہن لگا تو آپ صلی اللہ علیہ وسلم اپنی چادر گھسیٹتے ہوئے ( بڑی تیزی سے ) مسجد میں پہنچے۔ صحابہ بھی جمع ہو گئے۔ پھر آپ صلی اللہ علیہ وسلم نے انہیں دو رکعت نماز پڑھائی، گرہن بھی ختم ہو گیا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ سورج اور چاند اللہ تعالیٰ کی نشانیوں میں سے دو نشانیاں ہیں اور ان میں گرہن کسی کی موت پر نہیں لگتا اس لیے جب گرہن لگے تو اس وقت تک نماز اور دعا میں مشغول رہو جب تک یہ صاف نہ ہو جائے۔ یہ آپ صلی اللہ علیہ وسلم نے اس لیے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کے ایک صاحبزادے ابراہیم رضی اللہ عنہ کی وفات ( اسی دن ) ہوئی تھی اور بعض لوگ ان کے متعلق کہنے لگے تھے ( کہ گرہن ان کی موت پر لگا ہے ) ۔' WHERE id = 1034;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا کہ ہم سے عبیداللہ عمری نے بیان کیا کہا کہ ہم سے نافع نے بیان کیا ان سے ابن عمر رضی اللہ عنہما نے کہا کہ نبی کریم صلی اللہ علیہ وسلم ہماری موجودگی میں آیت سجدہ پڑھتے اور سجدہ کرتے تو ہم بھی آپ صلی اللہ علیہ وسلم کے ساتھ ( ہجوم کی وجہ سے ) اس طرح سجدہ کرتے کہ پیشانی رکھنے کی جگہ بھی نہ ملتی جس پر سجدہ کرتے۔' WHERE id = 1045;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا کہا کہ ہم سے وہیب نے بیان کیا کہا کہ ہم سے ایوب نے بیان کیا ان سے ابوالعالیہ براء نے ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم صحابہ کو ساتھ لے کر تلبیہ کہتے ہوئے ذی الحجہ کی چوتھی تاریخ کو ( مکہ میں ) تشریف لائے پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ جن کے پاس ہدی نہیں ہے وہ بجائے حج کے عمرہ کی نیت کر لیں اور عمرہ سے فارغ ہو کر حلال ہو جائیں پھر حج کا احرام باندھیں۔ اس حدیث کی متابعت عطاء نے جابر سے کی ہے۔' WHERE id = 1055;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالعزیز بن مسلم نے بیان کیا، انہوں نے کہا کہ ہم سے عبداللہ بن دینار نے بیان کیا، انہوں نے کہا کہ عبداللہ بن عمر رضی اللہ عنہما سفر میں اپنی اونٹنی پر نماز پڑھتے خواہ اس کا منہ کسی طرف ہوتا۔ آپ اشاروں سے نماز پڑھتے۔ آپ کا بیان تھا کہ نبی کریم صلی اللہ علیہ وسلم بھی اسی طرح کرتے تھے۔' WHERE id = 1065;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا کہ میں نے زہری سے سنا، انہوں نے سالم سے اور انہوں نے اپنے باپ عبداللہ بن عمر سے کہ نبی کریم صلی اللہ علیہ وسلم کو اگر سفر میں جلد چلنا منظور ہوتا تو مغرب اور عشاء ایک ساتھ ملا کر پڑھتے۔' WHERE id = 1075;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا کہ ہم سے عبدالوارث نے بیان کیا، کہا کہ ہم سے حسین معلم نے بیان کیا اور ان سے عبداللہ بن بریدہ نے کہ عمران بن حصین نے جنہیں بواسیر کا مرض تھا۔ اور کبھی ابومعمر نے یوں کہا کہ عمران بن حصین رضی اللہ عنہما سے روایت ہے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے بیٹھ کر نماز پڑھنے کے بارے میں پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ کھڑے ہو کر نماز پڑھنا افضل ہے لیکن اگر کوئی بیٹھ کر نماز پڑھے تو کھڑے ہو کر پڑھنے والے سے اسے آدھا ثواب ملے گا اور لیٹ کر پڑھنے والے کو بیٹھ کر پڑھنے والے سے آدھا ثواب ملے گا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) فرماتے ہیں کہ حدیث کے الفاظ میں «نائم» «مضطجع» کے معنی میں ہے یعنی لیٹ کر نماز پڑھنے والا۔' WHERE id = 1085;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا کہ ہم سے امام مالک نے ابن شہاب زہری سے بیان کیا، ان سے عروہ نے، ان سے عائشہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم ایک کام کو چھوڑ دیتے اور آپ صلی اللہ علیہ وسلم کو اس کا کرنا پسند ہوتا۔ اس خیال سے ترک کر دیتے کہ دوسرے صحابہ بھی اس پر ( آپ کو دیکھ کر ) عمل شروع کر دیں اور اس طرح وہ کام ان پر فرض ہو جائے۔ چنانچہ رسول اللہ صلی اللہ علیہ وسلم نے چاشت کی نماز کبھی نہیں پڑھی لیکن میں پڑھتی ہوں۔' WHERE id = 1096;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ نے کہا کہ مجھ سے ابوحمزہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کی رات کی نماز تیرہ رکعت ہوتی تھی۔' WHERE id = 1107;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا اور انہوں نے کہا کہ ہم سے ہشام بن عروہ نے بیان کیا کہ مجھے میرے باپ عروہ نے خبر دی کہ عائشہ صدیقہ رضی اللہ عنہا نے بتلایا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو رات کی کسی نماز میں بیٹھ کر قرآن پڑھتے نہیں دیکھا۔ یہاں تک کہ آپ صلی اللہ علیہ وسلم بوڑھے ہو گئے تو بیٹھ کر قرآن پڑھتے تھے لیکن جب تیس چالیس آیتیں رہ جاتیں تو کھڑے ہو جاتے پھر اس کو پڑھ کر رکوع کرتے تھے۔' WHERE id = 1117;
UPDATE hadiths SET urdu = 'ہم سے بشر بن حکم نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان نے بیان کیا، انہوں نے کہا کہ مجھ سے سالم ابوالنضر نے ابوسلمہ بن عبدالرحمٰن سے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم جب فجر کی سنتیں پڑھ چکتے تو اگر میں جاگتی ہوتی تو آپ صلی اللہ علیہ وسلم مجھ سے باتیں کرتے ورنہ لیٹ جاتے جب تک نماز کی اذان ہوتی۔' WHERE id = 1128;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے شعبہ بن حجاج نے، ان سے توبہ بن کیسان نے، ان سے مورق بن مشمرج نے، انہوں نے بیان کیا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے پوچھا کہ کیا آپ چاشت کی نماز پڑھتے ہیں؟ انہوں نے فرمایا کہ نہیں۔ میں نے پوچھا اور عمر پڑھتے تھے؟ آپ نے فرمایا کہ نہیں۔ میں نے پوچھا اور ابوبکر رضی اللہ عنہ؟ فرمایا نہیں۔ میں نے پوچھا اور نبی کریم صلی اللہ علیہ وسلم ؟ فرمایا نہیں۔ میرا خیال یہی ہے۔' WHERE id = 1141;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھے عبدالملک نے قزعہ سے خبر دی، انہوں نے کہا کہ میں نے ابوسعید رضی اللہ عنہ سے چار باتیں سنیں اور انہوں نے بتلایا کہ میں نے انہیں نبی کریم صلی اللہ علیہ وسلم سے سنا تھا، آپ نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ بارہ جہاد کئے تھے۔' WHERE id = 1152;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو عیسیٰ بن یونس نے خبر دی، انہیں اسماعیل بن ابی خالد نے، انہیں حارث بن شبیل نے، انہیں ابوعمرو بن سعد بن ابی ایاس شیبانی نے بتایا کہ مجھ سے زید بن ارقم رضی اللہ عنہ نے بتلایا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے عہد میں نماز پڑھنے میں باتیں کر لیا کرتے تھے۔ کوئی بھی اپنے قریب کے نمازی سے اپنی ضرورت بیان کر دیتا۔ پھر آیت «حافظوا على الصلوات‏ الخ» اتری اور ہمیں ( نماز میں ) خاموش رہنے کا حکم ہوا۔' WHERE id = 1164;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا کہ ہم سے شبابہ نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے محمد بن زیاد نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے ایک مرتبہ ایک نماز پڑھی پھر فرمایا کہ میرے سامنے ایک شیطان آ گیا اور کوشش کرنے لگا کہ میری نماز توڑ دے۔ لیکن اللہ تعالیٰ نے اس کو میرے قابو میں کر دیا میں نے اس کا گلا گھونٹا یا اس کو دھکیل دیا۔ آخر میں میرا ارادہ ہوا کہ اسے مسجد کے ایک ستون سے باندھ دوں اور جب صبح ہو تو تم بھی دیکھو۔ لیکن مجھے سلیمان علیہ السلام کی دعا یاد آ گئی ”اے اللہ! مجھے ایسی سلطنت عطا کیجیو جو میرے بعد کسی اور کو نہ ملے“ ( اس لیے میں نے اسے چھوڑ دیا ) اور اللہ تعالیٰ نے اسے ذلت کے ساتھ بھگا دیا۔ اس کے بعد نضر بن شمیل نے کہا کہ «ذعته» ”ذال“ سے ہے۔ جس کے معنی ہیں کہ میں نے اس کا گلا گھونٹ دیا اور «دعته» اللہ تعالیٰ کے اس قول سے لیا گیا ہے۔ «يوم يدعون‏» جس کے معنی ہیں قیامت کے دن وہ دوزخ کی طرف دھکیلے جائیں گے۔ درست پہلا ہی لفظ ہے۔ البتہ شعبہ نے اسی طرح ”عین“ اور ”تاء“ کی تشدید کے ساتھ بیان کیا ہے۔' WHERE id = 1174;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی فلاس نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ہشام بن حسان فردوسی نے بیان کیا، ان سے محمد بن سیرین نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے پہلو پر ہاتھ رکھ کر نماز پڑھنے سے منع فرمایا۔' WHERE id = 1184;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے، ان سے ابن شہاب نے، ان سے اعرج نے، ان سے عبداللہ بن بحینہ اسدی نے جو بنو عبدالمطلب کے حلیف تھے کہ رسول اللہ صلی اللہ علیہ وسلم ظہر کی نماز میں قعدہ اولیٰ کئے بغیر کھڑے ہو گئے۔ حالانکہ اس وقت آپ صلی اللہ علیہ وسلم کو بیٹھنا چاہئے تھا۔ جب آپ صلی اللہ علیہ وسلم نے نماز پوری کی تو آپ صلی اللہ علیہ وسلم نے بیٹھے بیٹھے ہی سلام سے پہلے دو سجدے سہو کے کئے اور ہر سجدے میں «الله اكبر» کہا۔ مقتدیوں نے بھی آپ صلی اللہ علیہ وسلم کے ساتھ یہ دو سجدے کئے۔ آپ صلی اللہ علیہ وسلم بیٹھنا بھول گئے تھے، اس لیے یہ سجدے اسی کے بدلہ میں کئے تھے۔ اس روایت کی مطابعت ابن جریج نے ابن شہاب سے تکبیر کے ذکر میں کی ہے۔' WHERE id = 1195;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، انہوں نے کہا کہ ہم سے عمرو بن ابی سلمہ نے بیان کیا، ان سے امام اوزاعی نے، انہوں نے کہا کہ مجھے ابن شہاب نے خبر دی، کہا کہ مجھے سعید بن مسیب نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے کہ مسلمان کے مسلمان پر پانچ حق ہیں سلام کا جواب دینا، مریض کا مزاج معلوم کرنا، جنازے کے ساتھ چلنا، دعوت قبول کرنا، اور چھینک پر ( اس کے «الحمدلله» کے جواب میں ) «يرحمک الله» کہنا۔ اس روایت کی متابعت عبدالرزاق نے کی ہے۔ انہوں نے کہا کہ مجھے معمر نے خبر دی تھی۔ اور اس کی روایت سلامہ نے بھی عقیل سے کی ہے۔' WHERE id = 1205;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالوہاب ثقفی نے بیان کیا، ان سے ایوب نے، ان سے محمد نے، ان سے ام عطیہ رضی اللہ عنہا نے کہ ہم رسول اللہ صلی اللہ علیہ وسلم کی بیٹی کو غسل دے رہی تھیں کہ آپ صلی اللہ علیہ وسلم تشریف لائے اور فرمایا کہ تین یا پانچ مرتبہ غسل دو یا اس سے بھی زیادہ، پانی اور بیری کے پتوں سے اور آخر میں کافور بھی استعمال کرنا۔ پھر فارغ ہو کر مجھے خبر دے دینا۔ جب ہم فارغ ہوئے تو آپ صلی اللہ علیہ وسلم کو خبر کر دی۔ آپ صلی اللہ علیہ وسلم نے اپنا ازار عنایت فرمایا اور فرمایا کہ یہ اندر اس کے بدن پر لپیٹ دو۔' WHERE id = 1217;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، انہوں نے کہا کہ ہم سے ایوب نے، ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کے ساتھ میدان عرفہ میں وقوف کئے ہوئے تھا کہ وہ اپنے اونٹ سے گر پڑا اور اونٹ نے انہیں کچل دیا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں پانی اور بیری کے پتوں سے غسل دے کر دو کپڑوں کا کفن دو، خوشبو نہ لگاؤ اور نہ سر ڈھکو کیونکہ اللہ تعالیٰ قیامت کے دن انہیں لبیک کہتے ہوئے اٹھائے گا۔' WHERE id = 1228;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا ‘ کہا کہ ہم سے میرے والد نے بیان کیا ‘ کہا کہ ہم سے اعمش نے بیان کیا ‘ کہا کہ ہم سے شقیق نے بیان کیا ‘ کہا ہم سے خباب بن ارت رضی اللہ عنہ نے بیان کیا ‘ کہ ہم نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ صرف اللہ کے لیے ہجرت کی۔ اب ہمیں اللہ تعالیٰ سے اجر ملنا ہی تھا۔ ہمارے بعض ساتھی تو انتقال کر گئے اور ( اس دنیا میں ) انہوں نے اپنے کئے کا کوئی پھل نہیں دیکھا۔ مصعب بن عمیر رضی اللہ عنہ بھی انہیں لوگوں میں سے تھے اور ہمارے بعض ساتھیوں کا میوہ پک گیا اور وہ چن چن کر کھاتا ہے۔ ( مصعب بن عمیر رضی اللہ عنہ ) احد کی لڑائی میں شہید ہوئے ہم کو ان کے کفن میں ایک چادر کے سوا اور کوئی چیز نہ ملی اور وہ بھی ایسی کہ اگر اس سے سر چھپاتے ہیں تو پاؤں کھل جاتا ہے اور اگر پاؤں ڈھکتے تو سر کھل جاتا۔ آخر یہ دیکھ کر نبی کریم صلی اللہ علیہ وسلم نے ارشاد فرمایا کہ سر کو چھپا دیں اور پاؤں پر سبز گھاس اذخر نامی ڈال دیں۔' WHERE id = 1238;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا کہ ہم سے سعید بن عبید نے ‘ ان سے علی بن ربیعہ نے اور ان سے مغیرہ بن شعبہ رضی اللہ عنہ نے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم فرماتے تھے کہ میرے متعلق کوئی جھوٹی بات کہنا عام لوگوں سے متعلق جھوٹ بولنے کی طرح نہیں ہے جو شخص بھی جان بوجھ کر میرے اوپر جھوٹ بولے وہ اپنا ٹھکانا جہنم میں بنا لے۔ اور میں نے نبی کریم صلی اللہ علیہ وسلم سے یہ بھی سنا کہ کسی میت پر اگر نوحہ و ماتم کیا جائے تو اس نوحہ کی وجہ سے بھی اس پر عذاب ہوتا ہے۔' WHERE id = 1250;
UPDATE hadiths SET urdu = 'ہم سے بشر بن حکم نے بیان کیا ‘ کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا ‘ کہا کہ ہم سے اسحاق بن عبداللہ بن ابی طلحہ نے بیان کیا ‘ کہ انہوں نے انس بن مالک رضی اللہ عنہ سے سنا ‘ آپ نے بتلایا کہ ابوطلحہ رضی اللہ عنہ کا ایک بچہ بیمار ہو گیا انہوں نے کہا کہ اس کا انتقال بھی ہو گیا۔ اس وقت ابوطلحہ رضی اللہ عنہ گھر میں موجود نہ تھے۔ ان کی بیوی ( ام سلیم رضی اللہ عنہا ) نے جب دیکھا کہ بچے کا انتقال ہو گیا تو انہوں نے کچھ کھانا تیار کیا اور بچے کو گھر کے ایک کونے میں لٹا دیا۔ جب ابوطلحہ رضی اللہ عنہ تشریف لائے تو انہوں نے پوچھا کہ بچے کی طبیعت کیسی ہے؟ ام سلیم رضی اللہ عنہا نے کہا کہ اسے آرام مل گیا ہے اور میرا خیال ہے کہ اب وہ آرام ہی کر رہا ہو گا۔ ابوطلحہ رضی اللہ عنہ نے سمجھا کہ وہ صحیح کہہ رہی ہیں۔ ( اب بچہ اچھا ہے ) پھر ابوطلحہ رضی اللہ عنہ نے ام سلیم رضی اللہ عنہا کے پاس رات گزاری اور جب صبح ہوئی تو غسل کیا لیکن جب باہر جانے کا ارادہ کیا تو بیوی ( ام سلیم رضی اللہ عنہا ) نے اطلاع دی کہ بچے کا انتقال ہو چکا ہے۔ پھر انہوں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھی اور آپ سے ام سلیم رضی اللہ عنہا کا حال بیان کیا۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ شاید اللہ تعالیٰ تم دونوں کو اس رات میں برکت عطا فرمائے گا۔ سفیان بن عیینہ نے بیان کیا کہ انصار کے ایک شخص نے بتایا کہ میں نے ابوطلحہ رضی اللہ عنہ کی انہیں بیوی سے نو بیٹے دیکھے جو سب کے سب قرآن کے عالم تھے۔' WHERE id = 1260;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ہشام نے بیان کیا ‘ ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عبید اللہ بن مقسم نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ ہمارے سامنے سے ایک جنازہ گزرا تو نبی کریم صلی اللہ علیہ وسلم کھڑے ہو گئے اور ہم بھی کھڑے ہو گئے۔ پھر ہم نے کہا کہ یا رسول اللہ! یہ تو یہودی کا جنازہ تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم لوگ جنازہ دیکھو تو کھڑے ہو جایا کرو۔' WHERE id = 1270;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا ‘ ان سے جریر بن حازم نے بیان کیا ‘ کہا کہ میں نے نافع سے سنا ‘ آپ نے بیان کیا کہ ابن عمر رضی اللہ عنہما نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ جو دفن تک جنازہ کے ساتھ رہے اسے ایک قیراط کا ثواب ملے گا۔ ابن عمر رضی اللہ عنہما نے فرمایا کہ ابوہریرہ احادیث بہت زیادہ بیان کرتے ہیں۔' WHERE id = 1281;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا ‘ کہا کہ ہم سے شعبہ نے بیان کیا ‘ کہا کہ مجھ سے سلیمان شیبانی نے بیان کیا ‘ کہا کہ میں نے شعبی سے سنا ‘ انہوں نے بیان کیا کہ مجھے اس صحابی نے خبر دی جو نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک الگ تھلگ قبر سے گزرے تھے۔ قبر پر آپ صلی اللہ علیہ وسلم امام بنے اور صحابہ نے آپ صلی اللہ علیہ وسلم کے پیچھے نماز جنازہ پڑھی۔ شیبانی نے کہا کہ میں نے شعبی سے پوچھا کہ ابوعمرو! یہ آپ سے کس صحابی نے بیان کیا تھا تو انہوں نے بتلایا کہ ابن عباس رضی اللہ عنہما نے۔' WHERE id = 1292;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے بیان کیا ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن کعب نے اور ان سے جابر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں خون سمیت دفن کر دو یعنی احد کی لڑائی کے موقع پر اور انہیں غسل نہیں دیا تھا۔' WHERE id = 1302;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا ‘ انہوں نے کہا کہ ہمیں عبداللہ نے خبر دی ‘ انہوں نے کہا کہ ہم کو یونس نے خبر دی ‘ انہیں زہری نے ‘ انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہر بچہ فطرت پر پیدا ہوتا ہے لیکن اس کے ماں باپ اسے یہودی یا نصرانی یا مجوسی بنا دیتے ہیں۔ بالکل اسی طرح جیسے ایک جانور ایک صحیح سالم جانور جنتا ہے۔ کیا تم اس کا کوئی عضو ( پیدائشی طور پر ) کٹا ہوا دیکھتے ہو؟ پھر ابوہریرہ رضی اللہ عنہ نے فرمایا کہ یہ اللہ تعالیٰ کی فطرت ہے جس پر لوگوں کو اس نے پیدا کیا ہے۔ اللہ تعالیٰ کی خلقت میں کوئی تبدیلی ممکن نہیں ‘ یہی «دين القيم‏» ہے۔' WHERE id = 1313;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے ‘ ان سے ہشام بن عروہ نے ‘ ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے بدر کے کافروں کو یہ فرمایا تھا کہ میں جو ان سے کہا کرتا تھا اب ان کو معلوم ہوا ہو گا کہ وہ سچ ہے۔ اور اللہ نے سورۃ الروم میں فرمایا «إنك لا تسمع الموتى‏» اے پیغمبر! تو مردوں کو نہیں سنا سکتا۔' WHERE id = 1324;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا ‘ انہوں نے کہا ہم سے اسماعیل بن علیہ نے بیان کیا ‘ ان سے عبدالعزیز بن صہیب نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس مسلمان کے بھی تین نابالغ بچے مر جائیں تو اللہ تعالیٰ اپنے فضل و رحمت سے جو ان بچوں پر کرے گا ‘ ان کو بہشت میں لے جائے گا۔' WHERE id = 1334;
UPDATE hadiths SET urdu = 'ہشام اپنے والد سے اور وہ عائشہ رضی اللہ عنہا سے روایت کرتے ہیں کہ آپ نے عبداللہ بن زبیر رضی اللہ عنہما کو وصیت کی تھی کہ مجھے نبی کریم صلی اللہ علیہ وسلم اور آپ صلی اللہ علیہ وسلم کے ساتھیوں کے ساتھ دفن نہ کرنا۔ بلکہ میری دوسری سوکنوں کے ساتھ بقیع غرقد میں مجھے دفن کرنا۔ میں یہ نہیں چاہتی کہ ان کے ساتھ میری بھی تعریف ہوا کرے۔' WHERE id = 1346;
UPDATE hadiths SET urdu = 'ہم سے ابولیمان حکم بن نافع نے بیان کیا ‘ کہا کہ ہمیں شعیب بن ابی حمزہ نے خبر دی ‘ کہا کہ ہم سے ابوالزناد نے بیان کیا کہ عبدالرحمٰن بن ہرمز اعرج نے ان سے بیان کیا کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا ‘ آپ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اونٹ ( قیامت کے دن ) اپنے مالکوں کے پاس جنہوں نے ان کا حق ( زکوٰۃ ) نہ ادا کیا کہ اس سے زیادہ موٹے تازے ہو کر آئیں گے ( جیسے دنیا میں تھے ) اور انہیں اپنے کھروں سے روندیں گے۔ بکریاں بھی اپنے ان مالکوں کے پاس جنہوں نے ان کے حق نہیں دئیے تھے پہلے سے زیادہ موٹی تازی ہو کر آئیں گی اور انہیں اپنے کھروں سے روندیں گی اور اپنے سینگوں سے ماریں گی۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اس کا حق یہ بھی ہے کہ اسے پانی ہی پر ( یعنی جہاں وہ چراگاہ میں چر رہی ہوں ) دوہا جائے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کوئی شخص قیامت کے دن اس طرح نہ آئے کہ وہ اپنی گردن پر ایک ایسی بکری اٹھائے ہوئے ہو جو چلا رہی ہو اور وہ ( شخص ) مجھ سے کہے کہ اے محمد ( صلی اللہ علیہ وسلم ) ! مجھے عذاب سے بچائیے میں اسے یہ جواب دوں گا کہ تیرے لیے میں کچھ نہیں کر سکتا ( میرا کام پہنچانا تھا ) سو میں نے پہنچا دیا۔ اسی طرح کوئی شخص اپنی گردن پر اونٹ لیے ہوئے قیامت کے دن نہ آئے کہ اونٹ چلا رہا ہو اور وہ خود مجھ سے فریاد کرے ‘ اے محمد ( صلی اللہ علیہ وسلم ) ! مجھے بچائیے اور میں یہ جواب دے دوں کہ تیرے لیے میں کچھ نہیں کر سکتا۔ میں نے تجھ کو ( اللہ کا حکم زکوٰۃ ) پہنچا دیا تھا۔' WHERE id = 1356;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ابواسامہ (حماد بن اسامہ) نے بیان کیا ‘ انہوں نے کہا ہم سے برید بن عبداللہ نے ‘ ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ لوگوں پر ضرور ایک زمانہ ایسا آ جائے گا کہ ایک شخص سونے کا صدقہ لے کر نکلے گا لیکن کوئی اسے لینے والا نہیں ملے گا اور یہ بھی ہو گا کہ ایک مرد کی پناہ میں چالیس چالیس عورتیں ہو جائیں گی کیونکہ مردوں کی کمی ہو جائے گی اور عورتوں کی زیادتی ہو گی۔' WHERE id = 1367;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا ‘ کہا کہ ہمیں شعبہ نے خبر دی ‘ کہا کہ مجھے معبد بن خالد نے خبر دی ‘ کہا کہ میں نے حارثہ بن وہب خزاعی رضی اللہ عنہ سے سنا۔ انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ‘ آپ صلی اللہ علیہ وسلم نے فرمایا کہ صدقہ کیا کرو پس عنقریب ایک ایسا زمانہ آنے والا ہے جب آدمی اپنا صدقہ لے کر نکلے گا ( کوئی اسے قبول کر لے مگر جب وہ کسی کو دے گا تو وہ ) آدمی کہے گا کہ اگر اسے تم کل لائے ہوتے تو میں لے لیتا لیکن آج مجھے اس کی حاجت نہیں رہی۔' WHERE id = 1377;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا کہ ہم سے ہشام نے بیان کیا ‘ کہا کہ ہمیں معمر نے زہری سے خبر دی ‘ انہیں عروہ نے اور ان سے حکیم بن حزام رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا یا رسول اللہ! ان نیک کاموں سے متعلق آپ کیا فرماتے ہیں جنہیں میں جاہلیت کے زمانہ میں صدقہ ‘ غلام آزاد کرنے اور صلہ رحمی کی صورت میں کیا کرتا تھا۔ کیا ان کا مجھے ثواب ملے گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم اپنی ان تمام نیکیوں کے ساتھ اسلام لائے ہو جو پہلے گزر چکی ہیں۔' WHERE id = 1388;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا ‘ کہا کہ ہم سے ابوشہاب نے بیان کیا ‘ ان سے خالد حذاء نے ‘ ان سے حفصہ بنت سیرین نے اور ان سے ام عطیہ رضی اللہ عنہا نے کہ نسیبہ نامی ایک انصاری عورت کے ہاں کسی نے ایک بکری بھیجی ( یہ نسیبہ نامی انصاری عورت خود ام عطیہ رضی اللہ عنہا ہی کا نام ہے ) ۔ اس بکری کا گوشت انہوں نے عائشہ رضی اللہ عنہا کے یہاں بھی بھیج دیا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے ان سے دریافت کیا کہ تمہارے پاس کھانے کو کوئی چیز ہے؟ عائشہ رضی اللہ عنہا نے کہا کہ اور تو کوئی چیز نہیں البتہ اس بکری کا گوشت جو نسیبہ رضی اللہ عنہا نے بھیجا تھا ‘ وہ موجود ہے۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ وہی لاؤ اب اس کا کھانا درست ہو گیا۔' WHERE id = 1398;
UPDATE hadiths SET urdu = 'ہم سے امیہ بن بسطام نے بیان کیا ‘ انہوں نے کہا ہم سے زید بن زریع نے بیان کیا ‘ انہوں نے کہا کہ ہم سے روح بن قاسم نے بیان کیا ‘ ان سے اسماعیل بن امیہ نے ‘ ان سے یحییٰ بن عبداللہ بن صیفی نے ‘ ان سے ابومعبد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ جب رسول اللہ صلی اللہ علیہ وسلم نے معاذ رضی اللہ عنہ کو یمن بھیجا تو ان سے فرمایا کہ دیکھو! تم ایک ایسی قوم کے پاس جا رہے ہو جو اہل کتاب ( عیسائی یہودی ) ہیں۔ اس لیے سب سے پہلے انہیں اللہ کی عبادت کی دعوت دینا۔ جب وہ اللہ تعالیٰ کو پہچان لیں ( یعنی اسلام قبول کر لیں ) تو انہیں بتانا کہ اللہ تعالیٰ نے ان کے لیے دن اور رات میں پانچ نمازیں فرض کی ہیں۔ جب وہ اسے بھی ادا کریں تو انہیں بتانا کہ اللہ تعالیٰ نے ان پر زکوٰۃ فرض قرار دی ہے جو ان کے سرمایہ داروں سے لی جائے گی ( جو صاحب نصاب ہوں گے ) اور انہیں کے فقیروں میں تقسیم کر دی جائے گی۔ جب وہ اسے بھی مان لیں تو ان سے زکوٰۃ وصول کر۔ البتہ ان کی عمدہ چیزیں ( زکوٰۃ کے طور پر لینے سے ) پرہیز کرنا۔' WHERE id = 1409;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا کہ ہمیں شعیب نے خبر دی ‘ کہا کہ ہم سے ابوالزناد نے اعرج سے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے زکوٰۃ وصول کرنے کا حکم دیا۔ پھر آپ صلی اللہ علیہ وسلم سے کہا گیا کہ ابن جمیل اور خالد بن ولید اور عباس بن عبدالمطلب نے زکوٰۃ دینے سے انکار کر دیا ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابن جمیل یہ شکر نہیں کرتا کہ کل تک وہ فقیر تھا۔ پھر اللہ نے اپنے رسول کی دعا کی برکت سے اسے مالدار بنا دیا۔ باقی رہے خالد ‘ تو ان پر تم لوگ ظلم کرتے ہو۔ انہوں نے تو اپنی زرہیں اللہ تعالیٰ کے راستے میں وقف کر رکھی ہیں۔ اور عباس بن عبدالمطلب ‘ تو وہ رسول اللہ صلی اللہ علیہ وسلم کے چچا ہیں۔ اور ان کی زکوٰۃ انہی پر صدقہ ہے۔ اور اتنا ہی اور انہیں میری طرف سے دینا ہے۔ اس روایت کی متابعت ابوالزناد نے اپنے والد سے کی اور ابن اسحاق نے ابوالزناد سے یہ الفاظ بیان کیے۔ «هي عليه ومثلها معها» ( صدقہ کے لفظ کے بغیر ) اور ابن جریج نے کہا کہ مجھ سے اعرج سے اسی طرح یہ حدیث بیان کی گئی۔' WHERE id = 1419;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا ‘ کہا کہ مجھ سے میرے باپ نے بیان کیا ‘ کہا کہ ہم سے اعمش نے بیان کیا ‘ کہا کہ ہم سے ابوصالح ذکوان نے بیان کیا ‘ اور ان سے ابوہریرہ رضی اللہ عنہ نے ‘ کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اگر تم میں سے کوئی شخص اپنی رسی لے کر ( میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے یوں فرمایا ) پہاڑوں میں چلا جائے پھر لکڑیاں جمع کر کے انہیں فروخت کرے۔ اس سے کھائے بھی اور صدقہ بھی کرے۔ یہ اس کے لیے اس سے بہتر ہے کہ لوگوں کے سامنے ہاتھ پھیلائے۔' WHERE id = 1430;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا ‘ کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا ‘ ان سے یونس نے ‘ ان سے ابن شہاب نے ‘ کہا کہ مجھ سے عبیداللہ بن عبداللہ نے بیان کیا ‘ اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے میمونہ رضی اللہ عنہا کی باندی کو جو بکری صدقہ میں کسی نے دی تھی وہ مری ہوئی دیکھی۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ اس کے چمڑے کو کیوں نہیں کام میں لائے۔ لوگوں نے کہا کہ یہ تو مردہ ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ حرام تو صرف اس کا کھانا ہے۔' WHERE id = 1441;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا ‘ کہا کہ ہم سے ولید نے بیان کیا ‘ کہا کہ ہم سے ابوعمرو اوزاعی نے بیان کیا ‘ کہا کہ مجھ سے اسحاق بن عبداللہ بن ابی طلحہ نے بیان کیا ‘ کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ میں عبداللہ بن ابی طلحہ کو لے کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا کہ آپ صلی اللہ علیہ وسلم ان کی تحنیک کر دیں۔ ( یعنی اپنے منہ سے کوئی چیز چبا کر ان کے منہ میں ڈال دیں ) میں نے اس وقت دیکھا کہ آپ صلی اللہ علیہ وسلم کے ہاتھ میں داغ لگانے کا آلہ تھا اور آپ صلی اللہ علیہ وسلم زکوٰۃ کے اونٹوں پر داغ لگا رہے تھے۔' WHERE id = 1451;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ انہوں نے کہا کہ ہم سے یحییٰ قطان نے عبیداللہ عمری کے واسطے سے بیان کیا ‘ انہوں نے کہا کہ مجھ سے نافع نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک صاع جَو یا ایک صاع کھجور کا صدقہ فطر، چھوٹے، بڑے، آزاد اور غلام سب پر فرض قرار دیا۔' WHERE id = 1461;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے زہیر نے بیان کیا، انہوں نے کہا کہ مجھ سے زید بن جبیر نے بیان کیا کہ وہ عبداللہ بن عمر رضی اللہ عنہما کی قیام گاہ پر حاضر ہوئے۔ وہاں قنات کے ساتھ شامیانہ لگا ہوا تھا ( زید بن جبیر نے کہا کہ ) میں نے پوچھا کہ کس جگہ سے عمرہ کا احرام باندھنا چاہئے۔ عبداللہ رضی اللہ عنہ نے جواب دیا کہ رسول اللہ صلی اللہ علیہ وسلم نے نجد والوں کے لیے قرن، مدینہ والوں کے لیے ذوالحلیفہ اور شام والوں کے لیے حجفہ مقرر کیا ہے۔' WHERE id = 1471;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے خبر دی، انہیں نافع نے، انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے مقام ذوالحلیفہ کے پتھریلے میدان میں اپنی سواری روکی اور پھر وہیں آپ صلی اللہ علیہ وسلم نے نماز پڑھی۔ عبداللہ بن عمر رضی اللہ عنہما بھی ایسا ہی کیا کرتے تھے۔' WHERE id = 1481;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا کہ مجھے ابن جریج نے خبر دی، انہوں نے کہا کہ مجھ سے محمد بن المنکدر نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ میں چار رکعتیں پڑھیں لیکن ذوالحلیفہ میں دو رکعت ادا فرمائیں پھر آپ صلی اللہ علیہ وسلم نے رات وہیں گزاری۔ صبح کے وقت جب آپ صلی اللہ علیہ وسلم اپنی سواری پر سوار ہوئے تو آپ صلی اللہ علیہ وسلم نے لبیک پکاری۔' WHERE id = 1493;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہمیں امام مالک نے ابن شہاب سے خبر دی، انہیں عروہ بن زبیر نے، ان سے نبی کریم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ ہم حجتہ الوداع میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ روانہ ہوئے۔ پہلے ہم نے عمرہ کا احرام باندھا لیکن نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس کے ساتھ قربانی ہو تو اسے عمرہ کے ساتھ حج کا بھی احرام باندھ لینا چاہئے۔ ایسا شخص درمیان میں حلال نہیں ہو سکتا بلکہ حج اور عمرہ دونوں سے ایک ساتھ حلال ہو گا۔ میں بھی مکہ آئی تھی اس وقت میں حائضہ ہو گئی، اس لیے نہ بیت اللہ کا طواف کر سکی اور نہ صفا اور مروہ کی سعی۔ میں نے اس کے متعلق نبی کریم صلی اللہ علیہ وسلم سے شکوہ کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنا سر کھول ڈال، کنگھا کر اور عمرہ چھوڑ کر حج کا احرام باندھ لے۔ چنانچہ میں نے ایسا ہی کیا پھر جب ہم حج سے فارغ ہو گئے تو رسول اللہ صلی اللہ علیہ وسلم نے مجھے میرے بھائی عبدالرحمٰن بن ابی بکر کے ساتھ تنعیم بھیجا۔ میں نے وہاں سے عمرہ کا احرام باندھا ( اور عمرہ ادا کیا ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ تمہارے اس عمرہ کے بدلے میں ہے۔ ( جسے تم نے چھوڑ دیا تھا ) عائشہ رضی اللہ عنہا نے بیان کیا کہ جن لوگوں نے ( حجۃ الوداع میں ) صرف عمرہ کا احرام باندھا تھا، وہ بیت اللہ کا طواف صفا اور مروہ کی سعی کر کے حلال ہو گئے۔ پھر منیٰ سے واپس ہونے پر دوسرا طواف ( یعنی طواف الزیارۃ ) کیا لیکن جن لوگوں نے حج اور عمرہ کا ایک ساتھ احرام باندھا تھا، انہوں نے صرف ایک ہی طواف کیا یعنی طواف الزیارۃ کیا۔' WHERE id = 1503;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا کہ ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں نافع نے اور انہیں ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ حفصہ رضی اللہ عنہا نے بیان کیا کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے دریافت کیا یا رسول اللہ! کیا بات ہے اور لوگ تو عمرہ کر کے حلال ہو گئے لیکن آپ حلال نہیں ہوئے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے اپنے سر کی تلبید ( بالوں کو جمانے کے لیے ایک لیس دار چیز کا استعمال کرنا ) کی ہے اور اپنے ساتھ ہدی ( قربانی کا جانور ) لایا ہوں اس لیے میں قربانی کرنے سے پہلے احرام نہیں کھول سکتا۔' WHERE id = 1513;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد بصریٰ نے بیان کیا، انہوں نے کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے عبیداللہ عمری نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم «الثنية العليا» یعنی مقام کداء کی طرف سے داخل ہوتے جو بطحاء میں ہے اور «الثنية السفلى‏.» کی طرف سے نکلتے تھے یعنی نیچے والی گھاٹی کی طرف سے۔ امام بخاری رحمہ اللہ نے کہا مسدد اسم بامسمی تھے یعنی مسدد کے معنی عربی زبان میں مضبوط اور درست کے ہیں تو حدیث کی روایت میں مضبوط اور درست تھے اور میں نے یحییٰ بن معین سے سنا وہ کہتے ہیں میں نے یحییٰ قطان سے سنا، وہ کہتے تھے اگر میں مسدد کے گھر جا کر ان کو حدیث سنایا کرتا تو وہ اس کے لائق تھے اور میری کتابیں حدیث کی میرے پاس رہیں یا مسدد کے پاس مجھے کچھ پرواہ نہیں۔ گویا یحییٰ قطان نے مسدد کی بےحد تعریف کی۔' WHERE id = 1523;
UPDATE hadiths SET urdu = 'ہم سے بیان بن عمرو نے بیان کیا، انہوں نے کہا کہ ہم سے یزید بن ہارون نے بیان کیا، انہوں نے کہا کہ ہم سے جریر بن حازم نے بیان کیا، انہوں نے کہا کہ ہم سے یزید بن رومان نے بیان کیا، ان سے عروہ نے اور ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، عائشہ! اگر تیری قوم کا زمانہ جاہلیت ابھی تازہ نہ ہوتا، تو میں بیت اللہ کو گرانے کا حکم دے دیتا تاکہ ( نئی تعمیر میں ) اس حصہ کو بھی داخل کر دوں جو اس سے باہر رہ گیا ہے اور اس کی کرسی زمین کے برابر کر دوں اور اس کے دو دروازے بنا دوں، ایک مشرق میں اور ایک مغرب میں۔ اس طرح ابراہیم علیہ السلام کی بنیاد پر اس کی تعمیر ہو جاتی۔ عبداللہ بن زبیر رضی اللہ عنہما کا کعبہ کو گرانے سے یہی مقصد تھا۔ یزید نے بیان کیا کہ میں اس وقت موجود تھا جب عبداللہ بن زبیر رضی اللہ عنہما نے اسے گرایا تھا اور اس کی نئی تعمیر کر کے حطیم کو اس کے اندر کر دیا تھا۔ میں نے ابراہیم علیہ السلام کی تعمیر کے پائے بھی دیکھے جو اونٹ کی کوہان کی طرح تھے۔ جریر بن حازم نے کہا کہ میں نے ان سے پوچھا، ان کی جگہ کہاں ہے؟ انہوں نے فرمایا کہ میں ابھی دکھاتا ہوں۔ چنانچہ میں ان کے ساتھ حطیم میں گیا اور آپ نے ایک جگہ کی طرف اشارہ کر کے کہا کہ یہ وہ جگہ ہے۔ جریر نے کہا کہ میں نے اندازہ لگایا کہ وہ جگہ حطیم میں سے چھ ہاتھ ہو گی یا ایسی ہی کچھ۔' WHERE id = 1533;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے سعید بن مسیب نے کہ ابوہریرہ رضی اللہ عنہ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کعبہ کو دو پتلی پنڈلیوں والا حبشی خراب کرے گا۔“' WHERE id = 1543;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے یحییٰ قطان نے بیان کیا، ان سے عبیداللہ عمری نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا۔ جب سے میں نے رسول اللہ صلی اللہ علیہ وسلم کو ان دونوں رکن یمانی کو چومتے ہوئے دیکھا میں نے بھی اس کے چومنے کو خواہ سخت حالات ہوں یا نرم نہیں چھوڑا۔ میں نے نافع سے پوچھا کیا ابن عمر رضی اللہ عنہما ان دونوں یمنی رکنوں کے درمیان معمول کے مطابق چلتے تھے؟ تو انہوں نے بتایا کہ آپ معمول کے مطابق اس لیے چلتے تھے تاکہ حجر اسود کو چھونے میں آسانی رہے۔' WHERE id = 1553;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا کہ مجھ سے عمرو بن علی نے بیان کیا، کہا کہ ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے بیان کیا اور انہیں عطاء نے خبر دی کہ جب ابن ہشام ( جب وہ ہشام بن عبدالملک کی طرف سے مکہ کا حاکم تھا ) نے عورتوں کو مردوں کے ساتھ طواف کرنے سے منع کر دیا تو اس سے انہوں نے کہا کہ تم کس دلیل پر عورتوں کو اس سے منع کر رہے ہو؟ جب کہ رسول اللہ صلی اللہ علیہ وسلم کی پاک بیویوں نے مردوں کے ساتھ طواف کیا تھا۔ ابن جریج نے پوچھا یہ پردہ ( کی آیت نازل ہونے ) کے بعد کا واقعہ ہے یا اس سے پہلے کا؟ انہوں نے کہا میری عمر کی قسم! میں نے انہیں پردہ ( کی آیت نازل ہونے ) کے بعد دیکھا۔ اس پر ابن جریج نے پوچھا کہ پھر مرد عورت مل جل جاتے تھے۔ انہوں نے فرمایا کہ اختلاط نہیں ہوتا تھا، عائشہ رضی اللہ عنہا مردوں سے الگ رہ کر ایک الگ کونے میں طواف کرتی تھیں، ان کے ساتھ مل کر نہیں کرتی تھیں۔ ایک عورت ( وقرہ نامی ) نے ان سے کہا ام المؤمنین! چلئے ( حجر اسود کو ) بوسہ دیں۔ تو آپ نے انکار کر دیا اور کہا تو جا چوم، میں نہیں چومتی اور ازواج مطہرات رات میں پردہ کر کے نکلتی تھیں کہ پہچانی نہ جاتیں اور مردوں کے ساتھ طواف کرتی تھیں۔ البتہ عورتیں جب کعبہ کے اندر جانا چاہتیں تو اندر جانے سے پہلے باہر کھڑی ہو جاتیں اور مرد باہر آ جاتے ( تو وہ اندر جاتیں ) میں اور عبید بن عمیر عائشہ رضی اللہ عنہا کی خدمت میں اس وقت حاضر ہوئے جب آپ ثبیر ( پہاڑ ) پر ٹھہری ہوئی تھیں، ( جو مزدلفہ میں ہے ) ابن جریج نے کہا کہ میں نے عطاء سے پوچھا کہ اس وقت پردہ کس چیز سے تھا؟ عطاء نے بتایا کہ ایک ترکی قبہ میں ٹھہری ہوئی تھیں۔ اس پر پردہ پڑا ہوا تھا۔ ہمارے اور ان کے درمیان اس کے سوا اور کوئی چیز حائل نہ تھی۔ اس وقت میں نے دیکھا کہ ان کے بدن پر ایک گلابی رنگ کا کرتہ تھا۔' WHERE id = 1564;
UPDATE hadiths SET urdu = 'ہم سے اسحاق واسطی نے بیان کیا، کہا کہ ہم سے خالد طحان نے خالد حذاء سے بیان کیا، ان سے عکرمہ نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے بیت اللہ کا طواف اونٹ پر سوار ہو کر کیا۔ آپ صلی اللہ علیہ وسلم جب بھی ( طواف کرتے ہوئے ) حجر اسود کے نزدیک آتے تو اپنے ہاتھ کو ایک چیز ( چھڑی ) سے اشارہ کرتے اور تکبیر کہتے۔' WHERE id = 1576;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے زہری سے خبر دی کہ عروہ نے بیان کیا کہ میں نے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا سے پوچھا کہ اللہ تعالیٰ کے اس فرمان کے بارے میں آپ کا کیا خیال ہے ( جو سورۃ البقرہ میں ہے کہ ) ”صفا اور مروہ اللہ تعالیٰ کی نشانیوں میں سے ہیں۔ اس لے جو بیت اللہ کا حج یا عمرہ کرے اس کے لیے ان کا طواف کرنے میں کوئی گناہ نہیں“۔ قسم اللہ کی پھر تو کوئی حرج نہ ہونا چاہئیے اگر کوئی صفا اور مروہ کی سعی نہ کرنی چاہے۔ عائشہ رضی اللہ عنہا نے فرمایا بھتیجے! تم نے یہ بری بات کہی۔ اللہ کا مطلب یہ ہوتا تو قرآن میں یوں اترتا“ ان کے طواف نہ کرنے میں کوئی گناہ نہیں“ بات یہ ہے کہ یہ آیت تو انصار کے لیے اتری تھی جو اسلام سے پہلے منات بت کے نام پر جو مشلل میں رکھا ہوا تھا اور جس کی یہ پوجا کیا کرتے تھے۔، احرام باندھتے تھے۔ یہ لوگ جب ( زمانہ جاہلیت میں ) احرام باندھتے تو صفا مروہ کی سعی کو اچھا نہیں خیال کرتے تھے۔ اب جب اسلام لائے تو رسول اللہ صلی اللہ علیہ وسلم سے اس کے متعلق پوچھا اور کہا کہ یا رسول اللہ! ہم صفا اور مروہ کی سعی اچھی نہیں سمجھتے تھے۔ اس پر اللہ تعالیٰ نے یہ آیت نازل فرمائی کہ صفا اور مروہ دونوں اللہ کی نشانیاں ہیں آخر آیت تک۔ عائشہ صدیقہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے ان دو پہاڑوں کے درمیان سعی کی سنت جاری کی ہے۔ اس لیے کسی کے لیے مناسب نہیں ہے کہ اسے ترک کر دے۔ انہوں نے کہا کہ پھر میں نے اس کا ذکر ابوبکر بن عبدالرحمٰن سے کیا تو انہوں نے فرمایا کہ میں نے تو یہ علمی بات اب تک نہیں سنی تھی، بلکہ میں نے بہت سے اصحاب علم سے تو یہ سنا ہے کہ وہ یوں کہتے تھے کہ عرب کے لوگ ان لوگوں کے سوا جن کا عائشہ صدیقہ رضی اللہ عنہا نے ذکر کیا جو مناۃ کے لیے احرام باندھتے تھے سب صفا مروہ کا پھیرا کیا کرتے تھے۔ اور جب اللہ نے قرآن شریف میں بیت اللہ کے طواف کا ذکر فرمایا اور صفا مروہ کا ذکر نہیں کیا تو وہ لوگ کہنے لگے یا رسول اللہ! ہم تو جاہلیت کے زمانہ میں صفا اور مروہ کا پھیرا کیا کرتے تھے اور اب اللہ نے بیت اللہ کے طواف کا ذکر تو فرمایا لیکن صفا مروہ کا ذکر نہیں کیا تو کیا صفا مروہ کی سعی کرنے میں ہم پر کچھ گناہ ہو گا؟ تب اللہ نے یہ آیت اتاری۔ ”صفا مروہ اللہ کی نشانیاں ہیں آخر آیت تک۔“ ابوبکر رضی اللہ عنہ نے کہا میں سنتا ہوں کہ یہ آیت دونوں فرقوں کے باب میں اتری ہے یعنی اس فرقے کے باب میں جو جاہلیت کے زمانے میں صفا مروہ کا طواف برا جانتا تھا اور اس کے باب میں جو جاہلیت کے زمانے میں صفا مروہ کا طواف کیا کرتے تھے۔ پھر مسلمان ہونے کے بعد اس کا کرنا اس وجہ سے کہ اللہ نے بیت اللہ کے طواف کا ذکر کیا اور صفا و مروہ کا نہیں کیا، برا سمجھے۔ یہاں تک کہ اللہ نے بیت اللہ کے طواف کے بعد ان کے طواف کا بھی ذکر فرما دیا۔' WHERE id = 1586;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے ابوبکر بن عیاش سے سنا کہ ہم سے عبدالعزیز بن رفیع نے بیان کیا، کہا کہ میں انس رضی اللہ عنہ سے ملا (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے اسماعیل بن ابان نے بیان کیا، کہا کہ ہم سے ابوبکر بن عیاش نے بیان کیا، ان سے عبدالعزیز نے کہا کہ میں آٹھویں تاریخ کو منیٰ گیا تو وہاں انس رضی اللہ عنہ سے ملا۔ وہ گدھی پر سوار ہو کر جا رہے تھے۔ میں نے پوچھا نبی کریم صلی اللہ علیہ وسلم نے اس دن ظہر کی نماز کہاں پڑھی تھی؟ انہوں نے فرمایا دیکھو جہاں تمہارے حاکم لوگ نماز پڑھیں وہیں تم بھی پڑھو۔' WHERE id = 1596;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے عمرو بن دینار نے بیان کیا، کہا ہم سے محمد بن جبیر بن مطعم نے، ان سے ان کے باپ نے کہ میں اپنا ایک اونٹ تلاش کر رہا تھا (دوسری سند) اور ہم سے مسدد نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمر بن دینار نے، انہوں نے محمد بن جبیر سے سنا کہ ان کے والد جبیر بن مطعم نے بیان کیا کہ میرا ایک اونٹ کھو گیا تھا تو میں عرفات میں اس کو تلاش کرنے گیا، یہ دن عرفات کا تھا، میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم عرفات کے میدان میں کھڑے ہیں۔ میری زبان سے نکلا قسم اللہ کی! یہ تو قریش ہیں پھر یہ یہاں کیوں ہیں۔' WHERE id = 1606;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن یونس نے بیان کیا، اور ان سے ابن شہاب نے بیان کیا کہ سالم نے کہا کہ عبداللہ بن عمر رضی اللہ عنہما اپنے گھر کے کمزوروں کو پہلے ہی بھیج دیا کرتے تھے اور وہ رات ہی میں مزدلفہ میں مشعر حرام کے پاس آ کر ٹھہرتے اور اپنی طاقت کے مطابق اللہ کا ذکر کرتے تھے، پھر امام کے ٹھہرنے اور لوٹنے سے پہلے ہی ( منیٰ ) آ جاتے تھے، بعض تو منیٰ فجر کی نماز کے وقت پہنچتے اور بعض اس کے بعد، جب منیٰ پہنچتے تو کنکریاں مارتے اور عبداللہ بن عمر رضی اللہ عنہما فرمایا کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے ان سب لوگوں کے لیے یہ اجازت دی ہے۔' WHERE id = 1617;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، انہیں نضر بن شمیل نے خبر دی، انہیں شعبہ نے خبر دی، ان سے ابوجمرہ نے بیان کیا، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے تمتع کے بارے میں پوچھا تو آپ نے مجھے اس کے کرنے کا حکم دیا، پھر میں نے قربانی کے متعلق پوچھا تو آپ نے فرمایا کہ تمتع میں ایک اونٹ، یا ایک گائے یا ایک بکری ( کی قربانی واجب ہے ) یا کسی قربانی ( اونٹ، یا گائے بھینس کی ) میں شریک ہو جائے، ابوجمرہ نے کہا کہ بعض لوگ تمتع کو ناپسندیدہ قرار دیتے تھے۔ پھر میں سویا تو میں نے خواب میں دیکھا کہ ایک شخص پکار رہا ہے یہ حج مبرور ہے اور یہ مقبول تمتع ہے۔ اب میں ابن عباس رضی اللہ عنہما کی خدمت میں حاضر ہوا اور ان سے خواب کا ذکر کیا تو انہوں نے فرمایا: اللہ اکبر! یہ تو ابوالقاسم صلی اللہ علیہ وسلم کی سنت ہے۔ کہا کہ وہب بن جریر اور غندر نے شعبہ کے حوالہ سے یوں نقل کیا ہے «عمرة متقبلة،‏‏‏‏ وحج مبرور‏» ( اس میں عمرہ کا ذکر پہلے ہے یعنی یہ عمرہ مقبول اور حج مبرور ہے ) ۔' WHERE id = 1628;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں عبداللہ بن ابی بکر بن عمرو بن حزم نے خبر دی، انہیں عمرہ بنت عبدالرحمٰن نے خبر دی کہ زیاد بن ابی سفیان نے عائشہ رضی اللہ عنہا کو لکھا کہ عبداللہ بن عباس رضی اللہ عنہما نے فرمایا ہے کہ جس نے ہدی بھیج دی اس پر وہ تمام چیزیں حرام ہو جاتی ہیں جو ایک حاجی پر حرام ہوتی ہیں تاآنکہ اس کی ہدی کی قربانی کر دی جائے، عمرہ نے کہا کہ اس پر عائشہ رضی اللہ عنہا نے فرمایا عبداللہ بن عباس رضی اللہ عنہما نے جو کچھ کہا مسئلہ اس طرح نہیں ہے، میں نے نبی کریم صلی اللہ علیہ وسلم کے قربانی کے جانوروں کے قلادے اپنے ہاتھوں سے خود بٹے ہیں، پھر نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھوں سے ان جانوروں کو قلادہ پہنایا اور میرے والد محترم ( ابوبکر رضی اللہ عنہ ) کے ساتھ انہیں بھیج دیا لیکن اس کے باوجود آپ صلی اللہ علیہ وسلم نے کسی بھی ایسی چیز کو اپنے اوپر حرام نہیں کیا جو اللہ نے آپ صلی اللہ علیہ وسلم کے لیے حلال کی تھی، اور ہدی کی قربانی بھی کر دی گئی۔' WHERE id = 1639;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم بن راہویہ نے بیان کیا، انہوں نے خالد بن حارث سے سنا، کہا ہم سے عبیداللہ بن عمر نے بیان کیا، ان سے نافع نے کہ عبداللہ رضی اللہ عنہ نحر کرنے کی جگہ نحر کرتے تھے، عبیداللہ بن بتایا کہ مراد نبی کریم صلی اللہ علیہ وسلم کے نحر کرنے کی جگہ سے تھی۔' WHERE id = 1649;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، ان سے سلیمان بن ہلال نے بیان کیا، کہا مجھ سے عمرہ نے بیان کیا، کہا میں نے عائشہ رضی اللہ عنہا سے سنا، انہوں نے فرمایا کہ ہم مدینہ سے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نکلے تو ذی قعدہ کے پانچ دن باقی رہ گئے تھے، ہمارا ارادہ صرف حج ہی کا تھا، پھر جب مکہ کے قریب پہنچے تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جن کے ساتھ ہدی نہ ہو وہ بیت اللہ کا طواف کر کے حلال ہو جائیں۔ عائشہ رضی اللہ عنہا نے فرمایا کہ پھر ہمارے پاس بقر عید کے دن گائے کا گوشت لایا گیا تو میں نے پوچھا کہ یہ کیا ہے؟ اس وقت معلوم ہوا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کی طرف سے قربانی کی ہے۔ یحییٰ بن سعید نے کہا کہ میں نے اس حدیث کا قاسم بن محمد سے ذکر کیا تو انہوں نے کہا کہ عمرہ نے تم سے ٹھیک ٹھیک حدیث بیان کر دی ہے۔ ( ہر دو احادیث سے مقصد باب ظاہر ہے ) کہ قربانی کا گوشت کھانے اور بطور توشہ رکھنے کی عام اجازت ہے، خود قرآن مجید میں «فكلوا منها» کا صیغہ موجود ہے کہ اسے غرباء مساکین کو بھی تقسیم کرو اور خود بھی کھاؤ۔' WHERE id = 1659;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، ان سے ابن جریج نے بیان کیا، ان سے حسن بن مسلم نے بیان کیا، ان سے طاؤس نے بیان کیا، ان سے عبداللہ بن عباس رضی اللہ عنہما اور ان سے معاویہ رضی اللہ عنہ نے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کے بال قینچی سے کاٹے تھے۔' WHERE id = 1669;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، ہم سے شعبہ نے بیان کیا، کہا کہ مجھے عمرو نے خبر دی، کہا کہ میں نے جابر بن زید سے سنا، انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، آپ رضی اللہ عنہما نے بتلایا کہ میدان عرفات میں رسول اللہ صلی اللہ علیہ وسلم کا خطبہ میں نے خود سنا تھا۔ اس کی متابعت ابن عیینہ نے عمرو سے کی ہے۔' WHERE id = 1679;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے عبدالواحد بن زیاد مصری نے بیان کیا، ان سے سلیمان اعمش نے بیان کیا، کہا کہ میں نے حجاج سے سنا، وہ منبر پر سورتوں کا یوں نام لے رہا تھا وہ سورۃ جس میں بقرہ ( گائے ) کا ذکر آیا ہے، وہ سورۃ جس میں آل عمران کا ذکر آیا ہے، وہ سورۃ جس میں نساء ( عورتوں ) کا ذکر آیا ہے، اعمش نے کہا میں نے اس کا ذکر ابراہیم نخعی رحمہ اللہ سے کیا تو انہوں نے فرمایا کہ مجھ سے عبدالرحمٰن بن یزید نے بیان کیا کہ جب عبداللہ بن مسعود رضی اللہ عنہ نے جمرہ عقبہ کی رمی کی تو وہ ان کے ساتھ تھے، اس وقت وہ وادی کے نشیب میں اتر گئے اور جب درخت کے ( جو اس وقت وہاں پر تھا ) برابر نیچے اس کے سامنے ہو کر سات کنکریوں سے رمی کی ہر کنکری کے ساتھ اللہ اکبر کہتے جاتے تھے۔ پھر فرمایا قسم ہے اس کی کہ جس ذات کے سوا کوئی معبود نہیں یہیں وہ ذات بھی کھڑی ہوئی تھی جس پر سورۃ البقرہ نازل ہوئی۔' WHERE id = 1689;
UPDATE hadiths SET urdu = 'ہم سے عبدالمتعال بن طالب نے بیان کیا، انہوں نے کہا کہ ہم سے ابن وہب نے بیان کیا، انہوں نے کہا کہ مجھے عمرو بن حارث نے خبر دی، ان سے قتادہ نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ظہر، عصر، مغرب، عشاء نبی کریم صلی اللہ علیہ وسلم نے پڑھی اور تھوڑی دیر کے لیے محصب میں سو رہے، پھر بیت اللہ کی طرف سوار ہو کر گئے اور طواف کیا۔ ( یہاں طواف الزیارۃ مراد ہے ) ۔' WHERE id = 1701;
UPDATE hadiths SET urdu = 'ہم سے حسان بن حسان نے بیان کیا کہ ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے قتادہ نے کہ میں نے انس رضی اللہ عنہ سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم نے کتنے عمرے کئے تھے؟ تو آپ نے فرمایا کہ چار، عمرہ حدیبیہ ذی قعدہ میں جہاں پر مشرکین نے آپ صلی اللہ علیہ وسلم کو روک دیا تھا، پھر آئندہ سال ذی قعدہ ہی میں ایک عمرہ قضاء جس کے متعلق آپ صلی اللہ علیہ وسلم نے مشرکین سے صلح کی تھی اور تیسرا عمرہ جعرانہ جس موقع پر آپ صلی اللہ علیہ وسلم نے غالباً حنین کی غنیمت تقسیم کی تھی، چوتھا حج کے ساتھ میں نے پوچھا اور نبی کریم صلی اللہ علیہ وسلم نے حج کتنے کئے؟ فرمایا کہ ایک۔' WHERE id = 1713;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے افلح بن حمید نے بیان کیا، ان سے قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ حج کے مہینوں اور آداب میں ہم حج کا احرام باندھ کر مدینہ سے چلے اور مقام سرف میں پڑاؤ کیا، نبی کریم صلی اللہ علیہ وسلم نے اپنے اصحاب سے فرمایا کہ جس کے ساتھ قربانی نہ ہو اور وہ چاہے کہ اپنے حج کے احرام کو عمرہ میں بدل دے تو وہ ایسا کر سکتا ہے، لیکن جس کے ساتھ قربانی ہے وہ ایسا نہیں کر سکتا۔ نبی کریم صلی اللہ علیہ وسلم اور آپ کے اصحاب میں سے بعض مقدور والوں کے ساتھ قربانی تھی، اس لیے ان کا ( احرام صرف ) عمرہ کا نہیں رہا، پھر نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف لائے تو میں رو رہی تھی، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ رو کیوں رہی ہو؟ میں نے کہا آپ صلی اللہ علیہ وسلم نے اپنے اصحاب سے جو کچھ فرمایا میں سن رہی تھی، اب تو میرا عمرہ رہ گیا آپ صلی اللہ علیہ وسلم نے پوچھا کیا بات ہوئی؟ میں نے کہا کہ میں نماز نہیں پڑھ سکتی ( حیض کی وجہ سے ) نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ کوئی حرج نہیں، تو بھی آدم کی بیٹیوں میں سے ایک ہے، اور جو ان سب کے مقدر میں لکھا ہے وہی تمہارا بھی مقدر ہے۔ اب حج کا احرام باندھ لے شاید اللہ تعالیٰ تمہیں عمرہ بھی نصیب کرے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے حج کا احرام باندھ لیا پھر جب ہم ( حج سے فارغ ہو کر اور ) منی سے نکل کر محصب میں اترے تو نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن کو بلایا اور ان سے کہا کہ اپنی بہن کو حد حرم سے باہر لے جا ( تنعیم ) تاکہ وہ وہاں سے عمرہ کا احرام باندھ لیں، پھر طواف و سعی کرو ہم تمہارا انتظار یہیں کریں گے۔ ہم آدھی رات کو آپ کی خدمت میں پہنچے تو آپ صلی اللہ علیہ وسلم نے پوچھا کیا فارغ ہو گئے؟ میں نے کہا ہاں، نبی کریم صلی اللہ علیہ وسلم نے اس کے بعد اپنے اصحاب میں کوچ کا اعلان کر دیا۔ بیت اللہ کا طواف وداع کرنے والے لوگ صبح کی نماز سے پہلے ہی روانہ ہو گئے اور مدینہ کی طرف چل دیئے۔' WHERE id = 1723;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے محارب بن دثار نے اور ان سے جابر رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( سفر سے ) گھر رات کے وقت اترنے سے منع فرمایا۔' WHERE id = 1734;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، کہا کہ ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور انہیں مسور رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( صلح حدیبیہ کے موقع پر ) قربانی سر منڈوانے سے پہلے کی تھی۔ اور آپ صلی اللہ علیہ وسلم نے اصحاب کو بھی اسی کا حکم دیا تھا۔' WHERE id = 1744;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، ان سے یحییٰ ابن کثیر نے، ان سے عبداللہ بن ابی قتادہ نے بیان کیا کہ میرے والد صلح حدیبیہ کے موقع پر ( دشمنوں کا پتہ لگانے ) نکلے۔ پھر ان کے ساتھیوں نے تو احرام باندھا لیا لیکن ( خود انہوں نے ابھی ) نہیں باندھا تھا ( اصل میں ) نبی کریم صلی اللہ علیہ وسلم کو کسی نے یہ اطلاع دی تھی کہ مقام غیقہ میں دشمن آپ کی تاک میں ہے، اس لیے نبی کریم صلی اللہ علیہ وسلم نے ( ابوقتادہ اور چند صحابہ رضی اللہ عنہم کو ان کی تلاش میں ) روانہ کیا میرے والد ( ابوقتادہ رضی اللہ عنہ ) اپنے ساتھیوں کے ساتھ تھے کہ یہ لوگ ایک دوسرے کو دیکھ کر ہنسنے لگے ( میرے والد نے بیان کیا کہ ) میں نے جو نظر اٹھائی تو دیکھا کہ ایک جنگلی گدھا سامنے ہے۔ میں اس پر جھپٹا اور نیزے سے اسے ٹھنڈا کر دیا۔ میں نے اپنے ساتھیوں کی مدد چاہی تھی لیکن انہوں نے انکار کر دیا تھا، پھر ہم نے گوشت کھایا۔ اب ہمیں یہ ڈر ہوا کہ کہیں ( رسول اللہ صلی اللہ علیہ وسلم سے ) دور نہ ہو جائیں، چنانچہ میں نے آپ کو تلاش کرنا شروع کر دیا کبھی اپنے گھوڑے تیز کر دیتا اور کبھی آہستہ، آخر رات گئے بنو غفار کے ایک شخص سے ملاقات ہو گئی۔ میں نے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کہاں ہیں؟ انہوں نے بتایا کہ جب میں آپ سے جدا ہوا تو آپ مقام تعھن میں تھے اور آپ کا ارادہ تھا کہ مقام سقیا میں پہنچ کر دوپہر کا آرام کریں گے۔ غرض میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو گیا اور میں نے عرض کی یا رسول اللہ! آپ کے اصحاب آپ پر سلام اور اللہ کی رحمت بھیجتے ہیں۔ انہیں یہ ڈر ہے کہ کہیں وہ بہت پیچھے نہ رہ جائیں۔ اس لیے آپ ٹھہر کر ان کا انتظار کریں، پھر میں نے کہا یا رسول اللہ! میں نے ایک جنگلی گدھا شکار کیا تھا اور اس کا کچھ بچا ہوا گوشت اب بھی میرے پاس موجود ہے، آپ صلی اللہ علیہ وسلم نے لوگوں سے کھانے کے لیے فرمایا حالانکہ وہ سب احرام باندھے ہوئے تھے۔' WHERE id = 1754;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے چھپکلی کو موذی کہا تھا لیکن میں نے آپ صلی اللہ علیہ وسلم سے یہ نہیں سنا کہ آپ نے اسے مارنے کا بھی حکم دیا تھا۔' WHERE id = 1764;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھے عمرو بن دینار نے خبر دی، انہوں نے جابر بن زید سے سنا، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا، آپ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو عرفات میں خطبہ دیتے سنا تھا کہ جس کے پاس احرام میں جوتے نہ ہوں وہ موزے پہن لے اور جس کے پاس تہبند نہ ہو وہ پاجامہ پہن لے۔' WHERE id = 1774;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، انہوں نے کہا ہمیں ابوبشر نے خبر دی، انہوں نے کہا کہ ہمیں سعید بن جبیر نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کے ساتھ میدان عرفات میں تھا کہ اس کے اونٹ نے گرا کر اس کی گردن توڑ دی۔ وہ شخص محرم تھا اور مر گیا۔ نبی کریم صلی اللہ علیہ وسلم نے یہ ہدایت دی کہ اسے پانی اور بیری کا غسل اور ( احرام کے ) دو کپڑوں کا کفن دیا جائے البتہ اس کو خوشبو نہ لگاؤ نہ اس کا سر چھپاؤ کیونکہ قیامت کے دن وہ لبیک کہتا ہوا اٹھے گا۔' WHERE id = 1784;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، ان سے حبیب بن عمرہ نے بیان کیا، انہوں نے کہا مجھ سے عائشہ بنت طلحہ نے بیان کیا اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے پوچھا یا رسول اللہ صلی اللہ علیہ وسلم ! ہم بھی کیوں نہ آپ صلی اللہ علیہ وسلم کے ساتھ جہاد اور غزووں میں جایا کریں؟ آپ صلی اللہ علیہ وسلم نے فرمایا تم لوگوں کے لیے سب سے عمدہ اور سب سے مناسب جہاد حج ہے، وہ حج جو مقبول ہو۔ عائشہ رضی اللہ عنہا کہتی تھیں کہ جب سے میں نے رسول اللہ صلی اللہ علیہ وسلم کا یہ ارشاد سن لیا ہے حج کو میں کبھی چھوڑنے والی نہیں ہوں۔' WHERE id = 1794;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں یحییٰ بن سعید نے، انہوں نے بیان کیا کہ میں نے ابوالحباب سعید بن یسار سے سنا، انہوں نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مجھے ایک ایسے شہر ( میں ہجرت ) کا حکم ہوا ہے جو دوسرے شہروں کو کھا لے گا۔ ( یعنی سب کا سردار بنے گا ) منافقین اسے یثرب کہتے ہیں لیکن اس کا نام مدینہ ہے وہ ( برے ) لوگوں کو اس طرح باہر کر دیتا ہے جس طرح بھٹی لوہے کے زنگ کو نکال دیتی ہے۔' WHERE id = 1804;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، ان سے ولید نے بیان کیا، ان سے ابوعمرو اوزاعی نے بیان کیا، ان سے اسحٰق نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کوئی ایسا شہر نہیں ملے گا جسے دجال پامال نہ کرے گا، سوائے مکہ اور مدینہ کے، ان کے ہر راستے پر صف بستہ فرشتے کھڑے ہوں گے جو ان کی حفاظت کریں گے پھر مدینہ کی زمین تین مرتبہ کانپے گی جس سے ایک ایک کافر اور منافق کو اللہ تعالیٰ اس میں سے باہر کر دے گا۔' WHERE id = 1814;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے اسماعیل بن جعفر نے بیان کیا، ان سے ابوسہیل نے، ان سے ان کے والد مالک نے اور ان سے طلحہ بن عبیداللہ رضی اللہ عنہ نے کہ ایک اعرابی پریشان حال بال بکھرے ہوئے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اس نے پوچھا: یا رسول اللہ! بتائیے مجھ پر اللہ تعالیٰ نے کتنی نمازیں فرض کی ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پانچ نمازیں، یہ اور بات ہے کہ تم اپنی طرف سے نفل پڑھ لو، پھر اس نے کہا بتائیے اللہ تعالیٰ نے مجھ پر روزے کتنے فرض کئے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ رمضان کے مہینے کے، یہ اور بات ہے کہ تم خود اپنے طور پر کچھ نفلی روزے اور بھی رکھ لو، پھر اس نے پوچھا اور بتائیے زکوٰۃ کس طرح مجھ پر اللہ تعالیٰ نے فرض کی ہے؟ آپ صلی اللہ علیہ وسلم نے اسے شرع اسلام کی باتیں بتا دیں۔ جب اس اعرابی نے کہا اس ذات کی قسم جس نے آپ صلی اللہ علیہ وسلم کو عزت دی نہ میں اس میں اس سے جو اللہ تعالیٰ نے مجھ پر فرض کر دیا ہے کچھ بڑھاؤں گا اور نہ گھٹاؤں گا، اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اگر اس نے سچ کہا ہے تو یہ مراد کو پہنچایا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) اگر سچ کہا ہے تو جنت میں جائے گا۔' WHERE id = 1824;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو کوئی شب قدر میں ایمان کے ساتھ اور حصول ثواب کی نیت سے عبادت میں کھڑا ہو اس کے تمام پچھلے گناہ بخش دیئے جائیں گے اور جس نے رمضان کے روزے ایمان کے ساتھ اور ثواب کی نیت سے رکھے اس کے اگلے تمام گناہ معاف کر دیئے جائیں گے۔' WHERE id = 1834;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیزبن عبداللہ نے بیان کیا، کہا ہم سے سلیمان بن بلال نے، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اپنی بیویوں سے جدا رہے تھے، آپ صلی اللہ علیہ وسلم کے پاؤں میں موچ آ گئی تھی تو آپ صلی اللہ علیہ وسلم نے بالاخانہ میں انتیس دن قیام کیا تھا، پھر وہاں سے اترے۔ لوگوں نے عرض کیا یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے ایک مہینہ کا ایلاء کیا تھا۔ جواب میں آپ نے فرمایا کہ مہینہ انتیس دن کا بھی ہوتا ہے۔' WHERE id = 1844;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے عبدالعزیز بن صہیب نے بیان کیا، انہوں نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، سحری کھاؤ کہ سحری میں برکت ہوتی ہے۔' WHERE id = 1855;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا کہ ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے زہری نے، ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کی کہ یہ بدنصیب رمضان میں اپنی بیوی سے جماع کر بیٹھا ہے، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارے پاس اتنی طاقت نہیں ہے کہ ایک غلام آزاد کر سکو؟ اس نے کہا کہ نہیں، آپ صلی اللہ علیہ وسلم نے پھر دریافت فرمایا کیا تم پے در پے دو مہینے کے روزے رکھ سکتے ہو؟ اس نے کہا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے پھر دریافت فرمایا کہ کیا تمہارے اندر اتنی طاقت ہے کہ ساٹھ مسکینوں کو کھانا کھلا سکو؟ اب بھی اس کا جواب نفی میں تھا۔ راوی نے بیان کیا پھر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ایک تھیلا لایا گیا جس میں کھجوریں تھیں «عرق» زنبیل کو کہتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے لے جا اور اپنی طرف سے ( محتاجوں کو ) کھلا دے، اس شخص نے کہا میں اپنے سے بھی زیادہ محتاج کو حالانکہ دو میدانوں کے درمیان کوئی گھرانہ ہم سے زیادہ محتاج نہیں آپ نے فرمایا کہ پھر جا اپنے گھر والوں ہی کو کھلا دے۔' WHERE id = 1867;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے امام مالک نے، ان سے حمید طویل نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ( رمضان میں ) سفر کیا کرتے تھے۔ ( سفر میں بہت سے روزے سے ہوتے اور بہت سے بے روزہ ہوتے ) لیکن روزے دار بے روزہ دار پر اور بے روزہ دار روزے دار پر کسی قسم کی عیب جوئی نہیں کیا کرتے تھے۔' WHERE id = 1877;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا، کہا کہ ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے فاطمہ بنت منذر نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہ نے کہ ایک مرتبہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں بادل تھا۔ ہم نے جب افطار کر لیا تو سورج نکل آیا۔ اس پر ہشام ( راوی حدیث ) سے کہا گیا کہ پھر انہیں اس روزے کی قضاء کا حکم ہوا تھا؟ تو انہوں نے بتلایا کہ قضاء کے سوا اور چارہ کار ہی کیا تھا؟ اور معمر نے کہا کہ میں نے ہشام سے یوں سنا ”مجھے معلوم نہیں کہ ان لوگوں نے قضاء کی تھی یا نہیں۔“' WHERE id = 1889;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک رحمہ اللہ نے خبری دی، انہیں ابوالنضر نے، انہیں ابوسلمہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا، کہ رسول اللہ صلی اللہ علیہ وسلم نفل روزہ رکھنے لگتے تو ہم ( آپس میں ) کہتے کہ اب آپ صلی اللہ علیہ وسلم روزہ رکھنا چھوڑیں گے ہی نہیں۔ اور جب روزہ چھوڑ دیتے تو ہم کہتے کہ اب آپ روزہ رکھیں گے ہی نہیں۔ میں نے رمضان کو چھوڑ کر رسول اللہ صلی اللہ علیہ وسلم کو کبھی پورے مہینے کا نفلی روزہ رکھتے نہیں دیکھتا اور جتنے روزے آپ شعبان میں رکھتے میں نے کسی مہینہ میں اس سے زیادہ روزے رکھتے آپ کو نہیں دیکھا۔' WHERE id = 1899;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے حبیب بن ابی ثابت نے بیان کیا، کہا کہ میں نے ابوعباس مکی سے سنا، وہ شاعر تھے لیکن روایت حدیث میں ان پر کسی قسم کا اتہام نہیں تھا۔ انہوں نے بیان کیا کہ میں نے عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے سنا، انہوں نے کہا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، کیا تو متواتر روزے رکھتا ہے اور رات بھر عبادت کرتا ہے؟ میں نے ہاں میں جواب دیا تو آپ صلی اللہ علیہ وسلم نے فرمایا، اگر تو یونہی کرتا رہا تو آنکھیں دھنس جائیں گی، اور تو بےحد کمزور ہو جائے گا یہ کوئی روزہ نہیں کہ کوئی زندگی بھر ( بلاناغہ ہر روز ) روزہ رکھے۔ تین دن کا ( ہر مہینہ میں ) روزہ پوری زندگی کے روزے کے برابر ہے۔ میں نے اس پر کہا کہ مجھے اس سے بھی زیادہ طاقت ہے۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر داؤد علیہ السلام کا روزہ رکھا کر۔ آپ ایک دن روزہ رکھتے تھے اور ایک دن روزہ چھوڑ دیتے تھے اور جب دشمن کا سامنا ہوتا تو پیٹھ نہیں دکھلایا کرتے تھے۔' WHERE id = 1909;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ ہم سے ابن وہب نے بیان کیا، (یا ان کے سامنے حدیث کی قرآت کی گئی) ۔ کہا کہ مجھ کو عمرو نے خبر دی، انہیں بکیر نے، انہیں کریب نے اور انہیں میمونہ رضی اللہ عنہا نے کہ عرفہ کے دن کچھ لوگوں کو نبی کریم صلی اللہ علیہ وسلم کے روزے کے متعلق شک ہوا۔ اس لیے انہوں نے آپ کی خدمت میں دودھ بھیجا۔ آپ اس وقت عرفات میں وقوف فرما تھے۔ آپ نے دودھ پی لیا اور سب لوگ دیکھ رہے تھے۔' WHERE id = 1919;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے کہا کہ ہم سے امام مالک رحمہ اللہ نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے حمید بن عبدالرحمٰن نے بیان کیا کہ انہوں نے معاویہ بن ابی سفیان رضی اللہ عنہما سے عاشوراء کے دن منبر پر سنا، انہوں نے کہا کہ اے اہل مدینہ! تمہارے علماء کدھر گئے، میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے سنا کہ یہ عاشوراء کا دن ہے۔ اس کا روزہ تم پر فرض نہیں ہے لیکن میں روزہ سے ہوں اور اب جس کا جی چاہے روزہ سے رہے ( اور میری سنت پر عمل کرے ) اور جس کا جی چاہے نہ رہے۔' WHERE id = 1931;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے سعید مقبری نے، ان سے ابوسلمہ بن عبدالرحمٰن نے کہ انہوں نے عائشہ رضی اللہ عنہا سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم ( تراویح یا تہجد کی نماز ) رمضان میں کتنی رکعتیں پڑھتے تھے؟ تو انہوں نے بتلایا کہ رمضان ہو یا کوئی اور مہینہ آپ گیارہ رکعتوں سے زیادہ نہیں پڑھتے تھے۔ آپ صلی اللہ علیہ وسلم پہلی چار رکعت پڑھتے، تم ان کے حسن و خوبی اور طول کا حال نہ پوچھو، پھر چار رکعت پڑھتے، ان کے بھی حسن و خوبی اور طول کا حال نہ پوچھو، آخر میں تین رکعت ( وتر ) پڑھتے تھے۔ میں نے ایک بار پوچھا، یا رسول اللہ! کیا آپ وتر پڑھنے سے پہلے سو جاتے ہیں؟ تو آپ صلی اللہ علیہ وسلم نے فرمایا، عائشہ! میری آنکھیں سوتی ہیں لیکن میرا دل نہیں سوتا۔' WHERE id = 1941;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا، ان سے خالد بن حارث نے بیان کیا، ان سے حمید طویل نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا اور ان سے عبادہ بن صامت رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ہمیں شب قدر کی خبر دینے کے لیے تشریف لا رہے تھے کہ دو مسلمان آپس میں جھگڑا کرنے لگے۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں آیا تھا کہ تمہیں شب قدر بتا دوں لیکن فلاں فلاں نے آپس میں جھگڑا کر لیا۔ پس اس کا علم اٹھا لیا گیا اور امید یہی ہے کہ تمہارے حق میں یہی بہتر ہو گا۔ پس اب تم اس کی تلاش ( آخری عشرہ کی ) نو یا سات یا پانچ ( کی راتوں ) میں کیا کرو۔' WHERE id = 1951;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا کہ مجھے امام زین العابدین علی بن حسین نے خبر دی، اور انہیں نبی کریم صلی اللہ علیہ وسلم کی پاک بیوی صفیہ رضی اللہ عنہا نے خبر دی کہ وہ رمضان کے آخری عشرہ میں جب رسول اللہ صلی اللہ علیہ وسلم اعتکاف میں بیٹھے ہوئے تھے، آپ صلی اللہ علیہ وسلم سے ملنے مسجد میں آئیں تھوڑی دیر تک باتیں کیں پھر واپس ہونے کے لیے کھڑی ہوئیں۔ نبی کریم صلی اللہ علیہ وسلم بھی انہیں پہنچانے کے لیے کھڑے ہوئے۔ جب وہ ام سلمہ رضی اللہ عنہا کے دروازے سے قریب والے مسجد کے دروازے پر پہنچیں، تو دو انصاری آدمی ادھر سے گزرے اور نبی کریم صلی اللہ علیہ وسلم کو سلام کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کسی سوچ کی ضرورت نہیں، یہ تو ( میری بیوی ) صفیہ بنت حیی ( رضی اللہ عنہا ) ہیں۔ ان دونوں صحابیوں نے عرض کیا، سبحان اللہ! یا رسول اللہ! ان پر آپ کا جملہ بڑا شاق گزرا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ شیطان خون کی طرح انسان کے بدن میں دوڑتا رہتا ہے۔ مجھے خطرہ ہوا کہ کہیں تمہارے دلوں میں وہ کوئی بدگمانی نہ ڈال دے۔' WHERE id = 1962;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل ابوالحسن نے بیان کیا، انہوں نے کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، انہیں اوزاعی نے خبر دی، کہا کہ مجھ سے یحییٰ بن سعید نے بیان کیا، کہا کہ مجھ سے عمرو بنت عبدالرحمٰن نے بیان کیا، ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے رمضان کے آخری عشرے میں اعتکاف کے لیے ذکر کیا۔ عائشہ رضی اللہ عنہا نے بھی آپ صلی اللہ علیہ وسلم سے اجازت مانگی۔ آپ نے انہیں اجازت دے دی، پھر حفصہ رضی اللہ عنہا نے عائشہ رضی اللہ عنہا سے کہا کہ ان کے لیے بھی اجازت لے دیں چنانچہ انہوں نے ایسا کر دیا۔ جب زینب بنت حجش رضی اللہ عنہا نے دیکھا تو انہوں نے بھی خیمہ لگانے کے لیے کہا، اور ان کے لیے بھی خیمہ لگا دیا گیا۔ انہوں نے ذکر کیا کہ رسول اللہ صلی اللہ علیہ وسلم صبح کی نماز کے بعد اپنے خیمہ میں تشریف لے جاتے آج آپ کو بہت خیمے دکھائی دیئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ کیا ہے؟ لوگوں نے بتایا کہ عائشہ رضی اللہ عنہا ، حفصہ رضی اللہ عنہا ، اور زینب رضی اللہ عنہا کے خیمے ہیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ، بھلا کیا ان کی ثواب کی نیت ہے اب میں بھی اعتکاف نہیں کروں گا۔ پھر جب ماہ رمضان ختم ہو گیا تو آپ صلی اللہ علیہ وسلم نے شوال میں اعتکاف کیا۔' WHERE id = 1972;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے منصور نے، ان سے طلحہ بن مصرف نے، ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ایک گری ہوئی کھجور پر گزرے، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر اس کے صدقہ ہونے کا شبہ نہ ہوتا تو میں اسے کھا لیتا۔ اور ہمام بن منبہ نے ابوہریرہ رضی اللہ عنہ سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، میں اپنے بستر پر پڑی ہوئی ایک کھجور پاتا ہوں۔' WHERE id = 1982;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یعقوب کرمانی نے بیان کیا، کہا کہ ہم سے حسان بن ابراہیم نے بیان کیا، ان سے یونس نے بیان کیا، ان سے محمد بن مسلم نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کیا کہ میں نے سنا رسول اللہ صلی اللہ علیہ وسلم فرما رہے تھے کہ جو شخص اپنی روزی میں کشادگی چاہتا ہو یا عمر کی دارازی چاہتا ہو تو اسے چاہئیے کہ صلہ رحمی کرے۔' WHERE id = 1993;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا کہ ہم سے زہیر نے بیان کیا کہا کہ ہم سے منصور نے، ان سے ربعی بن حراش نے بیان کیا اور ان سے حذیفہ بن یمان رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، تم سے پہلے گذشتہ امتوں کے کسی شخص کی روح کے پاس ( موت کے وقت ) فرشتے آئے اور پوچھا کہ تو نے کچھ اچھے کام بھی کئے ہیں؟ روح نے جواب دیا کہ میں اپنے نوکروں سے کہا کرتا تھا کہ وہ مالدار لوگوں کو ( جو ان کے مقروض ہوں ) مہت دے دیا کریں اور ان پر سختی نہ کریں۔ اور محتاجوں کو معاف کر دیا کریں۔ راوی نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، پھر فرشتوں نے بھی اس سے درگزر کیا اور سختی نہیں کی اور ابومالک نے ربعی سے ( اپنی روایت میں یہ الفاظ ) بیان کئے ہیں ”کھاتے کماتے کے ساتھ ( اپنا حق لیتے وقت ) نرم معاملہ کرتا تھا اور تنگ حال مقروض کو مہلت دیتا تھا۔ اس کی متابعت شعبہ نے کی ہے۔ ان سے عبدالملک نے اور ان سے ربعی نے بیان کیا، ابوعوانہ نے کہا کہ ان سے عبدالملک نے ربعی سے بیان کیا کہ ( اس روح نے یہ الفاظ کہے تھے ) میں کھاتے کماتے کو مہلت دے دیتا تھا اور تنگ حال والے مقروض سے درگزر کرتا تھا اور نعیم بن ابی ہند نے بیان کیا، ان سے ربعی نے ( کہ روح نے یہ الفاظ کہے تھے ) میں کھاتے کماتے لوگوں کے ( جن پر میرا کوئی حق واجب ہوتا ) عذر قبول کر لیا کرتا تھا اور تنگ حال والے سے درگزر کر دیتا تھا۔' WHERE id = 2003;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے کہ سعید بن مسیب نے بیان کیا کہ ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے خود نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے ہوئے سنا کہ ( سامان بیچتے وقت دکاندار کے ) قسم کھانے سے سامان تو جلدی بک جاتا ہے لیکن وہ قسم برکت کو مٹا دینے والی ہوتی ہے۔' WHERE id = 2013;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے عبدالوہاب نے بیان کیا، کہا کہ ہم سے عبیداللہ نے بیان کیا، ان سے وہب بن کیسان نے بیان کیا اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک غزوہ ( ذات الرقاع یا تبوک ) میں تھا۔ میرا اونٹ تھک کر سست ہو گیا۔ اتنے میں میرے پاس نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور فرمایا جابر! میں نے عرض کیا: یا رسول اللہ! حاضر ہوں۔ فرمایا کیا بات ہوئی؟ میں نے کہا کہ میرا اونٹ تھک کر سست ہو گیا ہے، چلتا ہی نہیں اس لیے میں پیچھے رہ گیا ہوں۔ پھر آپ اپنی سواری سے اترے اور میرے اسی اونٹ کو ایک ٹیرھے منہ کی لکڑی سے کھینچنے لگے ( یعنی ہانکنے لگے ) اور فرمایا کہ اب سوار ہو جا۔ چنانچہ میں سوار ہو گیا۔ اب تو یہ حال ہوا کہ مجھے اسے رسول اللہ صلی اللہ علیہ وسلم کے برابر پہنچنے سے روکنا پڑ جاتا تھا۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، جابر تو نے شادی بھی کر لی ہے؟ میں نے عرض کی جی ہاں! دریافت فرمایا کسی کنواری لڑکی سے کی ہے یا بیوہ سے۔ میں نے عرض کیا کہ میں نے تو ایک بیوہ سے کر لی ہے۔ فرمایا، کسی کنواری لڑکی سے کیوں نہ کی کہ تم اس کے ساتھ کھیلتے اور وہ بھی تمہارے ساتھ کھیلتی۔ ( جابر بھی کنوارے تھے ) میں نے عرض کیا کہ میری کئی بہنیں ہیں۔ ( اور میری ماں کا انتقال ہو چکا ہے ) اس لیے میں نے یہی پسند کیا کہ ایسی عورت سے شادی کروں، جو انہیں جمع رکھے۔ ان کے کنگھا کرے اور ان کی نگرانی کرے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا اب تم گھر پہنچ کر خیر و عافیت کے ساتھ خوب مزے اڑانا۔ اس کے بعد فرمایا، کیا تم اپنا اونٹ بیچو گے؟ میں نے کہا جی ہاں! چنانچہ آپ صلی اللہ علیہ وسلم نے ایک اوقیہ چاندی میں خرید لیا، رسول اللہ صلی اللہ علیہ وسلم مجھ سے پہلے ہی مدینہ پہنچ گئے تھے۔ اور میں دوسرے دن صبح کو پہنچا۔ پھر ہم مسجد آئے تو نبی کریم صلی اللہ علیہ وسلم مسجد کے دروازہ پر ملے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، کیا ابھی آئے ہو؟ میں نے عرض کیا کہ جی ہاں! فرمایا، پھر اپنا اونٹ چھوڑ دے اور مسجد میں جا کے دو رکعت نماز پڑھ۔ میں اندر گیا اور نماز پڑھی۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے بلال رضی اللہ عنہ کو حکم دیا کہ میرے لیے ایک اوقیہ چاندی تول دے۔ انہوں نے ایک اوقیہ چاندی جھکتی ہوئی تول دی۔ میں پیٹھ موڑ کر چلا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جابر کو ذرا بلاؤ۔ میں نے سوچا کہ شاید اب میرا اونٹ پھر مجھے واپس کریں گے۔ حالانکہ اس سے زیادہ ناگوار میرے لیے کوئی چیز نہیں تھی۔ چنانچہ آپ صلی اللہ علیہ وسلم نے یہی فرمایا کہ یہ اپنا اونٹ لے جا اور اس کی قیمت بھی تمہاری ہے۔' WHERE id = 2023;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا کہ ہم کو عبدالوہاب نے خبر دی، کہا کہ میں نے یحییٰ بن سعید سے سنا، کہا کہ میں نے نافع سے سنا اور انہوں نے ابن عمر رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، خرید و فروخت کرنے والوں کو جب تک وہ جدا نہ ہوں اختیار ہوتا ہے، یا خود بیع میں اختیار کی شرط ہو۔ ( تو شرط کے مطابق اختیار ہوتا ہے ) نافع نے کہا کہ جب عبداللہ بن عمر رضی اللہ عنہما کوئی ایسی چیز خریدتے جو انہیں پسند ہوتی تو ( خریدنے کے بعد ) اپنے معاملہ دار سے جدا ہو جاتے۔' WHERE id = 2033;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں عبداللہ بن دینار نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ ایک شخص ( حبان بن منقذ رضی اللہ عنہ ) نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ وہ اکثر خرید و فروخت میں دھوکہ کھا جاتے ہیں۔ اس پر آپ صلی اللہ علیہ وسلم نے ان سے فرمایا کہ جب تم کسی چیز کی خرید و فروخت کرو تو یوں کہہ دیا کرو کہ ”بھائی دھوکہ اور فریب کا کام نہیں۔“' WHERE id = 2043;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا کہ ہم سے امام مالک نے بیان کیا، ان سے اسحٰق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، اے اللہ! انہیں ان کے پیمانوں میں برکت دے، اے اللہ! انہیں ان کے صاع اور مد میں برکت دے۔ آپ صلی اللہ علیہ وسلم کی مراد اہل مدینہ تھے۔' WHERE id = 2055;
UPDATE hadiths SET urdu = 'ہم سے بشیر بن محمد نے بیان کیا، کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، انہیں حسین مکتب نے خبر دی، انہیں عطاء بن ابی رباح نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے کہ ایک شخص نے اپنا ایک غلام اپنے مرنے کے بعد کی شرط کے ساتھ آزاد کیا۔ لیکن اتفاق سے وہ شخص مفلس ہو گیا، تو نبی کریم صلی اللہ علیہ وسلم نے اس کے غلام کو لے کر فرمایا کہ اسے مجھ سے کون خریدے گا۔ اس پر نعیم بن عبداللہ رضی اللہ عنہ نے اسے اتنی اتنی قیمت پر خرید لیا اور آپ صلی اللہ علیہ وسلم نے غلام ان کے حوالہ کر دیا۔' WHERE id = 2066;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عمرو نے بیان کیا، کہا کہ ہم سے مکی بن ابراہیم نے بیان کیا، انہیں ابن جریج نے خبر دی، کہا کہ مجھے زیاد نے خبر دی کہ عبدالرحمٰن بن زید کے غلام ثابت نے انہیں خبر دی، کہ انہوں نے ابوہریرہ رضی اللہ عنہ کو یہ کہتے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس شخص نے «مصراة» بکری خریدی اور اسے دوہا۔ تو اگر وہ اس معاملہ پر راضی ہے تو اسے اپنے لیے روک لے اور اگر راضی نہیں ہے تو ( واپس کر دے اور ) اس کے دودھ کے بدلے میں ایک صاع کھجور دیدے۔' WHERE id = 2076;
UPDATE hadiths SET urdu = 'مجھ سے عیاش بن عبدالولید نے بیان کیا، کہا کہ ہم سے عبدالاعلیٰ نے بیان کیا، کہا کہ ہم سے معمر نے بیان کیا، ان سے ابن طاؤس نے، ان سے ان کے باپ نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم کے اس ارشاد کا مطلب کیا ہے کہ کوئی شہری کسی دیہاتی کا مال نہ بیچے؟ تو انہوں نے کہا کہ مطلب یہ ہے کہ اس کا دلال نہ بنے۔' WHERE id = 2087;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، انہوں نے کہا کہ ہم کو اسماعیل بن علیہ نے خبر دی، کہا کہ مجھے یحییٰ بن ابی اسحاق نے خبر دی، ان سے عبدالرحمٰن بن ابی بکرہ نے بیان کیا، ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، سونا سونے کے بدلے میں اس وقت تک نہ بیچو جب تک ( دونوں طرف سے ) برابر برابر ( کی لین دین ) نہ ہو۔ اسی طرح چاندی، چاندی کے بدلہ میں اس وقت تک نہ بیچو جب تک ( دونوں طرف سے ) برابر برابر نہ ہو۔ البتہ سونا، چاندی کے بدل اور چاندی سونے کے بدل میں جس طرح چاہو بیچو۔' WHERE id = 2098;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ یحییٰ بن سعید نے بیان کیا کہ میں نے بشیر سے سنا، انہوں نے بیان کیا کہ میں نے سہل بن ابی حثمہ رضی اللہ عنہ سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم نے درخت پر لگی ہوئی کھجور کو توڑی ہوئی کھجور کے بدلے بیچنے سے منع فرمایا، البتہ عریہ کی آپ صلی اللہ علیہ وسلم نے اجازت دی کہ اندازہ کر کے یہ بیع کی جا سکتی ہے کہ عریہ والے اس کے بدل تازہ کھجور کھائیں۔ سفیان نے دوسری مرتبہ یہ روایت بیان کی، لیکن نبی کریم صلی اللہ علیہ وسلم نے عریہ کی اجازت دے دی تھی۔ کہ اندازہ کر کے یہ بیع کی جا سکتی ہے، کھجور ہی کے بدلے میں۔ دونوں کا مفہوم ایک ہی ہے۔ سفیان نے بیان کیا کہ میں نے یحییٰ سے پوچھا، اس وقت میں ابھی کم عمر تھا کہ مکہ کے لوگ کہتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے عریہ کی اجازت دی ہے تو انہوں نے پوچھا کہ اہل مکہ کو یہ کس طرح معلوم ہوا؟ میں نے کہا کہ وہ لوگ جابر رضی اللہ عنہ سے روایت کرتے ہیں۔ اس پر وہ خاموش ہو گئے۔ سفیان نے کہا کہ میری مراد اس سے یہ تھی کہ جابر رضی اللہ عنہ مدینہ والے ہیں۔ سفیان سے پوچھا گیا کہ کیا ان کی حدیث میں یہ ممانعت نہیں ہے کہ پھلوں کو بیچنے سے آپ صلی اللہ علیہ وسلم نے منع فرمایا جب تک ان کی پختگی نہ کھل جائے انہوں نے کہا کہ نہیں۔' WHERE id = 2111;
UPDATE hadiths SET urdu = 'ابوعبداللہ (امام بخاری رحمہ اللہ) نے کہا کہ مجھ سے ابراہیم نے کہا، انہیں ہشام نے خبر دی، انہوں نے کہا کہ میں نے ابن ابی ملیکہ سے سنا، وہ عبداللہ بن عمر رضی اللہ عنہما کے غلام نافع سے خبر دیتے تھے کہ جو بھی کھجور کا درخت پیوند لگانے کے بعد بیجا جائے اور بیچتے وقت پھلوں کا کوئی ذکر نہ ہوا ہو تو پھل اسی کے ہوں گے جس نے پیوند لگایا ہے۔ غلام اور کھیت کا بھی یہی حال ہے۔ نافع نے ان تینوں چیزوں کا نام لیا تھا۔' WHERE id = 2122;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا، کہا کہ ہم سے عبدالرزاق نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ نے اور انہیں جابر رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے شفعہ کا حق ہر اس مال میں قرار دیا تھا جو تقسیم نہ ہوا ہو، لیکن اس کی حد بندی ہو جائے اور راستے بھی پھیر دیئے جائیں تو اب شفعہ کا حق باقی نہیں رہا۔' WHERE id = 2132;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، ان سے سفیان نے، ان سے عمرو بن دینار نے بیان کیا، کہا کہ مجھے طاؤس نے خبر دی، انہوں نے ابن عباس رضی اللہ عنہما سے سنا، آپ فرماتے تھے کہ عمر رضی اللہ عنہ کو معلوم ہوا کہ فلاں شخص نے شراب فروخت کی ہے، تو آپ نے فرمایا کہ اسے اللہ تعالیٰ تباہ و برباد کر دے۔ کیا اسے معلوم نہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا، اللہ تعالیٰ یہود کو برباد کرے کہ چربی ان پر حرام کی گئی تھی لیکن ان لوگوں نے اسے پگھلا کر فروخت کیا۔' WHERE id = 2143;
UPDATE hadiths SET urdu = 'ہم سے عبدالغفار بن داؤد نے بیان کیا، انہوں نے کہا کہ ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے عمرو بن ابی عمرو نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم خیبر تشریف لائے اور اللہ تعالیٰ نے قلعہ فتح کرا دیا تو آپ صلی اللہ علیہ وسلم کے سامنے صفیہ بنت حیی بن اخطب رضی اللہ عنہا کے حسن کی تعریف کی گئی۔ ان کا شوہر قتل ہو گیا تھا۔ وہ خود ابھی دلہن تھیں۔ پس رسول اللہ صلی اللہ علیہ وسلم نے انہیں اپنے لیے پسند کر لیا۔ پھر روانگی ہوئی۔ جب آپ سد الروحاء پہنچے تو پڑاؤ ہوا۔ اور آپ صلی اللہ علیہ وسلم نے وہیں ان کے ساتھ خلوت کی۔ پھر ایک چھوٹے دستر خوان پر حیس تیار کر کے رکھوایا۔ اور رسول اللہ صلی اللہ علیہ وسلم نے صحابہ سے فرمایا کہ اپنے قریب کے لوگوں کو ولیمہ کی خبر کر دو۔ صفیہ رضی اللہ عنہا کے ساتھ نکاح کا یہی ولیمہ رسول اللہ صلی اللہ علیہ وسلم نے کیا تھا۔ پھر جب ہم مدینہ کی طرف چلے تو میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم نے عباء سے صفیہ رضی اللہ عنہا کے لیے پردہ کرایا۔ اور اپنے اونٹ کو پاس بٹھا کر اپنا ٹخنہ بچھا دیا۔ صفیہ رضی اللہ عنہا اپنا پاؤں آپ صلی اللہ علیہ وسلم کے ٹخنے پر رکھ کر سوار ہو گئیں۔' WHERE id = 2154;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابن ابی نجیح نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو لوگ پھلوں میں دو اور تین سال تک کے لیے بیع سلم کیا کرتے تھے۔ آپ صلی اللہ علیہ وسلم نے انہیں ہدایت کی کہ پھلوں میں بیع سلم مقررہ پیمانے اور مقررہ مدت کے لیے کیا کرو۔ اور عبداللہ بن ولید نے کہا ہم سے سفیان بن عیینہ نے کہا، ان سے ابن ابی نجیح نے بیان کیا، اس روایت میں یوں ہے کہ ”پیمانے اور وزن کی تعیین کے ساتھ“ ( بیع سلم ہونی چاہئیے ) ۔' WHERE id = 2171;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم کو ہشام بن یوسف نے خبر دی، کہا کہ مجھے یعلیٰ بن مسلم اور عمرو بن دینار نے سعید سے خبر دی۔ یہ دونوں حضرات (سعید بن جبیر سے اپنی روایتوں میں) ایک دوسرے سے کچھ زیادہ روایت کرتے ہیں۔ ابن جریج نے کہا میں نے یہ حدیث اوروں سے بھی سنی ہے۔ وہ بھی سعید بن جبیر سے نقل کرتے تھے کہ مجھ سے ابن عباس رضی اللہ عنہما نے کہا، اور ان سے ابی بن کعب رضی اللہ عنہ نے کہا، انہوں نے کہا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے ارشاد فرمایا کہ پھر وہ دونوں ( موسیٰ اور خضر علیہما السلام ) چلے۔ تو انہیں ایک گاؤں میں ایک دیوار ملی جو گرنے ہی والی تھی۔ سعید نے کہا خضر علیہ السلام نے اپنے ہاتھ سے اس طرح اشارہ کیا اور ہاتھ اٹھایا، وہ دیوار سیدھی ہو گئی۔ یعلیٰ نے کہا میرا خیال ہے کہ سعید نے کہا، خضر علیہ السلام نے دیوار کو اپنے ہاتھ سے چھوا، اور وہ سیدھی ہو گئی، تب موسیٰ علیہ السلام بولے کہ اگر آپ چاہتے تو اس کام کی مزدوری لے سکتے تھے۔ سعید نے کہا کہ ( موسیٰ علیہ السلام کی مراد یہ تھی کہ ) کوئی ایسی چیز مزدوری میں ( آپ کو لینی چاہئیے تھی ) جسے ہم کھا سکتے ( کیونکہ بستی والوں نے ان کو کھانا نہیں کھلایا تھا ) ۔' WHERE id = 2183;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے حمید طویل نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ابوطیبہ حجام نے نبی کریم صلی اللہ علیہ وسلم کے پچھنا لگایا، تو آپ صلی اللہ علیہ وسلم نے انہیں اجرت میں ایک صاع یا دو صاع غلہ دینے کا حکم دیا اور ان کے مالکوں سے سفارش کی کہ جو محصول اس پر مقرر ہے اس میں کچھ کمی کر دیں۔' WHERE id = 2193;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا کہ ہم سے یزید بن ابی عبید نے بیان کیا، ان سے سلمہ بن اکوع رضی اللہ عنہ نے کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں موجود تھے کہ ایک جنازہ لایا گیا۔ لوگوں نے آپ صلی اللہ علیہ وسلم سے عرض کیا کہ اس کی نماز پڑھا دیجئیے۔ اس پر آپ صلی اللہ علیہ وسلم نے پوچھا کیا اس پر کوئی قرض ہے؟ لوگوں نے بتایا کہ نہیں کوئی قرض نہیں ہے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ میت نے کچھ مال بھی چھوڑا ہے؟ لوگوں نے عرض کیا کوئی مال بھی نہیں چھوڑا۔ آپ صلی اللہ علیہ وسلم نے ان کی نماز جنازہ پڑھائی۔ اس کے بعد ایک دوسرا جنازہ لایا گیا لوگوں نے عرض کیا یا رسول اللہ! آپ ان کی بھی نماز جنازہ پڑھا دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا، کسی کا قرض بھی میت پر ہے؟ عرض کیا گیا کہ ہے۔ پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، کچھ مال بھی چھوڑا ہے؟ لوگوں نے کہا کہ تین دینار چھوڑے ہیں۔ آپ نے ان کی بھی نماز جنازہ پڑھائی۔ پھر تیسرا جنازہ لایا گیا۔ لوگوں نے آپ کی خدمت میں عرض کیا کہ اس کی نماز پڑھا دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے متعلق بھی وہی دریافت فرمایا، کیا کوئی مال ترکہ چھوڑا ہے؟ لوگوں نے کہا کہ نہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا، اور اس پر کسی کا قرض بھی ہے؟ لوگوں نے کہا کہ ہاں تین دینار ہیں۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ پھر اپنے ساتھی کی تم ہی لوگ نماز پڑھ لو۔ ابوقتادۃ رضی اللہ عنہ بولے، یا رسول اللہ! آپ صلی اللہ علیہ وسلم ان کی نماز پڑھا دیجئیے، ان کا قرض میں ادا کر دوں گا۔ تب آپ صلی اللہ علیہ وسلم نے اس پر نماز پڑھائی۔' WHERE id = 2204;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے ابن ابی نجیح نے بیان کی، ان سے مجاہد نے، ان سے عبدالرحمٰن بن ابی لیلیٰ نے اور ان سے علی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھے حکم دیا تھا کہ ان قربانی کے جانوروں کے جھول اور ان کے چمڑے کو میں خیرات کر دوں جنہیں قربان کیا گیا تھا۔' WHERE id = 2214;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، انہوں نے کہا کہ عمر رضی اللہ عنہ نے صدقہ کے باب میں جو کتاب لکھوائی تھی اس میں یوں ہے کہ صدقے کا متولی اس میں سے کھا سکتا ہے اور دوست کو کھلا سکتا ہے لیکن روپیہ نہ جمع کرے اور عبداللہ بن عمر رضی اللہ عنہما اپنے والد عمر رضی اللہ عنہ کے صدقے کے متولی تھے۔ وہ مکہ والوں کو اس میں سے تحفہ بھیجتے تھے جہاں آپ قیام فرمایا کرتے تھے۔' WHERE id = 2226;
UPDATE hadiths SET urdu = 'ہم سے حکم بن نافع نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ انصار نے نبی کریم صلی اللہ علیہ وسلم سے کہا کہ ہمارے باغات آپ ہم میں اور ہمارے ( مہاجر ) بھائیوں میں تقسیم فرما دیں۔ آپ صلی اللہ علیہ وسلم نے انکار کیا تو انصار نے ( مہاجرین سے ) کہا کہ آپ لوگ درختوں میں محنت کرو۔ ہم تم میوے میں شریک رہیں گے۔ انہوں نے کہا اچھا ہم نے سنا اور قبول کیا۔' WHERE id = 2237;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، ان سے لیث بن سعد نے بیان کیا، ان سے عبیداللہ بن ابی جعفر نے بیان کیا، ان سے محمد بن عبدالرحمٰن نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جس نے کوئی ایسی زمین آباد کی، جس پر کسی کا حق نہیں تھا تو اس زمین کا وہی حقدار ہے۔ عروہ نے بیان کیا کہ عمر رضی اللہ عنہ نے اپنے عہد خلافت میں یہی فیصلہ کیا تھا۔' WHERE id = 2247;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا کہ ہم سے ابوغسان نے بیان کیا، کہا کہ مجھ سے ابوحازم نے بیان کیا اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں دودھ اور پانی کا ایک پیالہ پیش کیا گیا۔ آپ صلی اللہ علیہ وسلم نے اس کو پیا۔ آپ صلی اللہ علیہ وسلم کی دائیں طرف ایک نوعمر لڑکا بیٹھا ہوا تھا۔ اور کچھ بڑے بوڑھے لوگ بائیں طرف بیٹھے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا لڑکے! کیا تو اجازت دے گا کہ میں پہلے یہ پیالہ بڑوں کو دے دوں۔ اس پر اس نے کہا، یا رسول اللہ! میں تو آپ کے جھوٹے میں سے اپنے حصہ کو اپنے سوا کسی کو نہیں دے سکتا۔ چنانچہ آپ صلی اللہ علیہ وسلم نے وہ پیالہ پہلے اسی کو دے دیا۔' WHERE id = 2260;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے نافع نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، ایک عورت کو عذاب، ایک بلی کی وجہ سے ہوا جسے اس نے اتنی دیر تک باندھے رکھا تھا کہ وہ بھوک کی وجہ سے مر گئی۔ اور وہ عورت اسی وجہ سے دوزخ میں داخل ہوئی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے اس سے فرمایا تھا اور اللہ تعالیٰ ہی زیادہ جاننے والا ہے کہ جب تو نے اس بلی کو باندھے رکھا اس وقت تک نہ تو نے اسے کھلایا نہ پلایا اور نہ چھوڑا کہ وہ زمین کے کیڑے مکوڑے ہی کھا کر اپنا پیٹ بھر لیتی۔' WHERE id = 2272;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے ابن شہاب نے خبر دی، انہیں زید العابدین علی بن حسین بن علی رضی اللہ عنہما نے، ان سے ان کے والد حسین بن علی رضی اللہ عنہما نے کہ علی بن ابی طالب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ بدر کی لڑائی کے موقع پر مجھے ایک جوان اونٹنی غنیمت میں ملی تھی اور ایک دوسری اونٹنی مجھے رسول اللہ صلی اللہ علیہ وسلم نے عنایت فرمائی تھی۔ ایک دن ایک انصاری صحابی کے دروازے پر میں ان دونوں کو اس خیال سے باندھے ہوئے تھا کہ ان کی پیٹھ پر اذخر ( عرب کی ایک خوشبودار گھاس جسے سنار وغیرہ استعمال کرتے تھے ) رکھ کر بیچنے لے جاؤں گا۔ بنی قینقاع کا ایک سنار بھی میرے ساتھ تھا۔ اس طرح ( خیال یہ تھا کہ ) اس کی آمدنی سے فاطمہ رضی اللہ عنہا ( جن سے میں نکاح کرنے والا تھا ان ) کا ولیمہ کروں گا۔ حمزہ بن عبدالمطلب رضی اللہ عنہ اسی ( انصاری کے ) گھر میں شراب پی رہے تھے۔ ان کے ساتھ ایک گانے والی بھی تھی۔ اس نے جب یہ مصرعہ پڑھا: ”ہاں: اے حمزہ! اٹھو، فربہ جوان اونٹنیوں کی طرف“ ( بڑھ ) حمزہ رضی اللہ عنہ جوش میں تلوار لے کر اٹھے اور دونوں اونٹنیوں کے کوہان چیر دیئے۔ ان کے پیٹ پھاڑ ڈالے۔ اور ان کی کلیجی نکال لی ( ابن جریج نے بیان کیا کہ ) میں نے ابن شہاب سے پوچھا، کیا کوہان کا گوشت بھی کاٹ لیا تھا۔ تو انہوں نے بیان کیا کہ ان دونوں کے کوہان کاٹ لیے اور انہیں لے گئے۔ ابن شہاب نے بیان کیا کہ علی رضی اللہ عنہ نے فرمایا، مجھے یہ دیکھ کر بڑی تکلیف ہوئی۔ پھر میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آپ کی خدمت میں اس وقت زید بن حارثہ رضی اللہ عنہ بھی موجود تھے۔ میں نے آپ کو اس واقعہ کی اطلاع دی تو آپ تشریف لائے۔ زید رضی اللہ عنہ بھی آپ کے ساتھ ہی تھے اور میں بھی آپ کے ساتھ تھا۔ نبی کریم صلی اللہ علیہ وسلم جب حمزہ رضی اللہ عنہ کے پاس پہنچے اور آپ صلی اللہ علیہ وسلم نے خفگی ظاہر فرمائی تو حمزہ نے نظر اٹھا کر کہا ”تم سب میرے باپ دادا کے غلام ہو۔“ نبی کریم صلی اللہ علیہ وسلم الٹے پاؤں لوٹ کر ان کے پاس سے چلے آئے۔ یہ شراب کی حرمت سے پہلے کا قصہ ہے۔' WHERE id = 2282;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، ان سے سلیمان بن بلال نے بیان کیا، ان سے ثور بن زید نے، ان سے ابوغیث نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جو کوئی لوگوں کا مال قرض کے طور پر ادا کرنے کی نیت سے لیتا ہے تو اللہ تعالیٰ بھی اس کی طرف سے ادا کرے گا اور جو کوئی نہ دینے کے لیے لے، تو اللہ تعالیٰ بھی اس کو تباہ کر دے گا۔' WHERE id = 2293;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے خبر دی، وہ زہری سے روایت کرتے ہیں (دوسری سند) ہم سے اسماعیل نے بیان کیا، کہا کہ مجھ سے میرے بھائی عبدالحمید نے بیان کیا، ان سے سلیمان نے، ان سے محمد بن ابی عتیق نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عروہ نے بیان کیا، اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نماز میں دعا کرتے تو یہ بھی کہتے ”اے اللہ! میں گناہ اور قرض سے تیری پناہ مانگتا ہوں۔“ کسی نے عرض کیا یا رسول اللہ! آپ قرض سے اتنی پناہ مانگتے ہیں؟ آپ صلی اللہ علیہ وسلم نے جواب دیا کہ جب آدمی مقروض ہوتا ہے تو جھوٹ بولتا ہے اور وعدہ کر کے اس کی خلاف ورزی کرتا ہے۔' WHERE id = 2303;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا انہیں سالم بن عبداللہ نے خبر دی اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ فرماتے سنا، تم میں سے ہر فرد ایک طرح کا حاکم ہے اور اس کی رعیت کے بارے میں اس سے سوال ہو گا۔ پس بادشاہ حاکم ہی ہے اور اس کی رعیت کے بارے میں اس سے سوال ہو گا۔ ہر انسان اپنے گھر کا حاکم ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ عورت اپنے شوہر کے گھر کی حاکم ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ خادم اپنے آقا کے مال کا حاکم ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ انہوں نے بیان کیا کہ یہ سب میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا۔ اور میں سمجھتا ہوں کہ نبی کریم صلی اللہ علیہ وسلم نے یہ بھی فرمایا تھا کہ مرد اپنے والد کے مال کا حاکم ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ پس ہر شخص حاکم ہے اور ہر شخص سے اس کی رعیت کے بارے میں سوال ہو گا۔' WHERE id = 2314;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ زمعہ کی ایک باندی کے لڑے کے بارے میں عبد بن زمعہ رضی اللہ عنہ اور سعد بن ابی وقاص رضی اللہ عنہ اپنا جھگڑا رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں لے کر گئے۔ سعد رضی اللہ عنہ نے کہا: یا رسول اللہ! میرے بھائی نے مجھ کو وصیت کی تھی کہ جب میں ( مکہ ) آؤں اور زمعہ کی باندی کے لڑکے کو دیکھوں تو اسے اپنی پرورش میں لے لوں۔ کیونکہ وہ انہیں کا لڑکا ہے۔ اور عبد بن زمعہ نے کہا کہ وہ میرا بھائی ہے اور میرے باپ کی باندی کا لڑکا ہے۔ میرے والد ہی کے ”فراش“ میں اس کی پیدائش ہوئی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے بچے کے اندر ( عتبہ کی ) واضح مشابہت دیکھی۔ لیکن فرمایا کہ اے عبد بن زمعہ! لڑکا تو تمہاری ہی پرورش میں رہے گا کیونکہ لڑکا ”فراش“ کے تابع ہوتا ہے اور سودہ تو اس لڑکے سے پردہ کیا کر۔' WHERE id = 2325;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے منصور بن معتمر نے، ان سے طلحہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی راستے میں ایک کھجور پر نظر پڑی۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر اس کا ڈر نہ ہوتا کہ صدقہ کی ہے تو میں خود اسے کھا لیتا۔' WHERE id = 2335;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا کہ ہم سے ہمام نے بیان کیا، کہا کہ مجھے قتادہ نے خبر دی، ان سے صفوان بن محرزمازنی نے بیان کیا کہ میں عبداللہ بن عمر رضی اللہ عنہما کے ہاتھ میں ہاتھ دیئے جا رہا تھا۔ کہ ایک شخص سامنے آیا اور پوچھا رسول اللہ صلی اللہ علیہ وسلم سے آپ نے ( قیامت میں اللہ اور بندے کے درمیان ہونے والی ) سرگوشی کے بارے میں کیا سنا ہے؟ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا۔ آپ صلی اللہ علیہ وسلم فرماتے تھے کہ اللہ تعالیٰ مومن کو اپنے نزدیک بلا لے گا اور اس پر اپنا پردہ ڈال دے گا اور اسے چھپا لے گا۔ اللہ تعالیٰ اس سے فرمائے گا کیا تجھ کو فلاں گناہ یاد ہے؟ کیا فلاں گناہ تجھ کو یاد ہے؟ وہ مومن کہے گا ہاں، اے میرے پروردگار۔ آخر جب وہ اپنے گناہوں کا اقرار کر لے گا اور اسے یقین آ جائے گا کہ اب وہ ہلاک ہوا تو اللہ تعالیٰ فرمائے گا کہ میں نے دنیا میں تیرے گناہوں پر پردہ ڈالا۔ اور آج بھی میں تیری مغفرت کرتا ہوں، چنانچہ اسے اس کی نیکیوں کی کتاب دے دی جائے گی، لیکن کافر اور منافق کے متعلق ان پر گواہ ( ملائکہ، انبیاء، اور تمام جن و انس سب ) کہیں گے کہ یہی وہ لوگ ہیں جنہوں نے اپنے پروردگار پر جھوٹ باندھا تھا۔ خبردار ہو جاؤ! ظالموں پر اللہ کی پھٹکار ہو گی۔' WHERE id = 2346;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابوحازم بن دینار نے اور انہیں سہل بن سعد ساعدی رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں دودھ یا پانی پینے کو پیش کیا گیا۔ آپ صلی اللہ علیہ وسلم نے اسے پیا۔ آپ صلی اللہ علیہ وسلم کے دائیں طرف ایک لڑکا تھا اور بائیں طرف بڑی عمر والے تھے۔ لڑکے سے آپ صلی اللہ علیہ وسلم نے فرمایا کیا تم مجھے اس کی اجازت دو گے کہ ان لوگوں کو یہ ( پیالہ ) دے دوں؟ لڑکے نے کہا، نہیں اللہ کی قسم! یا رسول اللہ! آپ کی طرف سے ملنے والے حصے کا ایثار میں کسی پر نہیں کر سکتا۔ راوی نے بیان کیا کہ آخر رسول اللہ صلی اللہ علیہ وسلم نے وہ پیالہ اسی لڑکے کو دے دیا۔' WHERE id = 2356;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا کہ مجھ سے یزید نے بیان کیا، ان سے ابوالخیر نے اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ ہم نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا آپ ہمیں مختلف ملک والوں کے پاس بھیجتے ہیں اور ( بعض دفعہ ) ہمیں ایسے لوگوں کے پاس جانا پڑتا ہے کہ وہ ہماری ضیافت تک نہیں کرتے۔ آپ کی ایسے مواقع پر کیا ہدایت ہے؟ آپ صلی اللہ علیہ وسلم نے ہم سے فرمایا، اگر تمہارا قیام کسی قبیلے میں ہو اور تم سے ایسا برتاؤ کیا جائے جو کسی مہمان کے لیے مناسب ہے تو تم اسے قبول کر لو، لیکن اگر وہ نہ کریں تو تم خود مہمانی کا حق ان سے وصول کر لو۔' WHERE id = 2366;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے، ان سے منصور نے، ان سے ابووائل نے اور ان سے حذیفہ رضی اللہ عنہ نے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا، یا یہ کہا کہ نبی کریم صلی اللہ علیہ وسلم ایک قوم کی کوڑی پر تشریف لائے، اور آپ صلی اللہ علیہ وسلم نے وہاں کھڑے ہو کر پیشاب کیا۔' WHERE id = 2376;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم ازواج مطہرات میں سے کسی ایک کے یہاں تشریف رکھتے تھے۔ امہات المؤمنین میں سے ایک نے وہیں آپ صلی اللہ علیہ وسلم کے لیے خادم کے ہاتھ ایک پیالے میں کچھ کھانے کی چیز بھجوائی۔ انہوں نے ایک ہاتھ اس پیالے پر مارا، اور پیالہ ( گر کر ) ٹوٹ گیا۔ آپ صلی اللہ علیہ وسلم نے پیالے کو جوڑا اور جو کھانے کی چیز تھی اس میں دوبارہ رکھ کر صحابہ سے فرمایا کہ کھاؤ۔ آپ صلی اللہ علیہ وسلم نے پیالہ لانے والے ( خادم ) کو روک لیا اور پیالہ بھی نہیں بھیجا۔ بلکہ جب ( کھانے سے ) سب فارغ ہو گئے تو دوسرا اچھا پیالہ بھجوا دیا اور جو ٹوٹ گیا تھا اسے نہیں بھجوایا۔ ابن ابی مریم نے بیان کیا کہ ہمیں یحییٰ بن ایوب نے خبر دی، ان سے حمید نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 2386;
UPDATE hadiths SET urdu = 'ہم سے عمران بن میسرہ ابوالحسن بصری نے بیان کیا، کہا کہ ہم سے عبدالوارث بن سعید نے بیان کیا، کہا ہم سے ایوب سختیانی نے، کہا ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جو شخص مشترک ( ساجھے ) کے غلام میں اپنا حصہ آزاد کر دے اور اس کے پاس سارے غلام کی قیمت کے موافق مال ہو تو وہ پورا آزاد ہو جائے گا۔ اگر اتنا مال نہ ہو تو بس جتنا حصہ اس کا تھا اتنا ہی آزاد ہوا۔ ایوب نے کہا کہ یہ مجھے معلوم نہیں کہ روایت کا یہ آخری حصہ ”غلام کا وہی حصہ آزاد ہو گا جو اس نے آزاد کیا ہے“ یہ نافع کا اپنا قول ہے یا نبی کریم صلی اللہ علیہ وسلم کی حدیث میں داخل ہے۔' WHERE id = 2396;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا کہ ہم کو وکیع نے خبر دی، انہیں سفیان ثوری نے، انہیں ان کے والد سعید بن مسروق نے، انہیں عبایہ بن رفاعہ نے اور ان سے ان کے دادا رافع بن خدیج رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ تہامہ کے مقام ذوالحلیفہ میں تھے ( غنیمت میں ) ہمیں بکریاں اور اونٹ ملے تھے۔ بعض لوگوں نے جلدی کی اور ( جانور ذبح کر کے ) گوشت کو ہانڈیوں میں چڑھا دیا۔ پھر رسول اللہ صلی اللہ علیہ وسلم تشریف لائے۔ آپ صلی اللہ علیہ وسلم کے حکم سے گوشت کی ہانڈیوں کو الٹ دیا گیا۔ پھر ( آپ صلی اللہ علیہ وسلم نے تقسیم میں ) دس بکریوں کا ایک اونٹ کے برابر حصہ رکھا۔ ایک اونٹ بھاگ کھڑا ہوا۔ قوم کے پاس گھوڑوں کی کمی تھی۔ ایک شخص نے اونٹ کو تیر مار کر روک لیا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ان جانوروں میں بھی جنگی جانوروں کی طرح وحشت ہوتی ہے۔ اس لیے جب تک ان کو نہ پکڑ سکو تو تم ان کے ساتھ ہی ایسا سلوک کیا کرو۔ عبایہ نے بیان کیا کہ میرے دادا نے عرض کیا، یا رسول اللہ! ہمیں امید ہے یا خطرہ ہے کہ کہیں کل دشمن سے مڈبھیڑ نہ ہو جائے اور چھری ہمارے ساتھ نہیں ہے۔ کیا دھار دار لکڑی سے ہم ذبح کر سکتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا، لیکن ذبح کرنے میں جلدی کرو۔ جو چیز خون بہا دے ( اسی سے کاٹ ڈالو ) اگر اس پر اللہ کا نام لیا جائے تو اس کو کھاؤ اور ناخن اور دانت سے ذبح نہ کرو۔ اس کی وجہ میں بتلاتا ہوں دانت تو ہڈی ہے اور ناخن حبشیوں کی چھریاں ہیں۔' WHERE id = 2409;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن مسعود نے بیان کیا، انہوں نے کہا کہ ہم سے زائدۃ بن قدامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے فاطمہ بن منذر نے اور ان سے اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے سورج گرہن کے وقت غلام آزاد کرنے کا حکم فرمایا ہے۔ موسیٰ کے ساتھ اس حدیث کو علی بن مدینی نے بھی عبدالعزیز دراوردی سے روایت کیا ہے۔ انہوں نے ہشام سے۔' WHERE id = 2420;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے محمد بن ابراہیم تیمی نے، ان سے علقمہ بن وقاص لیثی نے، کہا کہ میں نے عمر بن خطاب رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اعمال کا مدار نیت پر ہے اور ہر شخص کو اس کی نیت کے مطابق پھل ملتا ہے۔ پس جس کی ہجرت اللہ اور اس کے رسول کے لیے ہو، وہ اللہ اور اس کے رسول کے لیے سمجھی جائے گی اور جس کی ہجرت دنیا کے لیے ہو گی یا کسی عورت سے شادی کرنے کے لیے تو یہ ہجرت محض اسی کے لیے ہو گی جس کی نیت سے اس نے ہجرت کی ہے۔“' WHERE id = 2430;
UPDATE hadiths SET urdu = 'ہم سے علی بن حسن نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو ابن عون نے خبر دی، انہوں نے بیان کیا کہ میں نے نافع رحمہ اللہ کو لکھا تو انہوں نے مجھے جواب دیا کہ نبی کریم صلی اللہ علیہ وسلم نے بنو مصطلق پر جب حملہ کیا تو وہ بالکل غافل تھے اور ان کے مویشی پانی پی رہے تھے۔ ان کے لڑنے والوں کو قتل کیا گیا، عورتوں بچوں کو قید کر لیا گیا۔ انہیں قیدیوں میں جویریہ رضی اللہ عنہا ( ام المؤمنین ) بھی تھیں۔ ( نافع رحمہ اللہ نے لکھا تھا کہ ) یہ حدیث مجھ سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کی تھی، وہ خود بھی اسلامی فوج کے ہمراہ تھے۔' WHERE id = 2441;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، انہوں نے برید بن عبداللہ سے، وہ ابوبردہ سے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”غلام جو اپنے رب کی عبادت احسن طریق کے ساتھ بجا لائے اور اپنے آقا کے جو اس پر خیر خواہی اور فرماں برداری ( کے حقوق ہیں ) انہیں بھی ادا کرتا رہے، تو اسے دوگنا ثواب ملتا ہے۔“' WHERE id = 2451;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا ہشام بن عروہ سے، وہ اپنے والد سے، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ بریرہ رضی اللہ عنہا آئیں اور کہا کہ میں نے اپنے مالکوں سے نو اوقیہ چاندی پر مکاتبت کا معاملہ کیا ہے۔ ہر سال ایک اوقیہ مجھے ادا کرنا پڑے گا۔ آپ بھی میری مدد کریں۔ اس پر عائشہ رضی اللہ عنہا نے کہا کہ اگر تمہارے مالک پسند کریں تو میں انہیں ( یہ ساری رقم ) ایک ہی مرتبہ دے دوں اور پھر تمہیں آزاد کر دوں، تو میں ایسا کر سکتی ہوں۔ لیکن تمہاری ولاء میرے ساتھ ہو جائے گی۔ بریرہ رضی اللہ عنہا اپنے مالکوں کے پاس گئیں تو انہوں نے اس صورت سے انکار کیا ( واپس آ کر ) انہوں نے بتایا کہ میں نے آپ کی یہ صورت ان کے سامنے رکھی تھی لیکن وہ اسے صرف اس صورت میں قبول کرنے کو تیار ہیں کہ ولاء ان کے ساتھ قائم رہے۔ رسول اللہ صلی اللہ علیہ وسلم نے یہ سنا تو آپ صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا۔ میں نے آپ صلی اللہ علیہ وسلم کو مطلع کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو انہیں لے کر آزاد کر دے اور انہیں ولاء کی شرط لگانے دے۔ ولاء تو بہرحال اسی کی ہوتی ہے جو آزاد کرے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم نے لوگوں کو خطاب کیا۔ اللہ کی حمد و ثناء کے بعد فرمایا، تم میں سے کچھ لوگوں کو یہ کیا ہو گیا ہے کہ ( معاملات میں ) ایسی شرطیں لگاتے ہیں جن کی کوئی اصل ( دلیل، بنیاد ) کتاب اللہ میں نہیں ہے۔ پس جو بھی شرط ایسی ہو جس کی اصل ( دلیل، بنیاد ) کتاب اللہ میں نہ ہو وہ باطل ہے۔ خواہ ایسی سو شرطیں کیوں نہ لگالی جائیں۔ اللہ کا فیصلہ ہی حق ہے اور اللہ کی شرط ہی مضبوط ہے کچھ لوگوں کو کیا ہو گیا ہے کہ وہ کہتے ہیں، اے فلاں! آزاد تم کرو اور ولاء میرے ساتھ قائم رہے گی۔ ولاء تو صرف اسی کے ساتھ قائم ہو گی جو آزاد کرے۔' WHERE id = 2462;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا ابن شہاب سے، وہ عبیداللہ بن عبداللہ بن عتبہ بن مسعود سے، وہ عبداللہ بن عباس رضی اللہ عنہما سے اور اور وہ صعب بن جثامہ رضی اللہ عنہ سے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں گورخر کا تحفہ پیش کیا تھا۔ آپ صلی اللہ علیہ وسلم اس وقت مقام ابواء یا مقام ودان میں تھے ( راوی کو شبہ ہے ) آپ صلی اللہ علیہ وسلم نے ان کا تحفہ واپس کر دیا۔ پھر ان کے چہرے پر ( رنج کے آثار ) دیکھ کر فرمایا کہ میں نے یہ تحفہ صرف اس لیے واپس کیا ہے کہ ہم احرام باندھے ہوئے ہیں۔' WHERE id = 2472;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے عیسیٰ بن یونس نے بیان کیا، کہا ہم سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ہم سے مسدد نے بیان کیا، کہا ہم سے عیسیٰ بن یونس نے بیان کیا، کہا ہم سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ' WHERE id = 2483;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ابوعمران جونی سے، ان سے بنو تیم بن مرہ کے ایک صاحب طلحہ بن عبداللہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا، یا رسول اللہ! میری دو پڑوسی ہیں، تو مجھے کس کے گھر ہدیہ بھیجنا چاہئے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”جس کا دروازہ تم سے قریب ہو۔“' WHERE id = 2493;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے امام مالک نے ابوحازم سے، وہ سہل بن سعد رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں کچھ پینے کو لایا گیا۔ آپ صلی اللہ علیہ وسلم کی دائیں طرف ایک بچہ تھا اور قوم کے بڑے لوگ بائیں طرف تھے۔ آپ صلی اللہ علیہ وسلم نے بچے سے فرمایا کہ کیا تمہاری طرف سے اس کی اجازت ہے کہ میں بچا ہوا پانی ان بزرگوں کو دے دوں؟ تو اس بچے نے کہا کہ نہیں قسم اللہ کی! میں آپ سے ملنے والے اپنے حصہ کا ہرگز ایثار نہیں کر سکتا۔ پھر آپ صلی اللہ علیہ وسلم نے مشروب ان کی طرف جھٹکے کے ساتھ بڑھا دیا۔' WHERE id = 2503;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے معتمر بن سلیمان نے بیان کیا، ان سے ان کے باپ نے بیان کیا، ان سے ابوعثمان نے بیان کیا اور ان سے عبدالرحمٰن بن ابی بکر رضی اللہ عنہما نے بیان کیا کہ ہم ایک سو تیس آدمی رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ( ایک سفر میں ) تھے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کیا کسی کے ساتھ کھانے کی بھی کوئی چیز ہے؟ ایک صحابی کے ساتھ تقریباً ایک صاع کھانا ( آٹا ) تھا۔ وہ آٹا گوندھا گیا۔ پھر ایک لمبا تڑنگا مشرک پریشان حال بکریاں ہانکتا ہوا آیا۔ تو نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا یہ بیچنے کے لیے ہیں۔ یا کسی کا عطیہ ہے یا آپ نے ( عطیہ کی بجائے ) ہبہ فرمایا۔ اس نے کہا کہ نہیں بیچنے کے لیے ہیں۔ آپ صلی اللہ علیہ وسلم نے اس سے ایک بکری خریدی پھر وہ ذبح کی گئی۔ پھر نبی کریم صلی اللہ علیہ وسلم نے اس کی کلیجی بھوننے کے لیے کہا۔ قسم اللہ کی ایک سو تیس اصحاب میں سے ہر ایک کو اس کلیجی میں سے کاٹ کے دیا۔ جو موجود تھے انہیں تو آپ صلی اللہ علیہ وسلم نے فوراً ہی دے دیا اور جو اس وقت موجود نہیں تھے ان کا حصہ محفوظ رکھ لیا۔ پھر بکری کے گوشت کو دو بڑی قابوں میں رکھا گیا اور سب نے خوب سیر ہو کر کھایا۔ جو کچھ قابوں میں بچ گیا تھا اسے اونٹ پر رکھ کر ہم واپس لائے۔ او کما قال۔' WHERE id = 2514;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عبدالواحد بن ایمن نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا، انہوں نے کہا کہ میں عائشہ رضی اللہ عنہا کی خدمت میں حاضر ہوا تو آپ قطر ( یمن کا ایک دبیز کھردرا کپڑا ) کی قمیص قیمتی پانچ درہم کی پہنے ہوئے تھیں۔ آپ نے ( مجھ سے ) فرمایا۔ ذرا نظر اٹھا کر میری اس لونڈی کو تو دیکھ۔ اسے گھر میں بھی یہ کپڑے پہننے سے انکار ہے۔ حالانکہ رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں میرے پاس اسی کی ایک قمیص تھی۔ جب کوئی لڑکی دلہن بنائی جاتی تو میرے یہاں آدمی بھیج کر وہ قمیص عاریتاً منگا لیتی تھی۔' WHERE id = 2524;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی زہری سے کہ سالم نے بیان کیا، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، آپ کہتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم ابی بن کعب انصاری رضی اللہ عنہ کو ساتھ لے کر کھجور کے اس باغ کی طرف تشریف لے گئے جس میں ابن صیاد تھا۔ جب رسول اللہ صلی اللہ علیہ وسلم باغ میں داخل ہوئے تو آپ صلی اللہ علیہ وسلم درختوں کی آڑ میں چھپ کر چلنے لگے۔ آپ صلی اللہ علیہ وسلم چاہتے تھے کہ ابن صیاد آپ کو دیکھنے نہ پائے اور اس سے پہلے آپ اس کی باتیں سن سکیں۔ ابن صیاد ایک روئیں دار چادر میں زمین پر لیٹا ہوا تھا اور کچھ گنگنا رہا تھا۔ ابن صیاد کی ماں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھ لیا کہ آپ صلی اللہ علیہ وسلم درخت کی آڑ لیے چلے آ رہے ہیں تو وہ کہنے لگی اے صاف! یہ محمد ( صلی اللہ علیہ وسلم ) آ رہے ہیں۔ ابن صیاد ہوشیار ہو گیا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر اسے اپنے حال پر رہنے دیتی تو بات ظاہر ہو جاتی۔“' WHERE id = 2534;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا مجھ سے عبداللہ بن وہب نے بیان کیا اور ان سے یونس نے اور لیث نے بیان کیا کہ مجھ سے یونس نے بیان کیا اور ان سے ابن شہاب نے، انہیں عروہ بن زبیر نے خبر دی کہ ایک عورت نے فتح مکہ پر چوری کر لی تھی۔ پھر اسے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر کیا گیا اور آپ صلی اللہ علیہ وسلم کے حکم کے مطابق اس کا ہاتھ کاٹ دیا گیا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر انہوں نے اچھی طرح توبہ کر لی اور شادی کر لی۔ اس کے بعد وہ آتی تھیں تو میں ان کی ضرورت رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں پیش کر دیا کرتی تھی۔' WHERE id = 2544;
UPDATE hadiths SET urdu = 'ہم سے ابن ابی مریم نے بیان کیا، انہوں نے کہا ہم کو محمد بن جعفر نے خبر دی، انہوں نے کہا کہ مجھے زید نے خبر دی، انہیں عیاض بن عبداللہ نے اور انہیں ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کیا عورت کی گواہی مرد کی گواہی کے آدھے کے برابر نہیں ہے؟“ ہم نے عرض کیا کیوں نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”یہی تو ان کی عقل کا نقصان ہے۔“' WHERE id = 2554;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا منصور سے، ان سے ابووائل نے بیان کیا کہ عبداللہ رضی اللہ عنہ نے کہا کہ جو شخص ( جھوٹی ) قسم کسی کا مال حاصل کرنے کے لیے کھائے گا تو اللہ تعالیٰ سے وہ اس حال میں ملے گا کہ اللہ پاک اس پر غضبناک ہو گا۔ اس کے بعد اللہ تعالیٰ نے ( اس حدیث کی ) تصدیق کے لیے یہ آیت نازل فرمائی «إن الذين يشترون بعهد الله وأيمانهم‏» ”جو لوگ اللہ کے عہد اور اپنی قسموں سے تھوڑی پونجی خریدتے ہیں۔ «عذاب أليم‏» “ تک۔ پھر اشعث بن قیس رضی اللہ عنہ ہماری طرف تشریف لائے اور پوچھنے لگے کہ ابوعبدالرحمٰن ( عبداللہ بن مسعود رضی اللہ عنہ ) تم سے کون سی حدیث بیان کر رہے تھے۔ ہم نے ان کی یہی حدیث بیان کی تو انہوں نے کہا کہ انہوں نے صحیح بیان کی، یہ آیت میرے ہی بارے میں نازل ہوئی تھی۔ میرا ایک شخص سے جھگڑا تھا۔ ہم اپنا مقدمہ رسول اللہ صلی اللہ علیہ وسلم کے پاس لے گئے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یا تم دو گواہ لاؤ، ورنہ اس کی قسم پر فیصلہ ہو گا۔ میں نے کہا کہ ( گواہ میرے پاس نہیں ہیں لیکن اگر فیصلہ اس کی قسم پر ہوا ) پھر تو یہ ضرور ہی قسم کھا لے گا اور کوئی پروانہ کرے گا۔ نبی کریم صلی اللہ علیہ وسلم نے یہ سن کر فرمایا ”جو شخص بھی کسی کا مال لینے کے لیے ( جھوٹی ) قسم کھائے تو اللہ تعالیٰ سے وہ اس حال میں ملے گا کہ وہ اس پر غضبناک ہو گا۔“ اس کی تصدیق میں اللہ تعالیٰ نے مذکورہ بالا آیت نازل فرمائی تھی، پھر انہوں نے یہی آیت تلاوت کی۔' WHERE id = 2564;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے ابوسہیل، نافع بن مالک بن ابی عامر نے بیان کیا، ان سے ان کے باپ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”منافق کی تین نشانیاں ہیں۔ جب بات کہی تو جھوٹ کہی، امانت دی گئی تو اس نے اس میں خیانت کی اور وعدہ کیا تو اسے پورا نہیں کیا۔“' WHERE id = 2575;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا صالح بن کیسان سے، ان سے ابن شہاب نے، انہیں حمید بن عبدالرحمٰن نے خبر دی کہ ان کی والدہ ام کلثوم بنت عقبہ نے انہیں خبر دی اور انہوں نے نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے سنا تھا کہ جھوٹا وہ نہیں ہے جو لوگوں میں باہم صلح کرانے کی کوشش کرے اور اس کے لیے کسی اچھی بات کی چغلی کھائے یا اسی سلسلہ کی اور کوئی اچھی بات کہہ دے۔' WHERE id = 2585;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ انصاری نے بیان کیا، کہا مجھ سے حمید نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نضر کی بیٹی ربیع رضی اللہ عنہا نے ایک لڑکی کے دانت توڑ دئیے۔ اس پر لڑکی والوں نے تاوان مانگا اور ان لوگوں نے معافی چاہی، لیکن معاف کرنے سے انہوں نے انکار کیا۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو آپ صلی اللہ علیہ وسلم نے بدلہ لینے کا حکم دیا۔ ( یعنی ان کا بھی دانت توڑ دیا جائے ) انس بن نضر رضی اللہ عنہ نے عرض کیا، یا رسول اللہ! ربیع کا دانت کس طرح توڑا جا سکے گا۔ نہیں اس ذات کی قسم جس نے آپ کو حق کے ساتھ مبعوث فرمایا ہے، اس کا دانت نہیں توڑا جائے گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا انس! کتاب اللہ کا فیصلہ تو بدلہ لینے ( قصاص ) ہی کا ہے۔ چنانچہ یہ لوگ راضی ہو گئے اور معاف کر دیا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے کچھ بندے ایسے بھی ہیں کہ اگر وہ اللہ کی قسم کھا لیں تو اللہ تعالیٰ خود ان کی قسم پوری کرتا ہے۔ فزاری نے ( اپنی روایت میں ) حمید سے، اور انہوں نے انس رضی اللہ عنہ سے یہ زیادتی نقل کی ہے کہ وہ لوگ راضی ہو گئے اور تاوان لے لیا۔' WHERE id = 2595;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے بیان کیا، انہوں نے کہا ہم سے اسماعیل نے بیان کیا، ان سے قیس بن ابی حازم نے اور ان سے جریر بن عبداللہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے میں نے نماز قائم کرنے، زکوٰۃ ادا کرنے اور ہر مسلمان کے ساتھ خیر خواہی کرنے کی شرطوں کے ساتھ بیعت کی تھی۔' WHERE id = 2606;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے، ان سے عدی بن ثابت نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( تجارتی قافلوں کی ) پیشوائی سے منع فرمایا تھا اور اس سے بھی کہ کوئی شہری کسی دیہاتی کا سامان تجارت بیچے اور اس سے بھی کہ کوئی عورت اپنی ( دینی یا نسبی ) بہن کے طلاق کی شرط لگائے اور اس سے کہ کوئی اپنے کسی بھائی کے بھاؤ پر بھاؤ لگائے، اسی طرح آپ صلی اللہ علیہ وسلم نے نجش اور تصریہ سے بھی منع فرمایا۔ محمد بن عرعرہ کے ساتھ اس حدیث کو معاذ بن معاذ اور عبدالصمد بن عبدالوارث نے بھی شعبہ سے روایت کیا ہے اور غندر اور عبدالرحمٰن بن مہدی نے یوں کہا کہ ممانعت کی گئی تھی ( مجہول کے صیغے کے ساتھ ) آدم بن ابی ایاس نے یوں کہا کہ ہمیں منع کیا گیا تھا نضر اور حجاج بن منہال نے یوں کہا کہ منع کیا تھا ( رسول اللہ صلی اللہ علیہ وسلم نے ) ۔' WHERE id = 2617;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم کو امام مالک نے خبر دی نافع سے ‘ وہ عبداللہ بن عمر رضی اللہ عنہما سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کسی مسلمان کے لیے جن کے پاس وصیت کے قابل کوئی بھی مال ہو درست نہیں کہ دو رات بھی وصیت کو لکھ کر اپنے پاس محفوظ رکھے بغیر گزارے۔“ امام مالک کے ساتھ اس روایت کی متابعت محمد بن مسلم نے عمرو بن دینار سے کی ہے ‘ انہوں نے ابن عمر رضی اللہ عنہما سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کی ہے۔' WHERE id = 2627;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا ‘ کہا ہم سے ابواسامہ نے بیان کیا سفیان ثوری سے ‘ وہ عمارہ سے ‘ ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ایک صحابی نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا یا رسول اللہ! کون سا صدقہ افضل ہے؟ فرمایا یہ کہ صدقہ تندرستی کی حالت میں کر کہ ( تجھ کو اس مال کو باقی رکھنے کی ) خواہش بھی ہو جس سے کچھ سرمایہ جمع ہو جانے کی تمہیں امید ہو اور ( اسے خرچ کرنے کی صورت میں ) محتاجی کا ڈر ہو اور اس میں تاخیر نہ کر کہ جب روح حلق تک پہنچ جائے تو کہنے بیٹھ جائے کہ اتنا مال فلاں کے لیے ‘ فلانے کو اتنا دینا ‘ اب تو فلانے کا ہو ہی گیا ( تو تو دنیا سے چلا ) ۔' WHERE id = 2637;
UPDATE hadiths SET urdu = 'اور اسماعیل بن جعفر نے بیان کیا کہ مجھے عبدالعزیز بن عبداللہ بن ابی سلمہ نے خبر دی ‘ انہیں اسحاق بن عبداللہ بن ابی طلحہ نے (امام بخاری رحمہ اللہ نے کہا کہ) میں سمجھتا ہوں کہ یہ روایت انہوں نے انس رضی اللہ عنہ سے کی ہے کہ انہوں نے بیان کیا ( جب سورۃ آل عمران کی ) یہ آیت نازل ہوئی «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”تم نیکی ہرگز نہیں پا سکتے جب تک اس مال میں سے خرچ نہ کرو جو تم کو زیادہ پسند ہے۔“ تو ابوطلحہ رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا یا رسول اللہ! اللہ تبارک و تعالیٰ اپنی کتاب میں فرماتا ہے «لن تنالوا البر حتى تنفقوا مما تحبون‏» ”تم نیکی ہرگز نہیں پا سکتے جب تک اس مال میں سے خرچ نہ کرو جو تم کو زیادہ پسند ہے۔“ اور میرے اموال میں سب سے پسند مجھے بیرحاء ہے۔ بیان کیا کہ بیرحاء ایک باغ تھا۔ رسول اللہ صلی اللہ علیہ وسلم بھی اس میں تشریف لے جایا کرتے ‘ اس کے سائے میں بیٹھتے اور اس کا پانی پیتے ( ابوطلحہ نے کہا کہ ) اس لیے وہ اللہ عزوجل کی راہ میں صدقہ اور رسول اللہ صلی اللہ علیہ وسلم کے لیے ہے۔ میں اس کی نیکی اور اس کے ذخیرہ آخرت ہونے کی امید رکھتا ہوں۔ پس یا رسول اللہ! جس طرح اللہ آپ کو بتائے اسے خرچ کیجئے۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا واہ واہ شاباش ابوطلحہ یہ تو بڑا نفع بخش مال ہے ‘ ہم تم سے اسے قبول کر کے پھر تمہارے ہی حوالے کر دیتے ہیں اور اب تم اسے اپنے عزیزوں کو دیدو۔ چنانچہ ابوطلحہ رضی اللہ عنہ نے وہ باغ اپنے عزیزوں کو دے دیا۔ انس رضی اللہ عنہ نے بیان کیا کہ جن لوگوں کو باغ آپ نے دیا تھا ان میں ابی اور حسان رضی اللہ عنہ تھے۔ انہوں نے بیان کیا کہ حسان رضی اللہ عنہ نے اپنا حصہ معاویہ رضی اللہ عنہ کو بیچ دیا تو کسی نے ان سے کہا کہ کیا آپ ابوطلحہ رضی اللہ عنہ کا دیا ہوا مال بیچ رہے ہو؟ حسان رضی اللہ عنہ نے جواب دیا کہ میں کھجور کا ایک صاع روپوں کے ایک صاع کے بدل کیوں نہ بیچوں۔ انس رضی اللہ عنہ نے کہا یہ باغ بنی حدیلہ کے محلہ کے قریب تھا جسے معاویہ رضی اللہ عنہ نے ( بطور قلعہ کے ) تعمیر کیا تھا۔' WHERE id = 2647;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم بن کثیر نے بیان کیا ‘ کہا ہم سے اسماعیل بن علیہ نے بیان کیا ‘ کہا ہم سے عبدالعزیز بن صہیب نے بیان کیا ‘ ان سے انس رضی اللہ عنہ نے بیان کیا کہ ہم سے یعقوب بن ابراہیم بن کثیر نے بیان کیا ‘ کہا ہم سے اسماعیل بن علیہ نے بیان کیا ‘ کہا ہم سے عبدالعزیز بن صہیب نے بیان کیا ‘ ان سے انس رضی اللہ عنہ نے بیان کیا کہ' WHERE id = 2657;
UPDATE hadiths SET urdu = 'عبدان نے بیان کیا کہ مجھے میرے والد نے خبر دی ‘ انہیں شعبہ نے ‘ انہیں ابواسحاق نے ‘ انہیں ابوعبدالرحمٰن نے کہ عبدان نے بیان کیا کہ مجھے میرے والد نے خبر دی ‘ انہیں شعبہ نے ‘ انہیں ابواسحاق نے ‘ انہیں ابوعبدالرحمٰن نے کہ' WHERE id = 2667;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن صالح نے بیان کیا ‘ کہا ہم سے فلیح نے بیان کیا ‘ ان سے ہلال بن علی نے ‘ ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جو شخص اللہ اور اس کے رسول پر ایمان لائے اور نماز قائم کرے اور رمضان کے روزے رکھے تو اللہ تعالیٰ پر حق ہے کہ وہ جنت میں داخل کرے گا خواہ اللہ کے راستے میں وہ جہاد کرے یا اسی جگہ پڑا رہے جہاں پیدا ہوا تھا۔ صحابہ نے عرض کیا یا رسول اللہ! کیا ہم لوگوں کو اس کی بشارت نہ دے دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جنت میں سو درجے ہیں جو اللہ تعالیٰ نے اپنے راستے میں جہاد کرنے والوں کے لیے تیار کئے ہیں ‘ ان کے دو درجوں میں اتنا فاصلہ ہے جتنا آسمان و زمین میں ہے۔ اس لیے جب اللہ تعالیٰ سے مانگنا ہو تو فردوس مانگو کیونکہ وہ جنت کا سب سے درمیانی حصہ اور جنت کے سب سے بلند درجے پر ہے۔ یحییٰ بن صالح نے کہا کہ میں سمجھتا ہوں یوں کہا کہ اس کے اوپر پروردگار کا عرش ہے اور وہیں سے جنت کی نہریں نکلتی ہیں۔ محمد بن فلیح نے اپنے والد سے «وفوقه عرش الرحمن» ہی کی روایت کی ہے۔' WHERE id = 2678;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسمٰعیل نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے بیان کیا ‘ ان سے اسود بن قیس نے اور ان سے جندب بن سفیان رضی اللہ عنہ کہ نبی کریم صلی اللہ علیہ وسلم کسی لڑائی کے موقع پر موجود تھے اور آپ صلی اللہ علیہ وسلم کی انگلی زخمی ہو گئی تھی۔ آپ صلی اللہ علیہ وسلم نے انگلی سے مخاطب ہو کر فرمایا تیری حقیقت ایک زخمی انگلی کے سوا کیا ہے اور جو کچھ ملا ہے اللہ کے راستے میں ملا ہے ( مولانا وحیدالزماں مرحوم نے ترجمہ یوں کیا ہے ) ایک انگلی ہے تیری ہستی یہی۔۔۔ تو اللہ کی راہ میں زخمی ہوئی۔۔۔' WHERE id = 2689;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا ‘ کہا ہم کو عبدہ نے خبر دی ہشام بن عروہ سے ‘ انہیں ان کے والد نے اور انہیں عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم جب جنگ خندق سے ( فارغ ہو کر ) واپس آئے اور ہتھیار رکھ کر غسل کرنا چاہا تو جبرائیل علیہ السلام آئے ‘ ان کا سر غبار سے اٹا ہوا تھا۔ جبرائیل علیہ السلام نے کہا آپ نے ہتھیار اتار دیئے ‘ اللہ کی قسم میں نے تو ابھی تک ہتھیار نہیں اتارے ہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا تو پھر اب کہاں کا ارادہ ہے؟ انہوں نے فرمایا ادھر اور بنو قریظہ کی طرف اشارہ کیا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم نے بنو قریظہ کے خلاف لشکر کشی کی۔' WHERE id = 2699;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے معتمر نے بیان کیا کہ میں نے اپنے والد سے سنا ‘ انہوں نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم فرمایا کرتے تھے ”اے اللہ! میں تیری پناہ مانگتا ہوں عاجزی اور سستی سے ‘ بزدلی اور بڑھاپے کی ذلیل حدود میں پہنچ جانے سے اور میں تیری پناہ مانگتا ہوں زندگی اور موت کے فتنوں سے اور میں تیری پناہ مانگتا ہوں قبر کے عذاب سے۔“' WHERE id = 2709;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا ہم سے معاویہ بن عمرو نے بیان کیا ‘ کہا ہم سے ابواسحاق موسیٰ بن عقبہ نے بیان کیا ‘ ان سے سالم بن ابی النضر نے کہ عبداللہ بن ابی اوفی رضی اللہ عنہ نے ( عمر بن عبیداللہ کو ) لکھا تو میں نے وہ تحریر پڑھی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے جب تمہاری کفار سے مڈبھیڑ ہو تو صبر سے کام لو۔' WHERE id = 2719;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا ‘ کہا ہم سے عبدالوارث نے بیان کیا ‘ ہم سے حسین نے بیان کیا ‘ کہا مجھ سے یحییٰ نے بیان کیا ‘ کہا مجھ سے ابوسلمہ نے بیان کیا ‘ کہا کہ مجھ سے بسر بن سعید نے بیان کیا ‘ کہا کہ مجھ سے زید بن خالد رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس شخص نے اللہ کے راستے میں غزوہ کرنے والے کو ساز و سامان دیا تو وہ ( گویا ) خود غزوہ میں شریک ہوا اور جس نے خیر خواہانہ طریقہ پر غازی کے گھر بار کی نگرانی کی تو وہ ( گویا ) خود غزوہ میں شریک ہوا۔' WHERE id = 2729;
UPDATE hadiths SET urdu = 'ہم سے علی بن حفص نے بیان کیا، کہا ہم سے امام عبداللہ بن المبارک نے بیان کیا، کہا مجھ کو طلحہ بن ابی سعید نے خبر دی، کہا کہ میں نے سعید مقبری سے سنا، وہ بیان کرتے تھے کہ انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس شخص نے اللہ تعالیٰ پر ایمان کے ساتھ اور اس کے وعدہ ثواب کو جانتے ہوئے اللہ کے راستے میں ( جہاد کے لیے ) گھوڑا پالا تو اس گھوڑے کا کھانا، پینا اور اس کا پیشاب و لید سب قیامت کے دن اس کی ترازو میں ہو گا اور سب پر اس کو ثواب ملے گا۔“' WHERE id = 2739;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا ابواسامہ سے، انہوں نے عبیداللہ عمری سے، انہوں نے نافع سے اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( مال غنیمت سے ) گھوڑے کے دو حصے لگائے تھے اور اس کے مالک کا ایک حصہ۔' WHERE id = 2749;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا کہ مجھ سے ابواسحاق نے بیان کیا، کہا کہ میں نے عمرو بن حارث رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ( وفات کے بعد ) سوا اپنے سفید خچر کے، اپنے ہتھیار اور اس زمین کے جو آپ صلی اللہ علیہ وسلم نے خیرات کر دی تھی اور کوئی چیز نہیں چھوڑی تھی۔' WHERE id = 2759;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن خلیل نے بیان کیا، کہا ہم کو علی بن مسہر نے خبر دی، کہا ہم کو یحییٰ بن سعید نے خبر دی، کہا ہم کو عبداللہ بن ربیعہ بن عامر نے خبر دی، کہا کہ میں نے عائشہ رضی اللہ عنہا سے سنا، آپ بیان کرتی تھیں کہ نبی کریم صلی اللہ علیہ وسلم نے ( ایک رات ) بیداری میں گزاری، مدینہ پہنچنے کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا ”کاش! میرے اصحاب میں سے کوئی نیک مرد ایسا ہوتا جو رات بھر ہمارا پہرہ دیتا!“ ابھی یہی باتیں ہو رہی تھیں کہ ہم نے ہتھیار کی جھنکار سنی۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا ”یہ کون صاحب ہیں؟“ ( آنے والے نے ) کہا میں ہوں سعد بن ابی وقاص، آپ کا پہرہ دینے کے لیے حاضر ہوا ہوں۔ پھر نبی کریم صلی اللہ علیہ وسلم خوش ہوئے۔ ان کے لیے دعا فرمائی اور آپ سو گئے۔' WHERE id = 2770;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، انہوں نے جابر رضی اللہ عنہ سے سنا، آپ ابو سعید خدری رضی اللہ عنہ سے بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایک زمانہ ایسا آئے گا کہ مسلمانوں کی فوج کی فوج جہاں پر ہوں گی جن میں پوچھا جائے گا کہ کیا فوج میں کوئی ایسے بزرگ بھی ہیں جنہوں نے نبی کریم صلی اللہ علیہ وسلم کی صحبت اٹھائی ہو، کہا جائے گا کہ ہاں تو ان سے فتح کی دعا کرائی جائے گی۔ پھر ایک ایسا زمانہ آئے گا اس وقت اس کی تلاش ہو گی کہ کوئی ایسے بزرگ مل جائیں جنہوں نے نبی کریم صلی اللہ علیہ وسلم کے صحابہ کی صحبت اٹھائی ہو، ( یعنی تابعی ) ایسے بھی بزرگ مل جائیں گے اور ان سے فتح کی دعا کرائی جائے گی اس کے بعد ایک ایسا زمانہ آئے گا کہ پوچھا جائے گا کہ کیا تم میں کوئی ایسے بزرگ ہیں جنہوں نے نبی کریم صلی اللہ علیہ وسلم کے صحابہ کے شاگردوں کی صحبت اٹھائی ہو کہا جائے گا کہ ہاں اور ان سے فتح کی دعا کرائی جائے گی۔“' WHERE id = 2781;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، انہوں نے کہا کہ ہم کو عبداللہ نے خبر دی، انہوں نے کہا ہم کو اوزاعی نے خبر دی، انہوں نے کہا کہ میں نے سلیمان بن حبیب سے سنا، کہا میں نے ابوامامہ باہلی سے سنا وہ بیان کرتے تھے کہ ایک قوم ( صحابہ رضوان اللہ علیہم اجمعین ) نے بہت سی فتوحات کیں اور ان کی تلواروں کی آرائش سونے چاندی سے نہیں ہوئی تھی بلکہ اونٹ کی پشت کا چمڑہ، سیسہ اور لوہا ان کی تلواروں کے زیور تھے۔' WHERE id = 2792;
UPDATE hadiths SET urdu = 'ہم سے احمد بن مقدام نے بیان کیا، کہا ہم سے خالد بن حارث نے بیان کیا، کہا ہم سے سعید بن ابی عروبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے عبدالرحمٰن بن عوف اور زبیر رضی اللہ عنہما کو خارش کے مرض کی وجہ سے ریشمی کرتہ پہننے کی اجازت دے دی تھی، جو ان دونوں کو لاحق ہو گئی تھی جو اس مرض میں مفید ہے۔' WHERE id = 2802;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سعید بن مسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہیں ہو گی جب تک تم ایک ایسی قوم سے لڑائی نہ کر لو گے جن کے جوتے بالوں کے ہوں گے اور قیامت اس وقت تک قائم نہیں ہو گی جب تک تم ایک ایسی قوم سے جنگ نہ کر لو گے جن کے چہرے تہ شدہ ڈھالوں جیسے ہوں گے۔“ سفیان نے بیان کیا کہ اس میں ابوالزناد نے اعرج سے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے یہ زیادہ نقل کیا کہ ان کی آنکھیں چھوٹی ہوں گی، ناک موٹی، چہرے ایسے ہوں گے جیسے تہ بتہ چمڑہ لگی ڈھال ہوتی ہے۔' WHERE id = 2812;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث نے بیان کیا، کہا مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے کہا کہ مجھے عبیداللہ بن عبداللہ بن عتبہ نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنا خط کسریٰ کے پاس بھیجا۔ آپ صلی اللہ علیہ وسلم نے ( ایلچی سے ) یہ فرمایا تھا کہ وہ آپ صلی اللہ علیہ وسلم کے خط کو بحرین کے گورنر کو دے دیں، بحرین کا گورنر اسے کسریٰ کے دربار میں پہنچا دے گا۔ جب کسریٰ نے مکتوب مبارک پڑھا تو اسے اس نے پھاڑ ڈالا۔ مجھے یاد ہے کہ سعید بن مسیب نے بیان کیا تھا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے اس پر بددعا کی تھی کہ وہ بھی پارہ پارہ ہو جائے ( چنانچہ ایسا ہی ہوا ) ۔' WHERE id = 2822;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ میں ظہر چار رکعت پڑھی پھر عصر کی نماز ذوالحلیفہ میں دو رکعت پڑھی اور میں نے سنا کہ صحابہ حج اور عمرہ دونوں کا لبیک ایک ساتھ پکار رہے تھے۔' WHERE id = 2833;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ میرے پاس ایک شخص آیا، اور ایسی بات پوچھی کہ میری کچھ سمجھ میں نہ آیا کہ اس کا جواب کیا دوں۔ اس نے پوچھا، مجھے یہ مسئلہ بتائیے کہ ایک شخص بہت ہی خوش اور ہتھیار بند ہو کر ہمارے امیروں کے ساتھ جہاد کے لیے جاتا ہے۔ پھر وہ امیر ہمیں ایسی چیزوں کا مکلف قرار دیتے ہیں کہ ہم ان کی طاقت نہیں رکھتے۔ میں نے کہا، اللہ کی قسم! میری کچھ سمجھ میں نہیں آتا کہ تمہاری بات کا جواب کیا دوں، البتہ جب ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ( آپ صلی اللہ علیہ وسلم کی حیات مبارکہ میں ) تھے تو آپ صلی اللہ علیہ وسلم کو کسی بھی معاملہ میں صرف ایک مرتبہ حکم کی ضرورت پیش آتی تھی اور ہم فوراً ہی اسے بجا لاتے تھے، یہ یاد رکھنے کی بات ہے کہ تم لوگوں میں اس وقت تک خیر رہے گی جب تک تم اللہ سے ڈرتے رہو گے، اور اگر تمہارے دل میں کسی معاملہ میں شبہ پیدا ہو جائے ( کہ کیا چاہئے یا نہیں ) تو کسی عالم سے اس کے متعلق پوچھ لو تاکہ تشفی ہو جائے، وہ دور بھی آنے والا ہے کہ کوئی ایسا آدمی بھی ( جو صحیح صحیح مسئلے بتا دے ) تمہیں نہیں ملے گا۔ اس ذات کی قسم جس کے سوا کوئی معبود نہیں! جتنی دنیا باقی رہ گئی ہے وہ وادی کے اس پانی کی طرح ہے جس کا صاف اور اچھا حصہ تو پیا جا چکا ہے اور گدلا حصہ باقی رہ گیا ہے۔' WHERE id = 2844;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے باپ نے اور ان سے نافع بن جبیر نے بیان کیا کہ میں نے سنا کہ عباس رضی اللہ عنہ، زبیر رضی اللہ عنہ سے کہہ رہے تھے کہ کیا یہاں پر نبی کریم صلی اللہ علیہ وسلم نے آپ کو پرچم نصب کرنے کا حکم فرمایا تھا؟' WHERE id = 2855;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالوہاب نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ میں ابوطلحہ رضی اللہ عنہ کی سواری پر ان کے پیچھے بیٹھا ہوا تھا۔ تمام صحابہ حج اور عمرہ دونوں ہی کے لیے ایک ساتھ لبیک کہہ رہے تھے۔' WHERE id = 2865;
UPDATE hadiths SET urdu = 'ہم سے مطر بن فضل نے بیان کیا، انہوں نے کہا ہم سے یزید بن ہارون نے بیان کیا، انہوں نے کہا ہم سے عوام بن حوشب نے بیان کیا، انہوں نے کہا ہم سے ابراہیم ابواسماعیل سکسکی نے بیان کیا، انہوں نے کہا کہ میں نے ابوبردہ بن ابی موسیٰ سے سنا، وہ اور یزید بن ابی کبشہ ایک سفر میں ساتھ تھے اور یزید سفر کی حالت میں بھی روزہ رکھا کرتے تھے۔ ابوبردہ نے کہا کہ میں نے ( اپنے والد ) ابوموسیٰ اشعری رضی اللہ عنہ سے بارہا سنا۔ وہ کہا کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب بندہ بیمار ہوتا ہے یا سفر کرتا ہے تو اس کے لیے ان تمام عبادات کا ثواب لکھا جاتا ہے جنہیں اقامت یا صحت کے وقت یہ کیا کرتا تھا۔' WHERE id = 2875;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے عمرو بن دینار نے ‘ ان سے ابومعبد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ‘ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کوئی مرد کسی ( غیر محرم ) عورت کے ساتھ تنہائی میں نہ بیٹھے اور کوئی عورت اس وقت تک سفر نہ کرے جب تک اس کے ساتھ کوئی اس کا محرم نہ ہو۔ اتنے میں ایک صحابی کھڑے ہوئے اور عرض کیا ‘ یا رسول اللہ! میں نے فلاں جہاد میں اپنا نام لکھوا دیا ہے اور ادھر میری بیوی حج کے لیے جا رہی ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر تو بھی جا اور اپنی بیوی کے ساتھ حج کر۔' WHERE id = 2885;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے لیث نے بیان کیا ‘ ان سے بکیر نے ‘ ان سے سلیمان بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں ایک مہم پر روانہ فرمایا اور یہ ہدایت فرمائی کہ اگر تمہیں فلاں اور فلاں مل جائیں تو انہیں آگ میں جلا دینا ‘ پھر جب ہم نے روانگی کا ارادہ کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تمہیں حکم دیا تھا کہ فلاں اور فلاں کو جلا دینا۔ لیکن آگ ایک ایسی چیز ہے جس کی سزا صرف اللہ تعالیٰ ہی دے سکتا ہے۔ اس لیے اگر وہ تمہیں ملیں تو انہیں قتل کرنا ( آگ میں نہ جلانا ) ۔' WHERE id = 2895;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا ‘ کہا ہم کو ابن عیینہ نے خبر دی ‘ انہیں عمرو نے ‘ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا ‘ آپ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا ”جنگ تو ایک چالبازی کا نام ہے۔“' WHERE id = 2907;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے ‘ ان سے اسرائیل نے ‘ ان سے ابواسحاق نے بیان کیا کہ انہوں نے براء بن عازب رضی اللہ عنہ سے پوچھا تھا ‘ اے ابوعمارہ! کیا آپ لوگ حنین کی جنگ میں واقعی فرار ہو گئے تھے؟ ابواسحاق نے کہا میں سن رہا تھا ‘ براء رضی اللہ عنہ نے یہ جواب دیا کہ رسول اللہ صلی اللہ علیہ وسلم اس دن اپنی جگہ سے بالکل نہیں ہٹے تھے۔ ابوسفیان بن حارث بن عبدالمطلب آپ کے خچر کی لگام تھامے ہوئے تھے ‘ جس وقت مشرکین نے آپ کو چاروں طرف سے گھیر لیا تو آپ سواری سے اترے اور ( تنہا میدان میں آ کر ) فرمانے لگے میں اللہ کا نبی ہوں ‘ اس میں بالکل جھوٹ نہیں۔ میں عبدالمطلب کا بیٹا ہوں۔ براء نے کہا کہ آپ صلی اللہ علیہ وسلم سے زیادہ بہادر اس دن کوئی بھی نہیں تھا۔' WHERE id = 2918;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے بیان کیا ‘ انہیں حصین بن عبدالرحمٰن نے ‘ ان سے عمرو بن میمون نے کہ عمر رضی اللہ عنہ نے ( وفات سے تھوڑی دیر پہلے ) فرمایا کہ میں اپنے بعد آنے والے خلیفہ کو اس کی وصیت کرتا ہوں کہ اللہ تعالیٰ اور اس کے رسول صلی اللہ علیہ وسلم کا ( ذمیوں سے ) جو عہد ہے اس کو وہ پورا کرے اور یہ کہ ان کی حمایت میں ان کے دشمنوں سے جنگ کرے اور ان کی طاقت سے زیادہ کوئی بوجھ ان پر نہ ڈالا جائے۔' WHERE id = 2928;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا ‘ کہا ہم سے ابن علیہ نے بیان کیا ‘ ان سے ایوب نے ‘ ان سے حمید بن ہلال نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( مدینہ میں ) غزوہ موتہ کے موقع پر خطبہ دیا ‘ ( جب کہ مسلمان سپاہی موتہ کے میدان میں داد شجاعت دے رہے تھے ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب اسلامی عَلم ( جھنڈا ) زید بن حارثہ نے سنبھالا اور انہیں شہید کر دیا گیا، پھر جعفر نے عَلم اپنے ہاتھ میں اٹھا لیا اور وہ بھی شہید کر دیئے گئے۔ اب عبداللہ بن رواحہ نے عَلم تھاما ‘ یہ بھی شہید کر دیئے گئے۔ آخر خالد بن ولید نے کسی نئی ہدایت کے بغیر اسلامی عَلم اٹھا لیا ہے۔ اور ان کے ہاتھ پر فتح حاصل ہو گئی ‘ اور میرے لیے اس میں کوئی خوشی کی بات نہیں تھی یا آپ صلی اللہ علیہ وسلم نے فرمایا ‘ کہ ان کے لیے کوئی خوشی کی بات نہیں تھی کہ وہ ( شہداء ) ہمارے پاس زندہ ہوتے۔ ( کیونکہ شہادت کے بعد وہ جنت میں عیش کر رہے ہیں ) اور انس رضی اللہ عنہ نے بیان کیا کہ اس وقت آپ صلی اللہ علیہ وسلم کی آنکھوں سے آنسو جاری تھے۔' WHERE id = 2938;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا ‘ کہا ہم سے یحییٰ نے بیان کیا ‘ ان سے ابوحیان نے بیان کیا ‘ ان سے ابوزرعہ نے بیان کیا ‘ کہا کہ مجھ سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں خطاب فرمایا اور غلول ( خیانت ) کا ذکر فرمایا ‘ اس جرم کی ہولناکی کو واضح کرتے ہوئے فرمایا کہ میں تم میں کسی کو بھی قیامت کے دن اس حالت میں نہ پاؤں کہ اس کی گردن پر بکری لدی ہوئی ہو اور وہ چلا رہی ہو یا اس کی گردن پر گھوڑا لدا ہوا ہو اور وہ چلا رہا ہو اور وہ شخص مجھ سے کہے کہ یا رسول اللہ! میری مدد فرمائیے۔ لیکن میں یہ جواب دے دوں کہ میں تمہاری کوئی مدد نہیں کر سکتا۔ میں تو ( اللہ کا پیغام ) تم تک پہنچا چکا تھا۔ اور اس کی گردن پر اونٹ لدا ہوا ہو اور چلا رہا ہو اور وہ شخص کہے کہ یا رسول اللہ! میری مدد فرمائیے۔ لیکن میں یہ جواب دے دوں کہ میں تمہاری کوئی مدد نہیں کر سکتا ‘ میں اللہ کا پیغام تمہیں پہنچا چکا تھا ‘ یا ( وہ اس حال میں آئے کہ ) وہ اپنی گردن پر سونا ‘ چاندی ‘ اسباب لادے ہوئے ہو اور وہ مجھ سے کہے کہ یا رسول اللہ! میری مدد فرمایئے ‘ لیکن میں اس سے یہ کہہ دوں کہ میں تمہاری کوئی مدد نہیں کر سکتا ‘ میں اللہ تعالیٰ کا پیغام تمہیں پہنچا چکا تھا۔ یا اس کی گردن پر کپڑے کے ٹکڑے ہوں جو اسے حرکت دے رہے ہوں اور وہ کہے کہ یا رسول اللہ! میری مدد کیجئے اور میں کہہ دوں کہ میں تمہاری کوئی مدد نہیں کر سکتا ‘ میں تو ( اللہ کا پیغام ) پہلے ہی پہنچا چکا تھا۔ اور ایوب سختیانی نے بھی ابوحیان سے روایت کیا ہے گھوڑا لادے دیکھوں جو ہنہنا رہا ہو۔' WHERE id = 2948;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا ‘ کہا ہم سے عبدالوارث نے بیان کیا ‘ کہا کہ مجھ سے یحییٰ بن ابی اسحاق نے بیان کیا ‘ اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیاکہ (غزوہ بنو لحیان میں جو 6 ھ میں ہوا) عسفان سے واپس ہوتے ہوئے ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ آپ اپنی اونٹنی پر سوار تھے اور آپ نے سواری پر پیچھے ( ام المؤمنین ) صفیہ بنت حیی رضی اللہ عنہا کو بٹھایا تھا۔ اتفاق سے آپ کی اونٹنی پھسل گئی اور آپ دونوں گر گئے۔ یہ حال دیکھ کر ابوطلحہ رضی اللہ عنہ بھی فوراً اپنی سواری سے کود پڑے اور کہا ‘ یا رسول اللہ! اللہ مجھے آپ پر قربان کرے ‘ کچھ چوٹ تو نہیں لگی؟ آپ صلی اللہ علیہ وسلم نے فرمایا: ”پہلے عورت کی خبر لو۔“ ابوطلحہ رضی اللہ عنہ نے ایک کپڑا اپنے چہرے پر ڈال لیا ‘ پھر صفیہ رضی اللہ عنہا کے قریب آئے اور وہی کپڑا ان کے اوپر ڈال دیا۔ اس کے بعد دونوں کی سواری درست کی ‘ جب آپ سوار ہو گئے تو ہم آپ صلی اللہ علیہ وسلم کے چاروں طرف جمع ہو گئے۔ پھر جب مدینہ دکھائی دینے لگا تو آپ صلی اللہ علیہ وسلم نے یہ دعا پڑھی «آيبون تائبون عابدون لربنا حامدون‏.‏» ”ہم اللہ کی طرف واپس ہونے والے ہیں۔ توبہ کرنے والے ‘ اپنے رب کی عبادت کرنے والے اور اس کی حمد پڑھنے والے ہیں۔“ آپ صلی اللہ علیہ وسلم یہ دعا برابر پڑھتے رہے یہاں تک کہ مدینہ میں داخل ہو گئے۔' WHERE id = 2959;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی شیبہ نے بیان کیا ‘ کہا ہم سے ابواسامہ نے ‘ کہا ہم سے ہشام بن عروہ نے ‘ ان سے ان کے والد نے بیان کیا ‘ ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات ہوئی تو میرے گھر میں آدھے وسق جو کے سوا جو ایک طاق میں رکھے ہوئے تھے اور کوئی چیز ایسی نہیں تھی جو کسی جگر والے ( جاندار ) کی خوراک بن سکتی۔ میں اسی میں سے کھاتی رہی اور بہت دن گزر گئے۔ پھر میں نے اس میں سے ناپ کر نکالنا شروع کیا تو وہ جلدی ختم ہو گئے۔' WHERE id = 2970;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا ‘ کہا ہم سے محمد بن عبداللہ اسدی نے بیان کیا ‘ ان سے عیسیٰ بن طہمان نے بیان کیا ‘ انہوں نے کہا کہ انس بن مالک رضی اللہ عنہ نے ہمیں دو پرانے جوتے نکال کر دکھائے جن میں دو تسمے لگے ہوئے تھے ‘ اس کے بعد پھر ثابت بنانی نے مجھ سے انس رضی اللہ عنہ سے بیان کیا کہ وہ دونوں جوتے نبی کریم صلی اللہ علیہ وسلم کے تھے۔' WHERE id = 2980;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا ‘ کہا ہم سے فلیح نے بیان کیا ‘ کہا ہم سے بلال نے بیان کیا ان سے عبدالرحمٰن بن ابی عمرہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”نہ میں تمہیں کوئی چیز دیتا ہوں ‘ نہ تم سے کسی چیز کو روکتا ہوں۔ میں تو صرف تقسیم کرنے والا ہوں۔ جہاں جہاں کا مجھے حکم ہوتا ہے بس وہیں رکھ دیتا ہوں۔“' WHERE id = 2990;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا ‘ کہا ہم سے حماد بن زید نے بیان کیا ‘ ان سے ایوب سختیانی نے اور ان سے عبداللہ بن ابی ملیکہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں دیبا کی کچھ قبائیں تحفہ کے طور پر آئی تھیں۔ جن میں سونے کی گھنڈیاں لگی ہوئی تھیں ‘ انہیں نبی کریم صلی اللہ علیہ وسلم نے اپنے چند اصحاب میں تقسیم فرما دیا اور ایک قباء مخرمہ بن نوفل رضی اللہ عنہ کے لیے رکھ لی۔ پھر مخرمہ رضی اللہ عنہ آئے اور ان کے ساتھ ان کے صاحبزادے مسور بن مخرمہ رضی اللہ عنہ بھی تھے۔ آپ دروازے پر کھڑے ہو گئے اور کہا کہ میرا نام لے کر نبی کریم صلی اللہ علیہ وسلم کو بلا لا۔ آپ صلی اللہ علیہ وسلم نے ان کی آواز سنی تو قباء لے کر باہر تشریف لائے اور اس کی گھنڈیاں ان کے سامنے کر دیں۔ پھر فرمایا: ابومسور! یہ قباء میں نے تمہارے لیے چھپا کر رکھ لی تھی۔ مخرمہ رضی اللہ عنہ ذرا تیز طبیعت کے آدمی تھے۔ ابن علیہ نے ایوب کے واسطے سے یہ حدیث ( مرسلاً ہی ) روایت کی ہے۔ اور حاتم بن وردان نے بیان کیا کہ ہم سے ایوب نے بیان کیا ‘ ان سے ابن ابی ملیکہ نے ان سے مسور رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے یہاں کچھ قبائیں آئیں تھیں ‘ اس روایت کی متابعت لیث نے ابن ابی ملیکہ سے کی ہے۔' WHERE id = 3000;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، انہیں معمر نے، انہیں زہری نے، انہیں محمد بن جبیر نے اور انہیں ان کے والد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے بدر کے قیدیوں کے بارے میں فرمایا تھا کہ اگر مطعم بن عدی ( جو کفر کی حالت میں مر گئے تھے ) زندہ ہوتے اور ان نجس، ناپاک لوگوں کی سفارش کرتے تو میں ان کی سفارش سے انہیں ( فدیہ لیے بغیر ) چھوڑ دیتا۔' WHERE id = 3011;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ جا رہا تھا۔ آپ صلی اللہ علیہ وسلم نجران کی بنی ہوئی چوڑے حاشیہ کی ایک چادر اوڑھے ہوئے تھے۔ اتنے میں ایک دیہاتی نے آپ صلی اللہ علیہ وسلم کو گھیر لیا اور زور سے آپ کو کھینچا، میں نے آپ کے شانے کو دیکھا، اس پر چادر کے کونے کا نشان پڑ گیا، ایسا کھینچا۔ پھر کہنے لگا۔ اللہ کا مال جو آپ کے پاس ہے اس میں سے کچھ مجھ کو دلائیے۔ آپ صلی اللہ علیہ وسلم نے اس کی طرف دیکھا اور ہنس دئیے۔ پھر آپ صلی اللہ علیہ وسلم نے اسے دینے کا حکم فرمایا ( آخری جملہ میں سے ترجمۃ الباب نکلتا ہے ) ۔' WHERE id = 3021;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، ان سے یحییٰ بن سعید انصاری نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے انصار کو بلایا، تاکہ بحرین میں ان کے لیے کچھ زمین لکھ دیں۔ لیکن انہوں نے عرض کیا کہ نہیں! اللہ کی قسم! ( ہمیں اسی وقت وہاں زمین عنایت فرمائیے ) جب اتنی زمین ہمارے بھائی قریش ( مہاجرین ) کے لیے بھی آپ لکھیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب تک اللہ کو منظور ہے یہ معاش ان کو بھی ( یعنی قریش والوں کو ) ملتی رہے گی۔“ لیکن انصار یہی اصرار کرتے رہے کہ قریش والوں کے لیے بھی سندیں لکھ دیجئیے۔ جب آپ صلی اللہ علیہ وسلم نے انصار سے فرمایا کہ میرے بعد تم یہ دیکھو گے کہ دوسروں کو تم پر ترجیح دی جائے گی، لیکن تم صبر سے کام لینا، تاآنکہ تم آخر میں مجھ سے آ کر ملو ( جنگ اور فساد نہ کرنا ) ۔' WHERE id = 3033;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، انہیں عبیداللہ بن عبداللہ بن عتبہ نے خبر دی، انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی، اور انہیں ابوسفیان بن حرب رضی اللہ عنہ نے خبر دی کہ ہرقل ( فرمانروائے روم ) نے انہیں قریش کے قافلے کے ساتھ بلا بھیجا ( یہ لوگ شام اس زمانے میں تجارت کی غرض سے گئے ہوئے تھے۔ ) جب رسول اللہ صلی اللہ علیہ وسلم نے ابوسفیان سے ( صلح حدیبیہ میں ) قریش کے کافروں کے مقدمہ میں صلح کی تھی۔' WHERE id = 3043;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عثمان بن حکیم نے بیان کیا، کہا ہم سے شریح بن مسلمہ نے بیان کیا، کہا ہم سے ابراہیم بن یوسف بن ابی اسحاق نے بیان کیا، کہا کہ مجھ سے میرے والد نے بیان کیا، ان سے ابواسحاق نے بیان کیا، کہا کہ مجھ سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے جب عمرہ کرنا چاہا تو آپ نے مکہ میں داخلہ کے لیے مکہ کے لوگوں سے اجازت لینے کے لیے آدمی بھیجا۔ انہوں نے اس شرط کے ساتھ ( اجازت دی ) کہ مکہ میں تین دن سے زیادہ قیام نہ کریں۔ ہتھیار نیام میں رکھے بغیر داخل نہ ہوں اور ( مکہ کے ) کسی آدمی کو اپنے ساتھ ( مدینہ ) نہ لے جائیں ( اگرچہ وہ جانا چاہے ) انہوں نے بیان کیا کہ پھر ان شرائط کو علی بن ابی طالب رضی اللہ عنہ نے لکھنا شروع کیا اور اس طرح ”یہ محمد اللہ کے رسول کے صلح نامہ کی تحریر ہے۔“ مکہ والوں نے کہا کہ اگر ہم جان لیتے کہ آپ اللہ کے رسول ہیں تو پھر آپ کو روکتے ہی نہیں بلکہ آپ پر ایمان لاتے، اس لیے تمہیں یوں لکھنا چاہئے، ”یہ محمد بن عبداللہ کی صلح نامہ کی تحریر ہے“۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا، اللہ گواہ ہے کہ میں محمد بن عبداللہ ہوں اور اللہ گواہ ہے کہ میں اللہ کا رسول بھی ہوں۔ آپ صلی اللہ علیہ وسلم لکھنا نہیں جانتے تھے۔ راوی نے بیان کیا کہ آپ صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ سے فرمایا کہ رسول اللہ کا لفظ مٹا دے۔ علی رضی اللہ عنہ نے عرض کیا کہ اللہ کی قسم! یہ لفظ تو میں کبھی نہ مٹاؤں گا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر مجھے دکھلاؤ، راوی نے بیان کیا کہ علی رضی اللہ عنہ نے آپ صلی اللہ علیہ وسلم کو وہ لفظ دکھایا۔ اور آپ صلی اللہ علیہ وسلم نے خود اپنے ہاتھ سے اسے مٹا دیا۔ پھر جب آپ صلی اللہ علیہ وسلم مکہ تشریف لے گئے اور ( تین ) دن گزر گئے تو قریش علی رضی اللہ عنہ کے پاس آئے اور کہا کہ اب اپنے ساتھی سے کہو کہ اب یہاں سے چلے جائیں ( علی رضی اللہ عنہ نے بیان کیا کہ ) میں نے اس کا ذکر آپ صلی اللہ علیہ وسلم سے کیا تو آپ نے فرمایا کہ ہاں، چنانچہ آپ وہاں سے روانہ ہو گئے۔' WHERE id = 3053;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، انہیں عبداللہ بن مبارک نے خبر دی، انہیں موسیٰ بن عقبہ نے، انہیں سالم بن عبداللہ بن عمر نے اور ان سے ان کے والد نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے کسی کی زمین میں سے کچھ ناحق لے لیا تو قیامت کے دن اسے سات زمینوں تک دھنسایا جائے گا۔“' WHERE id = 3064;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا ہم سے ابن جریج نے، ان سے عطاء نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم ابر کا کوئی ایسا ٹکڑا دیکھتے جس سے بارش کی امید ہوتی تو آپ کبھی آگے آتے، کبھی پیچھے جاتے، کبھی گھر کے اندر تشریف لاتے، کبھی باہر آ جاتے اور چہرہ مبارک کا رنگ بدل جاتا۔ لیکن جب بارش ہونے لگتی تو پھر یہ کیفیت باقی نہ رہتی۔ ایک مرتبہ عائشہ رضی اللہ عنہا نے اس کے متعلق آپ سے پوچھا۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا۔ میں نہیں جانتا ممکن ہے یہ بادل بھی ویسا ہی ہو جس کے بارے میں قوم عاد نے کہا تھا، جب انہوں نے بادل کو اپنی وادیوں کی طرف آتے دیکھا تھا۔ آخر آیت تک ( کہ ان کے لیے رحمت کا بادل آیا ہے، حالانکہ وہ عذاب کا بادل تھا ) ۔' WHERE id = 3074;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ اللہ کے راستے میں جو شخص کسی چیز کا بھی جوڑا دے، تو جنت کے چوکیدار فرشتے اسے بلائیں گے کہ فلاں اس دروازے سے اندر آ جا۔ ابوبکر رضی اللہ عنہ نے اس پر کہا کہ یہ تو وہ شخص ہو گا جسے کوئی نقصان نہ ہو گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مجھے امید ہے کہ تو بھی انہیں میں سے ہو گا۔' WHERE id = 3084;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، کہا ہم کو عمرو بن حارث نے خبر دی، ان سے بکیر بن اشج نے بیان کیا، ان سے بسر بن سعید نے بیان کیا اور ان سے زید بن خالد جہنی رضی اللہ عنہ نے بیان کیا اور ( راوی حدیث ) بسر بن سعید کے ساتھ عبیداللہ خولانی بھی روایت حدیث میں شریک ہیں، جو کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ میمونہ رضی اللہ عنہا کی پرورش میں تھے۔ ان دونوں سے زید بن خالد جہنی رضی اللہ عنہ نے بیان کیا کہ ان سے ابوطلحہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”فرشتے اس گھر میں نہیں داخل ہوتے جس میں ( جاندار کی ) تصویر ہو۔“ بسر نے بیان کیا کہ پھر زید بن خالد رضی اللہ عنہ بیمار پڑے اور ہم ان کی عیادت کے لیے ان کے گھر گئے۔ گھر میں ایک پردہ پڑا ہوا تھا اور اس پر تصویریں بنی ہوئی تھیں۔ میں نے عبیداللہ خولانی سے کہا، کیا انہوں نے ہم سے تصویروں کے متعلق ایک حدیث نہیں بیان کی تھی؟ انہوں نے بتایا کہ زید رضی اللہ عنہ نے یہ بھی کہا تھا کہ کپڑے پر اگر نقش و نگار ہوں ( جاندار کی تصویر نہ ہو ) تو وہ اس حکم سے الگ ہے۔ کیا آپ نے حدیث کا یہ حصہ نہیں سنا تھا؟ میں نے کہا کہ نہیں۔ انہوں نے بتایا کہ جی ہاں! زید رضی اللہ عنہ نے یہ بھی بیان کیا تھا۔' WHERE id = 3094;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے ابورجاء نے بیان کیا، ان سے سمرہ بن جندب رضی اللہ عنہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں نے آج رات ( خواب میں ) دیکھا کہ دو شخص میرے پاس آئے۔ ان دونوں نے مجھے بتایا کہ وہ جو آگ جلا رہا ہے۔ وہ جہنم کا داروغہ مالک نامی فرشتہ ہے۔ میں جبرائیل ہوں اور یہ میکائیل ہیں۔“' WHERE id = 3104;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے ابولزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جنت میں داخل ہونے والے سب سے پہلے گروہ کے چہرے ایسے روشن ہوں گے جیسے چودہویں کا چاند ہوتا ہے۔ جو گروہ اس کے بعد داخل ہو گا ان کے چہرے سب سے زیادہ چمکدار ستارے جیسے روشن ہوں گے۔ ان کے دل ایک ہوں گے کہ کوئی بھی اختلاف ان میں آپس میں نہ ہو گا اور نہ ایک دوسرے سے بغض و حسد ہو گا۔ ہر شخص کی دو بیویاں ہوں گی، ان کی خوبصورتی ایسی ہو گی کہ ان کی پنڈلیوں کا گودا گوشت کے اوپر سے دکھائی دے گا۔ وہ صبح و شام اللہ کی تسبیح کرتے رہیں گے نہ ان کو کوئی بیماری ہو گی، نہ ان کی ناک میں کوئی آلائش آئے گی اور نہ تھوک آئے گا۔ ان کے برتن سونے اور چاندی کے اور کنگھے سونے کے ہوں گے اور ان کی انگیٹھیوں کا ایندھن «ألوة» کا ہو گا، ابوالیمان نے بیان کیا کہ «ألوة» سے عود ہندی مراد ہے۔ اور ان کا پسینہ مشک جیسا ہو گا۔ مجاہد نے کہا کہ «إبكار» سے مراد اول فجر ہے۔ اور «العشي» سے مراد سورج کا اتنا ڈھل جانا کہ وہ غروب ہوتا نظر آنے لگے۔' WHERE id = 3114;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے مہاجر ابوالحسن نے بیان کیا کہ میں نے زید بن وہب سے سنا، انہوں نے بیان کیا کہ میں نے ابوذر رضی اللہ عنہ سے سنا وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم ایک سفر میں تھے ( جب بلال رضی اللہ عنہ ظہر کی اذان دینے اٹھے تو ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ وقت ذرا ٹھنڈا ہو لینے دو، پھر دوبارہ ( جب وہ اذان کے لیے اٹھے تو پھر ) آپ صلی اللہ علیہ وسلم نے انہیں یہی حکم دیا کہ وقت اور ٹھنڈا ہو لینے دو، یہاں تک کہ ٹیلوں کے نیچے سے سایہ ڈھل گیا، اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ نماز ٹھنڈے وقت اوقات میں پڑھا کرو، کیونکہ گرمی کی شدت جہنم کی بھاپ سے پیدا ہوتی ہے۔' WHERE id = 3125;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو عیسیٰ بن یونس نے خبر دی، انہیں ہشام نے، انہیں ان کے والد عروہ نے اور ان سے عائشہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم پر ( جب آپ صلی اللہ علیہ وسلم حدیبیہ سے لوٹے تھے ) جادو ہوا تھا۔ اور لیث بن سعد نے بیان کیا کہ مجھے ہشام نے لکھا تھا، انہوں نے اپنے والد سے سنا تھا اور یاد رکھا تھا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا تھا کہ نبی کریم صلی اللہ علیہ وسلم پر جادو کیا گیا تھا۔ آپ کے ذہن میں بات ہوتی تھی کہ فلاں کام میں کر رہا ہوں حالانکہ آپ اسے نہ کر رہے ہوتے۔ آخر ایک دن آپ نے دعا کی پھر دعا کی کہ اللہ پاک اس جادو کا اثر دفع کرے۔ اس کے بعد آپ نے عائشہ رضی اللہ عنہا سے فرمایا کہ تمہیں معلوم بھی ہوا اللہ تعالیٰ نے مجھے وہ تدبیر بتا دی ہے جس میں میری شفا مقدر ہے۔ میرے پاس دو آدمی آئے، ایک تو میرے سر کی طرف بیٹھ گئے اور دوسرا پاؤں کی طرف۔ پھر ایک نے دوسرے سے کہا، انہیں بیماری کیا ہے؟ دوسرے آدمی نے جواب دیا کہ ان پر جادو ہوا ہے۔ انہوں نے پوچھا، جادو ان پر کس نے کیا ہے؟ جواب دیا کہ لبید بن اعصم یہودی نے، پوچھا کہ وہ جادو ( ٹونا ) رکھا کس چیز میں ہے؟ کہا کہ کنگھے میں، کتان میں اور کھجور کے خشک خوشے کے غلاف میں۔ پوچھا، اور یہ چیزیں ہیں کہاں؟ کہا بئر دوران میں۔ پھر نبی کریم صلی اللہ علیہ وسلم وہاں تشریف لے گئے اور واپس آئے تو عائشہ رضی اللہ عنہا سے فرمایا، وہاں کے کھجور کے درخت ایسے ہیں جیسے شیطان کی کھوپڑی۔ میں نے آپ صلی اللہ علیہ وسلم سے پوچھا، وہ ٹونا آپ نے نکلوایا بھی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں مجھے تو اللہ تعالیٰ نے خود شفا دی اور میں نے اسے اس خیال سے نہیں نکلوایا کہ کہیں اس کی وجہ سے لوگوں میں کوئی جھگڑا کھڑا کر دوں۔ اس کے بعد وہ کنواں بند کر دیا گیا۔' WHERE id = 3135;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا، انہوں نے کہا ہم سے محمد بن عبداللہ انصاری نے بیان کیا، انہوں نے کہا ہم سے ابن جریج نے بیان کیا، انہوں نے کہا کہ مجھے عطاء بن ابی رباح نے خبر دی اور انہیں جابر رضی اللہ عنہ نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”رات کا اندھیرا شروع ہونے پر یا رات شروع ہونے پر اپنے بچوں کو اپنے پاس ( گھر میں ) روک لو، کیونکہ شیاطین اسی وقت پھیلنا شروع کرتے ہیں۔ پھر جب عشاء کے وقت میں سے ایک گھڑی گزر جائے تو انہیں چھوڑ دو ( چلیں پھریں ) پھر اللہ کا نام لے کر اپنا دروازہ بند کرو، اللہ کا نام لے کر اپنا چراغ بجھا دو، پانی کے برتن اللہ کا نام لے کر ڈھک دو، اور دوسرے برتن بھی اللہ کا نام لے کر ڈھک دو ( اور اگر ڈھکن نہ ہو ) تو درمیان میں ہی کوئی چیز رکھ دو۔“' WHERE id = 3146;
UPDATE hadiths SET urdu = 'ہم سے زکریا بن یحییٰ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا کہ ہشام نے ہمیں اپنے والد عروہ سے خبر دی اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا، کہا کہ احد کی لڑائی میں جب مشرکین کو شکست ہو گئی تو ابلیس نے چلا کر کہا کہ اے اللہ کے بندو! ( یعنی مسلمانو ) اپنے پیچھے والوں سے بچو، چنانچہ آگے کے مسلمان پیچھے کی طرف پل پڑے اور پیچھے والوں کو ( جو مسلمان ہی تھے ) انہوں نے مارنا شروع کر دیا۔ حذیفہ رضی اللہ عنہ نے دیکھا تو ان کے والد یمان رضی اللہ عنہ بھی پیچھے تھے۔ انہوں نے بہتیرا کہا کہ اے اللہ کے بندو! یہ میرے والد ہیں، یہ میرے والد ہیں۔ لیکن اللہ گواہ ہے کہ لوگوں نے جب تک انہیں قتل نہ کر لیا نہ چھوڑا۔ بعد میں حذیفہ رضی اللہ عنہ نے صرف اتنا کہا کہ خیر۔ اللہ تمہیں معاف کرے ( کہ تم نے غلط فہمی سے ایک مسلمان کو مار ڈالا ) عروہ نے بیان کیا کہ پھر حذیفہ رضی اللہ عنہ اپنے والد کے قاتلوں کے لیے برابر مغفرت کی دعا کرتے رہے۔ تاآنکہ اللہ سے جا ملے۔' WHERE id = 3156;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے اسماعیل نے بیان کیا کہ مجھ سے قیس نے بیان کیا اور ان سے عقبہ بن عمرو ابومسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے یمن کی طرف اپنے ہاتھ سے اشارہ کرتے ہوئے فرمایا کہ ایمان تو ادھر ہے یمن میں! ہاں، اور قساوت اور سخت دلی ان لوگوں میں ہے جو اونٹوں کی دمیں پکڑے چلاتے رہتے ہیں۔ جہاں سے شیطان کی چوٹیاں نمودار ہوں گی، یعنی ربیعہ اور مضر کی قوموں میں۔' WHERE id = 3167;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے کثیر نے، ان سے عطاء نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پانی کے برتنوں کو ڈھک لیا کرو، مشکیزوں ( کے منہ ) کو باندھ لیا کرو، دروازے بند کر لیا کرو اور اپنے بچوں کو اپنے پاس جمع کر لیا کرو، کیونکہ شام ہوتے ہی جنات ( روئے زمین پر ) پھیلتے ہیں اور اچکتے پھرتے ہیں اور سوتے وقت چراغ بجھا لیا کرو، کیونکہ موذی جانور ( چوہا ) بعض اوقات جلتی بتی کو کھینچ لاتا ہے اور اس طرح سارے گھر کو جلا دیتا ہے۔“ ابن جریج اور حبیب نے بھی اس کو عطاء سے روایت کیا، اس میں جنات کے بدل شیاطین مذکور ہیں۔' WHERE id = 3179;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے، ان سے ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ پاک نے آدم علیہ السلام کو پیدا کیا تو ان کو ساٹھ ہاتھ لمبا بنایا پھر فرمایا کہ جا اور ان ملائکہ کو سلام کر، دیکھنا کن لفظوں میں وہ تمہارے سلام کا جواب دیتے ہیں کیونکہ وہی تمہارا اور تمہاری اولاد کا طریقہ سلام ہو گا۔ آدم علیہ السلام ( گئے اور ) کہا، السلام علیکم فرشتوں نے جواب دیا، السلام علیک ورحمۃ اللہ۔ انہوں نے ورحمۃ اللہ کا جملہ بڑھا دیا، پس جو کوئی بھی جنت میں داخل ہو گا وہ آدم علیہ السلام کی شکل اور قامت پر داخل ہو گا، آدم علیہ السلام کے بعد انسانوں میں اب تک قد چھوٹے ہوتے رہے۔“' WHERE id = 3189;
UPDATE hadiths SET urdu = 'امام بخاری رحمہ اللہ نے کہا کہ لیث بن سعد نے روایت کیا یحییٰ بن سعید انصاری سے، ان سے عمرہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ امام بخاری رحمہ اللہ نے کہا کہ لیث بن سعد نے روایت کیا یحییٰ بن سعید انصاری سے، ان سے عمرہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے ”روحوں کے جھنڈ کے جھنڈ الگ الگ تھے۔ پھر وہاں جن روحوں میں آپس میں پہچان تھی ان میں یہاں بھی محبت ہوتی ہے اور جو وہاں غیر تھیں یہاں بھی وہ خلاف رہتی ہیں۔“ اور یحییٰ بن ایوب نے بھی اس حدیث کو روایت کیا، کہا مجھ سے یحییٰ بن سعید نے بیان کیا، آخر تک۔' WHERE id = 3199;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے اور ان سے زینب بنت ابی سلمہ رضی اللہ عنہا نے، ان سے ام حبیبہ بنت ابی سفیان رضی اللہ عنہا نے، ان سے زینب بنت جحش رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ان کے یہاں تشریف لائے آپ صلی اللہ علیہ وسلم کچھ گھبرائے ہوئے تھے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کے سوا اور کوئی معبود نہیں، ملک عرب میں اس برائی کی وجہ سے بربادی آ جائے گی جس کے دن قریب آنے کو ہیں، آج یاجوج ماجوج نے دیوار میں اتنا سوراخ کر دیا ہے پھر نبی کریم صلی اللہ علیہ وسلم نے انگوٹھے اور اس کے قریب کی انگلی سے حلقہ بنا کر بتلایا۔ ام المؤمنین زینب بنت جحش رضی اللہ عنہا نے بیان کیا کہ میں نے سوال کیا: یا رسول اللہ! کیا ہم اس کے باوجود ہلاک کر دئیے جائیں گے کہ ہم میں نیک لوگ بھی موجود ہوں گے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب فسق و فجور بڑھ جائے گا ( تو یقیناً بربادی ہو گی ) ۔' WHERE id = 3209;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے مغیرہ بن عبدالرحمٰن القرشی نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، پھر یہی حدیث نقل کی نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ابراہیم علیہ السلام نے اسی ( 80 ) سال کی عمر میں بسولے سے ختنہ کیا۔“ لیکن پہلی روایت میں «قدوم» بہ تشدید دال ہے اور اس میں «قدوم» بہ تخفیف دال ہے۔ دونوں کے معنی ایک ہی ہیں۔ یعنی بسولہ ( جو بڑھیوں کا ایک مشہور ہتھیار ہوتا ہے اسے بسوہ بھی کہتے ہیں ) شعیب کے ساتھ اس حدیث کو عبدالرحمٰن بن اسحاق نے بھی ابوالزناد سے روایت کیا ہے اور عجلان نے ابوہریرہ رضی اللہ عنہ سے اور محمد بن عمرو نے ابوسلمہ سے روایت کیا ہے، انہوں نے ابوہریرہ رضی اللہ عنہ سے۔' WHERE id = 3219;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں سالم بن عبداللہ نے کہ عبداللہ بن عمر رضی اللہ عنہما کو ابن ابی بکر نے خبر دی اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تمہیں معلوم نہیں کہ جب تمہاری قوم نے کعبہ کی ( نئی ) تعمیر کی تو کعبہ کی ابراہیمی بنیاد کو چھوڑ دیا۔“ میں نے عرض کیا: یا رسول اللہ! پھر آپ ابراہیمی بنیادوں کے مطابق دوبارہ اس کی تعمیر کیوں نہیں کر دیتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہاری قوم کا زمانہ کفر سے قریب نہ ہوتا ( تو میں ایسا ہی کرتا ) عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ جب کہ یہ حدیث عائشہ رضی اللہ عنہما نے رسول اللہ صلی اللہ علیہ وسلم سے سنی ہے تو میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے ان دونوں رکنوں کے، جو حجر اسود کے قریب ہیں، بوسہ لینے کو صرف اسی وجہ سے چھوڑا تھا کہ بیت اللہ ابراہیم علیہ السلام کی بنیاد پر نہیں بنا ہے ( یہ دونوں رکن آگے ہٹ گئے ہیں ) اسماعیل بن ابی اویس نے اس حدیث میں عبداللہ بن محمد بن ابی بکر کہا۔' WHERE id = 3230;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مسکین ابوالحسن نے بیان کیا ‘ انہوں نے کہا ہم سے یحییٰ بن حسان بن حیان ابوزکریا نے بیان کیا ‘ انہوں نے کہا ہم سے سلیمان نے بیان کیا ‘ ان سے عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جب حجر ( ثمود کی بستی ) میں غزوہ تبوک کے لیے جاتے ہوئے پڑاؤ کیا تو آپ صلی اللہ علیہ وسلم نے صحابہ رضی اللہ عنہم کو حکم فرمایا کہ یہاں کے کنوؤں کا پانی نہ پینا اور نہ اپنے برتنوں میں ساتھ لینا۔ صحابہ رضوان اللہ علیہم اجمعین نے عرض کیا کہ ہم نے تو اس سے اپنا آٹا بھی گوندھ لیا ہے اور پانی اپنے برتنوں میں بھی رکھ لیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں حکم دیا کہ گندھا ہوا آٹا پھینک دیا جائے اور ابوذر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے نقل کیا ہے کہ جس نے آٹا اس پانی سے گوندھ لیا ہو ( وہ اسے پھینک دے ) ۔' WHERE id = 3240;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا ‘ کہا ہم کو محمد بن فضیل نے خبر دی ‘ کہا ہم سے حصین نے بیان کیا ‘ ان سے سفیان نے ‘ ان سے مسروق نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا کی والدہ ام رومان رضی اللہ عنہا سے عائشہ رضی اللہ عنہا کے بارے میں جو بہتان تراشا گیا تھا اس کے متعلق پوچھا تو انہوں نے کہا کہ عائشہ رضی اللہ عنہا کے ساتھ بیٹھی ہوئی تھی کہ ایک انصاریہ عورت ہمارے یہاں آئی اور کہا کہ اللہ فلاں ( مسطح بن اثاثہ ) کو تباہ کر دے اور وہ اسے تباہ کر بھی چکا انہوں نے بیان کیا کہ میں نے کہا آپ یہ کیا کہہ رہی ہیں انہوں نے بتایا کہ اسی نے تو یہ جھوٹ مشہور کیا ہے۔ پھر انصاریہ عورت نے ( عائشہ رضی اللہ عنہا پر تہمت کا سارا ) واقعہ بیان کیا۔ عائشہ رضی اللہ عنہا نے ( اپنی والدہ سے ) پوچھا کہ کون سا واقعہ؟ تو ان کی والدہ نے انہیں واقعہ کی تفصیل بتائی۔ عائشہ نے پوچھا کہ کیا یہ قصہ ابوبکر رضی اللہ عنہ اور رسول اللہ صلی اللہ علیہ وسلم کو بھی معلوم ہو گیا ہے؟ ان کی والدہ نے بتایا کہ ہاں۔ یہ سنتے ہی عائشہ رضی اللہ عنہا بیہوش ہو کر گر پڑیں اور جب ہوش آیا تو جاڑے کے ساتھ بخار چڑھا ہوا تھا۔ پھر نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور دریافت فرمایا کہ انہیں کیا ہوا؟ میں نے کہا کہ ایک بات ان سے ایسی کہی گئی تھی اور اسی کے صدمے سے ان کو بخار آ گیا ہے۔ پھر عائشہ رضی اللہ عنہا اٹھ کر بیٹھ گئیں اور کہا اللہ کی قسم! اگر میں قسم کھاؤں جب بھی آپ لوگ میری بات نہیں مان سکتے اور اگر کوئی عذر بیان کروں تو اسے بھی تسلیم نہیں کر سکتے۔ بس میری اور آپ لوگوں کی مثال یعقوب علیہ السلام اور ان کے بیٹوں کی سی ہے ( کہ انہوں نے اپنے بیٹوں کی من گھڑت کہانی سن کر فرمایا تھا کہ ) ”جو کچھ تم کہہ رہے ہو میں اس پر اللہ ہی کی مدد چاہتا ہوں۔“ اس کے بعد نبی کریم صلی اللہ علیہ وسلم واپس تشریف لے گئے اور اللہ تعالیٰ کو جو کچھ منظور تھا وہ نازل فرمایا۔ جب نبی کریم صلی اللہ علیہ وسلم نے اس کی خبر عائشہ رضی اللہ عنہا کو دی تو انہوں نے کہا کہ اس کے لیے میں صرف اللہ کا شکر ادا کرتی ہوں کسی اور کا نہیں۔' WHERE id = 3250;
UPDATE hadiths SET urdu = 'ہم سے عمر بن محمد نے بیان کیا ‘ کہا ہم سے یعقوب بن ابراہیم نے بیان کیا ‘ کہا کہ مجھ سے میرے والد نے بیان کیا ‘ ان سے صالح نے ‘ ان سے ابن شہاب نے ‘ انہیں عبیداللہ بن عبداللہ نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے کہ حر بن قیس فزاری رضی اللہ عنہ سے صاحب موسیٰ علیہ السلام کے بارے میں ان کا اختلاف ہوا۔ پھر ابی بن کعب رضی اللہ عنہ وہاں سے گزرے تو عبداللہ بن عباس رضی اللہ عنہما نے انہیں بلایا اور کہا کہ میرا اپنے ان ساتھی سے صاحب موسیٰ علیہ السلام کے بارے میں اختلاف ہو گیا ہے جن سے ملاقات کے لیے موسیٰ علیہ السلام نے راستہ پوچھا تھا ‘ کیا رسول اللہ صلی اللہ علیہ وسلم سے آپ نے ان کے بارے میں کچھ سنا ہے؟ انہوں نے فرمایا کہ جی ہاں ‘ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ فرماتے سنا تھا کہ موسیٰ علیہ السلام بنی اسرائیل کی ایک جماعت میں تشریف رکھتے تھے کہ ایک شخص نے ان سے پوچھا ‘ کیا آپ کسی ایسے شخص کو جانتے ہیں جو اس تمام زمین پر آپ سے زیادہ علم رکھنے والا ہو؟ انہوں نے فرمایا کہ نہیں۔ اس پر اللہ تعالیٰ نے موسیٰ علیہ السلام پر وحی نازل کی کہ کیوں نہیں ‘ ہمارا بندہ خضر ہے۔ موسیٰ علیہ السلام نے ان تک پہنچنے کا راستہ پوچھا تو انہیں مچھلی کو اس کی نشانی کے طور پر بتایا گیا اور کہا گیا کہ جب مچھلی گم ہو جائے ( تو جہاں گم ہوئی ہو وہاں ) واپس آ جانا وہیں ان سے ملاقات ہو گی۔ چنانچہ موسیٰ علیہ السلام دریا میں ( سفر کے دوران ) مچھلی کی برابر نگرانی کرتے رہے۔ پھر ان سے ان کے رفیق سفر نے کہا کہ آپ نے خیال نہیں کیا جب ہم چٹان کے پاس ٹھہرے تو میں مچھلی کے متعلق آپ کو بتانا بھول گیا تھا اور مجھے شیطان نے اسے یاد رکھنے سے غافل رکھا۔ موسیٰ علیہ السلام نے فرمایا کہ اسی کی تو ہمیں تلاش ہے چنانچہ یہ بزرگ اسی راستے سے پیچھے کی طرف لوٹے اور خضر علیہ السلام سے ملاقات ہوئی ان دونوں کے ہی وہ حالات ہیں جنہیں اللہ تعالیٰ کی کتاب میں بیان فرمایا ہے۔' WHERE id = 3261;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے حصین بن نمیر نے بیان کیا ‘ ان سے حصین بن عبدالرحمٰن نے ‘ ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ ایک دن نبی کریم صلی اللہ علیہ وسلم ہمارے پاس تشریف لائے اور فرمایا ”میرے سامنے تمام امتیں لائی گئیں اور میں نے دیکھا کہ ایک بہت بڑی جماعت آسمان کے کناروں پر چھائی ہوئی ہے۔ پھر بتایا گیا کہ یہ اپنی قوم کے ساتھ موسیٰ علیہ السلام ہیں۔“' WHERE id = 3271;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہب نے بیان کیا، ان سے ایوب نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ سورۃ ص کا سجدہ ضروری نہیں، لیکن میں نے نبی کریم صلی اللہ علیہ وسلم کو اس سورۃ میں سجدہ کرتے دیکھا ہے۔' WHERE id = 3282;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، انہوں نے کہا ہم کہ میں نے مرہ ہمدانی سے سنا۔ وہ ابوموسیٰ اشعری رضی اللہ عنہ سے بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”عورتوں پر عائشہ کی فضیلت ایسے ہے جیسے تمام کھانوں پر ثرید کی۔ مردوں میں سے تو بہت سے کامل ہو گزرے ہیں لیکن عورتوں میں مریم بنت عمران اور فرعون کی بیوی آسیہ کے سوا اور کوئی کامل پیدا نہیں ہوئی۔“' WHERE id = 3292;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا کہ میں نے زہری سے سنا، وہ بیان کرتے تھے کہ مجھے عبیداللہ بن عبداللہ نے خبر دی اور انہیں ابن عباس رضی اللہ عنہما نے، انہوں نے عمر رضی اللہ عنہ کو منبر پر یہ کہتے سنا تھا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”مجھے میرے مرتبے سے زیادہ نہ بڑھاؤ جیسے عیسیٰ ابن مریم علیہما السلام کو نصاریٰ نے ان کے رتبے سے زیادہ بڑھا دیا ہے۔ میں تو صرف اللہ کا بندہ ہوں، اس لیے یہی کہا کرو ( میرے متعلق ) کہ میں اللہ کا بندہ اور اس کا رسول ہوں۔“' WHERE id = 3303;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو نے، ان سے طاؤس نے، ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں نے عمر رضی اللہ عنہ سے سنا انہوں نے کہا اللہ تعالیٰ فلاں کو تباہ کرے۔ انہیں کیا معلوم نہیں کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا ”یہود پر اللہ کی لعنت ہو، ان کے لیے چربی حرام ہوئی تو انہوں نے اسے پگھلا کر بیچنا شروع کر دیا۔“ اس روایت کو ابن عباس رضی اللہ عنہما کے ساتھ جابر اور ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا ہے۔' WHERE id = 3315;
UPDATE hadiths SET urdu = '(ہم سے محمد بن بشار نے بیان کیا کہا ہم سے محمد بن ابی عدی نے بیان کیا ان سے شعبہ نے ان سے قتادہ نے ان سے ابوصدیق ناجی بکر بن قیس نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بنی اسرائیل میں ایک شخص تھا جس نے ننانوے خون ناحق کئے تھے پھر وہ نادم ہو کر ) مسئلہ پوچھنے نکلا۔ وہ ایک درویش کے پاس آیا اور اس سے پوچھا کیا اس گناہ سے توبہ قبول ہونے کی کوئی صورت ہے؟ درویش نے جواب دیا کہ نہیں۔ یہ سن کر اس نے اس درویش کو بھی قتل کر دیا ( اور سو خون پورے کر دئیے ) پھر وہ ( دوسروں سے ) پوچھنے لگا۔ آخر اس کو ایک درویش نے بتایا کہ فلاں بستی میں چلا جا ) ( وہ آدھے راستے بھی نہیں پہنچا تھا کہ ) اس کی موت واقع ہو گئی۔ مرتے مرتے اس نے اپنا سینہ اس بستی کی طرف جھکا دیا۔ آخر رحمت کے فرشتوں اور عذاب کے فرشتوں میں باہم جھگڑا ہوا۔ ( کہ کون اسے لے جائے ) لیکن اللہ تعالیٰ نے اس نصرہ نامی بستی کو ( جہاں وہ توبہ کے لیے جا رہا تھا ) حکم دیا کہ اس کی نعش سے قریب ہو جائے اور دوسری بستی کو ( جہاں سے وہ نکلا تھا ) حکم دیا کہ اس کی نعش سے دور ہو جا۔ پھر اللہ تعالیٰ نے فرشتوں سے فرمایا کہ اب دونوں کا فاصلہ دیکھو اور ( جب ناپا تو ) اس بستی کو ( جہاں وہ توبہ کے لیے جا رہا تھا ) ایک بالشت نعش سے نزدیک پایا اس لیے وہ بخش دیا گیا۔' WHERE id = 3325;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا ان سے ابن شہاب نے ان سے عبیداللہ بن عبداللہ بن عتبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایک شخص لوگوں کو قرض دیا کرتا تھا اور اپنے نوکروں کو اس نے یہ کہہ رکھا تھا کہ جب تم کسی کو مفلس پاؤ ( جو میرا قرض دار ہو ) تو اسے معاف کر دیا کرو۔ ممکن ہے اللہ تعالیٰ بھی ہمیں معاف فرما دے۔“ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب وہ اللہ تعالیٰ سے ملا تو اللہ نے اسے بخش دیا۔“' WHERE id = 3335;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے کلیب بن وائل نے بیان کیا، کہا کہ مجھ سے زینب بنت ابی سلمہ رضی اللہ عنہا نے بیان کیا جو نبی کریم صلی اللہ علیہ وسلم کی زیر پرورش رہ چکی تھیں، کلیب نے بیان کیا کہ ہمیں نے زینب سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم کا تعلق قبیلہ مضر سے تھا؟ انہوں نے کہا پھر کس قبیلہ سے تھا؟ یقیناً نبی کریم صلی اللہ علیہ وسلم قبیلہ مضر کی شاخ بنی نضر بن کنانہ کی اولاد میں سے تھے۔' WHERE id = 3345;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے، کہا کہ مجھ سے ابوالاسود نے، ان سے عروہ بن زبیر نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ کے بعد عبداللہ بن زبیر رضی اللہ عنہما سے عائشہ رضی اللہ عنہا کو سب سے زیادہ محبت تھی۔ عائشہ رضی اللہ عنہا کی عادت تھی کہ اللہ تعالیٰ کی طرف سے جو رزق بھی ان کو ملتا وہ اسے صدقہ کر دیا کرتی تھیں۔ عبداللہ بن زبیر رضی اللہ عنہما نے ( کسی سے ) کہا ام المؤمنین کو اس سے روکنا چاہیے ( جب عائشہ رضی اللہ عنہا کو ان کی بات پہنچی ) تو انہوں نے کہا: کیا اب میرے ہاتھوں کو روکا جائے گا، اب اگر میں نے عبداللہ سے بات کی تو مجھ پر نذر واجب ہے۔ عبداللہ بن زبیر رضی اللہ عنہما نے ( عائشہ رضی اللہ عنہا کو راضی کرنے کے لیے ) قریش کے چند لوگوں اور خاص طور سے رسول اللہ صلی اللہ علیہ وسلم کے نانہالی رشتہ داروں ( بنو زہرہ ) کو ان کی خدمت میں معافی کی سفارش کے لیے بھیجا لیکن عائشہ رضی اللہ عنہا پھر بھی نہ مانیں۔ اس پر بنو زہرہ نے جو رسول اللہ صلی اللہ علیہ وسلم کے ماموں ہوتے تھے اور ان میں عبدالرحمٰن بن اسود بن عبدیغوث اور مسور بن مخرمہ رضی اللہ عنہ بھی تھے، عبداللہ بن زبیر رضی اللہ عنہما سے کہا کہ جب ہم ان کی اجازت سے وہاں جا بیٹھیں تو تم ایک دفعہ آن کر پردہ میں گھس جاؤ۔ چنانچہ انہوں نے ایسا ہی کیا ( جب عائشہ رضی اللہ عنہا خوش ہو گئیں تو ) انہوں نے ان کی خدمت میں دس غلام ( آزاد کرانے کے لیے بطور کفارہ قسم ) بھیجے اور ام المؤمنین نے انہیں آزاد کر دیا۔ پھر آپ برابر غلام آزاد کرتی رہیں۔ یہاں تک کہ چالیس غلام آزاد کر دیئے پھر انہوں نے کہا کاش میں نے جس وقت قسم کھائی تھی ( منت مانی تھی ) تو میں کوئی خاص چیز بیان کر دیتی جس کو کر کے میں فارغ ہو جاتی۔' WHERE id = 3357;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے سفیان نے، ان سے عبدالملک بن عمیر نے، ان سے عبدالرحمٰن بن ابی بکرہ نے اور ان سے ان کے والد ابوبکرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بتاؤ کیا جہینہ، مزینہ، اسلم اور غفار کے قبیلے بنی تمیم، بنی اسد، بنی عبداللہ بن غطفان اور بنی عامر بن صعصعہ کے مقابلے میں بہتر ہیں؟“ ایک شخص ( اقرع بن حابس ) نے کہا کہ وہ تو تباہ و برباد ہوئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں یہ چاروں قبیلے بنو تمیم، بنو اسد، بنو عبداللہ بن غطفان اور بنو عامر بن صعصعہ کے قبیلوں سے بہتر ہیں۔' WHERE id = 3367;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے، کہا ان سے عمرو بن مرہ نے، ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ جب ( سورۃ الشعراء کی ) یہ آیت اتری «وأنذر عشيرتك الأقربين‏» ”اے پیغمبر! اپنے قریبی رشتہ داروں کو ڈرا۔“ تو نبی کریم صلی اللہ علیہ وسلم نے قریش کے مختلف قبیلوں کو بلایا اے بنی فہر! اے بنی عدی! جو قریش کے خاندان تھے۔' WHERE id = 3377;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ بن زبیر نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے تریسٹھ سال کی عمر میں وفات پائی اور ابن شہاب نے کہا کہ مجھ سے سعید بن مسیب نے اسی طرح بیان کیا۔' WHERE id = 3387;
UPDATE hadiths SET urdu = 'ہم سے عصام بن خالد نے بیان کیا، انہوں نے کہا ہم سے حریز بن عثمان نے بیان کیا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم کے صحابی عبداللہ بن بسر رضی اللہ عنہ سے پوچھا، کیا رسول اللہ صلی اللہ علیہ وسلم بوڑھے ہو گئے تھے؟ انہوں نے کہا کہ آپ صلی اللہ علیہ وسلم کی ٹھوڑی کے چند بال سفید ہو گئے تھے۔' WHERE id = 3397;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن عبداللہ بن کعب نے اور ان سے عبداللہ بن کعب نے بیان کیا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا، آپ غزوہ تبوک میں اپنے پیچھے رہ جانے کا واقعہ بیان کر رہے تھے۔ انہوں نے بیان کیا کہ پھر میں نے ( توبہ قبول ہونے کے بعد ) حاضر ہو کر رسول اللہ صلی اللہ علیہ وسلم کو سلام کیا تو چہرہ مبارک مسرت و خوشی سے چمک رہا تھا۔ جب بھی نبی کریم صلی اللہ علیہ وسلم کسی بات پر مسرور ہوتے تو چہرہ مبارک چمک اٹھتا، ایسا معلوم ہوتا جیسے چاند کا ٹکڑا ہو اور آپ صلی اللہ علیہ وسلم کی خوشی کو ہم اسی سے پہچان جاتے تھے۔' WHERE id = 3407;
UPDATE hadiths SET urdu = 'ہم سے حسن بن صباح بزار نے بیان کیا، کہا ہم سے محمد بن سابق نے بیان کیا، کہا ہم سے مالک بن مغول نے بیان کیا، کہا کہ میں نے عون بن ابی جحیفہ سے سنا، وہ اپنے والد (ابوجحیفہ رضی اللہ عنہ) سے نقل کرتے تھے کہ میں سفر کے ارادہ سے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم ابطح میں ( محصب میں ) خیمہ کے اندر تشریف رکھتے تھے۔ کڑی دوپہر کا وقت تھا۔ اتنے میں بلال رضی اللہ عنہ نے باہر نکل کر نماز کے لیے اذان دی اور اندر آ گئے اور بلال رضی اللہ عنہ نے آپ صلی اللہ علیہ وسلم کے وضو کا بچا ہوا پانی نکالا تو لوگ اسے لینے کے لیے ٹوٹ پڑے۔ پھر بلال رضی اللہ عنہ نے ایک نیزہ نکالا اور آپ صلی اللہ علیہ وسلم باہر تشریف لائے، گویا آپ کی پنڈلیوں کی چمک اب بھی میری نظروں کے سامنے ہے۔ بلال رضی اللہ عنہ نے ( سترہ کے لیے ) نیزہ گاڑ دیا۔ آپ صلی اللہ علیہ وسلم نے ظہر اور عصر کی دو دو رکعت قصر نماز پڑھائی، گدھے اور عورتیں آپ کے سامنے سے گزر رہی تھیں۔' WHERE id = 3418;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے خبر دی، انہیں اسحٰق بن عبداللہ بن ابی طلحہ نے اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے کہا کہ ابوطلحہ رضی اللہ عنہ نے ( میری والدہ ) ام سلیم رضی اللہ عنہما سے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کی آواز سنی تو آپ کی آواز میں بہت ضعف معلوم ہوا۔ میرا خیال ہے کہ آپ بہت بھوکے ہیں۔ کیا تمہارے پاس کچھ کھانا ہے؟ انہوں نے کہا جی ہاں، چنانچہ انہوں نے جَو کی چند روٹیاں نکالیں، پھر اپنی اوڑھنی نکالی او اس میں روٹیوں کو لپیٹ کر میرے ہاتھ میں چھپا دیا اور اس اوڑھنی کا دوسرا حصہ میرے بدن پر باندھ دیا۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں مجھے بھیجا۔ میں جو گیا تو آپ مسجد میں تشریف رکھتے تھے۔ آپ کے ساتھ بہت سے صحابہ بھی بیٹھے ہوئے تھے۔ میں آپ کے پاس کھڑا ہو گیا تو آپ نے فرمایا کیا ابوطلحہ نے تمہیں بھیجا ہے؟ میں نے عرض کیا جی ہاں۔ آپ نے دریافت فرمایا، کچھ کھانا دے کر؟ میں نے عرض کیا جی ہاں، جو صحابہ آپ کے ساتھ اس وقت موجود تھے، ان سب سے آپ نے فرمایا کہ چلو اٹھو، آپ تشریف لانے لگے اور میں آپ کے آگے آگے لپک رہا تھا اور ابوطلحہ رضی اللہ عنہ کے گھر پہنچ کر میں نے انہیں خبر دی۔ ابوطلحہ رضی اللہ عنہ بولے، ام سلیم! نبی کریم صلی اللہ علیہ وسلم تو بہت سے لوگوں کو ساتھ لائے ہیں ہمارے پاس اتنا کھانا کہاں ہے کہ سب کو کھلایا جا سکے؟ ام سلیم رضی اللہ عنہ نے کہا: اللہ اور اس کے رسول زیادہ جانتے ہیں ( ہم فکر کیوں کریں؟ ) خیر ابوطلحہ آگے بڑھ کر نبی کریم صلی اللہ علیہ وسلم سے ملے۔ اب رسول اللہ صلی اللہ علیہ وسلم کے ساتھ وہ بھی چل رہے تھے۔ ام سلیم نے وہی روٹی لا کر آپ کے سامنے رکھ دی، پھر نبی کریم صلی اللہ علیہ وسلم کے حکم سے روٹیوں کا چورا کر دیا گیا، ام سلیم رضی اللہ عنہا نے کپی نچوڑ کر اس پر کچھ گھی ڈال دیا، اور اس طرح سالن ہو گیا، آپ نے اس کے بعد اس پر دعا کی جو کچھ بھی اللہ تعالیٰ نے چاہا۔ پھر فرمایا دس آدمیوں کو بلا لو، انہوں نے ایسا ہی کیا، ان سب نے روٹی پیٹ بھر کر کھائی اور جب یہ لوگ باہر گئے تو آپ نے فرمایا کہ پھر دس آدمیوں کو بلا لو۔ چنانچہ دس آدمیوں کو بلایا گیا، انہوں نے بھی پیٹ بھر کر کھایا، جب یہ لوگ باہر گئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر دس ہی آدمیوں کو اندر بلا لو۔ انہوں نے ایسا ہی کیا اور انہوں نے بھی پیٹ بھر کر کھایا۔ جب وہ باہر گئے تو آپ نے فرمایا کہ پھر دس آدمیوں کو دعوت دے دو۔ اس طرح سب لوگوں نے پیٹ بھر کر کھانا کھایا۔ ان لوگوں کی تعداد ستر یا اسی تھی۔' WHERE id = 3429;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ان سے معمر نے اور ان سے ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت اس وقت تک قائم نہ ہو گی جب تک کہ تم ایرانیوں کے شہر خوز اور کرمان والوں سے جنگ نہ کر لو گے۔ چہرے ان کے سرخ ہوں گے۔ ناک چپٹی ہو گی۔ آنکھیں چھوٹی ہوں گی اور چہرے ایسے ہوں گے جیسے تہ بہ تہ ڈھال ہوتی ہے اور ان کے جوتے بالوں والے ہوں گے۔ یحییٰ کے علاوہ اس حدیث کو اوروں نے بھی عبدالرزاق سے روایت کیا ہے۔' WHERE id = 3439;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی سلمہ بن ماجشون نے بیان کیا، ان سے عبدالرحمٰن بن ابی صعصعہ نے، ان سے ان کے والد نے کہا، ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ میں دیکھ رہا ہوں کہ تمہیں بکریوں سے بہت محبت ہے اور تم انہیں پالتے ہو تو تم ان کی نگہداشت اچھی کیا کرو اور ان کی ناک کی صفائی کا بھی خیال رکھا کرو۔ کیونکہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ لوگوں پر ایسا زمانہ آئے گا کہ مسلمان کا سب سے عمدہ مال اس کی بکریاں ہوں گی جنہیں لے کر وہ پہاڑ کی چوٹیوں پر چڑھ جائے گا یا ( آپ نے «سعف الجبال» کے لفظ فرمائے ) وہ بارش گرنے کی جگہ میں چلا جائے گا۔ اس طرح وہ اپنے دین کو فتنوں سے بچانے کے لیے بھاگتا پھرے گا۔' WHERE id = 3450;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے اسماعیل نے، کہا ہم سے قیس نے بیان کیا، ان سے خباب بن ارت رضی اللہ عنہ نے بیان کیا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم سے شکایت کی۔ آپ اس وقت اپنی ایک چادر پر ٹیک دیئے کعبہ کے سائے میں بیٹھے ہوئے تھے۔ ہم نے آپ صلی اللہ علیہ وسلم کی خدمت میں عرض کیا کہ آپ ہمارے لیے مدد کیوں نہیں طلب فرماتے۔ ہمارے لیے اللہ سے دعا کیوں نہیں مانگتے ( ہم کافروں کی ایذا دہی سے تنگ آ چکے ہیں ) ۔ آپ صلی اللہ علیہ وسلم نے فرمایا ” ( ایمان لانے کی سزا میں ) تم سے پہلی امتوں کے لوگوں کے لیے گڑھا کھودا جاتا اور انہیں اس میں ڈال دیا جاتا۔ پھر ان کے سر پر آرا رکھ کر ان کے دو ٹکڑے کر دیئے جاتے پھر بھی وہ اپنے دین سے نہ پھرتے۔ لوہے کے کنگھے ان کے گوشت میں دھنسا کر ان کی ہڈیوں اور پٹھوں پر پھیرے جاتے پھر بھی وہ اپنا ایمان نہ چھوڑتے۔ اللہ کی قسم یہ امر ( اسلام ) بھی کمال کو پہنچے گا اور ایک زمانہ آئے گا کہ ایک سوار مقام صنعاء سے حضر موت تک سفر کرے گا ( لیکن راستوں کے پرامن ہونے کی وجہ سے اسے اللہ کے سوا اور کسی کا ڈر نہیں ہو گا۔ یا صرف بھیڑئیے کا خوف ہو گا کہ کہیں اس کی بکریوں کو نہ کھا جائے لیکن تم لوگ جلدی کرتے ہو۔)' WHERE id = 3461;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے عبدالرحمٰن بن سلیمان بن حنظلہ بن غسیل نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ مرض الوفات میں رسول اللہ صلی اللہ علیہ وسلم باہر تشریف لائے، آپ ایک چکنے کپڑے سے سر مبارک پر پٹی باندھے ہوئے تھے، آپ صلی اللہ علیہ وسلم مسجد نبوی میں منبر پر تشریف فرما ہوئے پھر جیسے ہونی چاہیے اللہ تعالیٰ کی حمد و ثنا کی، پھر فرمایا: امابعد: ( آنے والے دور میں ) دوسرے لوگوں کی تعداد بہت بڑھ جائے گی لیکن انصار کم ہوتے جائیں گے اور ایک زمانہ آئے گا کہ دوسروں کے مقابلے میں ان کی تعداد اتنی کم ہو جائے گی جیسے کھانے میں نمک ہوتا ہے۔ پس اگر تم میں سے کوئی شخص کہیں کا حاکم بنے اور اپنی حکومت کی وجہ سے وہ کسی کو نقصان اور نفع بھی پہنچا سکتا ہو تو اسے چاہیے کہ انصار کے نیکوں ( کی نیکیوں ) کو قبول کرے اور جو برے ہوں ان سے درگزر کر دیا کرے۔ یہ نبی کریم صلی اللہ علیہ وسلم کی آخری مجلس وعظ تھی۔' WHERE id = 3474;
UPDATE hadiths SET urdu = 'مجھ سے خلف بن خالد قرشی نے بیان کیا، کہا ہم سے بکر بن مضر نے بیان کیا، ان سے جعفر بن ربیعہ نے بیان کیا، ان سے عراق بن مالک نے، ان سے عبیداللہ بن عبداللہ بن مسعود نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں چاند کے دو ٹکڑے ہو گئے تھے۔' WHERE id = 3484;
UPDATE hadiths SET urdu = 'مجھ سے اسحٰق بن راہویہ نے بیان کیا، کہا ہم سے نضر نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں ابوجمرہ نے، کہا میں نے زہدم بن مضرب سے سنا، کہا کہ میں نے عمران بن حصین رضی اللہ عنہما سے سنا، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میری امت کا سب سے بہترین زمانہ میرا زمانہ ہے، پھر ان لوگوں کا جو اس زمانہ کے بعد آئیں گے۔ پھر ان لوگوں کا جو اس زمانہ کے بعد آئیں گے۔ عمران رضی اللہ عنہ کہتے ہیں کہ مجھے یاد نہیں ہے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے دور کے بعد دو زمانوں کا ذکر کیا یا تین کا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے بعد ایک ایسی قوم پیدا ہو گی جو بغیر کہے گواہی دینے کے لیے تیار ہو جایا کرے گی اور ان میں خیانت اور چوری اتنی عام ہو جائے گی کہ ان پر کسی قسم کا بھروسہ باقی نہیں رہے گا۔ اور نذریں مانیں گے لیکن انہیں پورا نہیں کریں گے ( حرام مال کھا کھا کر ) ان پر مٹاپا عام ہو جائے گا۔' WHERE id = 3495;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی طیب نے بیان کیا، کہا ہم سے اسماعیل بن ابی مجالد نے بیان کیا، ان سے بیان بن بشر نے کہا، ان سے وبرہ بن عبدالرحمٰن نے، ان سے ہمام نے بیان کیا کہ میں نے عمار رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس وقت دیکھا ہے جب آپ صلی اللہ علیہ وسلم کے ساتھ ( اسلام لانے والوں میں صرف ) پانچ غلام، دو عورتوں اور ابوبکر رضی اللہ عنہم کے سوا اور کوئی نہ تھا۔' WHERE id = 3505;
UPDATE hadiths SET urdu = 'ہم سے ابوالحسن محمد بن مسکین نے بیان کیا، کہا ہم سے یحییٰ بن حسان نے بیان کیا، کہا ہم سے سلیمان نے بیان کیا، ان سے شریک بن ابی نمر نے، ان سے سعید بن مسیب نے بیان کیا، کہا مجھ کو ابوموسیٰ اشعری رضی اللہ عنہ نے خبر دی کہ انہوں نے ایک دن اپنے گھر میں وضو کیا اور اس ارادہ سے نکلے کہ آج دن بھر رسول اللہ صلی اللہ علیہ وسلم کا ساتھ نہ چھوڑوں گا۔ انہوں نے بیان کیا کہ پھر وہ مسجد نبوی میں حاضر ہوئے اور نبی کریم صلی اللہ علیہ وسلم کے متعلق پوچھا تو وہاں موجود لوگوں نے بتایا کہ نبی کریم صلی اللہ علیہ وسلم تو تشریف لے جا چکے ہیں اور آپ اس طرف تشریف لے گئے ہیں۔ چنانچہ میں آپ کے متعلق پوچھتا ہوا آپ کے پیچھے پیچھے نکلا اور آخر میں نے دیکھا کہ آپ ( قباء کے قریب ) بئراریس میں داخل ہو رہے ہیں، میں دروازے پر بیٹھ گیا اور اس کا دروازہ کھجور کی شاخوں سے بنا ہوا تھا۔ جب آپ قضائے حاجت کر چکے اور آپ نے وضو بھی کر لیا تو میں آپ کے پاس گیا۔ میں نے دیکھا کہ آپ بئراریس ( اس باغ کے کنویں ) کی منڈیر پر بیٹھے ہوئے ہیں، اپنی پنڈلیاں آپ نے کھول رکھی ہیں اور کنویں میں پاؤں لٹکائے ہوئے ہیں۔ میں نے آپ کو سلام کیا اور پھر واپس آ کر باغ کے دروازے پر بیٹھ گیا۔ میں نے سوچا کہ آج رسول اللہ صلی اللہ علیہ وسلم کا دربان رہوں گا۔ پھر ابوبکر رضی اللہ عنہ آئے اور دروازہ کھولنا چاہا تو میں نے پوچھا کہ کون صاحب ہیں؟ انہوں نے کہا کہ ابوبکر! میں نے کہا تھوڑی دیر ٹھہر جائیے۔ پھر میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا کہ ابوبکر دروازے پر موجود ہیں اور اندر آنے کی اجازت آپ سے چاہتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اجازت دے دو اور جنت کی بشارت بھی۔ میں دروازہ پر آیا اور ابوبکر رضی اللہ عنہ سے میں نے کہا کہ اندر تشریف لے جائیے اور رسول اللہ صلی اللہ علیہ وسلم نے آپ کو جنت کی بشارت دی ہے۔ ابوبکر رضی اللہ عنہ اندر داخل ہوئے اور اسی کنویں کی منڈیر پر آپ صلی اللہ علیہ وسلم کی داہنی طرف بیٹھ گئے اور اپنے دونوں پاؤں کنویں میں لٹکا لیے۔ جس طرح آپ صلی اللہ علیہ وسلم نے لٹکائے ہوئے تھے اور اپنی پنڈلیوں کو بھی کھول لیا تھا۔ پھر میں واپس آ کر اپنی جگہ پر بیٹھ گیا۔ میں آتے وقت اپنے بھائی کو وضو کرتا ہوا چھوڑ آیا تھا۔ وہ میرے ساتھ آنے والے تھے۔ میں نے اپنے دل میں کہا، کاش اللہ تعالیٰ فلاں کو خبر دے دیتا۔ ان کی مراد اپنے بھائی سے تھی اور انہیں یہاں پہنچا دیتا۔ اتنے میں کسی صاحب نے دروازہ پر دستک دی میں نے پوچھا کون صاحب ہیں؟ کہا کہ عمر بن خطاب۔ میں نے کہا کہ تھوڑی دیر کے لیے ٹھہر جائیے، چنانچہ میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور سلام کے بعد عرض کیا کہ عمر بن خطاب رضی اللہ عنہ دروازے پر کھڑے ہیں اندر آنے کی اجازت چاہتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اجازت دے دو اور جنت کی بشارت بھی پہنچا دو۔ میں واپس آیا اور کہا کہ اندر تشریف لے جائیے اور آپ کو رسول اللہ صلی اللہ علیہ وسلم نے جنت کی بشارت دی ہے۔ وہ بھی داخل ہوئے اور آپ کے ساتھ اسی منڈیر پر بائیں طرف بیٹھ گئے اور اپنے پاؤں کنویں میں لٹکا لیے۔ میں پھر دروازے پر آ کر بیٹھ گیا اور سوچتا رہا کہ اگر اللہ تعالیٰ فلاں ( ان کے بھائی ) کے ساتھ خیر چاہے گا تو اسے یہاں پہنچا دے گا، اتنے میں ایک اور صاحب آئے اور دروازے پر دستک دی، میں نے پوچھا کون صاحب ہیں؟ بولے کہ عثمان بن عفان، میں نے کہا تھوڑی دیر کے لیے رک جائیے، میں آپ کے پاس آیا اور میں نے آپ کو ان کی اطلاع دی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اجازت دے دو اور ایک مصیبت پر جو انہیں پہنچے گی جنت کی بشارت پہنچا دو۔ میں دروازے پر آیا اور میں نے ان سے کہا کہ اندر تشریف لے جائیے۔ نبی کریم صلی اللہ علیہ وسلم نے آپ کو جنت کی بشارت دی ہے، ایک مصیبت پر جو آپ کو پہنچے گی۔ وہ جب داخل ہوئے تو دیکھا چبوترہ پر جگہ نہیں ہے اس لیے وہ دوسری طرف آپ صلی اللہ علیہ وسلم کے سامنے بیٹھ گئے۔ شریک نے بیان کیا کہ سعید بن مسیب نے کہا میں نے اس سے ان کی قبروں کی تاویل لی ہے ( کہ اسی طرح بنیں گی ) ۔' WHERE id = 3517;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے اسماعیل نے بیان کیا، کہا ہم سے قیس نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ عمر رضی اللہ عنہ کے اسلام لانے کے بعد پھر ہمیں ہمیشہ عزت حاصل رہی۔' WHERE id = 3527;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھے حیوہ بن شریح نے خبر دی، کہا کہ مجھ سے ابوعقیل زہرہ بن معبد نے بیان کیا اور انہوں نے اپنے دادا عبداللہ بن ہشام رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم ایک مرتبہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھے۔ آپ اس وقت عمر بن خطاب رضی اللہ عنہ کا ہاتھ اپنے ہاتھ میں لیے ہوئے تھے۔' WHERE id = 3537;
UPDATE hadiths SET urdu = 'ہم سے محمد بن رافع نے بیان کیا، کہا ہم سے حسین نے، ان سے زائدۃ نے، ان سے ابوحصین نے، ان سے سعد بن عبیدہ نے بیان کیا کہ ایک شخص عبداللہ بن عمر رضی اللہ عنہما کی خدمت میں آیا اور عثمان رضی اللہ عنہ کے متعلق پوچھا، ابن عمر رضی اللہ عنہما نے ان کے محاسن کا ذکر کیا، پھر کہا کہ شاید یہ باتیں تمہیں بری لگی ہوں گی، اس نے کہا جی ہاں، ابن عمر رضی اللہ عنہما نے کہا اللہ تیری ناک خاک آلودہ کرے پھر اس نے علی رضی اللہ عنہ کے متعلق پوچھا، انہوں نے ان کے بھی محاسن ذکر کئے اور کہا کہ علی رضی اللہ عنہ کا گھرانہ نبی کریم صلی اللہ علیہ وسلم کے خاندان کا نہایت عمدہ گھرانہ ہے، پھر کہا شاید یہ باتیں بھی تمہیں بری لگی ہوں گی، اس نے کہا کہ جی ہاں، عبداللہ بن عمر رضی اللہ عنہما بولے اللہ تیری ناک خاک آلودہ کرے، جا، اور میرا جو بگاڑنا چاہے بگاڑ لینا، کچھ کمی نہ کرنا۔' WHERE id = 3547;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے علی بن مسہر نے، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے بیان کیا کہ مجھے مروان بن حکم نے خبر دی کہ جس سال نکسیر پھوٹنے کی بیماری پھوٹ پڑی تھی اس سال عثمان رضی اللہ عنہ کو اتنی سخت نکسیر پھوٹی کہ آپ حج کے لیے بھی نہ جا سکے، اور ( زندگی سے مایوس ہو کر ) وصیت بھی کر دی، پھر ان کی خدمت میں قریش کے ایک صاحب گئے اور کہا کہ آپ کسی کو اپنا خلیفہ بنا دیں۔ عثمان رضی اللہ عنہ نے دریافت فرمایا: کیا یہ سب کی خواہش ہے، انہوں نے کہا جی ہاں۔ آپ نے پوچھا کہ کسے بناؤں؟ اس پر وہ خاموش ہو گئے۔ اس کے بعد ایک دوسرے صاحب گئے۔ میرا خیال ہے کہ وہ حارث تھے،۔ انہوں نے بھی یہی کہا کہ آپ کسی کو خلیفہ بنا دیں، آپ نے ان سے بھی پوچھا کیا یہ سب کی خواہش ہے؟ انہوں نے کہا: جی ہاں، آپ نے پوچھا: لوگوں کی رائے کس کے لیے ہے؟ اس پر وہ بھی خاموش ہو گئے، تو آپ نے خود فرمایا: غالباً زبیر کی طرف لوگوں کا رجحان ہے؟ انہوں نے کہا جی ہاں، پھر آپ صلی اللہ علیہ وسلم نے فرمایا: اس ذات کی قسم جس کے ہاتھ میں میری جان ہے میرے علم کے مطابق بھی وہی ان میں سب سے بہتر ہیں اور بلاشبہ وہ رسول اللہ صلی اللہ علیہ وسلم کی نظروں میں بھی ان میں سب سے زیادہ محبوب تھے۔' WHERE id = 3558;
UPDATE hadiths SET urdu = 'ہم سے ابولیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ سے علی بن حسین نے بیان کیا اور ان سے مسور بن مخرمہ رضی اللہ عنہ نے بیان کیا کہ علی رضی اللہ عنہ نے ابوجہل کی لڑکی کو ( جو مسلمان تھیں ) پیغام نکاح دیا، اس کی اطلاع جب فاطمہ رضی اللہ عنہا کو ہوئی تو وہ رسول اللہ صلی اللہ علیہ وسلم کے پاس آئیں اور عرض کیا کہ آپ کی قوم کا خیال ہے کہ آپ کو اپنی بیٹیوں کی خاطر ( جب انہیں کوئی تکلیف دے ) کسی پر غصہ نہیں آتا۔ اب دیکھئیے یہ علی ابوجہل کی بیٹی سے نکاح کرنا چاہتے ہیں، اس پر آپ صلی اللہ علیہ وسلم نے صحابہ کو خطاب فرمایا: میں نے آپ صلی اللہ علیہ وسلم کو خطبہ پڑھتے سنا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا: امابعد: میں نے ابوالعاص بن ربیع سے ( زینب رضی اللہ عنہا کی، آپ کی سب سے بڑی صاحبزادی ) شادی کرائی تو انہوں نے جو بات بھی کہی اس میں وہ سچے اترے اور بلاشبہ فاطمہ بھی میرے ( جسم کا ) ایک ٹکڑا ہے اور مجھے یہ پسند نہیں کہ کوئی بھی اسے تکلیف دے۔ اللہ کی قسم! رسول اللہ کی بیٹی اور اللہ تعالیٰ کے ایک دشمن کی بیٹی ایک شخص کے پاس جمع نہیں ہو سکتیں۔ چنانچہ علی رضی اللہ عنہ نے اس شادی کا ارادہ ترک کر دیا۔ محمد بن عمرو بن حلحلہ نے ابن شہاب سے یہ اضافہ کیا ہے، انہوں نے علی بن حسین سے اور انہوں نے مسور رضی اللہ عنہ سے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ نے بنی عبدشمس کے اپنے ایک داماد کا ذکر کیا اور حقوق دامادی کی ادائیگی کی تعریف فرمائی۔ پھر فرمایا کہ انہوں نے مجھ سے جو بات بھی کہی سچی کہی اور جو وعدہ بھی کیا پورا کر دکھایا۔' WHERE id = 3569;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے مغیرہ نے بیان کیا، ان سے ابراہیم نے بیان کیا کہ علقمہ رضی اللہ عنہ شام میں تشریف لے گئے اور مسجد میں جا کر یہ دعا کی۔ اے اللہ! مجھے ایک نیک ساتھی عطا فرما، چنانچہ آپ کو ابودرداء رضی اللہ عنہ کی صحبت نصیب ہوئی۔ ابودرداء رضی اللہ عنہ نے دریافت کیا: تمہارا تعلق کہاں سے ہے؟ عرض کیا کہ کوفہ سے، اس پر انہوں نے کہا: کیا تمہارے یہاں نبی کریم صلی اللہ علیہ وسلم کے راز دار نہیں ہیں کہ ان رازوں کو ان کے سوا اور کوئی نہیں جانتا؟ ( ان کی مراد ابوحذیفہ رضی اللہ عنہ سے تھی ) انہوں نے بیان کیا کہ میں نے عرض کیا جی ہاں موجود ہیں، پھر انہوں نے کہا کیا تم میں وہ شخص نہیں ہیں جنہیں اللہ تعالیٰ نے اپنے نبی کی زبانی شیطان سے اپنی پناہ دی تھی۔ ان کی مراد عمار رضی اللہ عنہ سے تھی۔ میں نے عرض کیا کہ جی ہاں وہ بھی موجود ہیں، اس کے بعد انہوں نے دریافت کیا کہ عبداللہ بن مسعود رضی اللہ عنہ آیت «والليل إذا يغشى * والنهار إذا تجلى‏» کی قرآت کس طرح کرتے تھے؟ میں نے کہا کہ وہ ( «وما خلق» کے حذف کے ساتھ ) «والذكر والأنثى‏» پڑھا کرتے تھے۔ اس پر انہوں نے کہا یہ شام والے ہمیشہ اس کوشش میں رہے کہ اس آیت کی تلاوت کو جس طرح میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا اس سے مجھے ہٹا دیں۔' WHERE id = 3581;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے محمد بن ابی یعقوب نے، انہوں نے ابن ابی نعم سے سنا اور انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا اور کسی نے ان سے محرم کے بارے میں پوچھا تھا، شعبہ نے بیان کیا کہ میرے خیال میں یہ پوچھا تھا کہ اگر کوئی شخص ( احرام کی حالت میں ) مکھی مار دے تو اسے کیا کفارہ دینا پڑے گا؟ اس پر عبداللہ بن عمر رضی اللہ عنہما نے فرمایا: عراق کے لوگ مکھی کے بارے میں سوال کرتے ہیں جب کہ یہی لوگ رسول اللہ صلی اللہ علیہ وسلم کے نواسے کو قتل کر چکے ہیں، جن کے بارے میں نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ دونوں ( نواسے حسن و حسین رضی اللہ عنہما ) دنیا میں میرے دو پھول ہیں۔' WHERE id = 3591;
UPDATE hadiths SET urdu = 'ہم سے ابن ابی مریم نے بیان کیا، کہا ہم سے نافع بن عمر نے بیان کیا، کہا مجھ سے ابن ابی ملیکہ نے بیان کیا کہ عبداللہ بن عباس رضی اللہ عنہما سے کہا گیا کہ امیرالمؤمنین معاویہ رضی اللہ عنہ کے متعلق آپ کیا فرماتے ہیں، انہوں نے وتر کی نماز صرف ایک رکعت پڑھی ہے؟ انہوں نے کہا کہ وہ خود فقیہ ہیں۔' WHERE id = 3603;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، کہا ہم سے حماد نے کہا، ہم سے ہشام نے، انہوں نے اپنے والد (عروہ) سے، انہوں نے کہا کہ لوگ آپ صلی اللہ علیہ وسلم کو تحفے بھیجنے میں عائشہ رضی اللہ عنہا کی باری کا انتظار کیا کرتے تھے۔ عائشہ رضی اللہ عنہا کہتی ہیں کہ میری سوکنیں سب ام سلمہ رضی اللہ عنہا کے پاس گئیں اور ان سے کہا: اللہ کی قسم لوگ جان بوجھ کر اپنے تحفے اس دن بھیجتے ہیں جس دن عائشہ رضی اللہ عنہا کی باری ہوتی ہے، ہم بھی عائشہ رضی اللہ عنہا کی طرح اپنے لیے فائدہ چاہتی ہیں، اس لیے تم نبی کریم صلی اللہ علیہ وسلم سے کہو کہ آپ لوگوں کو فرما دیں کہ میں جس بھی بیوی کے پاس رہوں جس کی بھی باری ہو اسی گھر میں تحفے بھیج دیا کرو۔ ام سلمہ رضی اللہ عنہا نے یہ بات آپ صلی اللہ علیہ وسلم کے سامنے بیان کی، آپ نے کچھ بھی جواب نہیں دیا۔ انہوں نے دوبارہ عرض کیا جب بھی جواب نہ دیا، پھر تیسری بار عرض کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا: اے ام سلمہ! عائشہ کے بارے میں مجھ کو نہ ستاؤ۔ اللہ کی قسم! تم میں سے کسی بیوی کے لحاف میں ( جو میں اوڑھتا ہوں سوتے وقت ) مجھ پر وحی نازل نہیں ہوتی ہاں ( عائشہ کا مقام یہ ہے ) ان کے لحاف میں وحی نازل ہوتی ہے۔' WHERE id = 3613;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، انہوں نے کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے عبدالعزیز نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ایک مرتبہ نبی کریم صلی اللہ علیہ وسلم نے ( انصار کی ) عورتوں اور بچوں کو میرے گمان کے مطابق کسی شادی سے واپس آتے ہوئے دیکھا تو آپ صلی اللہ علیہ وسلم کھڑے ہو گئے اور فرمایا اللہ ( گواہ ہے ) تم لوگ مجھے سب سے زیادہ عزیز ہو، تین بار آپ نے ایسا ہی فرمایا۔' WHERE id = 3623;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے ابوایاس نے بیان کیا ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( خندق کھودتے وقت ) فرمایا ”حقیقی زندگی تو صرف آخرت کی زندگی ہے، پس اے اللہ! انصار اور مہاجرین پر اپنا کرم فرما۔“ اور قتادہ سے روایت ہے ان سے انس رضی اللہ عنہ نے بیان کیا نبی کریم صلی اللہ علیہ وسلم سے اسی طرح، اور انہوں نے بیان کیا اس میں یوں ہے ”پس انصار کی مغفرت فرما دے۔“' WHERE id = 3633;
UPDATE hadiths SET urdu = 'ہم سے علی بن مسلم نے بیان کیا، کہا ہم سے حبان نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، انہیں قتادہ نے خبر دی اور انہیں انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی مجلس سے اٹھ کر دو صحابی ایک تاریک رات میں ( اپنے گھر کی طرف ) جانے لگے تو ایک غیبی نور ان کے آگے آگے چل رہا تھا، پھر جب وہ جدا ہوئے تو ان کے ساتھ ساتھ وہ نور بھی الگ الگ ہو گیا اور معمر نے ثابت سے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ اسید بن حضیر رضی اللہ عنہ اور ایک دوسرے انصاری صحابی ( کے ساتھ یہ کرامت پیش آئی تھی ) اور حماد نے بیان کیا، انہیں ثابت نے خبر دی اور انہیں انس رضی اللہ عنہ نے کہ اسید بن حضیر اور عباد بن بشر رضی اللہ عنہما کے ساتھ یہ کرامت پیش آئی تھی۔ یہ نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے نقل کیا ہے۔' WHERE id = 3643;
UPDATE hadiths SET urdu = 'مجھ سے محمد نے بیان کیا، کہا ہم کو خبر دی عبدہ نے، انہیں ہشام بن عروہ نے، ان سے ان کے والد نے بیان کیا کہ میں نے عبداللہ بن جعفر سے سنا، انہوں نے بیان کیا کہ میں نے علی رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا آپ نے فرمایا ( دوسری سند ) اور مجھ سے صدقہ نے بیان کیا، کہا ہم کو عبدہ نے خبر دی، انہیں ہشام نے ان سے ان کے والد نے بیان کیا کہ میں نے عبداللہ بن جعفر سے سنا انہوں نے علی رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( اپنے زمانے میں ) مریم علیہاالسلام سب سے افضل عورت تھیں اور ( اس امت میں ) خدیجہ ( رضی اللہ عنہا ) سب سے افضل ہیں۔“' WHERE id = 3653;
UPDATE hadiths SET urdu = '(اور عبدان نے بیان کیا، انہیں عبداللہ نے خبر دی انہیں یونس نے خبر دی، انہیں زہری نے، ان سے عروہ نے بیان کیا کہ عائشہ رضی اللہ عنہا نے بیان کیا: ہند بنت عتبہ رضی اللہ عنہا رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں اسلام لانے کے بعد ) حاضر ہوئیں اور کہنے لگیں یا رسول اللہ! روئے زمین پر کسی گھرانے کی ذلت آپ کے گھرانے کی ذلت سی زیادہ میرے لیے خوشی کا باعث نہیں تھی لیکن آج کسی گھرانے کی عزت روئے زمین پر آپ کے گھرانے کی عزت سے زیادہ میرے لیے خوشی کی وجہ نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اس میں ابھی اور ترقی ہو گی۔ اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے“ پھر ہند نے کہا: یا رسول اللہ! ابوسفیان بہت بخیل ہیں تو کیا اس میں کچھ حرج ہے اگر میں ان کے مال میں سے ( ان کی اجازت کے بغیر ) بال بچوں کو کھلا دیا اور پلا دیا کروں؟ آپ صلی اللہ علیہ وسلم فرمایا ہاں لیکن میں سمجھتا ہوں کہ یہ دستور کے مطابق ہونا چاہئے۔' WHERE id = 3663;
UPDATE hadiths SET urdu = 'مجھ سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم کو علی بن مسہر نے خبر دی، انہیں ہشام نے، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک کالی عورت جو کسی عرب کی باندی تھی اسلام لائی اور مسجد میں اس کے رہنے کے لیے ایک کوٹھری تھی۔ عائشہ رضی اللہ عنہا نے بیان کیا وہ ہمارے یہاں آیا کرتی اور باتیں کیا کرتی تھی، لیکن جب باتوں سے فارغ ہو جاتی تو وہ یہ شعر پڑھتی ”اور ہار والا دن بھی ہمارے رب کے عجائب قدرت میں سے ہے، کہ اسی نے ( بفضلہ ) کفر کے شہر سے مجھے چھڑایا۔“ اس نے جب کئی مرتبہ یہ شعر پڑھا تو عائشہ رضی اللہ عنہا نے اس سے دریافت کیا کہ ہار والے دن کا قصہ کیا ہے؟ اس نے بیان کیا کہ میرے مالکوں کے گھرانے کی ایک لڑکی ( جو نئی دولہن تھی ) لال چمڑے کا ایک ہار باندھے ہوئے تھی۔ وہ باہر نکلی تو اتفاق سے وہ گر گیا۔ ایک چیل کی اس پر نظر پڑی اور وہ اسے گوشت سمجھ کر اٹھا لے گئی۔ لوگوں نے مجھ پر اس کی چوری کی تہمت لگائی اور مجھے سزائیں دینی شروع کیں۔ یہاں تک کہ میری شرمگاہ کی بھی تلاشی لی۔ خیر وہ ابھی میرے چاروں طرف جمع ہی تھے اور میں اپنی مصیبت میں مبتلا تھی کہ چیل آئی اور ہمارے سروں کے بالکل اوپر اڑنے لگی۔ پھر اس نے وہی ہار نیچے گرا دیا۔ لوگوں نے اسے اٹھا لیا تو میں نے ان سے کہا اسی کے لیے تم لوگ مجھے اتہام لگا رہے تھے حالانکہ میں بےگناہ تھی۔' WHERE id = 3673;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے قطن ابوالہیثم نے کہا، ہم سے ابویزید مدنی نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا جاہلیت میں سب سے پہلا قسامہ ہمارے ہی قبیلہ بنو ہاشم میں ہوا تھا، بنو ہاشم کے ایک شخص عمرو بن علقمہ کو قریش کے کسی دوسرے خاندان کے ایک شخص ( خداش بن عبداللہ عامری ) نے نوکری پر رکھا، اب یہ ہاشمی نوکر اپنے صاحب کے ساتھ اس کے اونٹ لے کر شام کی طرف چلا وہاں کہیں اس نوکر کے پاس سے ایک دوسرا ہاشمی شخص گزرا، اس کی بوری کا بندھن ٹوٹ گیا تھا۔ اس نے اپنے نوکر بھائی سے التجا کی میری مدد کر اونٹ باندھنے کی مجھے ایک رسی دیدے، میں اس سے اپنا تھیلا باندھوں اگر رسی نہ ہو گی تو وہ بھاگ تھوڑے جائے گا۔ اس نے ایک رسی اسے دے دی اور اس نے اپنی بوری کا منہ اس سے باندھ لیا ( اور چلا گیا ) ۔ پھر جب اس نوکر اور صاحب نے ایک منزل پر پڑاؤ کیا تو تمام اونٹ باندھے گئے لیکن ایک اونٹ کھلا رہا۔ جس صاحب نے ہاشمی کو نوکری پر اپنے ساتھ رکھا تھا اس نے پوچھا سب اونٹ تو باندھے، یہ اونٹ کیوں نہیں باندھا گیا کیا بات ہے؟ نوکر نے کہا اس کی رسی موجود نہیں ہے۔ صاحب نے پوچھا کیا ہوا اس کی رسی؟ اور غصہ میں آ کر ایک لکڑی اس پر پھینک ماری اس کی موت آن پہنچی۔ اس کے ( مرنے سے پہلے ) وہاں سے ایک یمنی شخص گزر رہا تھا۔ ہاشمی نوکر نے پوچھا کیا حج کے لیے ہر سال تم مکہ جاتے ہو؟ اس نے کہا ابھی تو ارادہ نہیں ہے لیکن میں کبھی جاتا رہتا ہوں۔ اس نوکر نے کہا جب بھی تم مکہ پہنچو کیا میرا ایک پیغام پہنچا دو گے؟ اس نے کہا ہاں پہنچا دوں گا۔ اس نوکر نے کہا کہ جب بھی تم حج کے لیے جاؤ تو پکارنا: اے قریش کے لوگو! جب وہ تمہارے پاس جمع ہو جائیں تو پکارنا: اے بنی ہاشم! جب وہ تمہارے پاس آ جائیں تو ان سے ابوطالب پوچھنا اور انہیں بتلانا کہ فلاں شخص نے مجھے ایک رسی کے لیے قتل کر دیا۔ اس وصیت کے بعد وہ نوکر مر گیا، پھر جب اس کا صاحب مکہ آیا تو ابوطالب کے یہاں بھی گیا۔ جناب ابوطالب نے دریافت کیا ہمارے قبیلہ کے جس شخص کو تم اپنے ساتھ نوکری کے لیے لے گئے تھے اس کا کیا ہوا؟ اس نے کہا کہ وہ بیمار ہو گیا تھا میں نے خدمت کرنے میں کوئی کسر نہیں اٹھا رکھی ( لیکن وہ مر گیا تو ) میں نے اسے دفن کر دیا۔ ابوطالب نے کہا کہ اس کے لیے تمہاری طرف سے یہی ہونا چاہئے تھا۔ ایک مدت کے بعد وہی یمنی شخص جسے ہاشمی نوکر نے پیغام پہنچانے کی وصیت کی تھی، موسم حج میں آیا اور آواز دی: اے قریش کے لوگو! لوگوں نے بتا دیا کہ یہاں ہیں قریش اس نے آواز دی، اے بنو ہاشم! لوگوں نے بتایا کہ بنو ہاشم یہ ہیں اس نے پوچھا ابوطالب کہاں ہیں؟ لوگوں نے بتایا تو اس نے کہا کہ فلاں شخص نے مجھے ایک پیغام پہنچانے کے لیے کہا تھا کہ فلاں شخص نے اسے ایک رسی کی وجہ سے قتل کر دیا ہے۔ اب جناب ابوطالب اس صاحب کے یہاں آئے اور کہا کہ ان تین چیزوں میں سے کوئی چیز پسند کر لو اگر تم چاہو تو سو اونٹ دیت میں دے دو کیونکہ تم نے ہمارے قبیلہ کے آدمی کو قتل کیا ہے اور اگر چاہو تو تمہاری قوم کے پچاس آدمی اس کی قسم کھا لیں کہ تم نے اسے قتل نہیں کیا۔ اگر تم اس پر تیار نہیں تو ہم تمہیں اس کے بدلے میں قتل کر دیں گے۔ وہ شخص اپنی قوم کے پاس آیا تو وہ اس کے لیے تیار ہو گئے کہ ہم قسم کھا لیں گے۔ پھر بنو ہاشم کی ایک عورت ابوطالب کے پاس آئی جو اسی قبیلہ کے ایک شخص سے بیاہی ہوئی تھی اور اپنے اس شوہر سے اس کا بچہ بھی تھا۔ اس نے کہا: اے ابوطالب! آپ مہربانی کریں اور میرے اس لڑکے کو ان پچاس آدمیوں میں معاف کر دیں اور جہاں قسمیں لی جاتی ہیں ( یعنی رکن اور مقام ابراہیم کے درمیان ) اس سے وہاں قسم نہ لیں۔ ابوطالب نے اسے معاف کر دیا۔ اس کے بعد ان میں کا ایک اور شخص آیا اور کہا: اے ابوطالب! آپ نے سو اونٹوں کی جگہ پچاس آدمیوں سے قسم طلب کی ہے، اس طرح ہر شخص پر دو دو اونٹ پڑتے ہیں۔ یہ دو اونٹ میری طرف سے آپ قبول کر لیں اور مجھے اس مقام پر قسم کھانے کے لیے مجبور نہ کریں جہاں قسم لی جاتی ہے۔ ابوطالب نے اسے بھی منظور کر لیا۔ اس کے بعد بقیہ جو اڑتالیس آدمی آئے اور انہوں نے قسم کھائی۔ ابن عباس رضی اللہ عنہما نے کہا: اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے ابھی اس واقعہ کو پورا سال بھی نہیں گزرا تھا کہ ان اڑتالیس آدمیوں میں سے ایک بھی ایسا نہیں رہا جو آنکھ ہلاتا۔' WHERE id = 3683;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے منصور نے، کہا مجھ سے سعید بن جبیر نے بیان کیا یا (منصور نے) اس طرح بیان کیا کہ مجھ سے حکم نے بیان کیا، ان سے سعید بن جبیر نے بیان کیا کہ مجھ سے عبدالرحمٰن بن ابزیٰ رضی اللہ عنہ نے کہا کہ ابن عباس رضی اللہ عنہما سے ان دونوں آیتوں کے متعلق پوچھو کہ ان میں مطابقت کس طرح پیدا کی جائے ( ایک آیت «ولا تقتلوا النفس التي حرم الله» اور دوسری آیت «ومن يقتل مؤمنا متعمدا‏» ہے۔ ابن عباس رضی اللہ عنہما سے میں نے پوچھا تو انہوں نے بتلایا کہ جب سورۃ الفرقان کی آیت نازل ہوئی تو مشرکین مکہ نے کہا ہم نے تو ان جانوں کا بھی خون کیا ہے جن کے قتل کو اللہ تعالیٰ نے حرام قرار دیا تھا ہم اللہ کے سوا دوسرے معبودوں کی عبادت بھی کرتے رہے ہیں اور بدکاریوں کا بھی ہم نے ارتکاب کیا ہے۔ اس پر اللہ تعالیٰ نے آیت نازل فرمائی «إلا من تاب وآمن‏» ”وہ لوگ اس حکم سے الگ ہیں جو توبہ کر لیں اور ایمان لے آئیں“ تو یہ آیت ان کے حق میں نہیں ہے لیکن سورۃ النساء کی آیت اس شخص کے بارے میں ہے جو اسلام اور شرائع اسلام کے احکام جان کر بھی کسی کو قتل کرے تو اس کی سزا جہنم ہے۔ میں نے عبداللہ بن عباس رضی اللہ عنہما کے اس ارشاد کا ذکر مجاہد سے کیا تو انہوں نے کہا کہ وہ لوگ اس حکم سے الگ ہیں جو توبہ کر لیں۔)' WHERE id = 3693;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ میں نے عمرو بن دینار سے سنا، انہوں نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ جب عمر رضی اللہ عنہ اسلام لائے تو لوگ ان کے گھر کے قریب جمع ہو گئے اور کہنے لگے کہ عمر بےدین ہو گیا ہے۔ میں ان دنوں بچہ تھا اور اس وقت اپنے گھر کی چھت پر چڑھا ہوا تھا۔ اچانک ایک شخص آیا جو ریشم کی قباء پہنے ہوئے تھا، اس شخص نے لوگوں سے کہا ٹھیک ہے عمر بےدین ہو گیا لیکن یہ مجمع کیسا ہے؟ دیکھو میں عمر کو پناہ دے چکا ہوں۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے دیکھا کہ اس کی یہ بات سنتے ہی لوگ الگ الگ ہو گئے۔ میں نے پوچھا یہ کون صاحب تھے؟ عمر رضی اللہ عنہ نے کہا کہ یہ عاص بن وائل ہیں۔' WHERE id = 3703;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن حماد نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے سلیمان نے، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ نے بیان کیا کہ ( ابتداء اسلام میں ) نبی کریم صلی اللہ علیہ وسلم نماز پڑھتے ہوتے اور ہم آپ کو سلام کرتے تو آپ نماز ہی میں جواب عنایت فرماتے تھے۔ لیکن جب ہم نجاشی کے ملک حبشہ سے واپس ( مدینہ ) آئے اور ہم نے ( نماز پڑھتے میں ) آپ کو سلام کیا تو آپ نے جواب نہیں دیا۔ نماز کے بعد ہم نے عرض کیا: یا رسول اللہ! ہم پہلے آپ کو سلام کرتے تھے تو آپ نماز ہی میں جواب عنایت فرمایا کرتے تھے؟ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ ہاں نماز میں آدمی کو دوسرا شغل ہوتا ہے۔ سلیمان اعمش نے بیان کیا کہ میں نے ابراہیم نخعی سے پوچھا ایسے موقعہ پر آپ کیا کرتے ہیں؟ انہوں نے کہا کہ میں دل میں جواب دے دیتا ہوں۔' WHERE id = 3713;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا ہم سے یزید بن عبداللہ ابن الہاد نے، ان سے عبداللہ بن خباب نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم کی مجلس میں آپ کے چچا کا ذکر ہو رہا تھا تو آپ صلی اللہ علیہ وسلم نے فرمایا ”شاید قیامت کے دن انہیں میری شفاعت کام آ جائے اور انہیں صرف ٹخنوں تک جہنم میں رکھا جائے جس سے ان کا دماغ کھولے گا۔“ ہم سے ابراہیم بن حمزہ نے بیان کیا، کہا ہم سے ابن ابوحازم اور درا وردی نے بیان کیا یزید سے اسی مذکورہ حدیث کی طرح، البتہ اس روایت میں یہ بھی ہے کہ ابوطالب کے دماغ کا بھیجہ اس سے کھولے گا۔' WHERE id = 3723;
UPDATE hadiths SET urdu = 'ہم سے معلی نے بیان کیا، کہا ہم سے وہیب بن خالد نے بیان کیا، ان سے ہشام بن عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم مجھے دو مرتبہ خواب میں دکھائی گئی ہو۔ میں نے دیکھا کہ تم ایک ریشمی کپڑے میں لپٹی ہوئی ہو اور کہا جا رہا ہے کہ یہ آپ کی بیوی ہیں ان کا چہرہ کھولئے۔ میں نے چہرہ کھول کر دیکھا تو تم تھیں۔ میں نے سوچا کہ اگر یہ خواب اللہ تعالیٰ کی جانب سے ہے تو وہ خود اس کو پورا فرمائے گا۔“' WHERE id = 3733;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے کہ ابن شہاب نے بیان کیا، انہیں عروہ بن زبیر نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب سے میں نے ہوش سنبھالا میں نے اپنے ماں باپ کو دین اسلام ہی پر پایا اور کوئی دن ایسا نہیں گزرتا تھا جس میں رسول اللہ صلی اللہ علیہ وسلم ہمارے گھر صبح و شام دونوں وقت تشریف نہ لاتے ہوں۔ پھر جب ( مکہ میں ) مسلمانوں کو ستایا جانے لگا تو ابوبکر رضی اللہ عنہ حبشہ کی ہجرت کا ارادہ کر کے نکلے۔ جب آپ مقام برک غماد پر پہنچے تو آپ کی ملاقات ابن الدغنہ سے ہوئی جو قبیلہ قارہ کا سردار تھا۔ اس نے پوچھا ابوبکر! کہاں کا ارادہ ہے؟ انہوں نے کہا کہ میری قوم نے مجھے نکال دیا ہے اب میں نے ارادہ کر لیا ہے کہ ملک ملک کی سیاحت کروں ( اور آزادی کے ساتھ ) اپنے رب کی عبادت کروں۔ ابن الدغنہ نے کہا لیکن ابوبکر! تم جیسے انسان کو اپنے وطن سے نہ خود نکلنا چاہئے اور نہ اسے نکالا جانا چاہیے۔ تم محتاجوں کی مدد کرتے ہو، صلہ رحمی کرتے ہو، بے کسوں کا بوجھ اٹھاتے ہو، مہمان نوازی کرتے ہو اور حق پر قائم رہنے کی وجہ سے کسی پر آنے والی مصیبتوں میں اس کی مدد کرتے ہو، میں تمہیں پناہ دیتا ہوں واپس چلو اور اپنے شہر ہی میں اپنے رب کی عبادت کرو۔ چنانچہ وہ واپس آ گئے اور ابن الدغنہ بھی آپ کے ساتھ واپس آیا۔ اس کے بعد ابن الدغنہ قریش کے تمام سرداروں کے یہاں شام کے وقت گیا اور سب سے اس نے کہا کہ ابوبکر جیسے شخص کو نہ خود نکلنا چاہیے اور نہ نکالا جانا چاہیے۔ کیا تم ایسے شخص کو نکال دو گے جو محتاجوں کی امداد کرتا ہے، صلہ رحمی کرتا ہے، بے کسوں کا بوجھ اٹھاتا ہے، مہمان نوازی کرتا ہے اور حق کی وجہ سے کسی پر آنے والی مصیبتوں میں اس کی مدد کرتا ہے؟ قریش نے ابن الدغنہ کی پناہ سے انکار نہیں کیا صرف اتنا کہا کہ ابوبکر رضی اللہ عنہ سے کہہ دو کہ اپنے رب کی عبادت اپنے گھر کے اندر ہی کیا کریں، وہیں نماز پڑھیں اور جو جی چاہے وہیں پڑھیں، اپنی عبادات سے ہمیں تکلیف نہ پہنچائیں، اس کا اظہار نہ کریں کیونکہ ہمیں اس کا ڈر ہے کہ کہیں ہماری عورتیں اور بچے اس فتنہ میں نہ مبتلا ہو جائیں۔ یہ باتیں ابن الدغنہ نے ابوبکر رضی اللہ عنہ سے بھی آ کر کہہ دیں کچھ دنوں تک تو آپ اس پر قائم رہے اور اپنے گھر کے اندر ہی اپنے رب کی عبادت کرتے رہے، نہ نماز برسر عام پڑھتے اور نہ گھر کے سوا کسی اور جگہ تلاوت قرآن کرتے تھے لیکن پھر انہوں نے کچھ سوچا اور اپنے گھر کے سامنے نماز پڑھنے کے لیے ایک جگہ بنائی جہاں آپ نے نماز پڑھنی شروع کی اور تلاوت قرآن بھی وہیں کرنے لگے۔ نتیجہ یہ ہوا کہ وہاں مشرکین کی عورتوں اور بچوں کا مجمع ہونے لگا۔ وہ سب حیرت اور پسندیدگی کے ساتھ دیکھتے رہا کرتے تھے۔ ابوبکر رضی اللہ عنہ بڑے نرم دل انسان تھے۔ جب قرآن مجید کی تلاوت کرتے تو آنسوؤں کو روک نہ سکتے تھے۔ اس صورت حال سے مشرکین قریش کے سردار گھبرا گئے اور انہوں نے ابن الدغنہ کو بلا بھیجا جب ابن الدغنہ ان کے پاس آیا تو انہوں نے اس سے کہا کہ ہم نے ابوبکر کے لیے تمہاری پناہ اس شرط کے ساتھ تسلیم کی تھی کہ اپنے رب کی عبادت وہ اپنے گھر کے اندر کیا کریں لیکن انہوں نے شرط کی خلاف ورزی کی ہے اور اپنے گھر کے سامنے نماز پڑھنے کے لیے ایک جگہ بنا کر برسر عام نماز پڑھنے اور تلاوت قرآن کرنے لگے ہیں۔ ہمیں اس کا ڈر ہے کہ کہیں ہماری عورتیں اور بچے اس فتنے میں نہ مبتلا ہو جائیں اس لیے تم انہیں روک دو، اگر انہیں یہ شرط منظور ہو کہ اپنے رب کی عبادت صرف اپنے گھر کے اندر ہی کیا کریں تو وہ ایسا کر سکتے ہیں لیکن اگر وہ اظہار ہی کریں تو ان سے کہو کہ تمہاری پناہ واپس دے دیں، کیونکہ ہمیں یہ پسند نہیں کہ تمہاری دی ہوئی پناہ میں ہم دخل اندازی کریں لیکن ابوبکر کے اس اظہار کو بھی ہم برداشت نہیں کر سکتے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر ابن الدغنہ ابوبکر رضی اللہ عنہ کے یہاں آیا اور اس نے کہا کہ جس شرط کے ساتھ میں نے آپ کے ساتھ عہد کیا تھا وہ آپ کو معلوم ہے، اب یا آپ اس شرط پر قائم رہیے یا پھر میرے عہد کو واپس کیجئے کیونکہ یہ مجھے گوارا نہیں کہ عرب کے کانوں تک یہ بات پہنچے کہ میں نے ایک شخص کو پناہ دی تھی۔ لیکن اس میں ( قریش کی طرف سے ) دخل اندازی کی گئی۔ اس پر ابوبکر رضی اللہ عنہ نے کہا میں تمہاری پناہ واپس کرتا ہوں اور اپنے رب عزوجل کی پناہ پر راضی اور خوش ہوں۔ نبی کریم صلی اللہ علیہ وسلم ان دنوں مکہ میں تشریف رکھتے تھے۔ آپ نے مسلمانوں سے فرمایا کہ تمہاری ہجرت کی جگہ مجھے خواب میں دکھائی گئی ہے وہاں کھجور کے باغات ہیں اور دو پتھریلے میدانوں کے درمیان واقع ہے، چنانچہ جنہیں ہجرت کرنی تھی انہوں نے مدینہ کی طرف ہجرت کی اور جو لوگ سر زمین حبشہ ہجرت کر کے چلے گئے تھے وہ بھی مدینہ چلے آئے۔ ابوبکر رضی اللہ عنہ نے بھی مدینہ ہجرت کی تیاری شروع کر دی لیکن نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ کچھ دنوں کے لیے توقف کرو۔ مجھے توقع ہے کہ ہجرت کی اجازت مجھے بھی مل جائے گی۔ ابوبکر رضی اللہ عنہ نے عرض کیا: کیا واقعی آپ کو بھی اس کی توقع ہے، میرے باپ آپ پر فدا ہوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ ابوبکر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کی رفاقت سفر کے خیال سے اپنا ارادہ ملتوی کر دیا اور دو اونٹنیوں کو جو ان کے پاس تھیں کیکر کے پتے کھلا کر تیار کرنے لگے چار مہینے تک۔ ابن شہاب نے بیان کیا، ان سے عروہ نے کہ عائشہ رضی اللہ عنہا نے کہا، ایک دن ہم ابوبکر رضی اللہ عنہ کے گھر بیٹھے ہوئے تھے بھری دوپہر تھی کہ کسی نے ابوبکر رضی اللہ عنہ سے کہا رسول اللہ صلی اللہ علیہ وسلم سر پر رومال ڈالے تشریف لا رہے ہیں، نبی کریم صلی اللہ علیہ وسلم کا معمول ہمارے یہاں اس وقت آنے کا نہیں تھا۔ ابوبکر رضی اللہ عنہ بولے نبی کریم صلی اللہ علیہ وسلم پر میرے ماں باپ فدا ہوں۔ ایسے وقت میں آپ کسی خاص وجہ سے ہی تشریف لا رہے ہوں گے۔ انہوں نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم تشریف لائے اور اندر آنے کی اجازت چاہی ابوبکر رضی اللہ عنہ نے آپ کو اجازت دی تو آپ اندر داخل ہوئے پھر آپ صلی اللہ علیہ وسلم نے ان سے فرمایا اس وقت یہاں سے تھوڑی دیر کے لیے سب کو اٹھا دو۔ ابوبکر رضی اللہ عنہ نے عرض کیا یہاں اس وقت تو سب گھر کے ہی آدمی ہیں، میرے باپ آپ پر فدا ہوں، یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے اس کے بعد فرمایا کہ مجھے ہجرت کی اجازت دے دی گئی ہے۔ ابوبکر رضی اللہ عنہ نے عرض کیا: میرے ماں باپ آپ پر فدا ہوں، یا رسول اللہ! کیا مجھے رفاقت سفر کا شرف حاصل ہو سکے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ انہوں نے عرض کیا یا رسول اللہ! میرے ماں باپ آپ پر فدا ہوں ان دونوں میں سے ایک اونٹنی آپ لے لیجئے! نبی کریم صلی اللہ علیہ وسلم نے فرمایا لیکن قیمت سے، عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر ہم نے جلدی جلدی ان کے لیے تیاریاں شروع کر دیں اور کچھ توشہ ایک تھیلے میں رکھ دیا۔ اسماء بنت ابی بکر رضی اللہ عنہا نے اپنے پٹکے کے ٹکڑے کر کے تھیلے کا منہ اس سے باندھ دیا اور اسی وجہ سے انکا نام ذات النطاقین ( دو پٹکے والی ) پڑ گیا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ نے جبل ثور کے غار میں پڑاؤ کیا اور تین راتیں گزاریں۔ عبداللہ بن ابی بکر رضی اللہ عنہما رات وہیں جا کر گزارا کرتے تھے، یہ نوجوان بہت سمجھدار تھے اور ذہین بےحد تھے۔ سحر کے وقت وہاں سے نکل آتے اور صبح سویرے ہی مکہ پہنچ جاتے جیسے وہیں رات گزری ہو۔ پھر جو کچھ یہاں سنتے اور جس کے ذریعہ ان حضرات کے خلاف کاروائی کے لیے کوئی تدبیر کی جاتی تو اسے محفوظ رکھتے اور جب اندھیرا چھا جاتا تو تمام اطلاعات یہاں آ کر پہنچاتے۔ ابوبکر رضی اللہ عنہ کے غلام عامر بن فہیرہ رضی اللہ عنہ آپ ہر دو کے لیے قریب ہی دودھ دینے والی بکری چرایا کرتے تھے اور جب کچھ رات گزر جاتی تو اسے غار میں لاتے تھے۔ آپ اسی پر رات گزارتے اس دودھ کو گرم لوہے کے ذریعہ گرم کر لیا جاتا تھا۔ صبح منہ اندھیرے ہی عامر بن فہیرہ رضی اللہ عنہ غار سے نکل آتے تھے ان تین راتوں میں روزانہ ان کا یہی دستور تھا۔ ابوبکر رضی اللہ عنہ نے بنی الدیل جو بنی عبد بن عدی کی شاخ تھی، کے ایک شخص کو راستہ بتانے کے لیے اجرت پر اپنے ساتھ رکھا تھا۔ یہ شخص راستوں کا بڑا ماہر تھا۔ آل عاص بن وائل سہمی کا یہ حلیف بھی تھا اور کفار قریش کے دین پر قائم تھا۔ ان بزرگوں نے اس پر اعتماد کیا اور اپنے دونوں اونٹ اس کے حوالے کر دیئے۔ قرار یہ پایا تھا کہ تین راتیں گزار کر یہ شخص غار ثور میں ان سے ملاقات کرے۔ چنانچہ تیسری رات کی صبح کو وہ دونوں اونٹ لے کر ( آ گیا ) اب عامر بن فہیرہ رضی اللہ عنہ اور یہ راستہ بتانے والا ان حضرات کو ساتھ لے کر روانہ ہوئے ساحل کے راستے سے ہوتے ہوئے۔' WHERE id = 3743;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بشر نے بیان کیا، کہا ہم سے روح نے بیان کیا، ان سے عوف نے بیان کیا، ان سے معاویہ بن قرہ نے بیان کیا کہ مجھ سے ابوبردہ بن ابوموسیٰ اشعری نے بیان کیا، انہوں نے بیان کیا کہ مجھ سے عبداللہ بن عمر رضی اللہ عنہما نے پوچھا، کیا تم کو معلوم ہے کہ میرے والد عمر رضی اللہ عنہ نے تمہارے والد ابوموسیٰ رضی اللہ عنہ کو کیا جواب دیا تھا؟ انہوں نے کہا نہیں، تو عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ میرے والد نے تمہارے والد سے کہا: اے ابوموسیٰ! کیا تم اس پر راضی ہو کہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہمارا اسلام، آپ کے ساتھ ہماری ہجرت، آپ کے ساتھ ہمارا جہاد ہمارے تمام عمل جو ہم نے آپ کی زندگی میں کئے ہیں ان کے بدلہ میں ہم اپنے ان اعمال سے نجات پا جائیں جو ہم نے آپ کے بعد کئے ہیں گو وہ نیک بھی ہوں بس برابری پر معاملہ ختم ہو جائے۔ اس پر آپ کے والد نے میرے والد سے کہا اللہ کی قسم! میں اس پر راضی نہیں ہوں ہم نے رسول اللہ صلی اللہ علیہ وسلم کے بعد بھی جہاد کیا، نمازیں پڑھیں، روزے رکھے اور بہت سے اعمال خیر کئے اور ہمارے ہاتھ پر ایک مخلوق نے اسلام قبول کیا، ہم تو اس کے ثواب کی بھی امید رکھتے ہیں اس پر میرے والد نے کہا ( خیر ابھی تم سمجھو ) لیکن جہاں تک میرا سوال ہے تو اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے میری خواہش ہے کہ آپ صلی اللہ علیہ وسلم کی زندگی میں کئے ہوئے ہمارے اعمال محفوظ رہے ہوں اور جتنے اعمال ہم نے آپ کے بعد کئے ہیں ان سب سے اس کے بدلہ میں ہم نجات پا جائیں اور برابر پر معاملہ ختم ہو جائے۔ ابوبردہ کہتے ہیں اس پر میں نے کہا: اللہ کی قسم! آپ کے والد ( عمر رضی اللہ عنہ ) میرے والد ( ابوموسیٰ رضی اللہ عنہ ) سے بہتر تھے۔' WHERE id = 3753;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے بیان کیا اور انہوں نے براء بن عازب رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ سب سے پہلے ہمارے یہاں مصعب بن عمیر رضی اللہ عنہ اور ابن ام مکتوم رضی اللہ عنہ ( نابینا ) آئے یہ دونوں ( مدینہ کے ) مسلمانوں کو قرآن پڑھنا سکھاتے تھے۔ اس کے بعد بلال، سعد اور عمار بن یاسر رضی اللہ عنہم آئے۔ پھر عمر بن خطاب رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے بیس صحابہ کو ساتھ لے کر آئے اور نبی کریم صلی اللہ علیہ وسلم ( ابوبکر رضی اللہ عنہ اور عامر بن فہیرہ کو ساتھ لے کر ) تشریف لائے۔ مدینہ کے لوگوں کو جتنی خوشی اور مسرت آپ صلی اللہ علیہ وسلم کی تشریف آوری سے ہوئی میں نے کبھی انہیں کسی بات پر اس قدر خوش نہیں دیکھا۔ لونڈیاں بھی ( خوشی میں ) کہنے لگیں کہ رسول اللہ صلی اللہ علیہ وسلم آ گئے آپ صلی اللہ علیہ وسلم جب تشریف لائے تو اس سے پہلے میں مفصل کی دوسری کئی سورتوں کے ساتھ «سبح اسم ربك الأعلى‏» بھی سیکھ چکا تھا۔' WHERE id = 3763;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے معمر نے بیان کیا، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ( پہلے ) نماز صرف دو رکعت فرض ہوئی تھی پھر نبی کریم صلی اللہ علیہ وسلم نے ہجرت کی تو وہ فرض رکعات چار رکعات ہو گئیں۔ البتہ سفر کی حالت میں نماز اپنی حالت میں باقی رکھی گئی۔ اس روایت کی متابعت عبدالرزاق نے معمر سے کی ہے۔' WHERE id = 3773;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف بیکندی نے بیان کیا کہا، ہم سے ابن عیینہ نے بیان کیا، ان سے عوف اعرابی نے، ان سے ابوعثمان نہدی نے بیان کیا، کہا میں نے سلمان فارسی سے سنا، وہ بیان کرتے تھے کہ میں رام ہرمز ( فارس میں ایک مقام ہے ) کا رہنے والا ہوں۔' WHERE id = 3784;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا کہا، ہم سے زہیر بن معاویہ نے بیان کیا کہا، ہم سے ابواسحاق نے بیان کیا، کہا کہ میں نے براء رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ محمد صلی اللہ علیہ وسلم کے صحابہ نے جو بدر میں شریک تھے مجھ سے بیان کیا کہ بدر کی لڑائی میں ان کی تعداد اتنی ہی تھی جتنی طالوت علیہ السلام کے ان اصحاب کی تھی جنہوں نے ان کے ساتھ نہر فلسطین کو پار کیا تھا۔ تقریباً تین سو دس۔ براء رضی اللہ عنہ نے کہا نہیں، اللہ کی قسم! طالوت کے ساتھ نہر فلسطین کو صرف وہی لوگ پار کر سکے تھے جو مومن تھے۔' WHERE id = 3794;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم صواف نے بیان کیا، ہم سے یوسف بن یعقوب نے بیان کیا، ان کا بنی ضبیعہ کے یہاں آنا جانا تھا اور وہ بنی سدوس کے غلام تھے۔ کہا ہم سے سلیمان تیمی نے بیان کیا، ان سے ابومجلز نے اور ان سے قیس بن عباد نے بیان کیا کہ علی رضی اللہ عنہ نے کہا یہ آیت «هذان خصمان اختصموا في ربهم» ہمارے ہی بارے میں نازل ہوئی تھی۔' WHERE id = 3805;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا ‘ ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے عمرو بن دینار نے بیان کیا ‘ ان سے عطاء نے اور ان سے ابن عباس رضی اللہ عنہما نے ‘ قرآن مجید کی آیت «الذين بدلوا نعمة الله كفرا‏» ( سورۃ ابراہیم 28 ) کے بارے میں آپ نے فرمایا اللہ کی قسم! یہ کفار قریش تھے۔ عمرو نے کہا کہ اس سے مراد قریش تھے اور رسول اللہ صلی اللہ علیہ وسلم اللہ کی نعمت تھے۔ کفار قریش نے اپنی قوم کو جنگ بدر کے دن «دار البوار» یعنی دوزخ میں جھونک دیا۔' WHERE id = 3815;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عبیداللہ بن عبداللہ بن عتبہ نے بیان کیا کہ ان کے والد نے عمر بن عبداللہ بن ارقم زہری کو لکھا کہ تم سبیعہ بنت حارث اسلمیہ رضی اللہ عنہا کے پاس جاؤ اور ان سے ان کے واقعہ کے متعلق پوچھو کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے مسئلہ پوچھا تھا تو آپ نے ان کو کیا جواب دیا تھا؟ چنانچہ انہوں نے میرے والد کو اس کے جواب میں لکھا کہ سبیعہ بنت حارث رضی اللہ عنہا نے انہیں خبر دی ہے کہ وہ سعد بن خولہ رضی اللہ عنہما کے نکاح میں تھیں۔ ان کا تعلق بنی عامر بن لوئی سے تھا اور وہ بدر کی جنگ میں شرکت کرنے والوں میں سے تھے۔ پھر حجۃ الوداع کے موقع پر ان کی وفات ہو گئی تھی اور اس وقت وہ حمل سے تھیں۔ سعد بن خولہ رضی اللہ عنہما کی وفات کے کچھ ہی دن بعد ان کے یہاں بچہ پیدا ہوا۔ نفاس کے دن جب وہ گزار چکیں تو نکاح کا پیغام بھیجنے والوں کے لیے انہوں نے اچھے کپڑے پہنے۔ اس وقت بنو عبدالدار کے ایک صحابی ابوالسنابل بن بعکک رضی اللہ عنہ ان کے یہاں گئے اور ان سے کہا، میرا خیال ہے کہ تم نے نکاح کا پیغام بھیجنے والوں کے لیے یہ زینت کی ہے۔ کیا نکاح کرنے کا خیال ہے؟ لیکن اللہ کی قسم! جب تک ( سعد رضی اللہ عنہ کی وفات پر ) چار مہینے اور دس دن نہ گزر جائیں تم نکاح کے قابل نہیں ہو سکتیں۔ سبیعہ رضی اللہ عنہا نے بیان کیا کہ جب ابوالسنابل نے مجھ سے یہ بات کہی تو میں نے شام ہوتے ہی کپڑے پہنے اور نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہو کر اس کے بارے میں، میں نے آپ سے مسئلہ معلوم کیا۔ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا کہ میں بچہ پیدا ہونے کے بعد عدت سے نکل چکی ہوں اور اگر میں چاہوں تو نکاح کر سکتی ہوں۔ اس روایت کی متابعت اصبغ نے ابن وہب سے کی ہے، ان سے یونس نے بیان کیا اور لیث نے کہا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، ( انہوں نے بیان کیا کہ ) ہم نے ان سے پوچھا تو انہوں نے بیان کیا کہ مجھے بنو عامر بن لوئی کے غلام محمد بن عبدالرحمٰن بن ثوبان نے خبر دی کہ محمد بن ایاس بن بکیر نے انہیں خبر دی اور ان کے والد ایاس بدر کی لڑائی میں شریک تھے۔' WHERE id = 3827;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے بشر بن مفضل نے بیان کیا، کہا ہم سے خالد بن ذکوان نے، ان سے ربیع بنت معوذ رضی اللہ عنہا نے بیان کیا کہ جس رات میری شادی ہوئی تھی نبی کریم صلی اللہ علیہ وسلم اس کی صبح کو میرے یہاں تشریف لائے اور میرے بستر پر بیٹھے، جیسے اب تم یہاں میرے پاس بیٹھے ہوئے ہو۔ چند بچیاں دف بجا رہی تھیں اور وہ اشعار پڑھ رہی تھیں جن میں ان کے ان خاندان والوں کا ذکر تھا جو بدر کی لڑائی میں شہید ہو گئے تھے۔ انہیں میں ایک لڑکی نے یہ مصرع بھی پڑھا کہ ہم میں نبی کریم صلی اللہ علیہ وسلم ہیں جو کل ہونے والی بات کو جانتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ نہ پڑھو، بلکہ جو پہلے پڑھ رہی تھیں وہی پڑھو۔' WHERE id = 3837;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہمیں شعیب نے خبر دی، ان سے زہری نے بیان کیا، کہا کہ مجھے عبداللہ بن عامر بن ربیعہ رضی اللہ عنہ نے خبر دی، وہ قبیلہ بنی عدی کے سب لوگوں میں بڑے تھے اور ان کے والد عامر بن ربیعہ بدر میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ شریک تھے۔ ( انہوں نے بیان کیا کہ ) عمر رضی اللہ عنہ نے قدامہ بن مظعون رضی اللہ عنہ کو بحرین کا عامل بنایا تھا، وہ قدامہ رضی اللہ عنہ بھی بدر کے معرکے میں شریک تھے اور عبداللہ بن عمر اور حفصہ رضی اللہ عنہم کے ماموں تھے۔' WHERE id = 3847;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن عمر نمیری نے بیان کیا، کہا ہم سے یونس بن یزید نے بیان کیا، کہا کہ میں نے زہری سے سنا، کہا کہ میں نے عروہ بن زبیر، سعید بن مسیب، علقمہ بن وقاص اور عبیداللہ بن عبداللہ سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا کی تہمت کے متعلق سنا۔ ان میں سے ہر ایک نے مجھ سے اس واقعہ کا کوئی حصہ بیان کیا۔ عائشہ رضی اللہ عنہا نے بیان کیا تھا کہ میں اور ام مسطح باہر قضائے حاجت کو جا رہے تھے کہ ام مسطح رضی اللہ عنہا اپنی چادر میں الجھ کر پھسل پڑیں۔ اس پر ان کی زبان سے نکلا، مسطح کا برا ہو۔ میں نے کہا، آپ نے اچھی بات نہیں کہی۔ ایک ایسے شخص کو آپ برا کہتی ہیں جو بدر میں شریک ہو چکا ہے۔ پھر انہوں نے تہمت کا واقعہ بیان کیا۔' WHERE id = 3859;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے، ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ابورافع یہودی ( کے قتل ) کے لیے چند انصاری صحابہ کو بھیجا اور عبداللہ بن عتیک رضی اللہ عنہ کو ان کا امیر بنایا۔ یہ ابورافع نبی کریم صلی اللہ علیہ وسلم کو ایذا دیا کرتا تھا اور آپ کے دشمنوں کی مدد کیا کرتا تھا۔ حجاز میں اس کا ایک قلعہ تھا اور وہیں وہ رہا کرتا تھا۔ جب اس کے قلعہ کے قریب یہ پہنچے تو سورج غروب ہو چکا تھا۔ اور لوگ اپنے مویشی لے کر ( اپنے گھروں کو ) واپس ہو چکے تھے۔ عبداللہ بن عتیک رضی اللہ عنہ نے اپنے ساتھیوں سے کہا کہ تم لوگ یہیں ٹھہرے رہو میں ( اس قلعہ پر ) جا رہا ہوں اور دربان پر کوئی تدبیر کروں گا۔ تاکہ میں اندر جانے میں کامیاب ہو جاؤں۔ چنانچہ وہ ( قلعہ کے پاس ) آئے اور دروازے کے قریب پہنچ کر انہوں نے خود کو اپنے کپڑوں میں اس طرح چھپا لیا جیسے کوئی قضائے حاجت کر رہا ہو۔ قلعہ کے تمام آدمی اندر داخل ہو چکے تھے۔ دربان نے آواز دی، اے اللہ کے بندے! اگر اندر آنا ہے تو جلد آ جا، میں اب دروازہ بند کر دوں گا۔ ( عبداللہ بن عتیک رضی اللہ عنہ نے کہا ) چنانچہ میں بھی اندر چلا گیا اور چھپ کر اس کی کارروائی دیکھنے لگا۔ جب سب لوگ اندر آ گئے تو اس نے دروازہ بند کیا اور کنجیوں کا گچھا ایک کھونٹی پر لٹکا دیا۔ انہوں نے بیان کیا کہ اب میں ان کنجیوں کی طرف بڑھا اور میں نے انہیں لے لیا، پھر میں نے قلعہ کا دروازہ کھول لیا۔ ابورافع کے پاس رات کے وقت داستانیں بیان کی جا رہی تھیں اور وہ اپنے خاص بالاخانے میں تھا۔ جب داستان گو اس کے یہاں سے اٹھ کر چلے گئے تو میں اس کمرے کی طرف چڑھنے لگا۔ اس عرصہ میں، میں جتنے دروازے اس تک پہنچنے کے لیے کھولتا تھا انہیں اندر سے بند کرتا جاتا تھا۔ میرا مطلب یہ تھا کہ اگر قلعہ والوں کو میرے متعلق علم بھی ہو جائے تو اس وقت تک یہ لوگ میرے پاس نہ پہنچ سکیں جب تک میں اسے قتل نہ کر لوں۔ آخر میں اس کے قریب پہنچ گیا۔ اس وقت وہ ایک تاریک کمرے میں اپنے بال بچوں کے ساتھ ( سو رہا ) تھا مجھے کچھ اندازہ نہیں ہو سکا کہ وہ کہاں ہے۔ اس لیے میں نے آواز دی، یا ابا رافع؟ وہ بولا کون ہے؟ اب میں نے آواز کی طرف بڑھ کر تلوار کی ایک ضرب لگائی۔ اس وقت میرا دل دھک دھک کر رہا تھا۔ یہی وجہ ہوئی کہ میں اس کا کام تمام نہیں کر سکا۔ وہ چیخا تو میں کمرے سے باہر نکل آیا اور تھوڑی دیر تک باہر ہی ٹھہرا رہا۔ پھر دوبارہ اندر گیا اور میں نے آواز بدل کر پوچھا، ابورافع! یہ آواز کیسی تھی؟ وہ بولا تیری ماں غارت ہو۔ ابھی ابھی مجھ پر کسی نے تلوار سے حملہ کیا ہے۔ انہوں نے بیان کیا کہ پھر ( آواز کی طرف بڑھ کر ) میں نے تلوار کی ایک ضرب اور لگائی۔ انہوں نے بیان کیا کہ اگرچہ میں اسے زخمی تو بہت کر چکا تھا لیکن وہ ابھی مرا نہیں تھا۔ اس لیے میں نے تلوار کی نوک اس کے پیٹ پر رکھ کر دبائی جو اس کی پیٹھ تک پہنچ گئی۔ مجھے اب یقین ہو گیا کہ میں اسے قتل کر چکا ہوں۔ چنانچہ میں نے دروازے ایک ایک کر کے کھولنے شروع کئے۔ آخر میں ایک زینے پر پہنچا۔ میں یہ سمجھا کہ زمین تک میں پہنچ چکا ہوں ( لیکن ابھی میں پہنچا نہ تھا ) اس لیے میں نے اس پر پاؤں رکھ دیا اور نیچے گر پڑا۔ چاندنی رات تھی۔ اس طرح گر پڑنے سے میری پنڈلی ٹوٹ گئی۔ میں نے اسے اپنے عمامہ سے باندھ لیا اور آ کر دروازے پر بیٹھ گیا۔ میں نے یہ ارادہ کر لیا تھا کہ یہاں سے اس وقت تک نہیں جاؤں گا جب تک یہ نہ معلوم کر لوں کہ آیا میں اسے قتل کر چکا ہوں یا نہیں؟ جب مرغ نے آواز دی تو اسی وقت قلعہ کی فصیل پر ایک پکارنے والے نے کھڑے ہو کر پکارا کہ میں اہل حجاز کے تاجر ابورافع کی موت کا اعلان کرتا ہوں۔ میں اپنے ساتھیوں کے پاس آیا اور ان سے کہا کہ چلنے کی جلدی کرو۔ اللہ تعالیٰ نے ابورافع کو قتل کرا دیا۔ چنانچہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ کو اس کی اطلاع دی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اپنا پاؤں پھیلاؤ میں نے پاؤں پھیلایا تو آپ نے اس پر اپنا دست مبارک پھیرا اور پاؤں اتنا اچھا ہو گیا جیسے کبھی اس میں مجھ کو کوئی تکلیف ہوئی ہی نہ تھی۔' WHERE id = 3871;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عدی بن ثابت نے، میں نے عبداللہ بن یزید سے سنا، وہ زید بن ثابت رضی اللہ عنہ سے بیان کرتے تھے کہ انہوں نے بیان کیا، جب نبی کریم صلی اللہ علیہ وسلم غزوہ احد کے لیے نکلے تو کچھ لوگ جو آپ کے ساتھ تھے ( منافقین، بہانہ بنا کر ) واپس لوٹ گئے۔ پھر صحابہ کی ان واپس ہونے والے منافقین کے بارے میں دو رائیں ہو گئیں تھیں۔ ایک جماعت تو کہتی تھی ہمیں پہلے ان سے جنگ کرنی چاہیے اور دوسری جماعت کہتی تھی کہ ان سے ہمیں جنگ نہ کرنی چاہیے۔ اس پر آیت نازل ہوئی «فما لكم في المنافقين فئتين والله أركسهم بما كسبوا‏» ”پس تمہیں کیا ہو گیا ہے کہ منافقین کے بارے میں تمہاری دو جماعتیں ہو گئیں ہیں، حالانکہ اللہ تعالیٰ نے ان کی بداعمالی کی وجہ سے انہیں کفر کی طرف لوٹا دیا ہے۔“ اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مدینہ ”طیبہ“ ہے، سرکشوں کو یہ اس طرح اپنے سے دور کر دیتا ہے جیسے آگ کی بھٹی چاندی کے میل کچیل کو دور کر دیتی ہے۔' WHERE id = 3881;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے بیان کیا، ان سے محمد بن یوسف نے بیان کیا، ان سے سائب بن یزید نے کہ میں، عبدالرحمٰن بن عوف، طلحہ بن عبیداللہ، مقداد بن اسود اور سعد بن ابی وقاص رضی اللہ عنہم کی صحبت میں رہا ہوں لیکن میں نے ان حضرات میں سے کسی کو نبی کریم صلی اللہ علیہ وسلم سے کوئی حدیث بیان کرتے نہیں سنا۔ صرف طلحہ رضی اللہ عنہ سے غزوہ احد کے متعلق حدیث سنی تھی۔' WHERE id = 3892;
UPDATE hadiths SET urdu = 'مجھ سے ابو جعفر محمد بن عبداللہ نے بیان کیا، کہا ہم سے حجین بن مثنی نے بیان کیا، کہا ہم سے عبدالعزیز بن عبداللہ بن ابی سلمہ نے بیان کیا، ان سے عبداللہ بن فضل نے، ان سے سلیمان بن یسار نے، ان سے جعفر بن عمرو بن امیہ ضمری رضی اللہ عنہ نے بیان کیا کہ میں عبیداللہ بن عدی بن خیار رضی اللہ عنہ کے ساتھ روانہ ہوا۔ جب حمص پہنچے تو مجھ سے عبیداللہ رضی اللہ عنہ نے کہا، آپ کو وحشی ( ابن حرب حبشی جس نے غزوہ احد میں حمزہ رضی اللہ عنہ کو قتل کیا اور ہندہ زوجہ ابوسفیان نے ان کی لاش کا مثلہ کیا تھا ) سے تعارف ہے۔ ہم چل کے ان سے حمزہ رضی اللہ عنہ کی شہادت کے بارے میں معلوم کرتے ہیں۔ میں نے کہا کہ ٹھیک ہے ضرور چلو۔ وحشی حمص میں موجود تھے۔ چنانچہ ہم نے لوگوں سے ان کے بارے میں معلوم کیا تو ہمیں بتایا گیا کہ وہ اپنے مکان کے سائے میں بیٹھے ہوئے ہیں، جیسے کوئی بڑا سا کپا ہو۔ انہوں نے بیان کیا کہ پھر ہم ان کے پاس آئے اور تھوڑی دیر ان کے پاس کھڑے رہے۔ پھر سلام کیا تو انہوں نے سلام کا جواب دیا۔ بیان کیا کہ عبیداللہ نے اپنے عمامہ کو جسم پر اس طرح لپیٹ رکھا تھا کہ وحشی صرف ان کی آنکھیں اور پاؤں دیکھ سکتے تھے۔ عبیداللہ نے پوچھا: اے وحشی! کیا تم نے مجھے پہچانا؟ راوی نے بیان کیا کہ پھر اس نے عبیداللہ کو دیکھا اور کہا کہ نہیں، اللہ کی قسم! البتہ میں اتنا جانتا ہوں کہ عدی بن خیار نے ایک عورت سے نکاح کیا تھا۔ اسے ام قتال بنت ابی العیص کہا جاتا تھا پھر مکہ میں اس کے یہاں ایک بچہ پیدا ہوا اور میں اس کے لیے کسی دایا کی تلاش کے لیے گیا تھا۔ پھر میں اس بچے کو اس کی ( رضاعی ) ماں کے پاس لے گیا اور اس کی والدہ بھی ساتھ تھی۔ غالباً میں نے تمہارے پاؤں دیکھے تھے۔ بیان کیا کہ اس پر عبیداللہ بن عدی رضی اللہ عنہ نے اپنے چہرے سے کپڑا ہٹا لیا اور کہا، ہمیں تم حمزہ رضی اللہ عنہ کی شہادت کے واقعات بتا سکتے ہو؟ انہوں نے کہا کہ ہاں، بات یہ ہوئی کہ بدر کی لڑائی میں حمزہ رضی اللہ عنہ نے طعیمہ بن عدی بن خیار کو قتل کیا تھا۔ میرے آقا جبیر بن مطعم نے مجھ سے کہا کہ اگر تم نے حمزہ رضی اللہ عنہ کو میرے چچا ( طعیمہ ) کے بدلے میں قتل کر دیا تو تم آزاد ہو جاؤ گے۔ انہوں نے بتایا کہ پھر جب قریش عینین کی جنگ کے لیے نکلے۔ عینین احد کی ایک پہاڑی ہے اور اس کے اور احد کے درمیان ایک وادی حائل ہے۔ تو میں بھی ان کے ساتھ جنگ کے ارادہ سے ہو لیا۔ جب ( دونوں فوجیں آمنے سامنے ) لڑنے کے لیے صف آراء ہو گئیں تو ( قریش کی صف میں سے ) سباع بن عبدالعزیٰ نکلا اور اس نے آواز دی، ہے کوئی لڑنے والا؟ بیان کیا کہ ( اس کی اس دعوت مبازرت پر ) امیر حمزہ بن عبدالمطلب رضی اللہ عنہ نکل کر آئے اور فرمایا، اے سباع! اے ام انمار کے بیٹے! جو عورتوں کے ختنے کیا کرتی تھی، تو اللہ اور اس کے رسول سے لڑنے آیا ہے؟ بیان کیا کہ پھر حمزہ رضی اللہ عنہ نے اس پر حملہ کیا ( اور اسے قتل کر دیا ) اب وہ واقعہ گزرے ہوئے دن کی طرح ہو چکا تھا۔ وحشی نے بیان کیا کہ ادھر میں ایک چٹان کے نیچے حمزہ رضی اللہ عنہ کی تاک میں تھا اور جوں ہی وہ مجھ سے قریب ہوئے، میں نے ان پر اپنا چھوٹا نیزہ پھینک کر مارا، نیزہ ان کی ناف کے نیچے جا کر لگا اور ان کی سرین کے پار ہو گیا۔ بیان کیا کہ یہی ان کی شہادت کا سبب بنا، پھر جب قریش واپس ہوئے تو میں بھی ان کے ساتھ واپس آ گیا اور مکہ میں مقیم رہا۔ لیکن جب مکہ بھی اسلامی سلطنت کے تحت آ گیا تو میں طائف چلا گیا۔ طائف والوں نے بھی رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک قاصد بھیجا تو مجھ سے وہاں کے لوگوں نے کہا کہ انبیاء کسی پر زیادتی نہیں کرتے ( اس لیے تم مسلمان ہو جاؤ۔ اسلام قبول کرنے کے بعد تمہاری پچھلی تمام غلطیاں معاف ہو جائیں گی ) چنانچہ میں بھی ان کے ساتھ روانہ ہوا۔ جب نبی کریم صلی اللہ علیہ وسلم کی خدمت میں پہنچا اور آپ نے مجھے دیکھا تو دریافت فرمایا، کیا تمہارا ہی نام وحشی ہے؟ میں نے عرض کیا کہ جی ہاں۔ آپ صلی اللہ علیہ وسلم نے فرمایا: کیا تم ہی نے حمزہ کو قتل کیا تھا؟ میں نے عرض کیا، جو نبی کریم صلی اللہ علیہ وسلم کو اس معاملے میں معلوم ہے وہی صحیح ہے۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا: کیا تم ایسا کر سکتے ہو کہ اپنی صورت مجھے کبھی نہ دکھاؤ؟ انہوں نے بیان کیا کہ پھر میں وہاں سے نکل گیا۔ پھر آپ صلی اللہ علیہ وسلم کی جب وفات ہوئی تو مسیلمہ کذاب نے خروج کیا۔ اب میں نے سوچا کہ مجھے مسیلمہ کذاب کے خلاف جنگ میں ضرور شرکت کرنی چاہیے۔ ممکن ہے میں اسے قتل کر دوں اور اس طرح حمزہ رضی اللہ عنہ کے قتل کا بدل ہو سکے۔ انہوں نے بیان کیا کہ پھر میں بھی اس کے خلاف جنگ کے لیے مسلمانوں کے ساتھ نکلا۔ اس سے جنگ کے واقعات سب کو معلوم ہیں۔ بیان کیا کہ ( میدان جنگ میں ) میں نے دیکھا کہ ایک شخص ( مسیلمہ ) ایک دیوار کی دراز سے لگا کھڑا ہے۔ جیسے گندمی رنگ کا کوئی اونٹ ہو۔ سر کے بال منتشر تھے۔ بیان کیا کہ میں نے اس پر بھی اپنا چھوٹا نیزہ پھینک کر مارا۔ نیزہ اس کے سینے پر لگا اور شانوں کو پار کر گیا۔ بیان کیا کہ اتنے میں ایک صحابی انصاری جھپٹے اور تلوار سے اس کی کھوپڑی پر مارا۔ انہوں ( عبدالعزیز بن عبداللہ ) نے کہا، ان سے عبداللہ بن فضل نے بیان کیا کہ پھر مجھے سلیمان بن یسار نے خبر دی اور انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، وہ بیان کر رہے تھے کہ ( مسیلمہ کے قتل کے بعد ) ایک لڑکی نے چھت پر کھڑی ہو کر اعلان کیا کہ امیرالمؤمنین کو ایک کالے غلام ( یعنی وحشی ) نے قتل کر دیا۔' WHERE id = 3902;
UPDATE hadiths SET urdu = 'ہم سے نصر بن علی نے بیان کیا، کہا کہ مجھے میرے والد نے خبر دی، انہیں قرہ بن خالد نے، انہیں قتادہ نے اور انہوں نے انس رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”احد پہاڑ ہم سے محبت رکھتا ہے اور ہم اس سے محبت رکھتے ہیں۔“' WHERE id = 3912;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب مکہ میں مشرک لوگ ابوبکر صدیق رضی اللہ عنہ کو سخت تکلیف دینے لگے تو رسول اللہ صلی اللہ علیہ وسلم سے ابوبکر رضی اللہ عنہ نے بھی اجازت چاہی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابھی یہیں ٹھہرے رہو۔ انہوں نے عرض کیا: یا رسول اللہ! کیا آپ بھی ( اللہ تعالیٰ سے ) اپنے لیے ہجرت کی اجازت کے امیدوار ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا: ہاں مجھے اس کی امید ہے۔ عائشہ رضی اللہ عنہا کہتی ہیں کہ پھر ابوبکر رضی اللہ عنہ انتظار کرنے لگے۔ آخر نبی کریم صلی اللہ علیہ وسلم ایک دن ظہر کے وقت ( ہمارے گھر ) تشریف لائے اور ابوبکر رضی اللہ عنہ کو پکارا اور فرمایا کہ تخلیہ کر لو۔ ابوبکر رضی اللہ عنہ نے کہا کہ صرف میری دونوں لڑکیاں یہاں موجود ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم کو معلوم ہے مجھے بھی ہجرت کی اجازت دے دی گئی ہے۔ ابوبکر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! کیا مجھے بھی ساتھ چلنے کی سعادت حاصل ہو گی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں تم بھی میرے ساتھ چلو گے۔ ابوبکر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میرے پاس دو اونٹنیاں ہیں اور میں نے انہیں ہجرت ہی کی نیت سے تیار کر رکھا ہے۔ چنانچہ انہوں نے ایک اونٹنی جس کا نام ”الجدعا“ تھا آپ صلی اللہ علیہ وسلم کو دے دی۔ دونوں بزرگ سوار ہو کر روانہ ہوئے اور یہ غار ثور پہاڑی کا تھا اس میں جا کر دونوں پوشیدہ ہو گئے۔ عامر بن فہیرہ جو عبداللہ بن طفیل بن سنجرہ، عائشہ رضی اللہ عنہا کے والدہ کی طرف سے بھائی تھے، ابوبکر رضی اللہ عنہ کی ایک دودھ دینے والی اونٹنی تھی تو عامر بن فہیرہ صبح و شام ( عام مویشیوں کے ساتھ ) اسے چرانے لے جاتے اور رات کے آخری حصہ میں نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ کے پاس آتے تھے۔ ( غار ثور میں ان حضرات کی خوراک اسی کا دودھ تھی ) اور پھر اسے چرانے کے لیے لے کر روانہ ہو جاتے۔ اس طرح کوئی چرواہا اس پر آگاہ نہ ہو سکا۔ پھر جب آپ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ غار سے نکل کر روانہ ہوئے تو پیچھے پیچھے عامر بن فہیرہ بھی پہنچے تھے۔ آخر دونوں حضرات مدینہ پہنچ گئے۔ بئرمعونہ کے حادثہ میں عامر بن فہیرہ رضی اللہ عنہ بھی شہید ہو گئے تھے۔ ابواسامہ سے روایت ہے، ان سے ہشام بن عروہ نے بیان کیا، انہیں ان کے والد نے خبر دی، انہوں نے بیان کیا کہ جب بئرمعونہ کے حادثہ میں قاری صحابہ شہید کئے گئے اور عمرو بن امیہ ضمری رضی اللہ عنہ قید کئے گئے تو عامر بن طفیل نے ان سے پوچھا کہ یہ کون ہے؟ انہوں نے ایک لاش کی طرف اشارہ کیا۔ عمرو بن امیہ رضی اللہ عنہ نے انہیں بتایا کہ یہ عامر بن فہیرہ رضی اللہ عنہ ہیں۔ اس پر عامر بن طفیل رضی اللہ عنہ نے کہا کہ میں نے دیکھا کہ شہید ہو جانے کے بعد ان کی لاش آسمان کی طرف اٹھائی گئی۔ میں نے اوپر نظر اٹھائی تو لاش آسمان و زمین کے درمیان لٹک رہی تھی۔ پھر وہ زمین پر رکھ دی گئی۔ ان شہداء کے متعلق نبی کریم صلی اللہ علیہ وسلم کو جبرائیل علیہ السلام نے باذن خدا بتا دیا تھا۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے ان کی شہادت کی خبر صحابہ کو دی اور فرمایا کہ تمہارے ساتھی شہید کر دیئے گئے ہیں اور شہادت کے بعد انہوں نے اپنے رب کے حضور میں عرض کیا کہ اے ہمارے رب! ہمارے ( مسلمان ) بھائیوں کو اس کی اطلاع دیدے کہ ہم تیرے پاس پہنچ کر کس طرح خوش ہیں اور تو بھی ہم سے راضی ہے۔ چنانچہ اللہ تعالیٰ نے ( قرآن مجید کے ذریعہ ) مسلمانوں کو اس کی اطلاع دے دی۔ اسی حادثہ میں عروہ بن اسماء بن صلت رضی اللہ عنہما بھی شہید ہوئے تھے ( پھر زبیر رضی اللہ عنہ کے بیٹے جب پیدا ہوئے ) تو ان کا نام عروہ، انہیں عروہ ابن اسماء رضی اللہ عنہما کے نام پر رکھا گیا۔ منذر بن عمرو رضی اللہ عنہ اس حادثہ میں شہید ہوئے تھے۔ ( اور زبیر رضی اللہ عنہ کے دوسرے صاحب زادے کا نام ) منذر انہیں کے نام پر رکھا گیا تھا۔' WHERE id = 3922;
UPDATE hadiths SET urdu = 'مجھ سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے عبدہ بن سلیمان نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ( آیت ) «إذا جاؤوكم من فوقكم ومن أسفل منكم وإذ زاغت الأبصار وبلغت القلوب الحناجر» ”جب مشرکین تمہارے بالائی علاقہ سے اور تمہارے نشیبی علاقہ سے تم پر چڑھ آئے تھے اور جب مارے ڈر کے آنکھیں چکا چوند ہو گئی تھیں اور دل حلق تک آ گئے تھے۔“ عائشہ رضی اللہ عنہا نے بیان کیا کہ یہ آیت غزوہ خندق کے متعلق نازل ہوئی تھی۔' WHERE id = 3932;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا ‘ کہا ہم کو سفیان ثوری نے خبر دی ‘ ان سے محمد بن منکدر نے بیان کیا اور انہوں نے جابر رضی اللہ عنہ سے سنا ‘ وہ بیان کرتے تھے کہ غزوہ احزاب کے موقع پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کفار کے لشکر کی خبریں کون لائے گا؟ زبیر رضی اللہ عنہ نے عرض کیا کہ میں تیار ہوں۔ پھر آپ صلی اللہ علیہ وسلم نے پوچھا کہ کفار کے لشکر کی خبریں کون لائے گا؟ اس مرتبہ بھی زبیر رضی اللہ عنہ نے کہا کہ میں۔ پھر آپ صلی اللہ علیہ وسلم نے تیسری مرتبہ پوچھا کہ کفار کے لشکر کی خبریں کون لائے گا؟ زبیر رضی اللہ عنہ نے اس مرتبہ بھی اپنے آپ کو پیش کیا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہر نبی کے حواری ہوتے ہیں اور میرے حواری زبیر ہیں۔' WHERE id = 3942;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا ‘ کہا ہم کو شعبہ نے خبر دی ‘ کہا کہ مجھے عدی بن ثابت نے خبر دی ‘ انہوں نے براء بن عازب رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے حسان بن ثابت رضی اللہ عنہ سے فرمایا کہ مشرکین کی ہجو کر یا ( آپ صلی اللہ علیہ وسلم نے اس کے بجائے ) «هاجهم» فرمایا جبرائیل تمہارے ساتھ ہیں۔' WHERE id = 3952;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یزید بن زریع نے بیان کیا ‘ کہا ہم سے معمر نے بیان کیا ‘ ان سے زہری نے ‘ ان سے سالم بن عبداللہ بن عمر رضی اللہ عنہما نے اور ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک جماعت کے ساتھ نماز ( نماز خوف ) پڑھی اور دوسری جماعت اس عرصہ میں دشمن کے مقابلے پر کھڑی تھی۔ پھر یہ جماعت جب اپنے دوسرے ساتھیوں کی جگہ ( نماز پڑھ کر ) چلی گئی تو دوسری جماعت آئی اور نبی کریم صلی اللہ علیہ وسلم نے انہیں بھی ایک رکعت نماز پڑھائی۔ اس کے بعد آپ نے اس جماعت کے ساتھ سلام پھیرا۔ آخر اس جماعت نے کھڑے ہو کر اپنی ایک رکعت پوری کی اور پہلی جماعت نے بھی کھڑے ہو کر اپنی ایک رکعت پوری کی۔' WHERE id = 3962;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے ابوعوانہ نے بیان کیا ‘ ان سے حصین بن عبدالرحمٰن نے ‘ ان سے ابووائل شقیق بن سلمہ نے بیان کیا ‘ ان سے مسروق بن اجدع نے بیان کیا ‘ کہا کہ مجھ سے ام رومان رضی اللہ عنہا نے بیان کیا ‘ وہ عائشہ رضی اللہ عنہا کی والدہ ہیں۔ انہوں نے بیان کیا کہ میں اور عائشہ رضی اللہ عنہا بیٹھی ہوئی تھیں کہ ایک انصاری خاتون آئیں اور کہنے لگیں کہ اللہ فلاں، فلاں کو تباہ کرے۔ ام رومان نے پوچھا کہ کیا بات ہے؟ انہوں نے کہا کہ میرا لڑکا بھی ان لوگوں کے ساتھ شریک ہو گیا ہے۔ جنہوں نے اس طرح کی بات کی ہے۔ ام رومان رضی اللہ عنہا نے پوچھا کہ آخر بات کیا ہے؟ اس پر انہوں نے تہمت لگانے والوں کی باتیں نقل کر دیں۔ عائشہ رضی اللہ عنہا نے پوچھا: کیا رسول اللہ صلی اللہ علیہ وسلم نے بھی یہ باتیں سنیں ہیں؟ انہوں نے بیان کیا کہ ہاں۔ انہوں نے پوچھا اور ابوبکر رضی اللہ عنہ نے بھی؟ انہوں نے کہا کہ ہاں ‘ انہوں نے بھی۔ یہ سنتے ہی وہ غش کھا کر گر پڑیں اور جب ہوش آیا تو جاڑے کے ساتھ بخار چڑھا ہوا تھا۔ میں نے ان پر ان کے کپڑے ڈال دیئے اور اچھی طرح ڈھک دیا۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم تشریف لائے اور دریافت فرمایا کہ انہیں کیا ہوا ہے؟ میں نے عرض کیا: یا رسول اللہ! جاڑے کے ساتھ بخار چڑھ گیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ غالباً اس نے اس طوفان کی بات سن لی ہے۔ ام رومان رضی اللہ عنہا نے کہا کہ جی ہاں۔ پھر عائشہ رضی اللہ عنہا نے بیٹھ کر کہا کہ اللہ کی قسم! اگر میں قسم کھاؤں کہ میں بےگناہ ہوں تو آپ لوگ میری تصدیق نہیں کریں گے اور اگر کچھ کہوں تب بھی میرا عذر نہیں سنیں گے۔ میری اور آپ لوگوں کی یعقوب علیہ السلام اور ان کے بیٹوں جیسی مثال ہے کہ انہوں نے کہا تھا «والله المستعان على ما تصفون» یعنی ”اللہ ان باتوں پر جو تم بناتے ہو مدد کرنے والا ہے۔“ ام رومان رضی اللہ عنہا نے کہا: نبی کریم صلی اللہ علیہ وسلم عائشہ رضی اللہ عنہا کی یہ تقریر سن کر لوٹ گئے ‘ کچھ جواب نہیں دیا۔ چنانچہ اللہ تعالیٰ نے خود ان کی تلافی نازل کی۔ وہ نبی کریم صلی اللہ علیہ وسلم سے کہنے لگیں بس میں اللہ ہی کا شکر ادا کرتی ہوں نہ آپ کا نہ کسی اور کا۔' WHERE id = 3972;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے سعید بن ابی عروبہ نے، ان سے قتادہ نے کہ میں نے سعید بن مسیب سے پوچھا ‘ مجھے معلوم ہوا ہے کہ جابر رضی اللہ عنہ کہا کرتے تھے کہ ( حدیبیہ کی صلح کے موقع پر ) صحابہ کی تعداد چودہ سو تھی۔ اس پر سعید بن مسیب نے بیان کیا کہ مجھ سے جابر رضی اللہ عنہ نے یہ کہا تھا اس موقع پر پندرہ سو صحابہ رضی اللہ عنہم موجود تھے۔ جنہوں نے نبی کریم صلی اللہ علیہ وسلم سے حدیبیہ میں بیعت کی تھی۔ ابوداؤد طیالسی نے بیان کیا، ہم سے قرۃ بن خالد نے بیان کیا، ان سے قتادہ نے اور محمد بن بشار نے بھی ابوداؤد طیالسی کے ساتھ اس کو روایت کیا ہے۔' WHERE id = 3982;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا ‘ ان سے ان کے بھائی عبدالحمید نے ‘ ان سے سلیمان بن بلال نے ‘ ان سے عمرو بن یحییٰ نے اور ان سے عباد بن تمیم نے بیان کیا کہ حرہ کی لڑائی میں لوگ عبداللہ بن حنظلہ رضی اللہ عنہ کے ہاتھ پر بیعت کر رہے تھے۔ عبداللہ بن زید نے پوچھا کہ ابن حنظلہ سے کس بات پر بیعت کی جا رہی ہے؟ تو لوگوں نے بتایا کہ موت پر۔ ابن زید نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کے بعد اب میں کسی سے بھی موت پر بیعت نہیں کروں گا۔ وہ آپ صلی اللہ علیہ وسلم کے ساتھ غزوہ حدیبیہ میں شریک تھے۔' WHERE id = 3994;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم کو امام مالک نے خبر دی ‘ انہیں زید بن اسلم نے اور انہیں ان کے والد اسلم نے کہ رسول اللہ صلی اللہ علیہ وسلم کسی سفر یعنی ( سفر حدیبیہ ) میں تھے، رات کا وقت تھا اور عمر بن خطاب رضی اللہ عنہ آپ کے ساتھ ساتھ تھے۔ عمر رضی اللہ عنہ نے آپ سے کچھ پوچھا لیکن ( اس وقت آپ وحی میں مشغول تھے ‘ عمر رضی اللہ عنہ کو خبر نہ تھی ) آپ نے کوئی جواب نہیں دیا۔ انہوں نے پھر پوچھا ‘ آپ نے پھر کوئی جواب نہیں دیا۔ انہوں نے پھر پوچھا ‘ آپ نے اس مرتبہ بھی کوئی جواب نہیں دیا۔ اس پر عمر رضی اللہ عنہ نے ( اپنے دل میں ) کہا: عمر! تیری ماں تجھ پر روئے ‘ رسول اللہ صلی اللہ علیہ وسلم سے تم نے تین مرتبہ سوال کیا ‘ آپ صلی اللہ علیہ وسلم نے تمہیں ایک مرتبہ بھی جواب نہیں دیا۔ عمر رضی اللہ عنہ نے بیان کیا کہ پھر میں نے اپنے اونٹ کو ایڑ لگائی اور مسلمانوں سے آگے نکل گیا۔ مجھے ڈر تھا کہ کہیں میرے بارے میں کوئی وحی نہ نازل ہو جائے۔ ابھی تھوڑی دیر ہوئی تھی کہ میں نے سنا ‘ ایک شخص مجھے آواز دے رہا تھا۔ انہوں نے بیان کیا کہ میں نے سوچا کہ میں تو پہلے ہی ڈر رہا تھا کہ میرے بارے میں کہیں کوئی وحی نازل نہ ہو جائے۔ پھر میں آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ کو سلام کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ رات مجھ پر ایک سورت نازل ہوئی ہے اور وہ مجھے اس تمام کائنات سے زیادہ عزیز ہے جس پر سورج طلوع ہوتا ہے۔ پھر آپ نے سورۃ «إنا فتحنا لك فتحا مبينا‏» ”بیشک ہم نے آپ کو کھلی ہوئی فتح دی ہے۔“ کی تلاوت فرمائی۔' WHERE id = 4004;
UPDATE hadiths SET urdu = 'مجھ سے ابوعبداللہ محمد بن ہشام نے بیان کیا ‘ کہا ہم سے ہشیم نے بیان کیا ان سے ابوبشر نے ‘ ان سے مجاہد نے ‘ ان سے عبدالرحمٰن بن ابی لیلیٰ نے اور ان سے کعب بن عجرہ رضی اللہ عنہ نے بیان کیا کہ صلح حدیبیہ کے موقع پر ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے اور احرام باندھے ہوئے تھے۔ ادھر مشرکین ہمیں بیت اللہ تک جانے نہیں دینا چاہتے تھے۔ انہوں نے بیان کیا کہ میرے سر پر بال بڑے بڑے تھے جن سے جوئیں میرے چہرے پر گرنے لگیں۔ نبی کریم صلی اللہ علیہ وسلم نے مجھے دیکھ کر دریافت فرمایا کہ کیا یہ جوئیں تکلیف دے رہی ہیں؟ میں نے کہا: جی ہاں۔ انہوں نے بیان کیا کہ پھر یہ آیت نازل ہوئی «فمن كان منكم مريضا أو به أذى من رأسه ففدية من صيام أو صدقة أو نسك‏» ”پس اگر تم میں کوئی مریض ہو یا اس کے سر میں کوئی تکلیف دینے والی چیز ہو تو اسے ( بال منڈوا لینے چاہئیں اور ) تین دن کے روزے یا صدقہ یا قربانی کا فدیہ دینا چاہیے۔“' WHERE id = 4016;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ کہا ہم سے شعبہ بن حجاج نے بیان کیا ‘ ان سے عبدالعزیز بن صہیب نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا ‘ انہوں نے بیان کیا کہ صفیہ رضی اللہ عنہا رسول اللہ صلی اللہ علیہ وسلم کے قیدیوں میں تھیں لیکن آپ نے انہیں آزاد کر کے ان سے نکاح کر لیا تھا۔ ثابت رضی اللہ عنہ نے انس رضی اللہ عنہ سے پوچھا نبی کریم صلی اللہ علیہ وسلم نے انہیں مہر کیا دیا تھا؟ انہوں نے کہا کہ خود انہیں کو ان کے مہر میں دیا تھا یعنی انہیں آزاد کر دیا تھا۔' WHERE id = 4026;
UPDATE hadiths SET urdu = 'ہم سے عبدالغفار بن داؤد نے بیان کیا ‘ کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا (دوسری سند) اور مجھ سے احمد نے بیان کیا ‘ کہا ہم سے ابن وہب نے بیان کیا ‘ کہا کہ مجھے یعقوب بن عبدالرحمٰن زہری نے خبر دی ‘ انہیں مطلب کے مولیٰ عمرو نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ہم خیبر آئے پھر جب اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم کو خیبر کی فتح عنایت فرمائی تو آپ کے سامنے صفیہ بنت حیی بن اخطب رضی اللہ عنہا کی خوبصورتی کا کسی نے ذکر کیا ‘ ان کے شوہر قتل ہو گئے تھے اور ان کی شادی ابھی نئی ہوئی تھی۔ اس لیے آپ صلی اللہ علیہ وسلم نے انہیں اپنے لیے لے لیا اور انہیں ساتھ لے کر آپ صلی اللہ علیہ وسلم روانہ ہوئے۔ آخر جب ہم مقام سد الصہباء میں پہنچے تو ام المؤمنین صفیہ رضی اللہ عنہا حیض سے پاک ہوئیں اور نبی کریم صلی اللہ علیہ وسلم نے ان کے ساتھ خلوت فرمائی پھر آپ نے حیس بنایا۔ ( جو کھجور کے ساتھ گھی اور پنیر وغیرہ ملا کر بنایا جاتا ہے ) اور اسے چھوٹے سے ایک دستر خوان پر رکھ کر مجھ کو حکم فرمایا کہ جو لوگ تمہارے قریب ہیں انہیں بلا لو۔ ام المؤمنین صفیہ رضی اللہ عنہا کا نبی کریم صلی اللہ علیہ وسلم کی طرف سے یہی ولیمہ تھا۔ پھر ہم مدینہ کے لیے روانہ ہوئے تو میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم نے صفیہ رضی اللہ عنہا کے لیے عبا اونٹ کی کوہان میں باندھ دی تاکہ پیچھے سے وہ اسے پکڑے رہیں اور اپنے اونٹ کے پاس بیٹھ کر اپنا گھٹنا اس پر رکھا اور صفیہ رضی اللہ عنہا اپنا پاؤں آپ صلی اللہ علیہ وسلم کے گھٹنے پر رکھ کر سوار ہوئیں۔' WHERE id = 4036;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا ‘ ان سے شعبہ نے بیان کیا ‘ ان سے عدی بن ثابت نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ میں شریک تھے پھر پہلی حدیث کی طرح روایت نقل کی۔' WHERE id = 4048;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا ‘ کہا ہم کو محمد بن جعفر نے خبر دی ‘ کہا کہ مجھے زید نے خبر دی ‘ انہیں ان کے والد نے اور انہوں نے عمر بن خطاب رضی اللہ عنہ سے سنا انہوں نے کہا ہاں اس ذات کی قسم جس کے ہاتھ میں میری جان ہے اگر اس کا خطرہ نہ ہوتا کہ بعد کی نسلیں بے جائیداد رہ جائیں گی اور ان کے پاس کچھ نہ ہو گا تو جو بھی بستی میرے زمانہ خلافت میں فتح ہوتی ‘ میں اسے اسی طرح تقسیم کر دیتا جس طرح نبی کریم صلی اللہ علیہ وسلم نے خیبر کی تقسیم کی تھی۔ میں ان مفتوحہ اراضی کو بعد میں آنے والے مسلمانوں کے لیے محفوظ چھوڑے جا رہا ہوں تاکہ وہ اسے تقسیم کرتے رہیں۔' WHERE id = 4058;
UPDATE hadiths SET urdu = 'مجھ سے عبیداللہ بن موسیٰ نے بیان کیا ‘ ان سے اسرائیل نے بیان کیا ‘ ان سے ابواسحاق نے اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ انس رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم نے ذی قعدہ میں عمرہ کا احرام باندھا۔ مکہ والے آپ کے مکہ میں داخل ہونے سے مانع آئے۔ آخر معاہدہ اس پر ہوا کہ ( آئندہ سال ) مکہ میں تین دن آپ قیام کر سکتے ہیں۔ معاہدہ یوں لکھا جانے لگا ”یہ وہ معاہدہ ہے جو محمد رسول اللہ صلی اللہ علیہ وسلم نے کیا۔ کفار قریش کہنے لگے کہ ہم یہ تسلیم نہیں کرتے۔ اگر ہم آپ کو اللہ کا رسول مانتے تو روکتے ہی کیوں ‘ آپ تو بس محمد بن عبداللہ ہیں۔ آپ نے فرمایا کہ میں اللہ کا رسول بھی ہوں اور محمد بن عبداللہ بھی ہوں۔ پھر علی رضی اللہ عنہ سے فرمایا کہ ( رسول اللہ کا لفظ مٹا دو ) انہوں نے کہا کہ ہرگز نہیں، اللہ کی قسم! میں یہ لفظ کبھی نہیں مٹا سکتا۔ نبی کریم صلی اللہ علیہ وسلم نے وہ تحریر اپنے ہاتھ میں لے لی۔ آپ لکھنا نہیں جانتے تھے لیکن آپ نے اس کے الفاظ اس طرح کر دیئے ”یہ معاہدہ ہے جو محمد بن عبداللہ نے کیا کہ وہ ہتھیار لے کر مکہ میں نہیں آئیں گے۔ البتہ ایسی تلوار جو نیام میں ہو ساتھ لا سکتے ہیں اور یہ اگر مکہ والوں میں سے کوئی ان کے ساتھ جانا چاہے گا تو اسے اپنے ساتھ نہیں لے جائیں گے۔ لیکن اگر ان کے ساتھیوں میں کوئی مکہ میں رہنا چاہے گا اسے نہ روکیں گے۔ پھر جب ( آئندہ سال ) آپ اس معاہدہ کے مطابق مکہ میں داخل ہوئے ( اور تین دن کی ) مدت پوری ہو گئی تو مکہ والے علی رضی اللہ عنہ کے پاس آئے اور کہا کہ اپنے ساتھی سے کہو کہ اب یہاں سے چلے جائیں ‘ کیونکہ مدت پوری ہو گئی ہے۔ جب نبی کریم صلی اللہ علیہ وسلم مکہ سے نکلے تو آپ کے پیچھے حمزہ رضی اللہ عنہ کی بیٹی چچا چچا کہتی ہوئی آئیں۔ علی رضی اللہ عنہ نے انہیں لے لیا اور ہاتھ پکڑ کر فاطمہ رضی اللہ عنہا کے پاس لائے اور کہا کہ اپنے چچا کی بیٹی کو لے لو میں اسے لیتا آیا ہوں۔ علی ‘ زید ‘ جعفر رضی اللہ عنہم کا اختلاف ہوا۔ علی رضی اللہ عنہ نے کہا کہ یہ میرے چچا کی لڑکی ہے اور جعفر رضی اللہ عنہ نے کہا کہ یہ میرے چچا کی لڑکی ہے اس کی خالہ میرے نکاح میں ہیں۔ زید رضی اللہ عنہ نے کہا یہ میرے بھائی کی لڑکی ہے لیکن نبی کریم صلی اللہ علیہ وسلم نے ان کی خالہ کے حق میں فیصلہ فرمایا ( جو جعفر رضی اللہ عنہ کے نکاح میں تھیں ) اور فرمایا خالہ ماں کے درجے میں ہوتی ہے اور علی رضی اللہ عنہ سے فرمایا کہ تم مجھ سے ہو اور میں تم سے ہوں۔ جعفر رضی اللہ عنہ سے فرمایا کہ تم صورت و شکل اور عادت و اخلاق دونوں میں مجھ سے مشابہ ہو اور زید رضی اللہ عنہ سے فرمایا کہ تم ہمارے بھائی اور ہمارے مولا ہو۔ علی رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ حمزہ رضی اللہ عنہ کی صاحبزادی کو آپ اپنے نکاح میں لے لیں لیکن آپ نے فرمایا کہ وہ میرے رضاعی بھائی کی لڑکی ہے۔' WHERE id = 4071;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے عبدالوہاب بن عبدالمجید نے بیان کیا ‘ کہا کہ میں نے یحییٰ بن سعید سے سنا ‘ کہا کہ مجھے عمرہ بنت عبدالرحمٰن نے خبر دی ‘ کہا کہ میں نے عائشہ رضی اللہ عنہا سے سنا ‘ انہوں نے بیان کیا زید بن حارثہ ‘ جعفر بن ابی طالب اور عبداللہ بن رواحہ رضی اللہ عنہم کی شہادت کی خبر آئی تھی ‘ نبی کریم صلی اللہ علیہ وسلم بیٹھے ہوئے تھے اور آپ کے چہرے سے غم ظاہر ہو رہا تھا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں دروازے کی دراڑ سے جھانک رہی تھی۔ اتنے میں ایک آدمی نے آ کر عرض کیا: یا رسول اللہ! جعفر رضی اللہ عنہ کے گھر کی عورتیں چلاّ کر رو رہی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے حکم دیا کہ انہیں روک دو۔ بیان کیا کہ وہ صاحب گئے اور پھر واپس آ کر کہا کہ میں نے انہیں روکا اور یہ بھی کہہ دیا کہ انہوں نے اس کی بات نہیں مانی۔ پھر اس نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پھر منع کرنے کے لیے فرمایا۔ وہ صاحب پھر جا کر واپس آئے اور کہا: قسم اللہ کی! وہ تو ہم پر غالب آ گئی ہیں۔ عائشہ رضی اللہ عنہا بیان کرتی تھیں کہ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ پھر ان کے منہ میں مٹی جھونک دو۔ ام المؤمنین رضی اللہ عنہا نے بیان کیا ‘ میں نے کہا: اللہ تیری ناک غبار آلود کرے نہ تو تو عورتوں کو روک سکا نہ تو نے رسول اللہ صلی اللہ علیہ وسلم کو تکلیف دینا ہی چھوڑا۔' WHERE id = 4082;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ نے بیان کیا ‘ کہا ہم سے حماد بن مسعدہ نے بیان کیا ‘ ان سے یزید بن ابی عبید نے اور ان سے سلمہ بن اکوع رضی اللہ عنہ نے کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ سات غزوے کئے۔ اس سلسلہ میں انہوں نے غزوہ خیبر ‘ غزوہ حدیبیہ ‘ غزوہ حنین اور غزوہ ذات القرد کا ذکر کیا۔ یزید نے کہا کہ باقی غزووں کے نام میں بھول گیا۔' WHERE id = 4092;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا ‘ انہوں نے کہا ہم کو ابن شہاب نے خبر دی ‘ انہیں ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جب حنین کا ارادہ کیا تو فرمایا ”ان شاءاللہ کل ہمارا قیام خیف بنی کنانہ میں ہو گا جہاں قریش نے کفر کے لیے قسم کھائی تھی۔“' WHERE id = 4103;
UPDATE hadiths SET urdu = 'ہم سے سعید بن شرحبیل نے بیان کیا ‘ کہا ہم سے لیث بن سعد نے بیان کیا ‘ ان سے مقبری نے کہ ابوشریح عدوی رضی اللہ عنہ نے ( مدینہ کے امیر ) عمرو بن سعید سے کہا جب کہ عمرو بن سعید ( عبداللہ بن زبیر رضی اللہ عنہما کے خلاف ) مکہ کی طرف لشکر بھیج رہے تھے کہ اے امیر! مجھے اجازت دیجئیے کہ میں آپ سے ایک حدیث بیان کروں جو رسول اللہ صلی اللہ علیہ وسلم نے فتح مکہ کے دوسرے دن ارشاد فرمائی تھی۔ اس حدیث کو نبی کریم صلی اللہ علیہ وسلم ارشاد فرما رہے تھے تو میں اپنی آنکھوں سے آپ کو دیکھ رہا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے پہلے اللہ کی حمد و ثنا بیان کی اور پھر فرمایا ‘ بلاشبہ مکہ کو اللہ تعالیٰ نے حرمت والا شہر قرار دیا ہے کسی انسان نے اسے اپنے طرف سے حرمت والا قرار نہیں دیا۔ اس لیے کسی شخص کے لیے بھی جو اللہ اور یوم آخرت پر ایمان رکھتا ہو ‘ جائز نہیں کہ اس میں کسی کا خون بہائے اور کوئی اس سر زمیں کا کوئی درخت کاٹے اور اگر کوئی شخص رسول اللہ صلی اللہ علیہ وسلم کے ( فتح مکہ کے موقع پر ) جنگ سے اپنے لیے بھی رخصت نکالے تو تم اس سے کہہ دینا کہ اللہ تعالیٰ نے صرف اپنے رسول کو ( تھوڑی دیر کے لیے ) اس کی اجازت دی تھی۔ ہمارے لیے بالکل اجازت نہیں ہے اور مجھے بھی اس کی اجازت دن کے تھوڑے سے حصے کے لیے ملی تھی اور آج پھر اس کی حرمت اسی طرح لوٹ آئی ہے جس طرح کل یہ شہر حرمت والا تھا۔ پس جو لوگ یہاں موجود ہیں وہ ( ان کو میرا کلام ) پہنچا دیں جو موجود نہیں۔ ابوشریح سے پوچھا گیا کہ عمرو بن سعید نے آپ کو پھر جواب کیا دیا تھا؟ تو انہوں نے بتایا کہ اس نے کہا کہ میں یہ مسائل تم سے زیادہ جانتا ہوں ‘ حرم کسی گنہگار کو پناہ نہیں دیتا ‘ نہ کسی کا خون کر کے بھاگنے والے کو پناہ دیتا ہے ‘ مفسد کو بھی پناہ نہیں دیتا۔' WHERE id = 4113;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوبشر نے اور ان سے مجاہد نے کہ میں نے ابن عمر رضی اللہ عنہما سے عرض کیا کہ میرا ارادہ ہے کہ میں ملک شام کو ہجرت کر جاؤں، فرمایا: اب ہجرت باقی نہیں رہی، جہاد ہی باقی رہ گیا ہے۔ اس لیے جاؤ اور خود کو پیش کرو۔ اگر تم نے کچھ پا لیا تو بہتر ورنہ واپس آ جانا۔' WHERE id = 4125;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں یحییٰ بن سعید نے، انہیں عمرو بن کثیر بن افلح نے، انہیں قتادہ کے مولیٰ ابو محمد نے اور ان سے ابوقتادہ رضی اللہ عنہ نے بیان کیا کہ غزوہ حنین کے لیے ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ نکلے۔ جب جنگ ہوئی تو مسلمان ذرا ڈگمگا گئے ( یعنی آگے پیچھے ہو گئے ) ۔ میں نے دیکھا کہ ایک مشرک ایک مسلمان کے اوپر غالب ہو رہا ہے، میں نے پیچھے سے اس کی گردن پر تلوار ماری اور اس کی زرہ کاٹ ڈالی۔ اب وہ مجھ پر پلٹ پڑا اور مجھے اتنی زور سے بھینچا کہ موت کی تصویر میری آنکھوں میں پھر گئی، آخر وہ مر گیا اور مجھے چھوڑ دیا۔ پھر میری ملاقات عمر رضی اللہ عنہ سے ہوئی۔ میں نے پوچھا لوگوں کو کیا ہو گیا ہے؟ انہوں نے فرمایا، یہی اللہ عزوجل کا حکم ہے۔ پھر مسلمان پلٹے اور ( جنگ ختم ہونے کے بعد ) نبی کریم صلی اللہ علیہ وسلم تشریف فرما ہوئے اور فرمایا کہ جس نے کسی کو قتل کیا ہو اور اس کے لیے کوئی گواہ بھی رکھتا ہو تو اس کا تمام سامان و ہتھیار اسے ہی ملے گا۔ میں نے اپنے دل میں کہا کہ میرے لیے کون گواہی دے گا؟ پھر میں بیٹھ گیا۔ بیان کیا کہ پھر آپ نے دوبارہ یہی فرمایا۔ اس مرتبہ پھر میں نے دل میں کہا کہ میرے لیے کون گواہی دے گا؟ اور پھر بیٹھ گیا۔ آپ صلی اللہ علیہ وسلم نے پھر اپنا فرمان دہرایا تو میں اس مرتبہ کھڑا ہو گیا۔ آپ صلی اللہ علیہ وسلم نے اس مرتبہ فرمایا کیا بات ہے، اے ابوقتادہ! میں نے آپ صلی اللہ علیہ وسلم کو بتایا تو ایک صاحب ( اسود بن خزاعی اسلمی ) نے کہا کہ یہ سچ کہتے ہیں اور ان کے مقتول کا سامان میرے پاس ہے۔ آپ میرے حق میں انہیں راضی کر دیں ( کہ سامان مجھ سے نہ لیں ) اس پر ابوبکر رضی اللہ عنہ نے فرمایا: نہیں، اللہ کی قسم! اللہ کے شیروں میں سے ایک شیر، جو اللہ اور اس کے رسول صلی اللہ علیہ وسلم کی طرف سے لڑتا ہے پھر نبی کریم صلی اللہ علیہ وسلم اس کا حق تمہیں ہرگز نہیں دے سکتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہوں نے سچ کہا، تم سامان ابوقتادہ کو دے دو۔ انہوں نے سامان مجھے دے دیا۔ میں نے اس سامان سے قبیلہ سلمہ کے محلہ میں ایک باغ خریدا اسلام کے بعد یہ میرا پہلا مال تھا، جسے میں نے حاصل کیا تھا۔' WHERE id = 4136;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے ازہر بن سعد سمان نے بیان کیا اور ان سے عبداللہ بن عون نے، انہیں ہشام بن زید بن انس نے خبر دی اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ غزوہ حنین میں جب قبیلہ ہوازن سے جنگ شروع ہوئی تو نبی کریم صلی اللہ علیہ وسلم کے ساتھ دس ہزار فوج تھی۔ قریش کے وہ لوگ بھی ساتھ تھے جنہیں فتح مکہ کے بعد نبی کریم صلی اللہ علیہ وسلم نے چھوڑ دیا تھا پھر سب نے پیٹھ پھیر لی۔ آپ صلی اللہ علیہ وسلم نے پکارا: اے انصاریو! انہوں نے جواب دیا کہ ہم حاضر ہیں، یا رسول اللہ! آپ کے ہر حکم کی تعمیل کے لیے ہم حاضر ہیں۔ ہم آپ کے سامنے ہیں۔ پھر آپ صلی اللہ علیہ وسلم اپنی سواری سے اتر گئے اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں اللہ کا بندہ اور اس کا رسول ہوں پھر مشرکین کی ہار ہو گئی۔ جن لوگوں کو آپ صلی اللہ علیہ وسلم نے فتح مکہ کے بعد چھوڑ دیا تھا اور مہاجرین کو نبی کریم صلی اللہ علیہ وسلم نے دیا لیکن انصار کو کچھ نہیں دیا۔ اس پر انصار رضی اللہ عنہم نے اپنے غم کا اظہار کیا تو آپ نے انہیں بلایا اور ایک خیمہ میں جمع کیا پھر فرمایا کہ تم اس پر راضی نہیں ہو کہ دوسرے لوگ بکری اور اونٹ اپنے ساتھ لے جائیں اور تم رسول اللہ صلی اللہ علیہ وسلم کو اپنے ساتھ لے جاؤ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر لوگ کسی وادی یا گھاٹی میں رہیں اور انصار دوسری گھاٹی میں رہیں تو میں انصار کی گھاٹی کو اختیار کروں گا۔' WHERE id = 4147;
UPDATE hadiths SET urdu = 'مجھ سے حبان بن موسیٰ نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں زکریا بن اسحاق نے، انہیں یحییٰ بن عبداللہ بن صیفی نے، انہیں ابن عباس رضی اللہ عنہما کے غلام ابومعبد نافذ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے معاذ بن جبل رضی اللہ عنہ کو یمن کا ( حاکم بنا کر بھیجتے وقت انہیں ) ہدایت فرمائی تھی کہ تم ایک ایسی قوم کی طرف جا رہے ہو جو اہل کتاب یہودی اور نصرانی وغیرہ میں سے ہیں۔ اس لیے جب تم وہاں پہنچو تو پہلے انہیں اس کی دعوت دو کہ وہ گواہی دیں کہ اللہ کے سوا کوئی معبود نہیں اور محمد صلی اللہ علیہ وسلم اللہ کے رسول ہیں۔ اگر اس میں وہ تمہاری بات مان لیں تو پھر انہیں بتاؤ کہ اللہ تعالیٰ نے روزانہ ان پر پانچ وقت کی نمازیں فرض کی ہیں، جب یہ بھی مان لیں تو انہیں بتاؤ کہ اللہ تعالیٰ نے ان پر زکوٰۃ کو بھی فرض کیا ہے، جو ان کے مالدار لوگوں سے لی جائے گی اور انہیں کے غریبوں میں تقسیم کر دی جائے گی۔ جب یہ بھی مان جائیں تو ( پھر زکوٰۃ وصول کرتے وقت ) ان کا سب سے عمدہ مال لینے سے پرہیز کرنا اور مظلوم کی آہ سے ہر وقت ڈرتے رہنا کہ اس کے اور اللہ کے درمیان کوئی رکاوٹ نہیں ہوتی ہے۔ ابوعبداللہ امام بخاری رحمہ اللہ نے کہا کہ سورۃ المائدہ میں جو «طوعت‏» کا لفظ آیا ہے اس کا وہی معنی ہے جو «طاعت» اور «أطاعت» کا ہے جیسے کہتے ہیں «طعت وطعت وأطعت‏.‏» سب کا معنی ایک ہی ہے۔' WHERE id = 4159;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی شیبہ عبسی نے بیان کیا، کہا کہ ہم سے عبداللہ بن ادریس نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس بن ابی حازم نے اور ان سے جریر بن عبداللہ بجلی رضی اللہ عنہ نے بیان کیا کہ ( یمن سے واپسی پر مدینہ آنے کے لیے ) میں دریا کے راستے سے سفر کر رہا تھا۔ اس وقت یمن کے دو آدمیوں ذوکلاع اور ذوعمرو سے میری ملاقات ہوئی میں ان سے نبی کریم صلی اللہ علیہ وسلم کی باتیں کرنے لگا اس پر ذوعمرو نے کہا: اگر تمہارے صاحب ( یعنی نبی کریم صلی اللہ علیہ وسلم ) وہی ہیں جن کا ذکر تم کر رہے ہو تو ان کی وفات کو بھی تین دن گزر چکے۔ یہ دونوں میرے ساتھ ہی ( مدینہ ) کی طرف چل رہے تھے۔ راستے میں ہمیں مدینہ کی طرف سے آتے ہوئے کچھ سوار دکھائی دئیے، ہم نے ان سے پوچھا تو انہوں نے اس کی تصدیق کی کہ نبی کریم صلی اللہ علیہ وسلم وفات پا گئے ہیں۔ آپ کے خلیفہ ابوبکر رضی اللہ عنہ منتخب ہوئے ہیں اور لوگ اب بھی سب خیریت سے ہیں۔ ان دونوں نے مجھ سے کہا کہ اپنے صاحب ( ابوبکر رضی اللہ عنہ ) سے کہنا کہ ہم آئے تھے اور ان شاءاللہ پھر مدینہ آئیں گے یہ کہہ کر دونوں یمن کی طرف واپس چلے گئے۔ پھر میں نے ابوبکر رضی اللہ عنہ کو ان کی باتوں کی اطلاع دی تو آپ نے فرمایا کہ پھر انہیں اپنے ساتھ لائے کیوں نہیں؟ بہت دنوں بعد خلافت عمری میں ذوعمرو نے ایک مرتبہ مجھ سے کہا کہ جریر! تمہارا مجھ پر احسان ہے اور تمہیں میں ایک بات بتاؤں گا کہ تم اہل عرب اس وقت تک خیر و بھلائی کے ساتھ رہو گے جب تک تمہارا طرز عمل یہ ہو گا کہ جب تمہارا کوئی امیر وفات پا جائے گا تو تم اپنا کوئی دوسرا امیر منتخب کر لیا کرو گے۔ لیکن جب ( امارت کے لیے ) تلوار تک بات پہنچ جائے تو تمہارے امیر بادشاہ بن جائیں گے۔ بادشاہوں کی طرح غصہ ہوا کریں گے اور انہیں کی طرح خوش ہوا کریں گے۔' WHERE id = 4170;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ابوجمرہ نے بیان کیا، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا کہ وہ بیان کرتے تھے کہ جب قبیلہ عبدالقیس کا وفد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو انہوں نے عرض کیا یا رسول اللہ! ہم قبیلہ ربیعہ کی ایک شاخ ہیں اور ہمارے اور آپ کے درمیان کفار مضر کے قبائل پڑتے ہیں۔ ہم آپ کی خدمت میں صرف حرمت والے مہینوں میں ہی حاضر ہو سکتے ہیں۔ اس لیے آپ چند ایسی باتیں بتلا دیجئیے کہ ہم بھی ان پر عمل کریں اور جو لوگ ہمارے ساتھ نہیں آ سکے ہیں، انہیں بھی اس کی دعوت دیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں تمہیں چار چیزوں کا حکم دیتا ہوں اور چار چیزوں سے روکتا ہوں ( میں تمہیں حکم دیتا ہوں ) اللہ پر ایمان لانے کا یعنی اس کی گواہی دینے کا کہ اللہ کے سوا کوئی معبود نہیں، پھر آپ صلی اللہ علیہ وسلم نے ( اپنی انگلی سے ) ایک اشارہ کیا، اور نماز قائم کرنے کا، زکٰوۃ دینے کا اور اس کا کہ مال غنیمت میں سے پانچواں حصہ ( بیت المال کو ) ادا کرتے رہنا اور میں تمہیں دباء، نقیر، مزفت اور حنتم کے برتنوں کے استعمال سے روکتا ہوں۔' WHERE id = 4180;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا کہ انہوں نے محمد بن المنکدر سے سنا، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، وہ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھ سے فرمایا تھا جب میرے پاس بحرین سے روپیہ آئے گا تو میں تمہیں اتنا اتنا تین لپ بھر کر روپیہ دوں گا، لیکن بحرین سے جس وقت روپیہ آیا تو نبی کریم صلی اللہ علیہ وسلم کی وفات ہو چکی تھی۔ اس لیے وہ روپیہ ابوبکر صدیق رضی اللہ عنہ کے پاس آیا اور انہوں نے اعلان کروا دیا کہ اگر کسی کا نبی کریم صلی اللہ علیہ وسلم پر قرض یا کسی سے نبی کریم صلی اللہ علیہ وسلم کا کوئی وعدہ ہو تو وہ میرے پاس آئے۔ جابر رضی اللہ عنہ نے بیان کیا کہ میں ان کے یہاں آ گیا اور انہیں بتایا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے فرمایا تھا کہ اگر بحرین سے میرے پاس روپیہ آیا تو میں تمہیں اتنا اتنا تین لپ بھر کر دوں گا۔ جابر رضی اللہ عنہ نے بیان کیا کہ پھر میں نے ان سے ملاقات کی اور ان سے اس کے متعلق کہا لیکن انہوں نے اس مرتبہ مجھے نہیں دیا۔ میں پھر ان کے یہاں گیا اس مرتبہ بھی انہوں نے نہیں دیا۔ میں تیسری مرتبہ گیا، اس مرتبہ بھی انہوں نے نہیں دیا۔ اس لیے میں نے ان سے کہا کہ میں آپ کے یہاں ایک مرتبہ آیا۔ آپ نے نہیں دیا، پھر آیا اور آپ نے نہیں دیا۔ پھر تیسری مرتبہ آیا ہوں اور آپ اس مرتبہ بھی نہیں دے رہے ہیں۔ اگر آپ کو مجھے دینا ہے تو دے دیجئیے ورنہ صاف کہہ دیجئیے کہ میرا دل دینے کو نہیں چاہتا، میں بخیل ہوں۔ اس پر ابوبکر رضی اللہ عنہ نے فرمایا تم نے کہا ہے کہ میرے معاملہ میں بخل کر لو، بھلا بخل سے بڑھ کر اور کیا عیب ہو سکتا ہے۔ تین مرتبہ انہوں نے یہ جملہ دہرایا اور کہا میں نے تمہیں جب بھی ٹالا تو میرا ارادہ یہی تھا کہ بہرحال تمہیں دینا ہے۔ اور اسی سند سے عمرو بن دینار سے روایت ہے، ان سے محمد بن علی باقر نے بیان کیا، انہوں نے کہا کہ میں نے جابر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ میں حاضر ہوا تو ابوبکر رضی اللہ عنہ نے مجھے ایک لپ بھر کر روپیہ دیا اور کہا کہ اسے گن لو۔ میں نے گنا تو پانچ سو تھا۔ فرمایا کہ دو مرتبہ اتنا ہی اور لے لو۔' WHERE id = 4191;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے اسماعیل بن ابی خالد نے بیان کیا، ان سے قیس نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ جب میں اپنے وطن سے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہونے کے لیے چلا تو راستے میں، میں نے یہ شعر پڑھا ( ترجمہ ) ”کیسی ہے تکلیف کی لمبی یہ رات، خیر اس نے کفر سے دی ہے نجات“ اور میرا غلام راستے میں بھاگ گیا تھا، پھر میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور آپ سے بیعت کی، ابھی آپ کے پاس میں بیٹھا ہی ہوا تھا کہ وہ غلام دکھائی دیا، آپ صلی اللہ علیہ وسلم نے مجھ سے فرمایا: ابوہریرہ! یہ ہے تمہارا غلام! میں نے کہا اللہ کے لیے میں نے اس کو اب آزاد کر دیا۔' WHERE id = 4201;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، انہوں نے کہا ہم سے شعبہ بن حجاج نے بیان کیا، ان سے علی بن مدرک نے بیان کیا، ان سے ابوزرعہ ہرم بن عمرو بن جریر نے بیان کیا اور ان سے جریر بن عبداللہ بجلی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے حجۃ الوداع کے موقع پر جریر رضی اللہ عنہ سے فرمایا تھا لوگوں کو خاموش کر دو، پھر فرمایا، میرے بعد کافر نہ بن جانا کہ ایک دوسرے کی گردن مارنے لگو۔' WHERE id = 4212;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید بن عبداللہ بن ابی بردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ مجھے میرے ساتھیوں نے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں بھیجا کہ میں آپ صلی اللہ علیہ وسلم سے ان کے لیے سواری کے جانوروں کی درخواست کروں۔ وہ لوگ آپ کے ساتھ جیش عسرت ( یعنی غزوہ تبوک ) میں شریک ہونا چاہتے تھے۔ میں نے عرض کیا: یا رسول اللہ! میرے ساتھیوں نے مجھے آپ کی خدمت میں بھیجا ہے تاکہ آپ ان کے لیے سواری کے جانوروں کا انتظام کرا دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا: اللہ کی قسم! میں تم کو سواری کے جانور نہیں دے سکتا۔ میں جب آپ کی خدمت میں حاضر ہوا تھا تو آپ غصہ میں تھے اور میں اسے معلوم نہ کر سکا تھا۔ آپ صلی اللہ علیہ وسلم کے انکار سے میں بہت غمگین واپس ہوا۔ یہ خوف بھی تھا کہ کہیں آپ سواری مانگنے کی وجہ سے خفا نہ ہو گئے ہوں۔ میں اپنے ساتھیوں کے پاس آیا اور انہیں نبی کریم صلی اللہ علیہ وسلم کے ارشاد کی خبر دی، لیکن ابھی کچھ زیادہ وقت نہیں گزرا تھا کہ میں نے بلال رضی اللہ عنہ کی آواز سنی، وہ پکار رہے تھے، اے عبداللہ بن قیس! میں نے جواب دیا تو انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم تمہیں بلا رہے ہیں۔ میں آپ کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ دو جوڑے اور یہ دو جوڑے اونٹ کے لے جاؤ۔ آپ نے چھ اونٹ عنایت فرمائے۔ ان اونٹوں کو آپ نے اسی وقت سعد رضی اللہ عنہ سے خریدا تھا اور فرمایا کہ انہیں اپنے ساتھیوں کو دے دو اور انہیں بتاؤ کہ اللہ تعالیٰ نے یا آپ نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم نے تمہاری سواری کے لیے انہیں دیا ہے، ان پر سوار ہو جاؤ۔ میں ان اونٹوں کو لے کر اپنے ساتھیوں کے پاس گیا اور ان سے میں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے تمہاری سواری کے لیے یہ عنایت فرمائے ہیں لیکن اللہ کی قسم! کہ اب تمہیں ان صحابہ رضی اللہ عنہم کے پاس چلنا پڑے گا، جنہوں نے نبی کریم صلی اللہ علیہ وسلم کا انکار فرمانا سنا تھا، کہیں تم یہ خیال نہ کر بیٹھو کہ میں نے تم سے نبی کریم صلی اللہ علیہ وسلم کے ارشاد کے متعلق غلط بات کہہ دی تھی۔ انہوں نے کہا کہ تمہاری سچائی میں ہمیں کوئی شبہ نہیں ہے لیکن اگر آپ کا اصرار ہے تو ہم ایسا بھی کر لیں گے۔ ابوموسیٰ رضی اللہ عنہ ان میں سے چند لوگوں کو لے کر ان صحابہ رضی اللہ عنہم کے پاس آئے جنہوں نے نبی کریم صلی اللہ علیہ وسلم کا وہ ارشاد سنا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے پہلے تو دینے سے انکار کیا تھا لیکن پھر عنایت فرمایا۔ ان صحابہ رضی اللہ عنہم نے بھی اسی طرح حدیث بیان کی جس طرح ابوموسیٰ رضی اللہ عنہ نے ان سے بیان کی تھی۔' WHERE id = 4222;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ہیثم نے بیان کیا، کہا ہم سے عوف اعرابی نے بیان کیا، ان سے امام حسن بصری نے، ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ جنگ جمل کے موقع پر وہ جملہ میرے کام آ گیا جو میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا۔ میں ارادہ کر چکا تھا کہ اصحاب جمل، عائشہ رضی اللہ عنہا اور آپ کے لشکر کے ساتھ شریک ہو کر ( علی رضی اللہ عنہ کی ) فوج سے لڑوں۔ انہوں نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا کہ اہل فارس نے کسریٰ کی لڑکی کو وارث تخت و تاج بنایا ہے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ قوم کبھی فلاح نہیں پا سکتی جس نے اپنا حکمران کسی عورت کو بنایا ہو۔' WHERE id = 4232;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے کہ عروہ بن زبیر نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا تندرستی کے زمانے میں رسول اللہ صلی اللہ علیہ وسلم فرمایا کرتے تھے کہ جب بھی کسی نبی کی روح قبض کی گئی تو پہلے جنت میں اس کی قیام گاہ اسے ضرور دکھا دی گئی، پھر اسے اختیار دیا گیا ( راوی کو شک تھا کہ لفظ «يحيا» ہے یا «يخير»،‏‏‏‏ دونوں کا مفہوم ایک ہی ہے ) پھر جب نبی کریم صلی اللہ علیہ وسلم بیمار پڑے اور وقت قریب آ گیا تو سر مبارک عائشہ رضی اللہ عنہا کی ران پر تھا اور آپ پر غشی طاری ہو گئی تھی، جب کچھ ہوش ہوا تو آپ کی آنکھیں گھر کی چھت کی طرف اٹھ گئیں اور آپ صلی اللہ علیہ وسلم نے فرمایا۔ «اللهم في الرفيق الأعلى» ۔ میں سمجھ گئی کہ اب نبی کریم صلی اللہ علیہ وسلم ہمیں ( یعنی دنیاوی زندگی کو ) پسند نہیں فرمائیں گے۔ مجھے وہ حدیث یاد آ گئی جو آپ صلی اللہ علیہ وسلم نے تندرستی کے زمانے میں فرمائی تھی۔' WHERE id = 4243;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبید نے بیان کیا، کہا ہم سے عیسیٰ بن یونس نے بیان کیا، ان سے عمر بن سعید نے، انہیں ابن ابی ملیکہ نے خبر دی اور انہیں عائشہ رضی اللہ عنہا کے غلام ابوعمرو ذکوان نے کہ عائشہ رضی اللہ عنہا فرمایا کرتی تھیں، اللہ کی بہت سی نعمتوں میں ایک نعمت مجھ پر یہ بھی ہے کہ رسول اللہ صلی اللہ علیہ وسلم کی وفات میرے گھر میں اور میری باری کے دن ہوئی۔ آپ اس وقت میرے سینے سے ٹیک لگائے ہوئے تھے۔ اور یہ کہ اللہ تعالیٰ نے آپ صلی اللہ علیہ وسلم کی وفات کے وقت میرے اور آپ کے تھوک کو ایک ساتھ جمع کیا تھا کہ عبدالرحمٰن رضی اللہ عنہ گھر میں آئے تو ان کے ہاتھ میں مسواک تھی۔ آپ صلی اللہ علیہ وسلم مجھ پر ٹیک لگائے ہوئے تھے، میں نے دیکھا کہ آپ صلی اللہ علیہ وسلم اس مسواک کو دیکھ رہے ہیں۔ میں سمجھ گئی کہ آپ مسواک کرنا چاہتے ہیں، اس لیے میں نے آپ سے پوچھا، یہ مسواک آپ کے لیے لے لوں؟ آپ صلی اللہ علیہ وسلم نے سر کے اشارہ سے اثبات میں جواب دیا، میں نے وہ مسواک ان سے لے لی۔ آپ صلی اللہ علیہ وسلم اسے چبا نہ سکے، میں نے پوچھا آپ کے لیے میں اسے نرم کر دوں؟ آپ نے سر کے اشارہ سے اثبات میں جواب دیا۔ میں نے مسواک نرم کر دی۔ آپ کے سامنے ایک بڑا پیالہ تھا، چمڑے کا یا لکڑی کا ( راوی حدیث ) عمر کو اس سلسلے میں شک تھا، اس کے اندر پانی تھا، نبی کریم صلی اللہ علیہ وسلم باربار اپنے ہاتھ اس کے اندر داخل کرتے اور پھر انہیں اپنے چہرے پر پھیرتے اور فرماتے «لا إله إلا الله» ۔ موت کے وقت شدت ہوتی ہے پھر آپ صلی اللہ علیہ وسلم اپنا ہاتھ اٹھا کر کہنے لگے «في الرفيق الأعلى» یہاں تک کہ آپ رحلت فرما گئے اور آپ کا ہاتھ جھک گیا۔' WHERE id = 4254;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عتبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نخعی نے، ان سے اسود بن یزید نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ کی زرہ ایک یہودی کے یہاں تیس صاع جَو کے بدلے میں گروی رکھی ہوئی تھی۔' WHERE id = 4267;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا کہ ہم سے جریر نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے، ان سے عمرو بن شرحبیل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا، اللہ کے نزدیک کون سا گناہ سب سے بڑا ہے؟ فرمایا اور یہ کہ تم اللہ کے ساتھ کسی کو برابر ٹھہراؤ حالانکہ اللہ ہی نے تم کو پید اکیا ہے۔ میں نے عرض کیا یہ تو واقعی سب سے بڑا گناہ ہے، پھر اس کے بعد کون سا گناہ سب سے بڑا ہے؟ فرمایا یہ کہ تم اپنی اولاد کو اس خوف سے مار ڈالو کہ وہ تمہارے ساتھ کھائیں گے۔ میں نے پوچھا اور اس کے بعد؟ فرمایا یہ کہ تم اپنے پڑوسی کی عورت سے زنا کرو۔' WHERE id = 4277;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن راشد نے بیان کیا، کہا ہم سے جریر اور ابواسامہ نے بیان کیا۔ (حدیث کے الفاظ جریر کی روایت کے مطابق ہیں) ان سے اعمش نے، ان سے ابوصالح نے اور ابواسامہ نے بیان کیا (یعنی اعمش کے واسطہ سے کہ) ہم سے ابوصالح نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن نوح علیہ السلام کو بلایا جائے گا۔ وہ عرض کریں گے، «لبيك وسعديك» : یا رب! اللہ رب العزت فرمائے گا، کیا تم نے میرا پیغام پہنچا دیا تھا؟ نوح علیہ السلام عرض کریں گے کہ میں نے پہنچا دیا تھا، پھر ان کی امت سے پوچھا جائے گا، کیا انہوں نے تمہیں میرا پیغام پہنچا دیا تھا؟ وہ لوگ کہیں گے کہ ہمارے یہاں کوئی ڈرانے والا نہیں آیا۔ اللہ تعالیٰ فرمائے گا ( نوح علیہ السلام سے ) کہ آپ کے حق میں کوئی گواہی بھی دے سکتا ہے؟ وہ کہیں گے کہ محمد ( صلی اللہ علیہ وسلم ) اور ان کی امت میری گواہ ہے۔ چنانچہ آپ صلی اللہ علیہ وسلم کی امت ان کے حق میں گواہی دے گی کہ انہوں نے پیغام پہنچا دیا تھا اور رسول ( یعنی آپ صلی اللہ علیہ وسلم ) اپنی امت کے حق میں گواہی دیں گے ( کہ انہوں نے سچی گواہی دی ہے ) یہی مراد ہے اللہ کے اس ارشاد سے «وكذلك جعلناكم أمة وسطا لتكونوا شهداء على الناس ويكون الرسول عليكم شهيدا‏» کہ ”اور اسی طرح ہم نے تم کو امت وسط بنایا تاکہ تم لوگوں کے لیے گواہی دو اور رسول تمہارے لیے گواہی دیں۔“ آیت میں لفظ «وسط» کے معنی عادل، منصف، بہتر کے ہیں۔' WHERE id = 4287;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے شقیق نے اور ان سے عبداللہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک کلمہ ارشاد فرمایا اور میں نے ایک اور بات کہی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص اس حالت میں مر جائے کہ وہ اللہ کے سوا اوروں کو بھی اس کا شریک ٹھہراتا رہا ہو تو وہ جہنم میں جاتا ہے اور میں نے یوں کہا کہ جو شخص اس حالت میں مرے کہ اللہ کا کسی کو شریک نہ ٹھہراتا رہا تو وہ جنت میں جاتا ہے۔' WHERE id = 4297;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے بکر بن مضر نے بیان کیا، ان سے عمرو بن حارث نے، ان سے بکیر بن عبداللہ نے، ان سے سلمہ بن اکوع کے مولیٰ یزید بن ابی عبید نے اور ان سے سلمہ بن اکوع رضی اللہ عنہ نے بیان کیا کہ جب یہ آیت نازل ہوئی۔ «وعلى الذين يطيقونه فدية طَعام مسكين‏» تو جس کا جی چاہتا تھا روزہ چھوڑ دیتا تھا اور اس کے بدلے میں فدیہ دے دیتا تھا۔ یہاں تک کہ اس کے بعد والی آیت نازل ہوئی اور اس نے پہلی آیت کو منسوخ کر دیا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ بکیر کا انتقال یزید سے پہلے ہو گیا تھا۔ بکیر جو یزید کے شاگرد تھے یزید سے پہلے 120 ھ میں مر گئے تھے۔' WHERE id = 4307;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے محمد بن حازم نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے ان کے والد نے اور ان سے ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا نے کہ قریش اور ان کے طریقے کی پیروی کرنے والے عرب ( حج کے لیے ) مزدلفہ میں ہی وقوف کیا کرتے تھے، اس کا نام انہوں الحمس رکھا تھا اور باقی عرب عرفات کے میدان میں وقوف کرتے تھے۔ پھر جب اسلام آیا تو اللہ تعالیٰ نے اپنے نبی کریم صلی اللہ علیہ وسلم کو حکم دیا کہ آپ عرفات میں آئیں اور وہیں وقوف کریں اور پھر وہاں سے مزدلفہ آئیں۔ آیت «ثم أفيضوا من حيث أفاض الناس‏» سے یہی مراد ہے۔' WHERE id = 4318;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے حارث بن شبل نے، ان سے ابوعمرو شیبانی نے اور ان سے زید بن ارقم رضی اللہ عنہ نے بیان کیا کہ پہلے ہم نماز پڑھتے ہوئے بات بھی کر لیا کرتے تھے، کوئی بھی شخص اپنے دوسرے بھائی سے اپنی کسی ضرورت کے لیے بات کر لیتا تھا۔ یہاں تک کہ یہ آیت نازل ہوئی «حافظوا على الصلوات والصلاة الوسطى وقوموا لله قانتين‏» ”سب ہی نمازوں کی پابندی رکھو اور خاص طور پر بیچ والی نماز کی اور اللہ کے سامنے فرماں برداروں کی طرح کھڑے ہوا کرو۔“ اس آیت کے ذریعہ ہمیں نماز میں چپ رہنے کا حکم دیا گیا۔' WHERE id = 4330;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عاصم بن سلیمان نے، ان سے شعبی نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ آخری آیت جو نبی کریم صلی اللہ علیہ وسلم پر نازل ہوئی وہ سود کی آیت تھی۔' WHERE id = 4340;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے ابوضمرہ نے بیان کیا، ان سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ کچھ یہودی نبی کریم صلی اللہ علیہ وسلم کے پاس اپنے قبیلہ کے ایک مرد اور ایک عورت کو لے کر آئے، جنہوں نے زنا کیا تھا۔ آپ صلی اللہ علیہ وسلم نے ان سے پوچھا اگر تم میں سے کوئی زنا کرے تو تم اس کو کیا سزا دیتے ہو؟ انہوں نے کہا کہ ہم اس کا منہ کالا کر کے اسے مارتے پیٹتے ہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کیا توریت میں رجم کا حکم نہیں ہے؟ انہوں نے کہا کہ ہم نے توریت میں رجم کا حکم نہیں دیکھا۔ عبداللہ بن سلام رضی اللہ عنہ بولے کہ تم جھوٹ بول رہے ہو، توریت لاؤ اور اسے پڑھو، اگر تم سچے ہو۔ ( جب توریت لائی گئی ) تو ان کے ایک بہت بڑے مدرس نے جو انہیں توریت کا درس دیا کرتا تھا، آیت رجم پر اپنی ہتھیلی رکھ لی اور اس سے پہلے اور اس کے بعد کی عبارت پڑھنے لگا اور آیت رجم نہیں پڑھتا تھا۔ عبداللہ بن سلام رضی اللہ عنہ نے اس کے ہاتھ کو آیت رجم سے ہٹا دیا اور اس سے پوچھا کہ یہ کیا ہے؟ جب یہودیوں نے دیکھا تو کہنے لگے کہ یہ آیت رجم ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے حکم دیا اور ان دونوں کو مسجد نبوی کے قریب ہی جہاں جنازے لا کر رکھے جاتے تھے، رجم کر دیا گیا۔ میں نے دیکھا کہ اس عورت کا ساتھی عورت کو پتھر سے بچانے کے لیے اس پر جھک جھک پڑتا تھا۔' WHERE id = 4351;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں عروہ بن زبیر نے خبر دی اور انہیں اسامہ بن زید رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم ایک گدھے کی پشت پر فدک کی بنی ہوئی ایک موٹی چادر رکھنے کے بعد سوار ہوئے اور اسامہ بن زید رضی اللہ عنہما کو اپنے پیچھے بٹھایا۔ آپ صلی اللہ علیہ وسلم بنو حارث بن خزرج میں سعد بن عبادہ رضی اللہ کی مزاج پرسی کے لیے تشریف لے جا رہے تھے۔ یہ جنگ بدر سے پہلے کا واقعہ ہے۔ راستہ میں ایک مجلس سے آپ گزرے جس میں عبداللہ بن ابی ابن سلول ( منافق ) بھی موجود تھا، یہ عبداللہ بن ابی کے ظاہری اسلام لانے سے بھی پہلے کا قصہ ہے۔ مجلس میں مسلمان اور مشرکین یعنی بت پرست اور یہودی سب ہی طرح کے لوگ تھے، انہیں میں عبداللہ بن رواحہ رضی اللہ عنہ بھی تھے۔ سواری کی ( ٹاپوں سے گرد اڑی اور ) مجلس والوں پر پڑی تو عبداللہ بن ابی نے چادر سے اپنی ناک بند کر لی اور بطور تحقیر کہنے لگا کہ ہم پر گرد نہ اڑاؤ، اتنے میں رسول اللہ صلی اللہ علیہ وسلم بھی قریب پہنچ گئے اور انہیں سلام کیا، پھر آپ سواری سے اتر گئے اور مجلس والوں کو اللہ کی طرف بلایا اور قرآن کی آیتیں پڑھ کر سنائیں۔ اس پر عبداللہ بن ابی ابن سلول کہنے لگا، جو کلام آپ نے پڑھ کر سنایا ہے، اس سے عمدہ کوئی کلام نہیں ہو سکتا۔ اگرچہ یہ کلام بہت اچھا، پھر بھی ہماری مجلسوں میں آ آ کر آپ ہمیں تکلیف نہ دیا کریں، اپنے گھر بیٹھیں، اگر کوئی آپ کے پاس جائے تو اسے اپنی باتیں سنایا کریں۔ ( یہ سن کر ) عبداللہ بن رواحہ رضی اللہ عنہ نے کہا، ضرور یا رسول اللہ! آپ ہماری مجلسوں میں تشریف لایا کریں، ہم اسی کو پسند کرتے ہیں۔ اس کے بعد مسلمان، مشرکین اور یہودی آپس میں ایک دوسرے کو برا بھلا کہنے لگے اور قریب تھا کہ فساد اور لڑائی تک کی نوبت پہنچ جاتی لیکن آپ نے انہیں خاموش اور ٹھنڈا کر دیا اور آخر سب لوگ خاموش ہو گئے، پھر آپ صلی اللہ علیہ وسلم اپنی سواری پر سوار ہو کر وہاں سے چلے آئے اور سعد بن عبادہ رضی اللہ عنہ کے یہاں تشریف لے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے سعد بن عبادہ رضی اللہ عنہ سے بھی اس کا ذکر کیا کہ سعد! تم نے نہیں سنا، ابوحباب، آپ کی مراد عبداللہ بن ابی ابن سلول سے تھی، کیا کہہ رہا تھا؟ اس نے اس طرح کی باتیں کی ہیں۔ سعد بن عبادہ رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! آپ اسے معاف فرما دیں اور اس سے درگزر کر دیں۔ اس ذات کی قسم! جس نے آپ پر کتاب نازل کی ہے اللہ نے آپ کے ذریعہ وہ حق بھیجا ہے جو اس نے آپ پر نازل کیا ہے۔ اس شہر ( مدینہ ) کے لوگ ( پہلے ) اس پر متفق ہو چکے تھے کہ اس ( عبداللہ بن ابی ) کو تاج پہنا دیں اور ( شاہی ) عمامہ اس کے سر پر باندھ دیں لیکن جب اللہ تعالیٰ نے اس حق کے ذریعہ جو آپ کو اس نے عطا کیا ہے، اس باطل کو روک دیا تو اب وہ چڑ گیا ہے اور اس وجہ سے وہ معاملہ اس نے آپ کے ساتھ کیا جو آپ نے ملاحظہ فرمایا ہے۔ آپ نے اسے معاف کر دیا۔ نبی کریم صلی اللہ علیہ وسلم اور صحابہ رضی اللہ عنہم مشرکین اور اہل کتاب سے درگزر کیا کرتے تھے اور ان کی اذیتوں پر صبر کیا کرتے تھے۔ اسی کے بارے میں یہ آیت نازل ہوئی ”اور یقیناً تم بہت سی دل آزاری کی باتیں ان سے بھی سنو گے، جنہیں تم سے پہلے کتاب مل چکی ہے اور ان سے بھی جو مشرک ہیں اور اگر تم صبر کرو اور تقویٰ اختیار کرو تو یہ بڑے عزم و حوصلہ کی بات ہے“ اور اللہ تعالیٰ نے فرمایا ”بہت سے اہل کتاب تو دل ہی سے چاہتے ہیں کہ تمہیں ایمان ( لے آنے ) کے بعد پھر سے کافر بنا لیں، حسد کی راہ سے جو ان کے دلوں میں ہے۔“ آخر آیت تک۔ جیسا کہ اللہ تعالیٰ کا حکم تھا نبی کریم صلی اللہ علیہ وسلم ہمیشہ کفار کو معاف کر دیا کرتے تھے۔ آخر اللہ تعالیٰ نے آپ کو ان کے ساتھ جنگ کی اجازت دے دی اور جب آپ نے غزوہ بدر کیا تو اللہ تعالیٰ کی منشا کے مطابق قریش کے کافر سردار اس میں مارے گئے تو عبداللہ بن ابی ابن سلول اور اس کے دوسرے مشرک اور بت پرست ساتھیوں نے آپس میں مشورہ کر کے ان سب نے بھی نبی کریم صلی اللہ علیہ وسلم سے اسلام پر بیعت کر لی اور ظاہراً اسلام میں داخل ہو گئے۔' WHERE id = 4361;
UPDATE hadiths SET urdu = 'ہم سے احمد بن حمید نے بیان کیا، ہم کو عبیداللہ اشجعی نے خبر دی، انہیں سفیان ثوری نے، انہیں ابواسحاق شیبانی نے، انہیں عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے آیت «وإذا حضر القسمة أولو القربى واليتامى والمساكين‏» ”اور جب تقسیم کے وقت عزیز و اقارب اور یتیم اور مسکین موجود ہوں۔“ کے متعلق فرمایا کہ یہ محکم ہے، منسوخ نہیں ہے۔ عکرمہ کے ساتھ اس حدیث کو سعید بن جبیر نے بھی عبداللہ بن عباس رضی اللہ عنہما سے روایت کیا ہے۔' WHERE id = 4371;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن حوشب نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے والد نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا تھا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو نبی مرض الموت میں بیمار ہوتا ہے تو اسے دنیا اور آخرت کا اختیار دیا جاتا ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم کی مرض الموت میں جب آواز گلے میں پھنسنے لگی تو میں نے سنا کہ آپ صلی اللہ علیہ وسلم فرما رہے تھے «مع الذين أنعم الله عليهم من النبيين والصديقين والشهداء والصالحين‏» ”ان لوگوں کے ساتھ جن پر اللہ نے انعام کیا ہے یعنی انبیاء، صدیقین، شہداء اور صالحین کے ساتھ۔“ اس لیے میں سمجھ گئی کہ آپ کو بھی اختیار دیا گیا ہے ( اور آپ صلی اللہ علیہ وسلم نے «اللهم بالرفيق الاعلي» کہہ کر آخرت کو پسند فرمایا ) ۔' WHERE id = 4381;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید المقری نے بیان کیا، کہا ہم سے حیوہ بن شریح وغیرہ (ابن لہیعہ) نے بیان کیا، کہا کہ ہم سے محمد بن عبدالرحمٰن ابوالاسود نے بیان کیا، کہا کہ اہل مدینہ کو ( جب مکہ میں ابن زبیر رضی اللہ عنہما کی خلافت کا دور تھا ) شام والوں کے خلاف ایک فوج نکالنے کا حکم دیا گیا۔ اس فوج میں میرا نام بھی لکھا گیا تو ابن عباس رضی اللہ عنہما کے غلام عکرمہ سے میں ملا اور انہیں اس صورت حال کی اطلاع کی۔ انہوں نے بڑی سختی کے ساتھ اس سے منع کیا اور فرمایا کہ مجھے ابن عباس رضی اللہ عنہما نے خبر دی تھی کہ کچھ مسلمان مشرکین کے ساتھ رہتے تھے اور اس طرح رسول اللہ صلی اللہ علیہ وسلم کے خلاف ان کی زیادتی کا سبب بنتے، پھر تیر آتا اور وہ سامنے پڑ جاتے تو انہیں لگ جاتا اور اس طرح ان کی جان جاتی یا تلوار سے ( غلطی میں ) انہیں قتل کر دیا جاتا۔ اس پر اللہ تعالیٰ نے یہ آیت نازل فرمائی «إن الذين توفاهم الملائكة ظالمي أنفسهم‏» ”بیشک ان لوگوں کی جان جنہوں نے اپنے اوپر ظلم کر رکھا ہے ( جب ) فرشتے قبض کرتے ہیں۔“ آخر آیت تک۔ اس روایت کو لیث بن سعد نے بھی ابوالاسود سے نقل کیا ہے۔' WHERE id = 4391;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے قیس بن اسلم نے اور ان سے طارق بن شہاب نے کہ یہودیوں نے عمر رضی اللہ عنہ سے کہا کہ آپ لوگ ایک ایسی آیت کی تلاوت کرتے ہیں کہ اگر ہمارے یہاں وہ نازل ہوئی ہوتی تو ہم ( جس دن وہ نازل ہوئی ہوتی ) اس دن عید منایا کرتے۔ عمر رضی اللہ عنہ نے کہا، میں خوب اچھی طرح جانتا ہوں کہ یہ آیت «اليوم أكملت لكم دينكم‏» کہاں اور کب نازل ہوئی تھی اور جب عرفات کے دن نازل ہوئی تو نبی کریم صلی اللہ علیہ وسلم کہاں تشریف رکھتے تھے۔ اللہ کی قسم! ہم اس وقت میدان عرفات میں تھے۔ سفیان ثوری نے کہا کہ مجھے شک ہے کہ وہ جمعہ کا دن تھا یا اور کوئی دوسرا دن۔' WHERE id = 4401;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا ہم کو محمد بن بشر نے خبر دی، ان سے عبدالعزیز بن عمر بن عبدالعزیز نے بیان کیا، کہا کہ مجھ سے نافع نے بیان کیا اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ جب شراب کی حرمت نازل ہوئی تو مدینہ میں اس وقت پانچ قسم کی شراب استعمال ہوتی تھی۔ لیکن انگوری شراب کا استعمال نہیں ہوتا تھا ( بہرحال وہ بھی حرام قرار پائی ) ۔' WHERE id = 4411;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، انہوں نے کہا ہم سے مغیرہ بن نعمان نے بیان کیا، ان سے ابن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں قیامت کے دن جمع کیا جائے گا اور کچھ لوگوں کو جہنم کی طرف لے جایا جائے گا۔ اس وقت میں وہی کہوں گا جو نیک بندے نے کہا ہو گا «وكنت عليهم شهيدا ما دمت فيهم‏» ”میں ان کا حال دیکھتا رہا جب تک میں ان کے درمیان رہا“ آخر آیت «العزيز الحكيم‏» تک۔' WHERE id = 4421;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت اس وقت تک قائم نہ ہو گی، جب تک سورج مغرب سے نہ طلوع ہو لے۔ جب مغرب سے سورج طلوع ہو گا اور لوگ دیکھ لیں گے تو سب ایمان لائیں گے لیکن یہ وقت ہو گا جب کسی کو اس کا ایمان نفع نہ دے گا، پھر آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی۔' WHERE id = 4431;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے ورقاء بن عمر نے بیان کیا، ان سے ابن ابی نجیح نے، ان سے مجاہد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ آیت «إن شر الدواب عند الله الصم البكم الذين لا يعقلون‏» ”بدترین حیوانات اللہ کے نزدیک وہ بہرے گونگے ہیں جو عقل سے ذرا کام نہیں لیتے۔“ بنو عبدالدار کے کچھ لوگوں کے بارے میں اتری تھی۔' WHERE id = 4441;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، کہا مجھ کو حمید بن عبدالرحمٰن نے خبر دی کہ ابوہریرہ رضی اللہ عنہ نے کہا: ابوبکر صدیق رضی اللہ عنہ نے حج کے موقع پر ( جس کا نبی کریم صلی اللہ علیہ وسلم نے انہیں امیر بنایا تھا ) مجھ کو ان اعلان کرنے والوں میں رکھا تھا جنہیں آپ نے یوم نحر میں بھیجا تھا۔ منیٰ میں یہ اعلان کرنے کے لیے کہ اس سال کے بعد کوئی مشرک حج کرنے نہ آئے اور نہ کوئی شخص بیت اللہ کا طواف ننگا ہو کر کرے۔ حمید نے کہا کہ پھر پیچھے سے نبی کریم صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ کو بھیجا اور انہیں حکم دیا کہ سورۃ برات کا اعلان کر دیں۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ علی رضی اللہ عنہ نے ہمارے ساتھ منیٰ کے میدان میں دسویں تاریخ میں سورۃ برات کا اعلان کیا اور یہ کہ کوئی مشرک آئندہ سال سے حج کرنے نہ آئے اور نہ کوئی بیت اللہ کا طواف ننگا ہو کر کرے۔' WHERE id = 4451;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبید بن میمون نے بیان کیا، کہا ہم سے عیسیٰ بن یونس نے، ان سے عمر بن سعید نے، انہیں ابن ابی ملیکہ نے خبر دی کہ ہم ابن عباس رضی اللہ عنہما کی خدمت میں حاضر ہوئے تو انہوں نے کہا کہ ابن زبیر پر تمہیں حیرت نہیں ہوتی۔ وہ اب خلافت کے لیے کھڑے ہو گئے ہیں تو میں نے ارادہ کر لیا کہ ان کے لیے محنت مشقت کروں گا کہ ایسی محنت اور مشقت میں نے ابوبکر اور عمر رضی اللہ عنہما کے لیے بھی نہیں کی۔ حالانکہ وہ دونوں ان سے ہر حیثیت سے بہتر تھے۔ میں نے لوگوں سے کہا کہ وہ رسول اللہ صلی اللہ علیہ وسلم کی پھوپھی کی اولاد میں سے ہیں۔ زبیر رضی اللہ عنہ کے بیٹے اور ابوبکر رضی اللہ عنہ کے نواسے، خدیجہ رضی اللہ عنہا کے بھائی کے بیٹے، عائشہ رضی اللہ عنہا کی بہن کے بیٹے۔ لیکن عبداللہ بن زبیر نے کیا کیا وہ مجھ سے غرور کرنے لگے۔ انہوں نے نہیں چاہا کہ میں ان کے خاص مصاحبوں میں رہوں ( اپنے دل میں کہا ) مجھ کو ہرگز یہ گمان نہ تھا کہ میں تو ان سے ایسی عاجزی کروں گا اور وہ اس پر بھی مجھ سے راضی نہ ہوں گے۔ خیر اب مجھے امید نہیں کہ وہ میرے ساتھ بھلائی کریں گے جو ہونا تھا وہ ہوا اب بنی امیہ جو میرے چچا زاد بھائی ہیں اگر مجھ پر حکومت کریں تو یہ مجھ کو اوروں کے حکومت کرنے سے زیادہ پسند ہے۔' WHERE id = 4461;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھے یونس نے خبر دی (دوسری سند) احمد بن صالح نے بیان کیا کہ ہم سے عنبسہ بن خالد نے بیان کیا، کہا ہم سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، کہا مجھ کو عبدالرحمٰن بن کعب نے خبر دی، کہا کہ مجھے عبداللہ بن کعب نے خبر دی کہ ( ان کے والد ) کعب بن مالک رضی اللہ عنہ جب نابینا ہو گئے تو ان کے بیٹوں میں یہی ان کو راستے میں ساتھ لے کر چلتے ہیں۔ انہوں نے بیان کیا کہ میں نے کعب بن مالک سے ان کے واقعہ کے سلسلے میں سنا جس کے بارے میں آیت «وعلى الثلاثة الذين خلفوا‏» نازل ہوئی تھی۔ آپ نے آخر میں ( نبی کریم صلی اللہ علیہ وسلم سے ) عرض کیا تھا کہ اپنی توبہ کے قبول ہونے کی خوشی میں اپنا تمام مال اللہ اور اس کے رسول کے راستے میں خیرات کرتا ہوں۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں اپنا کچھ تھوڑا مال اپنے پاس ہی رہنے دو۔ یہ تمہارے حق میں بھی بہتر ہے۔' WHERE id = 4471;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم کو ابومعاویہ نے خبر دی، ان سے برید بن ابی بردہ نے بیان کیا، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ ظالم کو چند روز دنیا میں مہلت دیتا رہتا ہے لیکن جب پکڑتا ہے تو پھر نہیں چھوڑتا۔ راوی نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی «وكذلك أخذ ربك إذا أخذ القرى وهى ظالمة إن أخذه أليم شديد‏» ”اور تیرے پروردگار کی پکڑ اسی طرح ہے، جب وہ بستی والوں کو پکڑتا ہے۔ جو ( اپنے اوپر ) ظلم کرتے رہتے ہیں، بیشک اس کی پکڑ بڑی تکلیف دینے والی اور بڑی ہی سخت ہے۔“' WHERE id = 4481;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ نے، ان سے عبیداللہ نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر تھے، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا: اچھا مجھ کو بتلاؤ تو وہ کون سا درخت ہے جو مسلمان کی مانند ہے جس کے پتے نہیں گرتے، ہر وقت میوہ دے جاتا ہے؟ ابن عمر رضی اللہ عنہما کہتے ہیں میرے دل میں آیا وہ کھجور کا درخت ہے مگر میں نے دیکھا کہ ابوبکر اور عمر رضی اللہ عنہما بیٹھے ہوئے ہیں انہوں نے جواب نہیں دیا تو مجھ کو ان بزرگوں کے سامنے کلام کرنا اچھا معلوم نہیں ہوا۔ جب ان لوگوں نے کچھ جواب نہیں دیا تو نبی کریم صلی اللہ علیہ وسلم نے خود ہی فرمایا وہ کھجور کا درخت ہے۔ جب ہم اس مجلس سے کھڑے ہوئے تو میں نے اپنے والد عمر رضی اللہ عنہ سے عرض کیا: بابا جان! اللہ کی قسم! میرے دل میں آیا تھا کہ میں کہہ دوں وہ کھجور کا درخت ہے۔ انہوں نے کہا پھر تو نے کہہ کیوں نہ دیا۔ میں نے کہا آپ لوگوں نے کوئی بات نہیں کی میں نے آگے بڑھ کر بات کرنا مناسب نہ جانا۔ انہوں نے کہا واہ اگر تو اس وقت کہہ دیتا تو مجھ کو اتنے اتنے ( لال لال اونٹ کا ) مال ملنے سے بھی زیادہ خوشی ہوتی۔' WHERE id = 4493;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، ان سے ابواسحاق عمرو بن عبیداللہ سبیعی نے بیان کیا، کہا کہ میں نے عبدالرحمٰن بن یزید سے سنا، کہا کہ میں نے عبداللہ بن مسعود رضی اللہ عنہ سے سنا، انہوں نے سورۃ بنی اسرائیل، سورۃ الکہف اور سورۃ مریم کے متعلق کہا کہ یہ اول درجہ کی عمدہ نہایت فصیح و بلیغ سورتیں ہیں اور میری پرانی یاد کی ہوئی ( آیت ) «فسينغضون‏» کے متعلق ابن عباس رضی اللہ عنہما نے کہا کہ اپنے سر ہلائیں گے اور دوسرے لوگوں نے کہا کہ یہ «نغضت سنك» سے نکلا ہے یعنی تیرا دانت ہل گیا۔' WHERE id = 4503;
UPDATE hadiths SET urdu = 'مجھ سے اسماعیل بن ابان نے بیان کیا، کہا ہم سے ابوالاحوص (سلام بن سلیم) نے بیان کیا، ان سے آدم بن علی نے بیان کیا اور انہوں نے ابن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ قیامت کے دن امتیں گروہ در گروہ چلیں گی۔ ہر امت اپنے نبی کے پیچھے ہو گی اور ( انبیاء سے ) کہے گی کہ اے فلاں! ہماری شفاعت کرو ( مگر وہ سب ہی انکار کر دیں گے ) آخر شفاعت کے لیے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوں گے تو یہی وہ دن ہے جب اللہ تعالیٰ نبی کریم صلی اللہ علیہ وسلم کو مقام محمود عطا فرمائے گا۔' WHERE id = 4513;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، ان سے مصعب بن سعد بن ابی وقاص نے بیان کیا کہ میں نے اپنے والد ( سعد بن ابی وقاص رضی اللہ عنہ ) سے آیت «قل هل ننبئكم بالأخسرين أعمالا‏» کے متعلق سوال کیا کہ ان سے کون لوگ مراد ہیں؟ کیا ان سے خوارج مراد ہیں؟ انہوں نے کہا کہ نہیں، اس سے مراد یہود و نصاریٰ ہیں۔ یہود نے تو محمد صلی اللہ علیہ وسلم کی تکذیب کی اور نصاریٰ نے جنت کا انکار کیا اور کہا کہ اس میں کھانے پینے کی کوئی چیز نہیں ملے گی اور خوارج وہ ہیں جنہوں نے اللہ کے عہد و میثاق کو توڑا سعد رضی اللہ عنہ انہیں فاسق کہا کرتے تھے۔' WHERE id = 4523;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے ایوب بن نجار نے بیان کیا، ان سے یحییٰ بن ابی بکر نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام نے آدم علیہ السلام سے بحث کی اور ان سے کہا کہ آپ ہی نے اپنی غلطی کے نتیجہ میں انسانوں کو جنت سے نکالا اور مشقت میں ڈالا۔ آدم علیہ السلام بولے کہ اے موسیٰ! آپ کو اللہ نے اپنی رسالت کے لیے پسند فرمایا اور ہم کلامی کا شرف بخشا۔ کیا آپ ایک ایسی بات پر مجھے ملامت کرتے ہیں جسے اللہ تعالیٰ نے میری پیدائش سے بھی پہلے میرے لیے مقرر کر دیا تھا۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا چنانچہ آدم علیہ السلام موسیٰ علیہ السلام پر بحث میں غالب آ گئے۔' WHERE id = 4533;
UPDATE hadiths SET urdu = 'ہم سے مقدم بن محمد بن یحییٰ نے بیان کیا، کہا مجھ سے میرے چچا قاسم بن یحییٰ نے بیان کیا، ان سے عبیداللہ نے، قاسم نے عبیداللہ سے سنا تھا اور عبیداللہ نے نافع سے اور انہوں نے ابن عمر رضی اللہ عنہما سے کہ ایک صاحب نے اپنی بیوی پر رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں ایک غیر مرد کے ساتھ تہمت لگائی اور کہا کہ عورت کا حمل میرا نہیں ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم کے حکم سے دونوں میاں بیوی نے اللہ کے فرمان کے مطابق لعان کیا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے بچہ کے بارے میں فیصلہ کیا کہ وہ عورت ہی کا ہو گا اور لعان کرنے والے دونوں میاں بیوی میں جدائی کروا دی۔' WHERE id = 4543;
UPDATE hadiths SET urdu = 'اور احمد بن شبیب نے بیان کیا، کہا ہم سے ہمارے والد شبیب بن سعید نے بیان کیا، ان سے یونس بن یزید نے، ان سے ابن شہاب نے بیان کیا، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہا کہ اللہ ان عورتوں پر رحم کرے جنہوں نے پہلی ہجرت کی تھی۔ جب اللہ تعالیٰ نے آیت «وليضربن بخمرهن على جيوبهن‏» ”اور اپنے دوپٹے اپنے سینوں پر ڈالے رہا کریں۔“ ( تاکہ سینہ اور گلا وغیرہ نہ نظر آئے ) نازل کی، تو انہوں نے اپنی چادروں کو پھاڑ کر ان کے دوپٹے بنا لیے۔' WHERE id = 4553;
UPDATE hadiths SET urdu = 'اور ہم سے ابراہیم بن طہمان نے کہا کہ ان سے ابن ابی ذئب نے بیان کیا، ان سے سعید بن ابی سعید مقبری نے، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابراہیم علیہ الصلٰوۃ والسلام اپنے والد ( آذر ) کو قیامت کے دن گرد آلود کالا کلوٹا دیکھیں گے۔ امام بخاری رحمہ اللہ نے کہا «غبرة» اور «قترة‏.‏» ہم معنی ہیں۔' WHERE id = 4563;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے ابن وہب نے بیان کیا، کہا کہ مجھ سے عمر بن محمد بن عبداللہ بن عمر نے بیان کیا، ان سے ان کے والد نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ غیب کی کنجیاں پانچ ہیں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے اس آیت کی تلاوت کی «إن الله عنده علم الساعة‏» ”بیشک اللہ ہی کو قیامت کا علم ہے اور وہی بارش نازل کرتا ہے اور وہی جانتا ہے کہ مادہ کے رحم میں نر ہے یا مادہ اور کوئی نفس نہیں جانتا کہ وہ کل کیا کرے گا اور کوئی نہیں جانتا کہ وہ کہاں مرے گا۔' WHERE id = 4573;
UPDATE hadiths SET urdu = 'ہم سے زکریا بن یحییٰ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے ہشام نے اپنے والد سے سن کر بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جو عورتیں اپنے نفس کو رسول اللہ صلی اللہ علیہ وسلم کے لیے ہبہ کرنے آتی تھیں مجھے ان پر بڑی غیرت آتی تھی۔ میں کہتی کہ کیا عورت خود ہی اپنے کو کسی مرد کے لیے پیش کر سکتی ہے؟ پھر جب اللہ تعالیٰ نے یہ آیت نازل کی «ترجئ من تشاء منهن وتؤوي إليك من تشاء ومن ابتغيت ممن عزلت فلا جناح عليك‏» کہ ”ان میں سے جس کو چاہیں اپنے سے دور رکھیں اور جس کو چاہیں اپنے نزدیک رکھیں اور جن کو آپ نے الگ کر رکھا تھا اس میں سے کسی کو پھر طلب کر لیں جب بھی، آپ پر کوئی گناہ نہیں ہے۔“ تو میں نے کہا کہ میں تو سمجھتی ہوں کہ آپ کا رب آپ کی مراد بلا تاخیر پوری کر دینا چاہتا ہے۔' WHERE id = 4583;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا کہ مجھ سے ابن الہاد نے بیان کیا، ان سے عبداللہ بن خباب نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ ہم نے عرض کیا: یا رسول اللہ! آپ پر سلام بھیجنے کا طریقہ تو ہمیں معلوم ہو گیا ہے۔ لیکن «صلاة» ( درود ) بھیجنے کا کیا طریقہ ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یوں کہا کرو «اللهم صل على محمد عبدك ورسولك،‏‏‏‏ كما صليت على آل إبراهيم،‏‏‏‏ وبارك على محمد وعلى آل محمد كما باركت على إبراهيم» ۔ ابوصالح نے بیان کیا کہ اور ان سے لیث بن سعد نے ( ان الفاظ کے ساتھ ) «على محمد وعلى آل محمد،‏‏‏‏ كما باركت على آل إبراهيم» کے الفاظ روایت کئے ہیں۔' WHERE id = 4593;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے روح بن عبادہ اور محمد بن جعفر نے بیان کیا، ان سے شعبہ نے، سے محمد بن زیاد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ گزشتہ رات ایک سرکش جِن اچانک میرے پاس آیا، یا اسی طرح کا کلمہ آپ صلی اللہ علیہ وسلم نے فرمایا تاکہ میری نماز خراب کرے لیکن اللہ تعالیٰ نے مجھے اس پر قدرت دے دی اور میں نے سوچا کہ اسے مسجد کے ستون سے باندھ دوں تاکہ صبح کے وقت تم سب لوگ بھی اسے دیکھ سکو۔ پھر مجھ کو اپنے بھائی سلیمان علیہ السلام کی دعا یاد آ گئی «رب هب لي ملكا لا ينبغي لأحد من بعدي» کہ ”اے میرے رب! مجھے ایسی سلطنت دے کہ میرے بعد کسی کو میسر نہ ہو۔“ روح نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے اس جِن کو ذلت کے ساتھ بھگا دیا۔' WHERE id = 4603;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا کہ ہم سے شعبہ نے، ان سے عبدالملک بن میسرہ نے بیان کیا کہ میں نے طاؤس سے سنا کہ ابن عباس رضی اللہ عنہما سے اللہ تعالیٰ کے ارشاد «إلا المودة في القربى‏» ”سوا رشتہ داری کی محبت کے“ متعلق پوچھا گیا تو سعید بن جبیر نے فرمایا کہ آل محمد صلی اللہ علیہ وسلم کی قرابتداری مراد ہے۔ ابن عباس رضی اللہ عنہما نے اس پر کہا کہ تم نے جلد بازی کی۔ قریش کی کوئی شاخ ایسی نہیں جس میں نبی کریم صلی اللہ علیہ وسلم کی قرابت داری نہ ہو۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ تم سے صرف یہ چاہتا ہوں کہ تم اس قرابت داری کی وجہ سے صلہ رحمی کا معاملہ کرو جو میرے اور تمہارے درمیان میں موجود ہے۔' WHERE id = 4613;
UPDATE hadiths SET urdu = 'ہم سے احمد نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، انہیں عمرو نے خبر دی، ان سے ابوالنضر نے بیان کیا، ان سے سلیمان بن یسار نے اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو کبھی اس طرح ہنستے نہیں دیکھا کہ آپ کے حلق کا کوا نظر آ جائے بلکہ آپ تبسم فرمایا کرتے تھے، بیان کیا کہ جب بھی آپ بادل یا ہوا دیکھتے تو ( گھبراہٹ اور اللہ کا خوف ) آپ کے چہرہ مبارک سے پہچان لیا جاتا۔' WHERE id = 4623;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے، ان سے ابواسحاق نے اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے ایک صحابی ( اسید بن حضیر رضی اللہ عنہ رات میں سورۃ الکہف ) پڑھ رہے تھے۔ ان کا ایک گھوڑا جو گھر میں بندھا ہوا تھا بدکنے لگا تو وہ صحابی نکلے انہوں نے کوئی خاص چیز نہیں دیکھی وہ گھوڑا پھر بھی بدک رہا تھا۔ صبح کے وقت وہ صحابی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور رات کا واقعہ بیان کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ چیز ( جس سے گھوڑا بدکا تھا ) سکینت تھی جو قرآن کی وجہ سے نازل ہوئی۔' WHERE id = 4633;
UPDATE hadiths SET urdu = 'ہم سے محمد بن موسیٰ قطان نے بیان کیا، کہا ہم سے ابوسفیان حمیری سعید بن یحییٰ بن مہدی نے بیان کیا، ان سے عوف نے، ان سے محمد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کے حوالے سے ابوسفیان حمیری اکثر اس حدیث کو نبی کریم صلی اللہ علیہ وسلم سے موقوفاً ذکر کرتے تھے کہ جہنم سے پوچھا جائے گا تو بھر بھی گئی؟ وہ کہے گی «هل من مزيد‏.‏» کہ کچھ اور بھی ہے؟ پھر اللہ تبارک تعالیٰ اپنا قدم اس پر رکھے گا اور کہے گی کہ بس بس۔' WHERE id = 4643;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم فراہیدی نے بیان کیا، کہا ہم سے ابوالاشھب جعفر بن حیان نے بیان کیا، کہا کہ ہم سے ابوالجوزاء نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے لات اور عزیٰ کے حال میں کہا کہ لات ایک شخص کو کہتے تھے وہ حاجیوں کے لیے ستو گھولتا تھا۔' WHERE id = 4653;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے، ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم «فهل من مدكر‏» پڑھا کرتے تھے۔' WHERE id = 4663;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا کہ مجھ سے عبدالعزیز بن عبدالصمد نے بیان کیا، کہا ہم سے ابوعمران جونی نے بیان کیا، ان سے ابوبکر بن عبداللہ بن قیس نے اور ان سے ان کے والد نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جنت میں کھوکھلے موتی کا خیمہ ہو گا، اس کی چوڑائی ساٹھ میل ہو گی اور اس کے ہر کنارے پر مسلمان کی ایک بیوی ہو گی ایک کنارے والی دوسرے کنارے والی کو نہ دیکھ سکے گی۔' WHERE id = 4673;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے عمرو بن دینار نے بیان کیا، کہا کہ مجھ سے حسن بن محمد بن علی نے بیان کیا، انہوں نے علی رضی اللہ عنہ کے کاتب عبیداللہ بن ابی رافع سے سنا، وہ بیان کرتے تھے کہ میں نے علی رضی اللہ عنہ سے سنا انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے، زبیر اور مقداد رضی اللہ عنہما کو روانہ کیا اور فرمایا کہ چلے جاؤ اور جب مقام خاخ کے باغ پر پہنچ جاؤ گے ( جو مکہ اور مدینہ کے درمیان تھا ) تو وہاں تمہیں ہودج میں ایک عورت ملے گی، اس کے ساتھ ایک خط ہو گا، وہ خط تم اس سے لے لینا۔ چنانچہ ہم روانہ ہوئے ہمارے گھوڑے ہمیں تیز رفتاری کے ساتھ لے جا رہے تھے۔ آخر جب ہم اس باغ پر پہنچے تو واقعی وہاں ہم نے ہودج میں اس عورت کو پا لیا ہم نے اس سے کہا کہ خط نکال۔ اس نے کہا میرے پاس کوئی خط نہیں ہے ہم نے اس سے کہا کہ خط نکال دے ورنہ ہم تیرا سارا کپڑا اتار کر تلاشی لیں گے۔ آخر اس نے اپنی چوٹی سے خط نکالا ہم لوگ وہ خط لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ اس خط میں لکھا ہوا تھا کہ حاطب بن ابی بلتعہ کی طرف سے مشرکین کے چند آدمیوں کی طرف جو مکہ میں تھے اس خط میں انہوں نے نبی کریم صلی اللہ علیہ وسلم کی تیاری کا ذکر لکھا تھا ( کہ نبی کریم صلی اللہ علیہ وسلم ایک بڑی فوج لے کر آتے ہیں تم اپنا بچاؤ کر لو ) ۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا: حاطب! یہ کیا ہے؟ انہوں نے عرض کیا: یا رسول اللہ! میرے معاملہ میں جلدی نہ فرمائیں میں قریش کے ساتھ بطور حلیف ( زمانہ قیام مکہ میں ) رہا کرتا تھا لیکن ان کے قبیلہ و خاندان سے میرا کوئی تعلق نہیں تھا۔ اس کے برخلاف آپ کے ساتھ جو دوسرے مہاجرین ہیں ان کی قریش میں رشتہ داریاں ہیں اور ان کی رعایت سے قریش مکہ میں رہ جانے والے ان کے اہل و عیال اور مال کی حفاظت کرتے ہیں۔ میں نے چاہا کہ جبکہ ان سے میرا کوئی نسبی تعلق نہیں ہے تو اس موقع پر ان پر ایک احسان کر دوں اور اس کی وجہ سے وہ میرے رشتہ داروں کی مکہ میں حفاظت کریں۔ یا رسول اللہ! میں نے یہ عمل کفر یا اپنے دین سے پھر جانے کی وجہ سے نہیں کیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یقیناً انہوں نے تم سے سچی بات کہہ دی ہے۔ عمر رضی اللہ عنہ بولے کہ یا رسول اللہ! مجھے اجازت دیں میں اس کی گردن مار دوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا یہ بدر کی جنگ میں ہمارے ساتھ موجود تھے۔ تمہیں کیا معلوم، اللہ تعالیٰ بدر والوں کے تمام حالات سے واقف تھا اور اس کے باوجود ان کے متعلق فرما دیا کہ جو جی چاہے کرو کہ میں نے تمہیں معاف کر دیا۔ عمرو بن دینار نے کہا کہ حاطب بن ابی بلتعہ رضی اللہ عنہ ہی کے بارے میں یہ آیت نازل ہوئی تھی «يا أيها الذين آمنوا لا تتخذوا عدوي وعدوكم‏» کہ الایۃ۔ ”اے ایمان والو! تم میرے دشمن اور اپنے دشمن کو دوست نہ بنا لینا۔“ سفیان بن عیینہ نے کہا کہ مجھے اس کا علم نہیں کہ اس آیت کا ذکر حدیث میں داخل ہے یا نہیں یہ عمرو بن دینار کا قول ہے۔ ہم سے علی بن عبداللہ مدینی نے بیان کیا کہ سفیان بن عیینہ سے حاطب بن ابی بلتعہ رضی اللہ عنہ کے بارے میں پوچھا گیا کہ کیا آیت «لا تتخذوا عدوي‏» انہیں کے بارے میں نازل ہوئی تھی؟ سفیان نے کہا کہ لوگوں کی روایت میں تو یونہی ہے لیکن میں نے عمرو سے حدیث یاد کی اس میں سے ایک حرف بھی میں نے نہیں چھوڑا اور میں نہیں سمجھتا کہ میرے سوا اور کسی نے اس حدیث کو عمرو سے خوب یاد رکھا ہو۔' WHERE id = 4683;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، کہا ہم سے اسرائیل بن یونس نے بیان کیا، ان سے اسحاق نے اور ان سے زید بن ارقم رضی اللہ عنہما نے بیان کیا کہ میں ایک غزوہ ( غزوہ تبوک ) میں تھا اور میں نے ( منافقوں کے سردار ) عبداللہ بن ابی کو یہ کہتے سنا کہ جو لوگ ( مہاجرین ) رسول اللہ صلی اللہ علیہ وسلم کے پاس جمع ہیں ان پر خرچ نہ کرو تاکہ وہ خود ہی رسول اللہ صلی اللہ علیہ وسلم سے جدا ہو جائیں گے۔ اس نے یہ بھی کہا اب اگر ہم مدینہ لوٹ کر جائیں گے تو عزت والا وہاں سے ذلت والوں کو نکال باہر کرے گا۔ میں نے اس کا ذکر اپنے چچا ( سعد بن عبادہ انصاری ) سے کیا یا عمر رضی اللہ عنہ سے اس کا ذکر کیا۔ ( راوی کو شک تھا ) انہوں نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا۔ نبی کریم صلی اللہ علیہ وسلم نے مجھے بلایا میں نے تمام باتیں آپ کو سنا دیں۔ نبی کریم صلی اللہ علیہ وسلم نے عبداللہ بن ابی اور اس کے ساتھیوں کو بلا بھیجا۔ انہوں نے قسم کھا لی کہا کہ انہوں نے اس طرح کی کوئی بات نہیں کہی تھی۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے مجھ کو جھوٹا سمجھا اور عبداللہ کو سچا سمجھا۔ مجھے اس کا اتنا صدمہ ہوا کہ ایسا کبھی نہ ہوا تھا۔ پھر میں گھر میں بیٹھ رہا۔ میرے چچا نے کہا کہ میرا خیال نہیں تھا کہ نبی کریم صلی اللہ علیہ وسلم تمہاری تکذیب کریں گے اور تم پر ناراض ہوں گے۔ پھر اللہ تعالیٰ نے یہ سورت نازل کی «إذا جاءك المنافقون‏» ”جب منافق آپ کے پاس آتے ہیں“ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے مجھے بلوایا اور اس سورت کی تلاوت کی اور فرمایا کہ اے زید! اللہ تعالیٰ نے تم کو سچا کر دیا ہے۔' WHERE id = 4693;
UPDATE hadiths SET urdu = 'اور سلیمان بن حرب اور النعمان نے بیان کیا، کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے اور ان سے محمد بن سیرین نے بیان کیا کہ میں ایک مجلس میں جس میں عبدالرحمٰن بن ابی لیلیٰ بھی تھے موجود تھا۔ ان کے شاگرد ان کی بہت عزت کیا کرتے تھے۔ میں نے وہاں سبیعہ بنت الحارث کا عبداللہ بن عتبہ بن مسعود سے بیان کیا کہ اس پر ان کے شاگرد نے زبان اور آنکھوں کے اشارے سے ہونٹ کاٹ کر مجھے تنبیہ کی۔ محمد بن سیرین نے بیان کیا کہ میں سمجھ گیا اور کہا کہ عبداللہ بن عتبہ کوفہ میں ابھی زندہ موجود ہیں۔ اگر میں ان کی طرف بھی جھوٹ نسبت کرتا ہوں تو بڑی جرات کی بات ہو گی مجھے تنبیہ کرنے والے صاحب اس پر شرمندہ ہو گئے اور عبدالرحمٰن بن ابی لیلیٰ نے کہا لیکن ان کے چچا تو یہ بات نہیں کرتے تھے۔ ( ابن سیرین نے بیان کیا کہ ) پھر میں ابوعطیہ مالک بن عامر سے ملا اور ان سے یہ مسئلہ پوچھا وہ بھی سبیعہ والی حدیث بیان کرنے لگے لیکن میں نے ان سے کہا آپ نے عبداللہ بن مسعود رضی اللہ عنہ سے بھی اس سلسلہ میں کچھ سنا ہے؟ انہوں نے بیان کیا کہ ہم عبداللہ بن مسعود رضی اللہ عنہ کی خدمت میں حاضر تھے تو انہوں نے کہا کیا تم اس پر ( جس کے شوہر کا انتقال ہو گیا اور وہ حاملہ ہو۔ عدت کی مدت کو طول دے کر ) سختی کرنا چاہتے ہو اور رخصت و سہولت دینے کے لیے تیار نہیں، بات یہ ہے کہ چھوٹی سورۃ نساء یعنی ( سورۃ الطلاق ) بڑی سورۃ النساء کے بعد نازل ہوئی ہے اور کہا «وأولات الأحمال أجلهن أن يضعن حملهن‏» الایۃ اور حمل والیوں کی عدت ان کے حمل کا پیدا ہو جانا ہے۔' WHERE id = 4703;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، انہوں نے کہا ہم کو ہشام نے خبر دی، ان سے ابن جریج نے اور عطاء نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ جو بت موسیٰ علیہ السلام کی قوم میں پوجے جاتے تھے بعد میں وہی عرب میں پوجے جانے لگے۔ ود دومۃ الجندل میں بنی کلب کا بت تھا۔ سواع بنی ہذیل کا۔ یغوث بنی مراد کا اور مراد کی شاخ بنی غطیف کا جو وادی اجوف میں قوم سبا کے پاس رہتے تھے یعوق بنی ہمدان کا بت تھا۔ نسر حمیر کا بت تھا جو ذوالکلاع کی آل میں سے تھے۔ یہ پانچوں نوح علیہ السلام کی قوم کے نیک لوگوں کے نام تھے جب ان کی موت ہو گئی تو شیطان نے ان کے دل میں ڈالا کہ اپنی مجلسوں میں جہاں وہ بیٹھے تھے ان کے بت قائم کر لیں اور ان بتوں کے نام اپنے نیک لوگوں کے نام پر رکھ لیں چنانچہ ان لوگوں نے ایسا ہی کیا اس وقت ان بتوں کی پوجا نہیں ہوتی تھی لیکن جب وہ لوگ بھی مر گئے جنہوں نے بت قائم کئے تھے اور علم لوگوں میں نہ رہا تو ان کی پوجا ہونے لگی۔' WHERE id = 4713;
UPDATE hadiths SET urdu = 'ہم سے محمود نے بیان کیا، کہا ہم سے عبیداللہ نے بیان کیا، ان سے اسرائیل نے، ان سے منصور نے، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے اور آپ پر سورۃ والمرسلات نازل ہوئی تھی اور ہم اس کو آپ کے منہ سے سیکھ رہے تھے کہ اتنے میں ایک سانپ نکل آیا۔ ہم لوگ اس کے مارنے کو بڑھے لیکن وہ بچ نکلا اور اپنے سوراخ میں گھس گیا۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ وہ تمہارے شر سے بچ گیا اور تم اس کے شر سے بچ گئے۔' WHERE id = 4723;
UPDATE hadiths SET urdu = 'ہم سے سعید بن نضر نے بیان کیا، کہا ہم کو ہشیم نے خبر دی، کہا مجھ کو ابوبشر جعفر بن ایاس نے خبر دی، ان سے مجاہد نے بیان کیا کہ ابن عباس رضی اللہ عنہما نے کہا «لتركبن طبقا عن طبق‏» یعنی ”تم کو ضرور ایک حالت کے بعد دوسرے حالت پر پہنچنا ہے۔“ بیان کیا کہ یہاں مراد نبی کریم صلی اللہ علیہ وسلم ہیں کہ آپ کو کامیابی رفتہ رفتہ حاصل ہو گی۔' WHERE id = 4734;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، ان سے اسود بن قیس نے بیان کیا کہ میں نے جندب بن سفیان رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم بیمار پڑ گئے اور دو یا تین راتوں کو ( تہجد کے لیے ) نہیں اٹھ سکے۔ پھر ایک عورت ( ابولہب کی عورت عوراء ) آئی اور کہنے لگی۔ اے محمد! میرا خیال ہے کہ تمہارے شیطان نے تمہیں چھوڑ دیا ہے۔ دو یا تین راتوں سے دیکھ رہی ہوں کہ تمہارے پاس وہ نہیں آیا۔ اس پر اللہ تعالیٰ نے یہ آیت نازل کی «والضحى * والليل إذا سجى * ما ودعك ربك وما قلى‏» آخر تک یعنی ”قسم ہے دن کی روشنی کی اور رات کی جب وہ قرار پکڑے کہ آپ کے پروردگار نے نہ آپ کو چھوڑا ہے اور نہ آپ سے بیزار ہوا ہے۔“' WHERE id = 4745;
UPDATE hadiths SET urdu = 'ہم سے حسان بن حسان نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ابی بن کعب رضی اللہ عنہ سے فرمایا کہ اللہ تعالیٰ نے مجھے حکم دیا ہے کہ تمہیں قرآن ( سورۃ لم یکن ) پڑھ کر سناؤں۔ ابی بن کعب نے عرض کیا: کیا آپ سے اللہ تعالیٰ میرا نام بھی لیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، اللہ تعالیٰ نے تمہارا نام بھی مجھ سے لیا ہے۔ ابی بن کعب رضی اللہ عنہ یہ سن کر رونے لگے۔ قتادہ نے بیان کیا کہ مجھے خبر دی گئی ہے کہ نبی کریم صلی اللہ علیہ وسلم نے انہیں سورۃ «لم يكن الذين كفروا من أهل الكتاب‏» پڑھ کر سنائی تھی۔' WHERE id = 4755;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ عمر بن خطاب رضی اللہ عنہ مجھے بوڑھے بدری صحابہ کے ساتھ مجلس میں بٹھاتے تھے۔ بعض ( عبدالرحمٰن بن عوف ) کو اس پر اعتراض ہوا، انہوں نے عمر رضی اللہ عنہ سے کہا کہ اسے آپ مجلس میں ہمارے ساتھ بٹھاتے ہیں، اس کے جیسے تو ہمارے بھی بچے ہیں؟ عمر رضی اللہ عنہ نے کہا کہ اس کی وجہ تمہیں معلوم ہے۔ پھر انہوں نے ایک دن ابن عباس رضی اللہ عنہما کو بلایا اور انہیں بوڑھے بدری صحابہ کے ساتھ بٹھایا ( ابن عباس رضی اللہ عنہما نے کہا کہ ) میں سمجھ گیا کہ آپ نے مجھے انہیں دکھانے کے لیے بلایا ہے، پھر ان سے پوچھا اللہ تعالیٰ کے اس ارشاد کے متعلق تمہارا کیا خیال ہے «إذا جاء نصر الله والفتح‏» الخ یعنی ”جب اللہ کی مدد اور فتح آ پہنچی“ بعض لوگوں نے کہا کہ جب ہمیں مدد اور فتح حاصل ہوئی تو اللہ کی حمد اور اس سے استغفار کا ہمیں آیت میں حکم دیا گیا ہے۔ کچھ لوگ خاموش رہے اور کوئی جواب نہیں دیا۔ پھر آپ نے مجھ سے پوچھا: ابن عباس! کیا تمہارا بھی یہی خیال ہے؟ میں نے عرض کیا کہ نہیں۔ پوچھا پھر تمہاری کیا رائے ہے؟ میں نے عرض کی کہ اس میں رسول اللہ صلی اللہ علیہ وسلم کی وفات کی طرف اشارہ ہے۔ اللہ تعالیٰ نے نبی کریم صلی اللہ علیہ وسلم کو یہی چیز بتائی ہے اور فرمایا «إذا جاء نصر الله والفتح‏» کہ ”جب اللہ کی مدد اور فتح آ پہنچی“ یعنی پھر یہ آپ کی وفات کی علامت ہے۔ اس لیے آپ اپنے پروردگار کی پاکی و تعریف بیان کیجئے اور اس سے بخشش مانگا کیجئے۔ بیشک وہ بڑا توبہ قبول کرنے والا ہے۔ عمر رضی اللہ عنہ نے اس پر کہا میں بھی وہی جانتا ہوں جو تم نے کہا۔' WHERE id = 4765;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن محمد نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہمارے والد (ابراہیم بن سعد) نے، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے بیان کیا، کہا، مجھ سے انس بن مالک نے خبر دی کہ اللہ تعالیٰ نبی کریم صلی اللہ علیہ وسلم پر پے در پے وحی اتارتا رہا اور آپ صلی اللہ علیہ وسلم کی وفات کے قریبی زمانے میں تو بہت وحی اتری پھر اس کے بعد نبی کریم صلی اللہ علیہ وسلم کی وفات ہو گئی۔' WHERE id = 4776;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، کہا مجھ سے عروہ بن زبیر نے بیان کیا، ان سے مسور بن مخرمہ اور عبدالرحمٰن بن عبدالقاری نے بیان کیا، انہوں نے عمر بن خطاب رضی اللہ عنہ سے سنا وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم کی زندگی میں، میں نے ہشام بن حکیم کو سورۃ الفرقان نماز میں پڑھتے سنا، میں نے ان کی قرآت کو غور سے سنا تو معلوم ہوا کہ وہ سورت میں ایسے حروف پڑھ رہے ہیں کہ مجھے اس طرح نبی کریم صلی اللہ علیہ وسلم نے نہیں پڑھایا تھا، قریب تھا کہ میں ان کا سر نماز ہی میں پکڑ لیتا لیکن میں نے بڑی مشکل سے صبر کیا اور جب انہوں نے سلام پھیرا تو میں نے ان کی چادر سے ان کی گردن باندھ کر پوچھا یہ سورت جو میں نے ابھی تمہیں پڑھتے ہوئے سنی ہے، تمہیں کس نے اس طرح پڑھائی ہے؟ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے مجھے اسی طرح پڑھائی ہے، میں نے کہا تم جھوٹ بولتے ہو۔ خود نبی کریم صلی اللہ علیہ وسلم نے مجھے اس سے مختلف دوسرے حرفوں سے پڑھائی جس طرح تم پڑھ رہے تھے۔ آخر میں انہیں کھینچتا ہوا نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا کہ میں نے اس شخص سے سورۃ الفرقان ایسے حرفوں میں پڑھتے سنی جن کی آپ نے مجھے تعلیم نہیں دی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ عمر رضی اللہ عنہ تم پہلے انہیں چھوڑ دو اور اے ہشام! تم پڑھ کے سناؤ۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم کے سامنے بھی ان ہی حرفوں میں پڑھا جن میں میں نے انہیں نماز میں پڑھتے سنا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے سن کر فرمایا کہ یہ سورت اسی طرح نازل ہوئی ہے۔ پھر فرمایا عمر! اب تم پڑھ کر سناؤ میں نے اس طرح پڑھا جس طرح نبی کریم صلی اللہ علیہ وسلم نے مجھے تعلیم دی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے اسے بھی سن کر فرمایا کہ اسی طرح نازل ہوئی ہے۔ یہ قرآن سات حرفوں پر نازل ہوا ہے پس تمہیں جس طرح آسان ہو پڑھو۔' WHERE id = 4786;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا ہم سے مسلم نے بیان کیا، ان سے مسروق نے بیان کیا کہ ابن مسعود رضی اللہ عنہ نے کہا، اس اللہ کی قسم جس کے سوا اور کوئی معبود نہیں کتاب اللہ کی جو سورت بھی نازل ہوئی ہے اس کے متعلق میں جانتا ہوں کہ کہاں نازل ہوئی اور کتاب اللہ کی جو آیت بھی نازل ہوئی اس کے متعلق میں جانتا ہوں کہ کس کے بارے میں نازل ہوئی، اور اگر مجھے خبر ہو جائے کہ کوئی شخص مجھ سے زیادہ کتاب اللہ کا جاننے والا ہے اور اونٹ ہی اس کے پاس مجھے پہنچا سکتے ہیں ( یعنی ان کا گھر بہت دور ہے ) تب بھی میں سفر کر کے اس کے پاس جا کر اس سے اس علم کو حاصل کروں گا۔' WHERE id = 4796;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے زید بن اسلم نے اور ان سے ان کے والد اسلم نے کہ رسول اللہ صلی اللہ علیہ وسلم رات کو ایک سفر میں جا رہے تھے۔ عمر بن خطاب رضی اللہ عنہ بھی آپ کے ساتھ تھے۔ عمر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کچھ پوچھا۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے اس کا کوئی جواب نہ دیا۔ عمر رضی اللہ عنہ نے پھر پوچھا آپ نے پھر کوئی جواب نہیں دیا۔ تیسری مرتبہ پھر پوچھا اور جب اس مرتبہ بھی کوئی جواب نہیں دیا تو عمر رضی اللہ عنہ نے ( اپنے آپ کو ) کہا تیری ماں تجھ پر روئے تو نے نبی کریم صلی اللہ علیہ وسلم سے تین مرتبہ عاجزی سے سوال کیا اور نبی کریم صلی اللہ علیہ وسلم نے کسی مرتبہ بھی جواب نہیں دیا۔ عمر رضی اللہ عنہ نے بیان کیا کہ پھر میں نے اپنی اونٹنی کو دوڑایا اور لوگوں سے آگے ہو گیا ( آپ کے برابر چلنا چھوڑ دیا ) مجھے خوف تھا کہ کہیں اس حرکت پر میرے بارے میں کوئی آیت نازل نہ ہو جائے ابھی تھوڑا ہی وقت گزرا تھا کہ میں نے ایک پکارنے والے کو سنا جو پکار رہا تھا۔ عمر رضی اللہ عنہ نے بیان کیا کہ میں نے سوچا مجھے تو خوف تھا ہی کہ میرے بارے میں کچھ وحی نازل ہو گی۔ عمر رضی اللہ عنہ نے بیان کیا چنانچہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں آیا اور میں نے آپ کو سلام کیا ( سلام کے جواب کے بعد نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے عمر! آج رات مجھ پر ایسی سورت نازل ہوئی ہے جو مجھے ان سب چیزوں سے زیادہ پسند ہے جن پر سورج نکلتا ہے۔ پھر آپ نے سورۃ «إنا فتحنا لك فتحا مبينا‏» کی تلاوت فرمائی۔)' WHERE id = 4806;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے مالک بن مغول نے، کہا ہم سے طلحہ بن مصرف نے بیان کیا، کہ میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سوال کیا: کیا نبی کریم نے کوئی وصیت فرمائی تھی؟ انہوں نے کہا کہ نہیں۔ میں نے عرض کیا: پھر لوگوں پر وصیت کیسے فرض کی گئی کہ مسلمانوں کو تو وصیت کا حکم ہے اور خود نبی کریم صلی اللہ علیہ وسلم نے کوئی وصیت نہیں فرمائی۔ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے کتاب اللہ کو مضبوطی سے تھامے رہنے کی وصیت فرمائی تھی۔' WHERE id = 4816;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے منصور نے، ان سے ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بہت برا ہے کسی شخص کا یہ کہنا کہ میں فلاں فلاں آیت بھول گیا بلکہ یوں ( کہنا چاہیے ) کہ مجھے بھلا دیا گیا اور قرآن مجید کا پڑھنا جاری رکھو کیونکہ انسانوں کے دلوں سے دور ہو جانے میں وہ اونٹ کے بھاگنے سے بھی بڑھ کر ہے۔ ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے، اور ان سے منصور بن معتمر نے پچھلی حدیث کی طرح۔ محمد بن عرعرہ کے ساتھ اس کو بشر بن عبداللہ نے بھی عبداللہ بن مبارک سے، انہوں نے شعبہ سے روایت کیا ہے اور محمد بن عرعرہ کے ساتھ اس کو ابن جریج نے بھی عبدہ سے، انہوں نے شقیق سے، انہوں نے عبداللہ بن مسعود سے ایسا ہی روایت کیا ہے۔' WHERE id = 4826;
UPDATE hadiths SET urdu = 'ہم سے بشر بن آدم نے بیان کیا، کہا ہم کو علی بن مسہر نے خبر دی، کہا ہم کو ہشام بن عروہ نے خبر دی، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک قاری کو رات کے وقت مسجد میں قرآن مجید پڑھتے ہوئے سنا تو فرمایا کہ اللہ اس آدمی پر رحم کرے اس نے مجھے فلاں فلاں آیتیں یاد دلا دیں جنہیں میں نے فلاں فلاں سورتوں میں سے چھوڑ رکھا تھا۔' WHERE id = 4838;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے، ان سے مغیرہ بن مقسم نے، ان سے مجاہد بن جبیر نے اور ان سے عبداللہ بن عمرو رضی اللہ عنہما نے بیان کیا کہ میرے والد عمرو بن العاص رضی اللہ عنہ نے میرا نکاح ایک شریف خاندان کی عورت ( ام محمد بنت محمیہ ) سے کر دیا تھا اور ہمیشہ اس کی خبرگیری کرتے رہتے تھے اور ان سے باربار اس کے شوہر ( یعنی خود ان ) کے متعلق پوچھتے رہتے تھے۔ میری بیوی کہتی کہ بہت اچھا مرد ہے۔ البتہ جب سے میں ان کے نکاح میں آئی ہوں انہوں نے اب تک ہمارے بستر پر قدم بھی نہیں رکھا نہ میرے کپڑے میں کبھی ہاتھ ڈالا۔ جب بہت دن اسی طرح ہو گئے تو والد صاحب نے مجبور ہو کر اس کا تذکرہ نبی کریم صلی اللہ علیہ وسلم سے کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھ سے اس کی ملاقات کراؤ۔ چنانچہ میں اس کے بعد نبی کریم صلی اللہ علیہ وسلم سے ملا۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ روزہ کس طرح رکھتے ہو۔ میں نے عرض کیا کہ روزانہ پھر دریافت فرمایا قرآن مجید کس طرح ختم کرتے ہو؟ میں نے عرض کیا ہر رات۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہر مہینے میں تین دن روزے رکھو اور قرآن ایک مہینے میں ختم کرو۔ بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! مجھے اس سے زیادہ کی طاقت ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر بلا روزے کے رہو اور ایک دن روزے سے۔ میں نے عرض کیا مجھے اس سے بھی زیادہ کی طاقت ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر وہ روزہ رکھو جو سب سے افضل ہے، یعنی داؤد علیہ السلام کا روزہ، ایک دن روزہ رکھو اور ایک دن افطار کرو اور قرآن مجید سات دن میں ختم کرو۔ عبداللہ بن عمرو رضی اللہ عنہما کہا کرتے تھے کاش میں نے نبی کریم صلی اللہ علیہ وسلم کی رخصت قبول کر لی ہوتی کیونکہ اب میں بوڑھا اور کمزور ہو گیا ہوں۔ حجاج نے کہا کہ آپ اپنے گھر کے کسی آدمی کو قرآن مجید کا ساتواں حصہ یعنی ایک منزل دن میں سنا دیتے تھے۔ جتنا قرآن مجید آپ رات کے وقت پڑھتے اسے پہلے دن میں سنا رکھتے تاکہ رات کے وقت آسانی سے پڑھ سکیں اور جب ( قوت ختم ہو جاتی اور نڈھال ہو جاتے اور ) قوت حاصل کرنا چاہتے تو کئی کئی دن روزہ نہ رکھتے کیونکہ آپ کو یہ پسند نہیں تھا کہ جس چیز کا رسول اللہ صلی اللہ علیہ وسلم کے آگے وعدہ کر لیا ہے ( ایک دن روزہ رکھنا ایک دن افطار کرنا ) اس میں سے کچھ بھی چھوڑیں۔ امام بخاری رحمہ اللہ کہتے ہیں کہ بعض راویوں نے تین دن میں اور بعض نے پانچ دن میں۔ لیکن اکثر نے سات راتوں میں ختم کی حدیث روایت کی ہے۔' WHERE id = 4849;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے، ان سے عبدالملک بن میسرہ نے، ان سے نزال بن سبرہ نے کہ عبداللہ بن مسعود رضی اللہ عنہ نے ایک صاحب ( ابی بن کعب رضی اللہ عنہ ) کو ایک آیت پڑھتے سنا، وہی آیت انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کے خلاف سنی تھی۔ ( ابن مسعود رضی اللہ عنہ نے بیان کیا کہ ) پھر میں نے ان کا ہاتھ پکڑا اور انہیں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں لایا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم دونوں صحیح ہو ( اس لیے اپنے اپنے طور پر پڑھو۔ ) ( شعبہ کہتے ہیں کہ ) میرا غالب گمان یہ ہے کہ نبی کریم صلی اللہ علیہ وسلم نے یہ بھی فرمایا کہ ( اختلاف و نزاع نہ کیا کرو ) کیونکہ تم سے پہلے کی امتوں نے اختلاف کیا اور اسی وجہ سے اللہ تعالیٰ نے انہیں ہلاک کر دیا۔' WHERE id = 4859;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، ان سے حمید طویل نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، بیان کیا کہ عبدالرحمٰن بن عوف رضی اللہ عنہ ( ہجرت کر کے مدینہ ) آئے تو نبی کریم صلی اللہ علیہ وسلم نے ان کے اور سعد بن ربیع انصاری رضی اللہ عنہ کے درمیان بھائی چارہ کرایا۔ سعد انصاری رضی اللہ عنہ کے نکاح میں دو بیویاں تھیں۔ انہوں نے عبدالرحمٰن رضی اللہ عنہ سے کہا کہ وہ ان کے اہل ( بیوی ) اور مال میں سے آدھے لیں۔ اس پر عبدالرحمٰن نے کہا کہ اللہ تعالیٰ آپ کے اہل اور آپ کے مال میں برکت دے، مجھے تو بازار کا راستہ بتا دو۔ چنانچہ آپ بازار آئے اور یہاں آپ نے کچھ پنیر اور کچھ گھی کی تجارت کی اور نفع کمایا۔ چند دنوں کے بعد ان پر زعفران کی زردی لگی ہوئی تھی۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ عبدالرحمٰن یہ کیا ہے؟ انہوں نے عرض کیا کہ میں نے ایک انصاری خاتون سے شادی کر لی ہے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ انہیں مہر میں کیا دیا عرض کیا کہ ایک گٹھلی برابر سونا دیا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ولیمہ کر اگرچہ ایک بکری ہی کا ہو۔' WHERE id = 4869;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اونٹ پر سوار ہونے والی ( عرب ) عورتوں میں بہترین عورت قریش کی صالح عورت ہوتی ہے جو اپنے بچے سے بہت زیادہ محبت کرنے والی اور اپنے شوہر کے مال اسباب میں اس کی بہت عمدہ نگہبان و نگراں ثابت ہوتی ہے۔' WHERE id = 4879;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں عروہ بن زبیر نے خبر دی کہ انہوں نے عائشہ رضی اللہ عنہا سے آیت «وإن خفتم أن لا تقسطوا في اليتامى‏» ”اور اگر تمہیں خوف ہو کہ یتیم لڑکیوں کے بارے میں تم انصاف نہیں کر سکو گے۔“ کے متعلق سوال کیا۔ عائشہ رضی اللہ عنہا نے کہا میرے بھانجے! اس آیت میں اس یتیم لڑکی کا حکم بیان ہوا ہے جو اپنے ولی کی پرورش میں ہو اور اس کا ولی اس کی خوبصورتی اور مالداری پر ریجھ کر یہ چاہے کہ اس سے نکاح کرے لیکن اس کے مہر میں کمی کرنے کا بھی ارادہ ہو۔ ایسے ولی کو اپنی زیر پرورش یتیم لڑکی سے نکاح کرنے سے منع کیا گیا ہے جب وہ ان کا مہر انصاف سے پورا ادا کریں گے اگر وہ ایسا نہ کریں تو پھر آیت میں ایسے ولیوں کو حکم دیا گیا کہ وہ اپنی زیر پرورش یتیم لڑکی کے سوا کسی اور سے نکاح کر لیں۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ لوگوں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کے بعد سوال کیا تو اللہ تعالیٰ نے سورۃ نساء میں آیت «ويستفتونك في النساء‏» سے «وترغبون أن تنكحوهن‏» تک نازل کی۔ اس آیت میں اللہ تعالیٰ نے یہ حکم دیا کہ یتیم لڑکیاں اگر خوبصورت اور صاحب مال ہوں تو ان کے ولی بھی ان کے ساتھ نکاح کر لینا چاہتے ہیں، اس کا خاندان پسند کرتے ہیں اور مہر پورا ادا کر کے ان سے نکاح کر لیتے ہیں۔ لیکن ان میں حسن کی کمی ہو اور مال بھی نہ ہو تو پھر ان کی طرف رغبت نہیں ہو گی اور وہ انہیں چھوڑ کر دوسری عورتوں سے نکاح کر لیتے ہیں۔ عائشہ رضی اللہ عنہا نے کہا کہ آیت کا مطلب یہ ہے کہ جیسے اس وقت یتیم لڑکی کو چھوڑ دیتے ہیں جب وہ نادار ہو اور خوبصورت نہ ہو ایسے ہی اس وقت بھی چھوڑ دینا چاہئے جب وہ مالدار اور خوبصورت ہو البتہ اگر اس کے حق میں انصاف کریں اور اس کا مہر پورا ادا کریں تب اس سے نکاح کر سکتے ہیں۔' WHERE id = 4889;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اشعث نے، ان سے ان کے دادا نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم ان کے پاس تشریف لائے تو دیکھا کہ ان کے یہاں ایک مرد بیٹھا ہوا ہے۔ آپ صلی اللہ علیہ وسلم کے چہرے کا رنگ بدل گیا گویا کہ آپ نے اس کو پسند نہیں فرمایا عائشہ رضی اللہ عنہا نے عرض کیا یا رسول اللہ! یہ میرے دودھ والے بھائی ہیں آپ صلی اللہ علیہ وسلم نے فرمایا دیکھو، سوچ سمجھ کر کہو کون تمہارا بھائی ہے۔' WHERE id = 4899;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم کو سفیان بن عیینہ نے خبر دی، کہا ہم کو عمرو بن دینار نے خبر دی، کہا ہم سے جابر بن زید نے بیان کیا، کہا ہم کو ابن عباس رضی اللہ عنہما نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے ( میمونہ رضی اللہ عنہا سے ) نکاح کیا اور اس وقت آپ احرام باندھے ہوئے تھے۔' WHERE id = 4910;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم سلمہ بن دینار نے، ان سے سہل بن سعد رضی اللہ عنہ نے کہ ایک خاتون رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا: یا رسول اللہ! میں آپ کی خدمت میں اپنے آپ کو ہبہ کرنے آئی ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے ان کی طرف دیکھا اور نظر اٹھا کر دیکھا، پھر نظر نیچی کر لی اور سر کو جھکا لیا۔ جب خاتون نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے بارے میں کوئی فیصلہ نہیں فرمایا تو بیٹھ گئیں۔ اس کے بعد آپ کے صحابہ میں سے ایک صاحب کھڑے ہوئے اور عرض کیا کہ یا رسول اللہ! اگر آپ کو ان کی ضرورت نہیں تو ان کا نکاح مجھ سے کرا دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارے پاس کوئی چیز ہے؟ انہوں نے عرض کی کہ نہیں یا رسول اللہ، اللہ کی قسم! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اپنے گھر جاؤ اور دیکھو شاید کوئی چیز مل جائے۔ وہ گئے اور واپس آ کر عرض کی کہ نہیں یا رسول اللہ! میں نے کوئی چیز نہیں پائی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اور دیکھ لو، اگر ایک لوہے کی انگوٹھی بھی مل جائے۔ وہ گئے اور واپس آ کر عرض کیا: یا رسول اللہ! مجھے لوہے کی انگوٹھی بھی نہیں ملی، البتہ یہ میرا تہمد ہے۔ سہل رضی اللہ عنہ نے بیان کیا کہ ان کے پاس چادر بھی نہیں تھی ( ان صحابی نے کہا کہ ) ان خاتون کو اس تہمد میں سے آدھا عنایت فرما دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ تمہارے تہمد کا کیا کرے گی اگر تم اسے پہنو گے تو اس کے لیے اس میں سے کچھ باقی نہیں رہے گا۔ اس کے بعد وہ صاحب بیٹھ گئے اور دیر تک بیٹھے رہے پھر کھڑے ہوئے تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں واپس جاتے ہوئے دیکھا اور انہیں بلانے کے لیے فرمایا، انہیں بلایا گیا۔ جب وہ آئے تو آپ صلی اللہ علیہ وسلم نے ان سے دریافت فرمایا کہ تمہارے پاس قرآن مجید کتنا ہے۔ انہوں نے عرض کیا فلاں فلاں سورتیں۔ انہوں نے ان سورتوں کو گنایا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم ان سورتوں کو زبانی پڑھ لیتے ہو۔ انہوں نے ہاں میں جواب دیا۔ نبی کریم صلی اللہ علیہ وسلم نے پھر فرمایا کہ جاؤ میں نے اس خاتون کو تمہارے نکاح میں اس قرآن کی وجہ سے دیا جو تمہارے پاس ہے۔ ان سورتوں کو اس سے یاد کرا دو۔' WHERE id = 4921;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام دستوائی نے، ان سے یحییٰ بن ابی بشیر نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بیوہ عورت کا نکاح اس وقت تک نہ کیا جائے جب تک اس کی اجازت نہ لی جائے اور کنواری عورت کا نکاح اس وقت تک نہ کیا جائے جب تک اس کی اجازت نہ مل جائے۔ صحابہ نے کہا کہ یا رسول اللہ! کنواری عورت اذن کیونکر دے گی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کی صورت یہ ہے کہ وہ خاموش رہ جائے۔ یہ خاموشی اس کا اذن سمجھی جائے گی۔' WHERE id = 4931;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عبدالعزیز بن صہیب نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ عبدالرحمٰن بن عوف رضی اللہ عنہ نے ایک خاتون سے ایک گٹھلی کے وزن کے برابر ( سونے کے مہر پر ) نکاح کیا۔ پھر نبی کریم صلی اللہ علیہ وسلم شادی کی خوشی ان میں دیکھی تو ان سے پوچھا۔ انہوں نے عرض کیا کہ میں نے ایک عورت سے ایک گٹھلی کے برابر نکاح کیا ہے اور قتادہ رضی اللہ عنہ نے انس رضی اللہ عنہ سے یہ روایت اس طرح نقل کی ہے کہ عبدالرحمٰن بن عوف رضی اللہ عنہ نے ایک عورت سے۔ ایک گٹھلی کے وزن کے برابر سونے پر نکاح کیا تھا۔' WHERE id = 4942;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ہشام بن عروہ نے اور ان سے عروہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا سے نکاح کیا تو ان کی عمر چھ سال کی تھی اور جب ان کے ساتھ خلوت کی تو ان کی عمر نو سال کی تھی اور وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ نو سال تک رہیں۔' WHERE id = 4952;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت بنانی نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے زینب رضی اللہ عنہا جیسا ولیمہ اپنی بیویوں میں سے کسی کا نہیں کیا، ان کا ولیمہ آپ نے ایک بکری کا کیا تھا۔' WHERE id = 4962;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے ابوحازم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر مجھے بکری کے کھر کی دعوت دی جائے تو میں اسے بھی قبول کروں گا اور اگر مجھے وہ کھر بھی ہدیہ میں دیئے جائیں تو میں اسے قبول کروں گا۔' WHERE id = 4972;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ کچھ فوجی کھیل کا نیزہ بازی سے مظاہرہ کر رہے تھے، تو رسول اللہ صلی اللہ علیہ وسلم نے ( اپنے جسم مبارک سے ) میرے لیے پردہ کیا اور میں وہ کھیل دیکھتی رہی۔ میں نے اسے دیر تک دیکھا اور خود ہی اکتا کر لوٹ آئی۔ اب تم خود سمجھ لو کہ ایک کم عمر لڑکی کھیل کو کتنی دیر تک دیکھ سکتی ہے اور اس میں دلچسپی لے سکتی ہے۔' WHERE id = 4983;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، انہوں نے کہا ہم کو عبداللہ نے خبر دی، انہوں نے کہا ہم کو موسیٰ بن عقبہ نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے ہر ایک حاکم ہے اور ہر ایک سے اس کی رعیت کے بارے میں سوال ہو گا۔ امیر ( حاکم ) ہے، مرد اپنے گھر والوں پر حاکم ہے۔ عورت اپنے شوہر کے گھر اور اس کے بچوں پر حاکم ہے۔ تم میں سے ہر ایک حاکم ہے اور ہر ایک سے اس کی رعیت کے بارے میں سوال ہو گا۔' WHERE id = 4993;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے زہیر نے بیان کیا، اس سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ سودہ بنت زمعہ نے اپنی باری عائشہ رضی اللہ عنہا کو دے دی تھی اور رسول اللہ صلی اللہ علیہ وسلم عائشہ رضی اللہ عنہا کے یہاں خود ان کی باری کے دن اور سودہ رضی اللہ عنہا کی باری کے دن رہتے تھے۔' WHERE id = 5004;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ بن عبدالرحمٰن نے، ان سے عروہ بن زبیر نے بیان کیا اور ان سے ان کی والدہ اسماء بنت ابی بکر رضی اللہ عنہما نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم فرما رہے تھے کہ اللہ تعالیٰ سے زیادہ غیرت مند کوئی نہیں اور ( اسی سند سے ) یحییٰ سے روایت ہے کہ ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا۔' WHERE id = 5014;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یزید بن ابی حبیب نے، ان سے ابوالخیر نے اور ان سے عقبہ بن عامر نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ عورتوں میں جانے سے بچتے رہو اس پر قبیلہ انصار کے ایک صحابی نے عرض کیا: یا رسول اللہ! دیور کے متعلق آپ کی کیا رائے ہے؟ ( وہ اپنی بھاوج کے ساتھ جا سکتا ہے یا نہیں؟ ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دیور یا ( جیٹھ ) کا جانا ہی تو ہلاکت ہے۔' WHERE id = 5024;
UPDATE hadiths SET urdu = 'مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق نے، کہا ہم کو معمر نے خبر دی، انہیں عبداللہ بن طاؤس نے، انہیں ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ سلیمان بن داؤد علیہاالسلام نے فرمایا کہ آج رات میں اپنی سو بیویوں کے پاس ہو آؤں گا ( اور اس قربت کے نتیجہ میں ) ہر عورت ایک لڑکا جنے گی تو سو لڑکے ایسے پیدا ہوں گے جو اللہ کے راستے میں جہاد کریں گے۔ فرشتہ نے ان سے کہا کہ ان شاءاللہ کہہ لیجئے لیکن انہوں نے نہیں کہا اور بھول گئے۔ چنانچہ آپ تمام بیویوں کے پاس گئے لیکن ایک کے سوا کسی کے بھی بچہ پیدا نہ ہوا اور اس ایک کے یہاں بھی آدھا بچہ پیدا ہوا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر ان شاءاللہ کہہ لیتے تو ان کی مراد بر آتی اور ان کی خواہش پوری ہونے کی امید زیادہ ہوتی۔' WHERE id = 5034;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے، ان سے انس بن سیرین نے، کہا کہ میں نے ابن عمر رضی اللہ عنہما سے سنا، انہوں نے کہا کہ ابن عمر رضی اللہ عنہما نے اپنی بیوی کو حالت حیض میں طلاق دے دی۔ پھر عمر رضی اللہ عنہ نے اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا، نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ چاہیے کہ رجوع کر لیں۔ ( انس رضی اللہ عنہ نے بیان کیا کہ ) میں نے ابن عمر رضی اللہ عنہما سے پوچھا کہ کیا یہ طلاق، طلاق سمجھی جائے گی؟ انہوں نے کہا کہ چپ رہ۔ پھر کیا سمجھی جائے گی؟ اور قتادہ نے بیان کیا، ان سے یونس بن جبیر نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا ( کہ نبی کریم صلی اللہ علیہ وسلم نے ابن عمر رضی اللہ عنہما سے ) فرمایا کہ اسے حکم دو کہ رجوع کر لے ( یونس بن جبیر نے بیان کیا کہ ) میں نے پوچھا، کیا یہ طلاق طلاق سمجھی جائے گی؟ ابن عمر رضی اللہ عنہما نے کہا تو کیا سمجھتا ہے اگر کوئی کسی فرض کے ادا کرنے سے عاجز بن جائے یا احمق ہو جائے۔ تو وہ فرض اس کے ذمہ سے ساقط ہو جائے گا؟ ہرگز نہیں۔' WHERE id = 5044;
UPDATE hadiths SET urdu = 'اور لیث بن سعد نے نافع سے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما سے اگر ایسے شخص کا مسئلہ پوچھا جاتا جس نے اپنی بیوی کو تین طلاق دی ہوتی، تو وہ کہتے اگر تو ایک بار یا دو بار طلاق دیتا تو رجوع کر سکتا تھا کیونکہ نبی کریم صلی اللہ علیہ وسلم نے مجھ کو ایسا ہی حکم دیا تھا لیکن جب تو نے تین طلاق دے دی تو وہ عورت اب تجھ پر حرام ہو گئی یہاں تک کہ وہ تیرے سوا اور کسی شخص سے نکاح کرے۔' WHERE id = 5056;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن مبارک مخری نے کہا، کہا ہم سے قراد ابونوح نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، ان سے ایوب سختیانی نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ ثابت بن قیس بن شماس رضی اللہ عنہ کی بیوی نبی کریم صلی اللہ علیہ وسلم کے پاس آئیں اور عرض کیا: یا رسول اللہ! ثابت کے دین اور ان کے اخلاق سے مجھے کوئی شکایت نہیں لیکن مجھے خطرہ ہے ( کہ میں ثابت رضی اللہ عنہ کی ناشکری میں نہ پھنس جاؤں ) ۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر ان سے دریافت فرمایا کہ کیا تم ان کا باغ ( جو انہوں نے مہر میں دیا تھا ) واپس کر سکتی ہو؟ انہوں نے عرض کیا جی ہاں۔ چنانچہ انہوں نے وہ باغ واپس کر دیا اور نبی کریم صلی اللہ علیہ وسلم کے حکم سے ثابت رضی اللہ عنہ نے انہیں اپنے سے جدا کر دیا۔' WHERE id = 5067;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن عروہ نے خبر دی، انہیں ابن جریج نے کہ عطاء راسانی نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم اور مومنین کے لیے مشرکین دو طرح کے تھے۔ ایک تو مشرکین لڑائی کرنے والوں سے کہ نبی کریم صلی اللہ علیہ وسلم ان سے جنگ کرتے تھے اور وہ نبی کریم صلی اللہ علیہ وسلم سے جنگ کرتے تھے۔ دوسرے عہد و پیمان کرنے والے مشرکین کہ نبی کریم صلی اللہ علیہ وسلم ان سے جنگ نہیں کرتے تھے اور نہ وہ نبی کریم صلی اللہ علیہ وسلم سے جنگ کرتے تھے اور جب اہل کتاب حرب کی کوئی عورت ( اسلام قبول کرنے کے بعد ) ہجرت کر کے ( مدینہ منورہ ) آتی تو انہیں اس وقت تک پیغام نکاح نہ دیا جاتا یہاں تک کہ انہیں حیض آتا اور پھر وہ اس سے پاک ہوتیں، پھر جب وہ پاک ہو جاتیں تو ان سے نکاح جائز ہو جاتا، پھر اگر ان کے شوہر بھی، ان کے کسی دوسرے شخص سے نکاح کر لینے سے پہلے ہجرت کر کے آ جاتے تو یہ انہیں کو ملتیں اور اگر مشرکین میں سے کوئی غلام یا لونڈی مسلمان ہو کر ہجرت کرتی تو وہ آزاد سمجھے جاتے اور ان کے وہی حقوق ہوتے جو تمام مہاجرین کے تھے۔ پھر عطاء نے معاہد مشرکین کے سلسلے میں مجاہد کی حدیث کی طرح سے صورت حال بیان کی کہ اگر معاہد مشرکین کی کوئی غلام یا لونڈی ہجرت کر کے آ جاتی تو انہیں ان کے مالک مشرکین کو واپس نہیں کیا جاتا تھا۔ البتہ جو ان کی قیمت ہوتی وہ واپس کر دی جاتی تھی۔' WHERE id = 5077;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن سلمہ نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، ان سے سلیمان تیمی نے، ان سے ابوعثمان نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے کسی کو ( سحری کھانے سے ) بلال کی پکار نہ روکے یا آپ نے فرمایا کہ ”ان کی اذان“ کیونکہ وہ پکارتے ہیں، یا فرمایا، اذان دیتے ہیں تاکہ اس وقت نماز پڑھنے والا رک جائے۔ اس کا اعلان سے یہ مقصود نہیں ہوتا کہ صبح صادق ہو گئی۔ اس وقت یزید بن زریع نے اپنے دونوں ہاتھ بلند کئے ( صبح کاذب کی صورت بتانے کے لیے ) پھر ایک ہاتھ کو دوسرے پر پھیلایا ( صبح صادق کی صورت کے اظہار کے لیے ) ۔' WHERE id = 5089;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی ایاس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے اور انہیں سہل بن سعد ساعدی نے خبر دی کہ عویمر عجلانی، عاصم بن عدی انصاری کے پاس آئے اور ان سے کہا کہ عاصم آپ کا کیا خیال ہے کہ ایک شخص اگر اپنی بیوی کے ساتھ کسی غیر مرد کو دیکھے تو کیا اسے قتل کر دے گا لیکن پھر آپ لوگ اسے بھی قتل کر دیں گے۔ آخر اسے کیا کرنا چاہیئے؟ عاصم! میرے لیے یہ مسئلہ پوچھ دو۔ چنانچہ عاصم رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے یہ مسئلہ پوچھا۔ نبی کریم نے اس طرح کے سوالات کو ناپسند فرمایا اور اظہار ناگواری کیا۔ عاصم رضی اللہ عنہ نے اس سلسلے میں نبی کریم صلی اللہ علیہ وسلم سے جو کچھ سنا اس کا بہت اثر لیا۔ پھر جب گھر واپس آئے تو عویمر ان کے پاس آئے اور پوچھا۔ عاصم! آپ کو رسول اللہ صلی اللہ علیہ وسلم نے کیا جواب دیا۔ عاصم رضی اللہ عنہ نے کہا، عویمر! تم نے میرے ساتھ اچھا معاملہ نہیں کیا، جو مسئلہ تم نے پوچھا تھا، نبی کریم صلی اللہ علیہ وسلم نے اسے ناپسند فرمایا۔ عویمر رضی اللہ عنہ نے کہا کہ اللہ کی قسم! جب تک میں یہ مسئلہ نبی کریم صلی اللہ علیہ وسلم سے معلوم نہ کر لوں، باز نہیں آؤں گا۔ چنانچہ عویمر رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے، نبی کریم صلی اللہ علیہ وسلم اس وقت صحابہ کے درمیان میں موجود تھے۔ انہوں نے عرض کیا: یا رسول اللہ! آپ کا اس شخص کے متعلق کیا ارشاد ہے جو اپنی بیوی کے ساتھ کسی غیر مرد کو دیکھے، کیا اسے قتل کر دے؟ لیکن پھر آپ لوگ اسے ( قصاص ) میں قتل کر دیں گے، تو پھر اسے کیا کرنا چاہیئے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے اور تمہاری بیوی کے بارے میں ابھی وحی نازل ہوئی ہے۔ جاؤ اور اپنی بیوی کو لے کر آؤ۔ سہل نے بیان کیا کہ پھر ان دونوں نے لعان کیا۔ میں بھی نبی کریم صلی اللہ علیہ وسلم کے پاس اس وقت موجود تھا۔ جب لعان سے فارغ ہوئے تو عویمر رضی اللہ عنہ نے کہا کہ یا رسول اللہ! اگر اب بھی میں اسے ( اپنی بیوی کو ) اپنے ساتھ رکھتا ہوں تو اس کا مطلب یہ ہے کہ میں جھوٹا ہوں۔ چنانچہ انہوں نے انہیں تین طلاقیں نبی کریم صلی اللہ علیہ وسلم کے حکم سے پہلے ہی دے دیں۔ ابن شہاب نے بیان کیا کہ پھر لعان کرنے والوں کے لیے سنت طریقہ مقرر ہو گیا۔' WHERE id = 5099;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے جعفر بن ربیعہ نے، ان سے عبدالرحمٰن بن ہرمز نے، کہا کہ مجھے خبر دی ابوسلمہ بن عبدالرحمٰن نے کہ زینب ام سلمہ رضی اللہ عنہا نے اپنی والدہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا سے خبر دی کہ ایک خاتون جو اسلام لائی تھیں اور جن کا نام سبیعہ تھا، اپنے شوہر کے ساتھ رہتی تھیں، شوہر کا جب انتقال ہوا تو وہ حاملہ تھیں۔ ابوسنان بن بعکک رضی اللہ عنہ نے ان کے پاس نکاح کا پیغام بھیجا لیکن انہوں نے نکاح کرنے سے انکار کیا۔ ابوالسنابل نے کہا کہ اللہ کی قسم! جب تک عدت کی دو مدتوں میں سے لمبی نہ گزار لوں گی، تمہارے لیے اس سے ( جس سے نکاح وہ کرنا چاہتی تھیں ) نکاح کرنا صحیح نہیں ہو گا۔ پھر وہ ( وضع حمل کے بعد ) تقریباً دس دن تک رکی رہیں۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب نکاح کر لو۔' WHERE id = 5109;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، کہا ہم سے حمید بن نافع نے، ان سے زینب بنت ام سلمہ رضی اللہ عنہا نے اپنی والدہ سے کہ ایک عورت کے شوہر کا انتقال ہو گیا، اس کے بعد اس کی آنکھ میں تکلیف ہوئی تو اس کے گھر والے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ سے سرمہ لگانے کی اجازت مانگی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ سرمہ ( زمانہ عدت میں ) نہ لگاؤ۔ ( زمانہ جاہلیت میں ) تمہیں بدترین کپڑے میں وقت گزارنا پڑتا تھا، یا ( راوی کو شک تھا کہ یہ فرمایا کہ ) بدترین گھر میں وقت ( عدت ) گزارنا پڑتا تھا۔ جب اس طرح ایک سال پورا ہو جاتا تو اس کے پاس سے کتا گزرتا اور وہ اس پر مینگنی پھینکتی ( جب عدت سے باہر آتی ) پس سرمہ نہ لگاؤ۔ یہاں تک کہ چار مہینے دس دن گزر جائیں۔' WHERE id = 5125;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، انہوں نے کہا ہم کو شعبہ نے خبر دی، انہیں محمد بن جحادہ نے، انہیں ابوحازم نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے لونڈیوں کے زنا کی کمائی سے منع فرمایا۔' WHERE id = 5135;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب زہری نے بیان کیا کہ مجھے مالک بن اوس بن حدثان نے خبر دی ( ابن شہاب زہری نے بیان کیا کہ ) محمد بن جبیر بن مطعم نے اس کا بعض حصہ بیان کیا تھا، اس لیے میں روانہ ہوا اور مالک بن اوس کی خدمت میں پہنچا اور ان سے یہ حدیث پوچھی۔ مالک نے مجھ سے بیان کیا کہ میں عمر رضی اللہ عنہ کی خدمت میں حاضر ہوا تو ان کے دربان یرفاء ان کے پاس آئے اور کہا عثمان بن عفان، عبدالرحمٰن، زید اور سعد رضی اللہ عنہم ( آپ سے ملنے کی ) اجازت چاہتے ہیں کیا آپ انہیں اس کی اجازت دیں گے؟ عمر رضی اللہ عنہ نے کہا کہ اندر بلا لو۔ چنانچہ انہیں اس کی اجازت دے دی گئی۔ راوی نے کہا کہ پھر یہ سب اندر تشریف لائے اور سلام کر کے بیٹھ گئے۔ یرفاء نے تھوڑی دیر کے بعد پھر عمر رضی اللہ عنہ سے آ کر کہا کہ علی اور عباس رضی اللہ عنہما بھی ملنا چاہتے ہیں کیا آپ کی طرف سے اجازت ہے؟ عمر رضی اللہ عنہ نے انہیں بھی اندر بلانے کے لیے کہا۔ اندر آ کر ان حضرات نے بھی سلام کیا اور بیٹھ گئے۔ اس کے بعد عباس رضی اللہ عنہ نے کہا، امیرالمؤمنین میرے اور ان ( علی رضی اللہ عنہ ) کے درمیان فیصلہ کر دیجئیے۔ دوسرے صحابہ عثمان رضی اللہ عنہ اور ان کے ساتھیوں نے بھی کہا کہ امیرالمؤمنین ان کا فیصلہ فرما دیجئیے اور انہیں اس الجھن سے نجات دیجئیے۔ عمر رضی اللہ عنہ نے کہا جلدی نہ کرو میں اللہ کی قسم دے کر تم سے پوچھتا ہوں جس کے حکم سے آسمان و زمین قائم ہیں۔ کیا تمہیں معلوم ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ہے ہمارا کوئی وارث نہیں ہوتا، جو کچھ ہم انبیاء وفات کے وقت چھوڑتے ہیں وہ صدقہ ہوتا ہے۔ نبی کریم صلی اللہ علیہ وسلم کا اشارہ خود اپنی ذات کی طرف تھا۔ صحابہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے یہ ارشاد فرمایا تھا۔ اس کے بعد عمر رضی اللہ عنہ علی اور عباس رضی اللہ عنہما کی طرف متوجہ ہوئے اور ان سے پوچھا میں اللہ کی قسم دے کر آپ سے پوچھتا ہوں، کیا آپ لوگوں کو معلوم ہے کہ رسول اللہ صلی اللہ علیہ وسلم نے یہ ارشاد فرمایا تھا۔ انہوں نے بھی تصدیق کی کہ نبی کریم صلی اللہ علیہ وسلم نے واقعی یہ فرمایا تھا۔ پھر عمر رضی اللہ عنہ نے کہا کہ اب میں آپ سے اس معاملہ میں بات کروں گا۔ اللہ تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم کو اس مال ( مال فے ) میں مختار کل ہونے کی خصوصیت بخشی تھی اور نبی کریم صلی اللہ علیہ وسلم کے سوا اس میں سے کسی دوسرے کو کچھ نہیں دیا تھا۔ اللہ تعالیٰ نے ارشاد فرمایا تھا «ما أفاء الله على رسوله منهم فما أوجفتم عليه من خيل‏» سے «قدير‏» تک۔“ اس لیے یہ ( چار خمس ) خاص آپ کے لیے تھے۔ اللہ کی قسم نبی کریم صلی اللہ علیہ وسلم نے تمہیں نظر انداز کر کے اس مال کو اپنے لیے خاص نہیں کر لیا تھا اور نہ تمہارا کم کر کے اسے نبی کریم صلی اللہ علیہ وسلم نے اپنے لیے رکھا تھا، بلکہ نبی کریم صلی اللہ علیہ وسلم نے پہلے تم سب میں اس کی تقسیم کی آخر میں جو مال باقی رہ گیا تو اس میں سے آپ اپنے گھر والوں کے لیے سال بھر کا خرچ لیتے اور اس کے بعد جو باقی بچتا اسے اللہ کے مال کے مصرف ہی میں ( مسلمانوں کے لیے ) خرچ کر دیتے۔ آپ نے اپنی زندگی بھر اسی کے مطابق عمل کیا۔ اے عثمان! میں تمہیں اللہ کی قسم دیتا ہوں، کیا تمہیں یہ معلوم ہے؟ سب نے کہا کہ جی ہاں، پھر آپ نے علی اور عباس رضی اللہ عنہما سے پوچھا، میں تمہیں اللہ کی قسم دیتا ہوں، کیا تمہیں یہ بھی معلوم ہے؟ انہوں نے بھی کہا کہ جی ہاں معلوم ہے۔ پھر اللہ تعالیٰ نے اپنے نبی کی وفات کی اور ابوبکر رضی اللہ عنہ نے کہا کہ میں رسول اللہ صلی اللہ علیہ وسلم کا خلیفہ ہوں۔ چنانچہ انہوں نے اس جائیداد کو اپنے قبضہ میں لے لیا اور نبی کریم صلی اللہ علیہ وسلم کے عمل کے مطابق اس میں عمل کیا۔ علی اور عباس رضی اللہ عنہما کی طرف متوجہ ہو کر انہوں نے کہا۔ آپ دونوں اس وقت موجود تھے، آپ خوب جانتے ہیں کہ ابوبکر رضی اللہ عنہ نے ایسا ہی کیا تھا اور اللہ جانتا ہے کہ ابوبکر رضی اللہ عنہ اس میں مخلص، محتاط و نیک نیت اور صحیح راستے پر تھے اور حق کی اتباع کرنے والے تھے۔ پھر اللہ تعالیٰ نے ابوبکر رضی اللہ عنہ کی بھی وفات کی اور اب میں نبی کریم صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ کا جانشین ہوں۔ میں دو سال سے اس جائیداد کو اپنے قبضہ میں لیے ہوئے ہوں اور وہی کرتا ہوں جو رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر رضی اللہ عنہ نے اس میں کیا تھا۔ اب آپ حضرات میرے پاس آئے ہیں، آپ کی بات ایک ہی ہے اور آپ کا معاملہ بھی ایک ہے۔ آپ ( عباس رضی اللہ عنہ ) آئے اور مجھ سے اپنے بھتیجے ( نبی کریم صلی اللہ علیہ وسلم ) کی وراثت کا مطالبہ کیا اور آپ ( علی رضی اللہ عنہ ) آئے اور انہوں نے اپنی بیوی کی طرف سے ان کے والد کے ترکہ کا مطالبہ کیا۔ میں نے آپ دونوں سے کہا کہ اگر آپ چاہیں تو میں آپ کو یہ جائیداد دے سکتا ہوں لیکن اس شرط کے ساتھ کہ آپ پر اللہ کا عہد واجب ہو گا۔ وہ یہ کہ آپ دونوں بھی اس جائیداد میں وہی طرز عمل رکھیں گے جو رسول اللہ صلی اللہ علیہ وسلم نے رکھا تھا، جس کے مطابق ابوبکر رضی اللہ عنہ نے عمل کیا اور جب سے میں اس کا والی ہوا ہوں، میں نے جو اس کے ساتھ معاملہ رکھا۔ اور اگر یہ شرط منظور نہ ہو تو پھر آپ مجھ سے اس بارے میں گفتگو چھوڑیں۔ آپ لوگوں نے کہا کہ اس شرط کے مطابق وہ جائیداد ہمارے حوالہ کر دو اور میں نے اسے اس شرط کے ساتھ تم لوگوں کے حوالہ کر دیا۔ کیوں عثمان اور ان کے ساتھیو! میں آپ کو اللہ کی قسم دیتا ہوں میں نے اس شرط ہی پر وہ جائیداد علی اور عباس رضی اللہ عنہما کے قبضہ میں دی ہے نا؟ انہوں نے کہا کہ جی ہاں۔ راوی نے بیان کیا کہ پھر آپ علی اور عباس رضی اللہ عنہما کی طرف متوجہ ہوئے اور کہا میں آپ حضرات کو اللہ کی قسم دیتا ہوں کیا میں نے آپ دونوں کے حوالہ وہ اس شرط کے ساتھ کی تھی؟ دونوں حضرات نے فرمایا کہ جی ہاں۔ پھر عمر رضی اللہ عنہ نے فرمایا، کیا آپ حضرات اب اس کے سوا مجھ سے کوئی اور فیصلہ چاہتے ہیں؟ اس ذات کی قسم ہے جس کے حکم سے آسمان و زمین قائم ہیں اس کے سوا میں کوئی اور فیصلہ قیامت تک نہیں کر سکتا۔ اب لوگ اس کی ذمہ داری پوری کرنے سے عاجز ہیں تو مجھے واپس کر دیں میں اس اس کا بندوبست آپ ہی کر لوں گا۔' WHERE id = 5145;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم سے ابن شہاب نے بیان کیا، ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ایک صاحب آئے اور کہا کہ میں تو ہلاک ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آخر کیا بات ہوئی؟ انہوں نے کہا کہ میں نے اپنی بیوی سے رمضان میں ہمبستری کر لی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ایک غلام آزاد کر دو۔ ( یہ کفارہ ہو جائے گا ) انہوں نے عرض کیا کہ میرے پاس کچھ نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر دو مہینے متواتر روزے رکھ لو۔ انہوں نے کہا کہ مجھ میں اس کی بھی طاقت نہیں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ساٹھ مسکینوں کو کھانا کھلاؤ۔ انہوں نے کہا کہ اتنا بھی میرے پاس نہیں ہے۔ اس کے بعد آپ کے پاس ایک ٹوکرا لایا گیا جس میں کھجوریں تھیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ مسئلہ پوچھنے والا کہاں ہے؟ ان صاحب نے عرض کیا میں یہاں حاضر ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ لو اسے ( اپنی طرف سے ) صدقہ کر دینا۔ انہوں نے کہا اپنے سے زیادہ ضرورت مند پر؟ یا رسول اللہ! اس ذات کی قسم جس نے آپ کو حق کے ساتھ بھیجا ہے، ان دونوں پتھریلے میدانوں کے درمیان کوئی گھرانہ ہم سے زیادہ محتاج نہیں ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم ہنسے اور آپ کے مبارک دانت دکھائی دینے لگے اور فرمایا، پھر تم ہی اس کے زیادہ مستحق ہو۔' WHERE id = 5155;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تینسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، ان سے ابونعیم وہب بن کیسان نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں کھانا لایا گیا، آپ کے ساتھ آپ کے ربیب عمر بن ابی سلمہ رضی اللہ عنہ بھی تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بسم اللہ پڑھ اور اپنے سامنے سے کھا۔' WHERE id = 5165;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو ابومعاویہ نے خبر دی، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور وہب بن کیسان نے بیان کیا کہ اہل شام ( حجاج بن یوسف کے فوجی ) شام کے لوگ عبداللہ بن زبیر رضی اللہ عنہما کو عار دلانے کے لیے کہنے لگے ”یا ابن ذات النطاقین“ اے دو کمر بند والی کے بیٹے اور ان کی والدہ، اسماء رضی اللہ عنہا نے کہا، اے بیٹے! یہ تمہیں دو کمر بند والی کی عار دلاتے ہیں، تمہیں معلوم ہے وہ کمر بند کیا تھے؟ وہ میرا کمر بند تھا جس کے میں نے دو ٹکڑے کر دیئے تھے اور ایک ٹکڑے سے نبی کریم صلی اللہ علیہ وسلم کے برتن کا منہ باندھا تھا اور دوسرے سے دستر خوان بنایا ( اس میں توشہ لپیٹا ) ۔ وہب نے بیان کیا کہ پھر جب عبداللہ بن زبیر رضی اللہ عنہما کو اہل شام دو کمر بند والی کی عار دلاتے تھے، تو وہ کہتے ہاں۔ اللہ کی قسم! یہ بیشک سچ ہے اور وہ یہ مصرعہ پڑھتے «تلك شكاة ظاهر عنك عارها‏.» یہ تو ویسا طعنہ ہے جس میں کچھ عیب نہیں ہے۔' WHERE id = 5175;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے مسعر نے بیان کیا، ان سے علی ابن الاقمر نے کہ میں نے ابوجحیفہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں ٹیک لگا کر نہیں کھاتا۔' WHERE id = 5185;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں جعفر بن عمرو بن امیہ ضمری نے خبر دی، انہیں ان کے والد عمرو بن امیہ رضی اللہ عنہ نے خبر دی کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا آپ اپنے ہاتھ سے بکری کے شانے کا گوشت کاٹ کر کھا رہے تھے، پھر آپ صلی اللہ علیہ وسلم کو نماز کے لیے بلایا گیا تو آپ نے گوشت اور وہ چھری جس سے گوشت کی بوٹی کاٹ رہے تھے، ڈال دی اور نماز کے لیے کھڑے ہو گئے، پھر آپ صلی اللہ علیہ وسلم نے نماز پڑھی اور آپ نے نیا وضو نہیں کیا ( کیونکہ آپ پہلے ہی وضو کئے ہوئے تھے ) ۔' WHERE id = 5195;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ جملی نے بیان کیا، ان سے مرہ ہمدانی نے، ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مردوں میں تو بہت سے کامل ہوئے لیکن عورتوں میں مریم بنت عمران اور فرعون کی بیوی آسیہ کے سوا اور کوئی کامل نہیں ہوا اور عائشہ کی فضیلت تمام عورتوں پر ایسی ہے جیسے تمام کھانوں پر ثرید کی فضیلت ہے۔' WHERE id = 5205;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے عبداللہ بن عبدالرحمٰن نے بیان کیا، ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عورتوں پر عائشہ کی فضیلت ایسی ہے جیسے تمام کھانوں پر ثرید کی فضیلت ہے۔' WHERE id = 5215;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے عبدالرحمٰن بن عابس نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایسا کبھی نہیں کیا کہ تین دن سے زیادہ گوشت قربانی والا رکھنے سے منع فرمایا ہو۔ صرف اس سال یہ حکم دیا تھا جس سال قحط کی وجہ سے لوگ فاقے میں مبتلا تھے۔ مقصد یہ تھا کہ جو لوگ غنی ہیں وہ گوشت محتاجوں کو کھلائیں ( اور جمع کر کے نہ رکھیں ) اور ہم تو بکری کے پائے محفوظ کر کے رکھ لیتے تھے اور پندرہ دن بعد تک ( کھاتے تھے ) اور آل محمد صلی اللہ علیہ وسلم نے کبھی سالن کے ساتھ گیہوں کی روٹی تین دن تک برابر سیر ہو کر نہیں کھائی۔' WHERE id = 5225;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے محمد بن طلحہ نے بیان کیا، ان سے زبید نے بیان کیا، ان سے مجاہد نے بیان کیا، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ درختوں میں ایک درخت مثل مسلمان کے ہے اور وہ کھجور کا درخت ہے۔' WHERE id = 5236;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ثور نے، ان سے خالد بن معدان نے اور ان سے ابوامامہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے سے جب کھانا اٹھایا جاتا تو آپ یہ دعا پڑھتے «الحمد لله كثيرا طيبا مباركا فيه،‏‏‏‏ ‏‏‏‏ غير مكفي،‏‏‏‏ ولا مودع ولا مستغنى عنه،‏‏‏‏ ربنا» ”تمام تعریفیں اللہ کے لیے، بہت زیادہ پاکیزہ برکت والی، ہم اس کھانے کا حق پوری طرح ادا نہ کر سکے اور یہ ہمیشہ کے لیے رخصت نہیں کیا گیا ہے ( اور یہ اس لیے کہا تاکہ ) اس سے ہم کو بےپرواہی کا خیال نہ ہو، اے ہمارے رب!۔“' WHERE id = 5246;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ایک نو مولود بچہ لایا گیا تاکہ آپ اس کی تحنیک کر دیں اس بچہ نے آپ کے اوپر پیشاب کر دیا، آپ نے اس پر پانی بہا دیا۔' WHERE id = 5256;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یزید مقبری نے بیان کیا، کہا ہم سے حیوہ بن شریح نے بیان کیا، کہا کہ مجھے ربیعہ بن یزید دمشقی نے خبر دی، انہیں ابوادریس عائذ اللہ خولانی نے، انہیں ابوثعلبہ خشنی رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا: اے اللہ کے نبی! ہم اہل کتاب کے گاؤں میں رہتے ہیں تو کیا ہم ان کے برتن میں کھا سکتے ہیں؟ اور ہم ایسی زمین میں رہتے ہیں جہاں شکار بہت ہوتا ہے۔ میں تیر کمان سے بھی شکار کرتا ہوں اور اپنے اس کتے سے بھی جو سکھایا ہوا نہیں ہے اور اس کتے سے بھی جو سکھایا ہوا ہے تو اس میں سے کس کا کھانا میرے لیے جائز ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم نے جو اہل کتاب کے برتن کا ذکر کیا ہے تو اگر تمہیں اس کے سوا کوئی اور برتن مل سکے تو اس میں نہ کھاؤ لیکن تمہیں کوئی دوسرا برتن نہ ملے تو ان کے برتن کو خوب دھو کر اس میں کھا سکتے ہو اور جو شکار تم اپنی تیر کمان سے کرو اور ( تیر پھینکتے وقت ) اللہ کا نام لیا ہو تو ( اس کا شکار ) کھا سکتے ہو اور جو شکار تم نے غیر سدھائے ہوئے کتے سے کیا ہو اور شکار خود ذبح کیا ہو تو اسے کھا سکتے ہو۔' WHERE id = 5267;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نبیل نے بیان کیا، ان سے حیوہ بن شریح نے (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا، مجھ سے احمد بن ابی رجاء نے بیان کیا، ان سے سلمہ بن سلیمان نے بیان کیا، ان سے عبداللہ بن المبارک نے بیان کیا، ان سے حیوہ بن شریح نے بیان کیا کہ میں نے ربیعہ بن یزید دمشقی سے سنا، کہا کہ مجھے ابوادریس عائذ اللہ نے خبر دی، کہا کہ میں ابوثعلبہ خشنی رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا: یا رسول اللہ! ہم اہل کتاب کے ملک میں رہتے ہیں اور ان کے برتن میں کھاتے ہیں اور ہم شکار کی زمین میں رہتے ہیں، جہاں میں اپنے تیر سے شکار کرتا ہوں اور اپنے سدھائے ہوئے کتے سے۔ تو اس میں سے کیا چیز ہمارے لیے جائز ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا تم نے جو یہ کہا ہے کہ تم اہل کتاب کے ملک میں رہتے ہو اور ان کے برتن میں بھی کھاتے ہو تو اگر تمہیں ان کے برتنوں کے سوا دوسرے برتن مل جائیں تو ان کے برتنوں میں نہ کھاؤ لیکن ان کے برتنوں کے سوا دوسرے برتن نہ ملیں تو انہیں دھو کر پھر ان میں کھاؤ اور تم نے شکار کی سر زمین کا ذکر کیا ہے تو جو شکار تم اپنے تیر سے مارو اور تیر چلاتے وقت اللہ کا نام لیا ہو تو اسے کھاؤ اور جو شکار تم نے اپنے سدھائے ہوئے کتے سے کیا ہو اور اس پر اللہ کا نام لیا ہو تو اسے کھاؤ اور جو شکار تم نے اپنے بلا سدھائے کتے سے کیا ہو اور اسے ذبح بھی خود ہی کیا ہو تو اسے بھی کھاؤ۔' WHERE id = 5277;
UPDATE hadiths SET urdu = 'مجھ سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے سعید بن مسروق نے، ان سے عبایہ بن رفاعہ بن رافع نے اپنے دادا رافع بن خدیج سے، انہوں نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ مقام ذی الحلیفہ میں تھے کہ ( ہم ) لوگ بھوک اور فاقہ میں مبتلا ہو گئے پھر ہمیں ( غنیمت میں ) اونٹ اور بکریاں ملیں۔ نبی کریم صلی اللہ علیہ وسلم سب سے پیچھے تھے۔ لوگوں نے جلدی کی بھوک کی شدت کی وجہ سے ( اور نبی کریم صلی اللہ علیہ وسلم کے تشریف لانے سے پہلے ہی غنیمت کے جانوروں کو ذبح کر لیا ) اور ہانڈیاں پکنے کے لیے چڑھا دیں پھر جب نبی کریم صلی اللہ علیہ وسلم وہاں پہنچے تو آپ صلی اللہ علیہ وسلم نے حکم دیا اور ہانڈیاں الٹ دی گئیں پھر نبی کریم صلی اللہ علیہ وسلم نے غنیمت کی تقسیم کی اور دس بکریوں کو ایک اونٹ کے برابر قرار دیا۔ ان میں سے ایک اونٹ بھاگ گیا۔ قوم کے پاس گھوڑوں کی کمی تھی لوگ اس اونٹ کے پیچھے دوڑے لیکن اس نے سب کو تھکا دیا۔ آخر ایک شخص نے اس پر تیر کا نشانہ کیا تو اللہ تعالیٰ نے اسے روک دیا اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ان جانوروں میں جنگلیوں کی طرح وحشت ہوتی ہے۔ اس لیے جب کوئی جانور بھڑک کر بھاگ جائے تو اس کے ساتھ ایسا ہی کیا کرو۔ عبایہ نے بیان کیا کہ میرے دادا ( رافع بن خدیج رضی اللہ عنہ ) نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ ہمیں اندیشہ ہے کہ کل ہمارا دشمن سے مقابلہ ہو گا اور ہمارے پاس چھریاں نہیں ہیں کیا ہم ( دھاردار ) لکڑی سے ذبح کر لیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو چیز بھی خون بہا دے اور ( ذبح کرتے وقت ) جانور پر اللہ کا نام لیا ہو تو اسے کھاؤ البتہ ( ذبح کرنے والا آلہ ) دانت اور ناخن نہ ہونا چاہیئے۔ دانت اس لیے نہیں کہ یہ ہڈی ہے ( اور ہڈی سے ذبح کرنا جائز نہیں ہے ) اور ناخن کا اس لیے نہیں کہ حبشی لوگ ان کو چھری کی جگہ استعمال کرتے ہیں۔' WHERE id = 5287;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حمید بن ہلال نے اور ان سے عبداللہ بن مغفل رضی اللہ نے بیان کیا کہ ہم خیبر کے قلعے کا محاصرہ کئے ہوئے تھے کہ ایک شخص نے ایک تھیلا پھینکا جس میں ( یہودیوں کے ذبیحہ کی ) چربی تھی۔ میں اس پر جھپٹا کہ اٹھا لوں لیکن مڑ کے جو دیکھا تو پیچھے رسول اللہ صلی اللہ علیہ وسلم تشریف فرما تھے۔ میں آپ صلی اللہ علیہ وسلم کو دیکھ کر شرما گیا۔ ابن عباس رضی اللہ عنہما نے کہا کہ ( آیت میں ) «طَعامهم» سے مراد اہل کتاب کا ذبح کردہ جانور ہے۔' WHERE id = 5297;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے ایوب بن ابی تمیمہ نے بیان کیا، ان سے قاسم نے، ان سے زہدم جرمی نے بیان کیا کہ ہم سے ابوموسیٰ اشعری رضی اللہ عنہ کے پاس تھے ہم میں اور اس قبیلہ جرم میں بھائی چارہ تھا پھر کھانا لایا گیا جس میں مرغی کا گوشت بھی تھا، حاضرین میں ایک شخص سرخ رنگ کا بیٹھا ہوا تھا لیکن وہ کھانے میں شریک نہیں ہوا، ابوموسیٰ رضی اللہ عنہ نے اس سے کہا کہ تم بھی شریک ہو جاؤ۔ میں نے رسول اللہ صلی اللہ علیہ وسلم کو اس کا گوشت کھاتے ہوئے دیکھا ہے۔ اس نے کہا کہ میں نے مرغی کو گندگی کھاتے دیکھا تھا اسی وقت سے مجھے اس سے گھن آنے لگی ہے اور میں نے قسم کھا لی ہے کہ اب اس کا گوشت نہیں کھاؤں گا۔ ابوموسیٰ رضی اللہ عنہ نے کہا کہ شریک ہو جاؤ میں تمہیں خبر دیتا ہوں یا انہوں نے کہا کہ میں تم سے بیان کرتا ہوں کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں قبیلہ اشعر کے چند لوگوں کو ساتھ لے کر حاضر ہوا، میں نبی کریم صلی اللہ علیہ وسلم کے سامنے آیا تو آپ خفا تھے آپ صدقہ کے اونٹ تقسیم فرما رہے تھے۔ اسی وقت ہم نے نبی کریم صلی اللہ علیہ وسلم سے سواری کے لیے اونٹ کا سوال کیا نبی کریم صلی اللہ علیہ وسلم نے قسم کھا لی کہ آپ ہمیں سواری کے لیے اونٹ نہیں دیں گے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے پاس تمہارے لیے سواری کا کوئی جانور نہیں ہے۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم کے پاس غنیمت کے اونٹ لائے گئے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اشعری کہاں ہیں، اشعری کہاں ہیں؟ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں پانچ سفید کوہان والے اونٹ دے دیئے۔ تھوڑی دیر تک تو ہم خاموش رہے لیکن پھر میں نے اپنے ساتھیوں سے کہا کہ نبی کریم صلی اللہ علیہ وسلم اپنی قسم بھول گئے ہیں اور اگر ہم نے نبی کریم صلی اللہ علیہ وسلم کو آپ کی قسم کے بارے میں غافل رکھا تو ہم کبھی فلاح نہیں پا سکیں گے۔ چنانچہ ہم آپ کی خدمت میں واپس آئے اور عرض کیا کہ یا رسول اللہ! ہم نے آپ سے سواری کے اونٹ ایک مرتبہ مانگے تھے تو آپ نے ہمیں سواری کے لیے کوئی جانور نہ دینے کی قسم کھا لی تھی ہمارے خیال میں آپ اپنی قسم بھول گئے ہیں نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بلاشبہ اللہ ہی کی وہ ذات ہے جس نے تمہیں سواری کے لیے جانور عطا فرمایا۔ اللہ کی قسم! اگر اللہ نے چاہا تو کبھی ایسا نہیں ہو سکتا کہ میں کوئی قسم کھا لوں اور پھر بعد میں مجھ پر واضح ہو جائے کہ اس کے سوا دوسری چیز اس سے بہتر ہے اور پھر وہی میں نہ کروں جو بہتر ہے، میں قسم توڑ دوں گا اور وہی کروں گا جو بہتر ہو گا اور قسم توڑنے کا کفارہ ادا کر دوں گا۔' WHERE id = 5307;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں ابوادریس خولانی نے اور وہ ابوثعلبہ خشنی رضی اللہ عنہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے ہر پھاڑ کھانے والے درندوں کا گوشت کھانے سے منع کیا تھا۔ اس روایت کی متابعت یونس، معمر، ابن عیینہ اور ماجشون نے زہری کی سند سے کی ہے۔' WHERE id = 5318;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے عبداللہ بن عبداللہ نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے اور ان سے میمونہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے اس چوہے کا حکم پوچھا گیا جو گھی میں گر گیا ہو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ چوہے کو اور اس کے چاروں طرف سے گھی کو پھینک دو پھر باقی گھی کھا لو۔' WHERE id = 5328;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے عبدالوہاب نے بیان کیا، کہا ہم سے ایوب سختیانی نے بیان کیا، ان سے محمد بن سیرین نے، ان سے ابن ابی بکرہ نے اور ان سے ابوبکر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ زمانہ پھر کر اسی حالت پر آ گیا ہے جس حالت پر اس دن تھا جس دن اللہ تعالیٰ نے آسمان و زمین پیدا کئے تھے۔ سال بارہ مہینہ کا ہوتا ہے ان میں چار حرمت کے مہینے ہیں، تین پے در پے ذی قعدہ، ذی الحجہ اور محرم اور ایک مضر کا رجب جو جمادی الاخریٰ اور شعبان کے درمیان میں پڑتا ہے۔ ( پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا ) یہ کون سا مہینہ ہے، ہم نے عرض کیا اللہ اور اس کے رسول زیادہ جانتے ہیں۔ آپ صلی اللہ علیہ وسلم خاموش ہو گئے۔ ہم نے سمجھا کہ شاید نبی کریم صلی اللہ علیہ وسلم اس کا کوئی اور نام رکھیں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کیا یہ ذی الحجہ نہیں ہے؟ ہم نے عرض کیا ذی الحجہ ہی ہے۔ پھر فرمایا یہ کون سا شہر ہے؟ ہم نے کہا کہ اللہ اور اس کے رسول کو اس کا زیادہ علم ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم خاموش ہو گئے اور ہم نے سمجھا کہ شاید آپ اس کا کوئی اور نام رکھیں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کیا یہ بلدہ ( مکہ مکرمہ ) نہیں ہے؟ ہم نے عرض کیا کیوں نہیں۔ پھر آپ صلی اللہ علیہ وسلم نے دریافت فرمایا یہ دن کون سا ہے؟ ہم نے عرض کیا کہ اللہ اور اس کے رسول کو اس کا بہتر علم ہے۔ نبی کریم صلی اللہ علیہ وسلم خاموش ہو گئے اور ہم نے سمجھا کہ آپ اس کا کوئی اور نام تجویز کریں گے لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کیا یہ قربانی کا دن ( یوم النحر ) نہیں ہے؟ ہم نے عرض کیا کیوں نہیں! پھر آپ صلی اللہ علیہ وسلم نے فرمایا پس تمہارا خون، تمہارے اموال۔ محمد بن سیرین نے بیان کیا کہ میرا خیال ہے کہ ( ابن ابی بکرہ نے ) یہ بھی کہا کہ اور تمہاری عزت تم پر ( ایک کی دوسرے پر ) اس طرح باحرمت ہیں جس طرح اس دن کی حرمت تمہارے اس شہر میں اور اس مہینہ میں ہے اور عنقریب اپنے رب سے ملو گے اس وقت وہ تم سے تمہارے اعمال کے بارے میں سوال کرے گا آ گاہ ہو جاؤ میرے بعد گمراہ نہ ہو جانا کہ تم میں سے بعض بعض دوسرے کی گردن مارنے لگے۔ ہاں جو یہاں موجود ہیں وہ ( میرا یہ پیغام ) غیر موجود لوگوں کو پہنچا دیں۔ ممکن ہے کہ بعض وہ جنہیں یہ پیغام پہنچایا جائے بعض ان سے زیادہ اسے محفوظ کرنے والے ہوں جو اسے سن رہے ہیں۔ اس پر محمد بن سیرین کہا کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے سچ فرمایا۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آگاہ ہو جاؤ کیا میں نے ( اس کا پیغام تم کو ) پہنچا دیا ہے۔ آگاہ ہو جاؤ کیا میں نے پہنچا دیا ہے؟' WHERE id = 5338;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے زبید نے خبر دی، کہا کہ میں نے شعبی سے سنا، ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم خطبہ دے رہے تھے۔ خطبہ میں آپ صلی اللہ علیہ وسلم نے فرمایا کہ آج کے دن کی ابتداء ہم نماز ( عید ) سے کریں گے پھر واپس آ کر قربانی کریں گے جو شخص اس طرح کرے گا وہ ہماری سنت کو پا لے گا لیکن جس نے ( عید کی نماز سے پہلے ) جانور ذبح کر لیا تو وہ ایسا گوشت ہے جسے اس نے اپنے گھر والوں کے کھانے کے لیے تیار کیا ہے وہ قربانی کسی درجہ میں بھی نہیں۔ ابوبردہ رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میں نے تو عید کی نماز سے پہلے قربانی کر لی ہے البتہ میرے پاس ابھی ایک سال سے کم عمر کا ایک بکری کا بچہ ہے اور سال بھر کی بکری سے بہتر ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم اسی کی قربانی اس کے بدلہ میں کرو لیکن تمہارے بعد یہ کسی کے لیے جائز نہ ہو گا۔' WHERE id = 5348;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، کہا کہ مجھ سے میرے بھائی نے بیان کیا، ان سے سلیمان نے اور ان سے یحییٰ بن سعید نے، ان سے عمرہ بنت عبدالرحمٰن نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ مدینہ میں ہم قربانی کے گوشت میں نمک لگا کر رکھ دیتے تھے اور پھر اسے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں بھی پیش کرتے تھے پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قربانی کا گوشت تین دن سے زیادہ نہ کھایا کرو۔ یہ حکم ضروری نہیں تھا بلکہ آپ کا منشا یہ تھا کہ ہم قربانی کا گوشت ( ان لوگوں کو بھی جن کے یہاں قربانی نہ ہوئی ہو ) کھلائیں اور اللہ زیادہ جاننے والا ہے۔' WHERE id = 5358;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے ابوشہاب عبدربہ بن نافع نے بیان کیا، انہوں نے کہا کہ ہم سے یونس نے، ان سے ثابت بنانی نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ جب شراب ہم پر حرام کی گئی تو مدینہ منورہ میں انگور کی شراب بہت کم ملتی تھی۔ عام استعمال کی شراب کچی اور پکی کھجور سے تیار کی جاتی تھی۔' WHERE id = 5368;
UPDATE hadiths SET urdu = 'اور ہشام بن عمار نے بیان کیا کہ ان سے صدقہ بن خالد نے بیان کیا، ان سے عبدالرحمٰن بن یزید نے، ان سے عطیہ بن قیس کلابی نے، ان سے عبدالرحمٰن بن غنم اشعری نے بیان کیا کہا کہ مجھ سے ابوعامر رضی اللہ عنہ یا ابو مالک اشعری رضی اللہ عنہ نے بیان کیا: اللہ کی قسم! انہوں نے جھوٹ نہیں بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میری امت میں ایسے برے لوگ پیدا ہو جائیں گے جو زناکاری، ریشم کا پہننا، شراب پینا اور گانے بجانے کو حلال بنا لیں گے اور کچھ متکبر قسم کے لوگ پہاڑ کی چوٹی پر ( اپنے بنگلوں میں رہائش کرنے کے لیے ) چلے جائیں گے۔ چرواہے ان کے مویشی صبح و شام لائیں گے اور لے جائیں گے۔ ان کے پاس ایک فقیر آدمی اپنی ضرورت لے کر جائے گا تو وہ ٹالنے کے لیے اس سے کہیں گے کہ کل آنا لیکن اللہ تعالیٰ رات کو ان کو ( ان کی سرکشی کی وجہ سے ) ہلاک کر دے گا پہاڑ کو ( ان پر ) گرا دے گا اور ان میں سے بہت سوں کو قیامت تک کے لیے بندر اور سور کی صورتوں میں مسخ کر دے گا۔' WHERE id = 5378;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان نے کیا کہ میں نے ابوطلحہ، ابودجانہ اور سہیل بن بیضاء رضی اللہ عنہم کو کچی کھجور کی ملی ہوئی نبیذ پلا رہا تھا کہ شراب حرام کر دی گئی اور میں نے موجودہ شراب پھینک دی۔ میں ہی انہیں پلا رہا تھا میں سب سے کم عمر تھا۔ ہم اس نبیذ کو اس وقت شراب ہی سمجھتے تھے اور عمرو بن حارث راوی نے بیان کیا کہ ہم سے قتادہ نے بیان کیا، انہوں نے انس رضی اللہ عنہ سے سنا۔' WHERE id = 5388;
UPDATE hadiths SET urdu = 'اور ابراہیم بن طہمان نے کہا کہ ان سے شعبہ نے، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا، ان سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب مجھے سدرۃ المنتہیٰ تک لے جایا گیا تو وہاں میں نے چار نہریں دیکھیں۔ دو ظاہری نہریں اور دو باطنی۔ ظاہری نہریں تو نیل اور فرات ہیں اور باطنی نہریں جنت کی دو نہریں ہیں۔ پھر میرے پاس تین پیالے لائے گئے ایک پیالے میں دودھ تھا، دوسرے میں شہد تھا اور تیسرے میں شراب تھی۔ میں نے وہ پیالہ لیا جس میں دودھ تھا اور پیا۔ اس پر مجھ سے کہا گیا کہ تم نے اور تمہاری امت نے اصل فطرت کو پا لیا۔ ہشام، سعید اور ہمام نے قتادہ سے، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے مالک بن صعصعہ رضی اللہ عنہ سے یہ حدیث روایت کی ہے۔ اس میں ندیوں کا ذکر تو ایسا ہی ہے لیکن تین پیالوں کا ذکر نہیں ہے۔' WHERE id = 5398;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوحازم بن دینار نے اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک شربت لایا گیا نبی کریم صلی اللہ علیہ وسلم نے اس میں سے پیا، آپ کے دائیں طرف ایک لڑکا بیٹھا ہوا تھا اور بائیں طرف بوڑھے لوگ ( خالد بن ولید رضی اللہ عنہ جیسے بیٹھے ہوئے ) تھے۔ نبی کریم صلی اللہ علیہ وسلم نے بچے سے کہا کیا تم مجھے اجازت دو گے کہ میں ان ( شیوخ ) کو ( پہلے ) دے دوں۔ لڑکے نے کہا: اللہ کی قسم، یا رسول اللہ! آپ کے جھوٹے میں سے ملنے والے اپنے حصہ کے معاملہ میں، میں کسی پر ایثار نہیں کروں گا۔ راوی نے بیان کیا کہ اس پر نبی کریم صلی اللہ علیہ وسلم نے لڑکے کے ہاتھ میں پیالہ دے دیا۔' WHERE id = 5408;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے عبداللہ بن ابی قتادہ نے، ان سے ان کے والد نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں سے کوئی شخص پانی پئے تو ( پینے کے ) برتن میں ( پانی پیتے ہوئے ) سانس نہ لے اور جب تم میں سے کوئی شخص پیشاب کرے تو داہنے ہاتھ کو ذکر پر نہ پھیرے اور جب استنجاء کرے تو داہنے ہاتھ سے نہ کرے۔' WHERE id = 5418;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہوں نے کہا مجھ کو عروہ بن زبیر نے خبر دی اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو مصیبت بھی کسی مسلمان کو پہنچتی ہے اللہ تعالیٰ اسے اس کے گناہ کا کفارہ کر دیتا ہے ( کسی مسلمان کے ) ایک کانٹا بھی اگر جسم کے کسی حصہ میں چبھ جائے۔' WHERE id = 5428;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے عمران ابوبکر نے بیان کیا، ان سے عطاء بن ابی رباح نے بیان کیا، کہا کہ مجھ سے ابن عباس رضی اللہ عنہما نے کہا، تمہیں میں ایک جنتی عورت کو نہ دکھا دوں؟ میں نے عرض کیا کہ ضرور دکھائیں، کہا کہ ایک سیاہ عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آئی اور کہا کہ مجھے مرگی آتی ہے اور اس کی وجہ سے میرا ستر کھل جاتا ہے۔ میرے لیے اللہ تعالیٰ سے دعا کر دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر تو چاہے تو صبر کر تجھے جنت ملے گی اور اگر چاہے تو میں تیرے لیے اللہ سے اس مرض سے نجات کی دعا کر دوں۔ اس نے عرض کیا کہ میں صبر کروں گی پھر اس نے عرض کیا کہ مرگی کے وقت میرا ستر کھل جاتا ہے۔ آپ اللہ تعالیٰ سے اس کی دعا کر دیں کہ ستر نہ کھلا کرے۔ نبی کریم صلی اللہ علیہ وسلم نے اس کے لیے دعا فرمائی۔' WHERE id = 5439;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین واسطی نے بیان کیا، کہا ہم سے خالد بن عبداللہ نے بیان کیا، ان سے خالد حذاء نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم ایک شخص کی عیادت کے لیے تشریف لے گئے اور ان سے فرمایا «لا بأس طهور إن شاء الله» کہ ”کوئی فکر نہیں اگر اللہ نے چاہا ( یہ مرض ) گناہوں سے پاک کرنے والا ہو گا“ لیکن اس نے یہ جواب دیا کہ ہرگز نہیں یہ تو ایسا بخار ہے جو ایک بوڑھے پر غالب آ چکا ہے اور اسے قبر تک پہنچا کر ہی رہے گا، اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ایسا ہی ہو گا۔' WHERE id = 5449;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، ان سے اسماعیل بن ابی خالد نے اور ان سے قیس بن ابی حازم نے بیان کیا کہ ہم خباب بن ارت رضی اللہ عنہ کے یہاں ان کی عیادت کو گئے انہوں نے اپنے پیٹ میں سات داغ لگوائے تھے پھر انہوں نے کہا کہ ہمارے ساتھی جو رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں وفات پا چکے وہ یہاں سے اس حال میں رخصت ہوئے کہ دنیا ان کا اجر و ثواب کچھ نہ گھٹا سکی اور ان کے عمل میں کوئی کمی نہیں ہوئی اور ہم نے ( مال و دولت ) اتنی پائی کہ جس کے خرچ کرنے کے لیے ہم نے مٹی کے سوا اور کوئی محل نہیں پایا ( لگے عمارتیں بنوانے ) اور اگر نبی کریم صلی اللہ علیہ وسلم نے ہمیں موت کی دعا کرنے سے منع نہ کیا ہوتا تو میں اس کی دعا کرتا پھر ہم ان کی خدمت میں دوبارہ حاضر ہوئے تو وہ اپنی دیوار بنا رہے تھے انہوں نے کہا مسلمان کو ہر اس چیز پر ثواب ملتا ہے جسے وہ خرچ کرتا ہے مگر اس ( کم بخت ) عمارت میں خرچ کرنے کا ثواب نہیں ملتا۔' WHERE id = 5459;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا کہ مجھے ہشام نے خبر دی، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو شیرینی اور شہد پسند تھا۔' WHERE id = 5469;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ( ایک مرتبہ ) روزہ کی حالت میں پچھنا لگوایا۔' WHERE id = 5480;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے غندر نے بیان کیا کہا ہم سے شعبہ نے بیان کیا، ان سے عبدالملک بن عمیر نے کہا کہ میں نے عمرو بن حریث سے سنا، کہا کہ میں نے سعید بن زید رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کھنبی «من» میں سے ہے اور اس کا پانی آنکھ کے لیے شفاء ہے۔ اسی سند سے شعبہ نے بیان کیا کہ مجھے حکم بن عتیبہ نے خبر دی، انہیں حسن بن عبداللہ عرنی نے، انہیں عمرو بن حریث نے اور انہیں سعید بن زید رضی اللہ عنہ نے اور انہیں نبی کریم صلی اللہ علیہ وسلم نے یہی حدیث بیان کی، شعبہ نے کہا کہ جب حکم نے بھی مجھ سے یہ حدیث بیان کر دی تو پھر عبدالملک بن عمیر کی روایت پر مجھ کو اعتماد ہو گیا کیونکہ عبدالملک کا حافظہ آخر میں بگڑ گیا تھا شعبہ کو صرف اس کی روایت پر بھروسہ نہ رہا۔' WHERE id = 5492;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا کہ میرے والد نے مجھ کو خبر دی اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بخار جہنم کی بھاپ میں سے ہے اس لیے اسے پانی سے ٹھنڈا کرو۔“' WHERE id = 5504;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں معمر نے، انہیں زہری نے، انہیں عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم اپنے مرض الوفات میں اپنے اوپر معوذات ( سورۃ الاخلاص، سورۃ الفلق اور سورۃ الناس ) کا دم کیا کرتے تھے۔ پھر جب آپ کے لیے دشوار ہو گیا تو میں ان کا دم آپ پر کیا کرتی تھی اور برکت کے لیے نبی کریم صلی اللہ علیہ وسلم کا ہاتھ آپ کے جسم مبارک پر بھی پھیر لیتی تھی۔ پھر میں نے اس کے متعلق پوچھا کہ نبی کریم صلی اللہ علیہ وسلم کس طرح دم کرتے تھے، انہوں نے بتایا کہ اپنے ہاتھ پر دم کر کے ہاتھ کو چہرے پر پھیرا کرتے تھے۔' WHERE id = 5514;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، کہا کہ مجھ سے عبدربہ بن سعید نے بیان کیا، ان سے عمرہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم مریض کے لیے ( کلمے کی انگلی زمین پر لگا کر ) یہ دعا پڑھتے تھے «بسم الله،‏‏‏‏ تربة أرضنا‏.‏ بريقة بعضنا،‏‏‏‏ ‏‏‏‏يشفى سقيمنا بإذن ربنا‏ ‏‏.» ”اللہ کے نام کی مدد سے ہماری زمین کی مٹی ہم میں سے کسی کے تھوک کے ساتھ تاکہ ہمارا مریض شفاء پائے ہمارے رب کے حکم سے۔“' WHERE id = 5524;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم کو ہشام بن یوسف نے خبر دی، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں عبیداللہ بن عبداللہ بن عتبہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بدشگونی کی کوئی اصل نہیں اور اس میں بہتر فال نیک ہے۔“ لوگوں نے پوچھا کہ نیک فال کیا ہے یا رسول اللہ؟ فرمایا ”کلمہ صالحہ ( نیک بات ) جو تم میں سے کوئی سنے۔“' WHERE id = 5534;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں زید بن اسلم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ دو آدمی پورب کی طرف ( ملک عراق ) سے ( سنہ 9 ھ میں ) مدینہ آئے اور لوگوں کو خطاب کیا لوگ ان کی تقریر سے بہت متاثر ہوئے تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بعض تقریریں بھی جادو بھری ہوتی ہیں یا یہ فرمایا کہ بعض تقریر جادو ہوتی ہیں۔' WHERE id = 5545;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے اسماعیل بن جعفر نے بیان کیا، انہوں نے کہا ہم سے بنی تمیم کے مولیٰ عتبہ بن مسلم نے بیان کیا، ان سے بنی زریق کے مولیٰ عبید بن حنین نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب مکھی تم میں سے کسی کے برتن میں پڑ جائے تو پوری مکھی کو برتن میں ڈبو دے اور پھر اسے نکال کر پھینک دے کیونکہ اس کے ایک پر میں شفاء اور دوسرے میں بیماری ہے۔“' WHERE id = 5557;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے کہا کہ مجھ کو عروہ بن زبیر اور انہیں نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ رفاعہ قرظی رضی اللہ عنہ کی بیوی رسول اللہ صلی اللہ علیہ وسلم کے پاس آئیں۔ میں بھی بیٹھی ہوئی تھی اور نبی کریم صلی اللہ علیہ وسلم کے پاس ابوبکر رضی اللہ عنہ موجود تھے۔ انہوں نے کہا: یا رسول اللہ! میں رفاعہ کے نکاح میں تھی لیکن انہوں نے مجھے تین طلاق دے دی ہیں۔ ( مغلظہ ) ۔ اس کے بعد میں نے عبدالرحمٰن بن زبیر رضی اللہ عنہ سے نکاح کر لیا اور اللہ کی قسم کہ ان کے ساتھ یا رسول اللہ! صرف اس جھالر جیسا ہے۔ انہوں نے اپنی چادر کے جھالر کو اپنے ہاتھ میں لے کر اشارہ کیا۔ خالد بن سعید رضی اللہ عنہ جو دروازے پر کھڑے تھے اور انہیں ابھی اندر آنے کی اجازت نہیں ہوئی تھی، اس نے بھی ان کی بات سنی۔ بیان کیا کہ خالد رضی اللہ عنہ ( وہیں سے ) بولے۔ ابوبکر! آپ اس عورت کو روکتے نہیں کہ کس طرح کی بات رسول اللہ صلی اللہ علیہ وسلم کے سامنے کھول کر بیان کرتی ہے لیکن اللہ کی قسم اس بات پر نبی کریم صلی اللہ علیہ وسلم کا تبسم اور بڑھ گیا۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ غالباً تم دوبارہ رفاعہ کے پاس جانا چاہتی ہو؟ لیکن ایسا اس وقت تک ممکن نہیں جب تک وہ ( تمہارے دوسرے شوہر عبدالرحمٰن بن زبیر ) تمہارا مزا نہ چکھ لیں اور تم ان کا مزا نہ چکھ لو پھر بعد میں یہی قانون بن گیا۔' WHERE id = 5567;
UPDATE hadiths SET urdu = 'اور کہا مجھ سے مسدد نے اور کہا ہم سے معتمر نے کہ میں نے اپنے باپ سے سنا، کہا انہوں نے کہ میں نے انس رضی اللہ عنہ پر ریشمی زرد ٹوپی کو دیکھا۔' WHERE id = 5577;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عاصم نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا، قتادہ نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے پوچھا کہ رسول اللہ صلی اللہ علیہ وسلم کو کس طرح کا کپڑا زیادہ پسند تھا بیان کیا کہ حبرۃ کی سبز یمنی چادر۔' WHERE id = 5587;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، کہا کہ مجھ سے ابن ابی عدی نے بیان کیا، ان سے ابن عون نے، ان سے محمد نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ جب ام سلیم رضی اللہ عنہا کے یہاں بچہ پیدا ہوا تو انہوں نے مجھ سے کہا کہ انس اس بچہ کو دیکھتے رہو کوئی چیز اس کے پیٹ میں نہ جائے اور جا کر نبی کریم صلی اللہ علیہ وسلم کو اپنے ساتھ لاؤ تاکہ نبی کریم صلی اللہ علیہ وسلم اپنا جوٹھا اس کے منہ میں ڈالیں۔ چنانچہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا نبی کریم صلی اللہ علیہ وسلم اس وقت ایک باغ میں تھے اور آپ کے جسم پر قبیلہ بنی حریث کی بنی ہوئی چادر ( «خميصة حريثية» ) تھی اور آپ اس سواری پر نشان لگا رہے تھے جس پر آپ فتح مکہ کے موقع پر سوار تھے۔' WHERE id = 5598;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں ابوذہبان خلیفہ بن کعب نے، کہا کہ میں نے عبداللہ بن زبیر رضی اللہ عنہما سے سنا، کہا کہ میں نے عمر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس مرد نے دنیا میں ریشم پہنا وہ اسے آخرت میں نہیں پہن سکے گا۔ اور ہم سے ابومعمر نے بیان کیا، ان سے عبدالوارث نے بیان کیا، ان سے یزید نے کہ معاذ نے بیان کیا کہ مجھے ام عمرو بنت عبداللہ نے خبر دی، انہوں نے عبداللہ بن زبیر رضی اللہ عنہما سے سنا، انہوں نے عمر رضی اللہ عنہ سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا۔' WHERE id = 5608;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف صنعانی نے بیان کیا، انہوں نے کہا ہم کو معمر بن راشد نے خبر دی، انہیں زہری نے خبر دی، انہیں ہندہ بنت حارث نے خبر دی اور ان سے ام سلمہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم رات کے وقت بیدار ہوئے اور کہا اللہ کے سوا کوئی معبود نہیں، کیسی کیسی بلائیں اس رات میں نازل ہو رہی ہیں اور کیا کیا رحمتیں اس کے خزانوں سے اتر رہی ہیں۔ کوئی ہے جو ان حجرہ والیوں کو بیدار کر دے۔ دیکھو بہت سی دنیا میں پہننے اوڑھنے والیاں آخرت میں ننگی ہوں گی۔ زہری نے بیان کیا کہ ہندہ اپنی آستینوں میں انگلیوں کے درمیان گھنڈیاں لگاتی تھیں، تاکہ صرف انگلیاں کھلیں اس سے آگے نہ کھلے۔' WHERE id = 5618;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، انہوں نے کہا کہ مجھے اشعث بن سلیم نے خبر دی کہ میں نے اپنے والد سے سنا، وہ مسروق سے بیان کرتے تھے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم طہارت میں کنگھا کرنے میں اور جوتا پہننے میں داہنی طرف سے شروع کرنے کو پسند فرماتے تھے۔' WHERE id = 5628;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے نضر بن انس نے، ان سے بشیر بن نہیک نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے سونے کی انگوٹھی کے پہننے سے مردوں کو منع فرمایا تھا۔ اور عمرو نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں قتادہ نے، انہوں نے نضر سے سنا اور انہوں نے بشیر سے سنا، آگے اسی طرح روایت بیان کی۔' WHERE id = 5638;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، کہا ہم سے عبدالعزیز بن صہیب نے بیان کیا، ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک انگوٹھی بنوائی اور فرمایا کہ ہم نے ایک انگوٹھی بنوائی ہے اس پر لفظ ( «محمد رسول الله» ) کندہ کرایا ہے اس لیے انگوٹھی پر کوئی شخص یہ نقش نہ کندہ کرائے۔ انس نے بیان کیا کہ جیسے اس انگوٹھی کی چمک نبی کریم صلی اللہ علیہ وسلم کی چھنگلیاں میں اب بھی میں دیکھ رہا ہوں۔' WHERE id = 5648;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم حنظلی نے بیان کیا، کہا ہم کو یحییٰ بن آدم نے خبر دی، کہا ہم سے ورقاء بن عمر نے بیان کیا، ان سے عبیداللہ بن ابی یزید نے، ان سے نافع بن جبیر نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں مدینہ کے بازاروں میں سے ایک بازار میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھا۔ نبی کریم صلی اللہ علیہ وسلم واپس ہوئے تو میں پھر آپ کے ساتھ واپس ہوا، پھر آپ صلی اللہ علیہ وسلم نے فرمایا بچہ کہاں ہے۔ یہ آپ نے تین مرتبہ فرمایا۔ حسن بن علی کو بلاؤ۔ حسن بن علی رضی اللہ عنہما آ رہے تھے اور ان کی گردن میں ( خوشبودار لونگ وغیرہ کا ) ہار پڑا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اپنا ہاتھ اس طرح پھیلایا کہ ( آپ حسن رضی اللہ عنہ کو گلے سے لگانے کے لیے ) اور حسن رضی اللہ عنہ نے بھی اپنا ہاتھ پھیلایا اور وہ نبی کریم صلی اللہ علیہ وسلم سے لپٹ گئے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا، اے اللہ! میں اس سے محبت کرتا ہوں تو بھی اس سے محبت کر اور ان سے بھی محبت کر جو اس سے محبت رکھیں۔ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے اس ارشاد کے بعد کوئی شخص بھی حسن بن علی رضی اللہ عنہما سے زیادہ مجھے پیارا نہیں تھا۔' WHERE id = 5658;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، ان سے ایوب سختیانی نے، ان سے محمد بن سیرین نے بیان کیا کہ میں نے انس رضی اللہ عنہ سے پوچھا کیا نبی کریم صلی اللہ علیہ وسلم نے خضاب استعمال کیا تھا؟ بولے کہ نبی کریم صلی اللہ علیہ وسلم کے بال ہی بہت کم سفید ہوئے تھے۔' WHERE id = 5668;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے ( سر کے ) بال مونڈھوں تک پہنچتے تھے۔' WHERE id = 5678;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید اور عبداللہ بن رجاء نے بیان کیا، ان دونوں نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے حکم بن عتیبہ نے، ان سے ابراہیم نخعی نے، ان سے اسود نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا جیسے میں اب بھی نبی کریم صلی اللہ علیہ وسلم کی مانگ میں احرام کی حالت میں خوشبو کی چمک دیکھ رہی ہوں۔ عبداللہ بن رجاء نے ( اپنی روایت میں ) «مفرق النبي صلى الله عليه وسلم‏.‏» ( واحد کے صیغہ کے ساتھ ) بیان کیا یعنی مانگوں کی جگہ صرف لفظ مانگ استعمال کیا۔' WHERE id = 5690;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، ان سے عثمان بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو آپ کے احرام کے وقت عمدہ سے عمدہ خوشبو جو مل سکتی تھی، وہ لگاتی۔' WHERE id = 5700;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے عمرو بن مرہ نے بیان کیا کہ میں نے سعید بن مسیب سے سنا، انہوں نے بیان کیا کہ معاویہ رضی اللہ عنہ آخری مرتبہ مدینہ منورہ تشریف لائے اور ہمیں خطبہ دیا۔ آپ نے بالوں کا ایک گچھا نکال کے کہا کہ یہ یہودیوں کے سوا اور کوئی نہیں کرتا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اسے «زور‏.‏» یعنی فریبی فرمایا یعنی جو بالوں میں جوڑ لگائے تو ایسا آدمی مرد ہو یا عورت وہ مکار ہے جو اپنے مکر و فریب پر اس طور پر پردہ ڈالتا ہے۔' WHERE id = 5710;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے عبدالرحمٰن نے بیان کیا، ان سے سفیان بن عیینہ نے، ان سے منصور نے، ان سے ابراہیم نے، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ گودنے والیوں پر اور گدوانے والیوں پر، بال اکھاڑنے والیوں پر اور خوبصورتی کے لیے دانتوں کے درمیان کشادگی کرنے والیوں پر جو اللہ کی پیدائش میں تبدیلی کرتی ہیں، اللہ تعالیٰ نے لعنت بھیجی ہے پھر میں بھی کیوں نہ ان پر لعنت بھیجوں جن پر رسول اللہ صلی اللہ علیہ وسلم نے لعنت بھیجی ہے اور وہ کتاب اللہ میں بھی موجود ہے۔' WHERE id = 5721;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے بکیر بن عبداللہ نے، ان سے بسر بن سعید نے اور ان سے زید بن خالد رضی اللہ عنہ نے اور ان سے رسول اللہ صلی اللہ علیہ وسلم کے صحابی ابوطلحہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”فرشتے اس گھر میں نہیں داخل ہوتے جس میں تصویریں ہوں۔“ بسر نے بیان کیا کہ ( اس حدیث کو روایت کرنے کے بعد ) پھر زید رضی اللہ عنہ بیمار پڑے تو ہم ان کی مزاج پرسی کے لیے گئے۔ ہم نے دیکھا کہ ان کے دروازہ پر ایک پردہ پڑا ہوا ہے جس پر تصویر ہے۔ میں نے ام المؤمنین میمونہ رضی اللہ عنہا کے ربیب عبیداللہ بن اسود سے کہا کہ زید بن خالد رضی اللہ عنہ نے ہمیں اس سے پہلے ایک مرتبہ تصویروں کے متعلق حدیث سنائی تھی۔ عبیداللہ نے کہا کہ کیا تم نے سنا نہیں تھا، حدیث بیان کرتے ہوئے انہوں نے یہ بھی کہا تھا کہ جو مورت کپڑے میں ہو وہ جائز ہے ( بشرطیکہ غیر ذی روح کی ہو ) ۔ اور عبداللہ بن وہب نے کہا، انہیں عمرو نے خبر دی وہ ابن حارث ہیں، ان سے بکیر نے بیان کیا، ان سے بسر نے بیان کیا، ان سے زید نے بیان کیا، ان سے ابوطلحہ رضی اللہ عنہ نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم نے بیان فرمایا جیسا کہ اوپر مذکور ہوا۔' WHERE id = 5731;
UPDATE hadiths SET urdu = 'ہم سے حسن بن محمد بن صباح نے بیان کیا، کہا ہم سے یحییٰ بن عباد نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، انہیں یحییٰ بن ابی اسحاق نے خبر دی، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ خیبر سے واپس آ رہے تھے اور میں ابوطلحہ رضی اللہ عنہ کی سواری پر آپ کے پیچھے بیٹھا ہوا تھا اور چل رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم کی بعض بیوی صفیہ رضی اللہ عنہا نبی کریم صلی اللہ علیہ وسلم کی سواری پر آپ کے پیچھے تھیں کہ اچانک اونٹنی نے ٹھوکر کھائی، میں نے کہا عورت کی خبرگیری کرو پھر میں اتر پڑا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ تمہاری ماں ہیں پھر میں نے کجاوہ مضبوط باندھا اور نبی کریم صلی اللہ علیہ وسلم سوار ہو گئے پھر جب مدینہ منورہ کے قریب ہوئے یا ( راوی نے بیان کیا کہ ) مدینہ منورہ دیکھا تو فرمایا ”ہم واپس ہونے والے ہیں اللہ تعالیٰ کی طرف رجوع ہونے والے ہیں، اسی کو پوجنے والے ہیں، اپنے مالک کی تعریف کرنے والے ہیں۔“' WHERE id = 5741;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، کہا مجھ کو میرے والد نے خبر دی، انہیں اسماء بنت ابی بکر رضی اللہ عنہما نے خبر دی کہ میری والدہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں میرے پاس آئیں، وہ اسلام سے منکر تھیں۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کیا میں اس کے ساتھ صلہ رحمی کر سکتی ہوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں۔ اس کے بعد اللہ تعالیٰ نے یہ آیت نازل کی «لا ينهاكم الله عن الذين لم يقاتلوكم في الدين‏» یعنی ”اللہ پاک تم کو ان لوگوں کے ساتھ نیک سلوک کرنے سے منع نہیں کرتا جو تم سے ہمارے دین کے متعلق کوئی لڑائی جھگڑا نہیں کرتے۔“' WHERE id = 5751;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، کہا ہم سے سلیمان بن بلال نے بیان کیا، کہا ہم سے عبداللہ بن دینار نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ رحم کا تعلق رحمن سے جڑا ہوا ہے پس جو کوئی اس سے اپنے آپ کو جوڑتا ہے اللہ پاک نے فرمایا کہ میں بھی اس کو اپنے سے جوڑ لیتا ہوں اور جو کوئی اسے توڑتا ہے میں بھی اپنے آپ کو اس سے توڑ لیتا ہوں۔' WHERE id = 5761;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ہشام نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک دیہاتی نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور کہا آپ لوگ بچوں کو بوسہ دیتے ہیں، ہم تو انہیں بوسہ نہیں دیتے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر اللہ نے تمہارے دل سے رحم نکال دیا ہے تو میں کیا کر سکتا ہوں۔' WHERE id = 5771;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے اسماعیل بن علیہ نے بیان کیا، کہا ہم سے ایوب سختیانی نے بیان کیا، ان سے ابوقلابہ نے، ان سے ابوسلیمان مالک بن حویرث رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں مدینہ حاضر ہوئے اور ہم سب نوجوان اور ہم عمر تھے۔ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ بیس دنوں تک رہے۔ پھر نبی کریم صلی اللہ علیہ وسلم کو خیال ہوا کہ ہمیں اپنے گھر کے لوگ یاد آ رہے ہوں گے اور نبی کریم صلی اللہ علیہ وسلم نے ہم سے ان کے متعلق پوچھا جنہیں ہم اپنے گھروں پر چھوڑ کر آئے تھے۔ ہم نے نبی کریم صلی اللہ علیہ وسلم کو سارا حال سنا دیا۔ آپ بڑے ہی نرم خو اور بڑے رحم کرنے والے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم اپنے گھروں کو واپس جاؤ اور اپنے ملک والوں کو دین سکھاؤ اور بتاؤ اور تم اس طرح نماز پڑھو جس طرح تم نے مجھے نماز پڑھتے دیکھا ہے اور جب نماز کا وقت آ جائے تو تم میں سے ایک شخص تمہارے لیے اذان دے پھر جو تم میں بڑا ہو وہ امامت کرائے۔' WHERE id = 5781;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے ابوالاحوص نے بیان، ان سے ابوحصین نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ اپنے پڑوسی کو تکلیف نہ پہنچائے اور جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ اپنے مہمان کی عزت کرے اور جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ اچھی بات زبان سے نکالے ورنہ خاموش رہے۔“' WHERE id = 5791;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدالوہاب ثقفی نے خبر دی، انہیں ایوب سختیانی نے، انہیں عبداللہ بن ابی ملیکہ نے اور انہیں عائشہ رضی اللہ عنہا نے کہ کچھ یہودی رسول اللہ صلی اللہ علیہ وسلم کے یہاں آئے اور کہا «السام عليكم‏.‏» ( تم پر موت آئے ) اس پر عائشہ رضی اللہ عنہا نے کہا «عليكم،‏‏‏‏ ولعنكم الله،‏‏‏‏ وغضب الله عليكم‏.‏» کہ تم پر بھی موت آئے اور اللہ کی تم پر لعنت ہو اور اس کا غضب تم پر نازل ہو۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ( ٹھہرو ) عائشہ! تمہیں نرم خوئی اختیار کرنے چاہیے سختی اور بد زبانی سے بچنا چاہیئے۔ عائشہ رضی اللہ عنہا نے عرض کیا: یا رسول اللہ! آپ نے ان کی بات نہیں سنی، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم نے انہیں میرا جواب نہیں سنا، میں نے ان کی بات انہیں پر لوٹا دی اور ان کے حق میں میری بددعا قبول ہو جائے گی۔ لیکن میرے حق میں ان کی بددعا قبول ہی نہ ہو گی۔' WHERE id = 5802;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے ابوعاصم نے، ان سے ابن جریج نے، کہا مجھ کو موسیٰ بن عقبہ نے خبر دی، انہیں نافع نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب اللہ کسی بندہ سے محبت کرتا ہے تو جبرائیل علیہ السلام کو آواز دیتا ہے کہ اللہ فلاں بندے سے محبت کرتا ہے تم بھی اس سے محبت کرو۔ جبرائیل علیہ السلام بھی اس سے محبت کرنے لگتے ہیں، پھر وہ تمام آسمان والوں میں آواز دیتے ہیں کہ اللہ فلاں بندے سے محبت کرتا ہے۔ تم بھی اس سے محبت کرو۔ پھر تمام آسمان والے اس سے محبت کرنے لگتے ہیں۔ اس کے بعد وہ زمین میں بھی ( اللہ کے بندوں کا ) مقبول اور محبوب بن جاتا ہے۔' WHERE id = 5812;
UPDATE hadiths SET urdu = 'مجھ سے عمر بن حفص بن غیاث نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے معرور نے اور ان سے ابوذر رضی اللہ عنہ نے، معرور نے بیان کیا کہ میں نے ابوذر رضی اللہ عنہ کے جسم پر ایک چادر دیکھی اور ان کے غلام کے جسم پر بھی ایک ویسی ہی چادر تھی، میں نے عرض کیا: اگر اپنے غلام کی چادر لے لیں اور اسے بھی پہن لیں تو ایک رنگ کا جوڑا ہو جائے غلام کو دوسرا کپڑا دے دیں۔ ابوذر رضی اللہ عنہ نے اس پر کہا کہ مجھ میں اور ایک صاحب ( بلال رضی اللہ عنہ ) میں تکرار ہو گئی تھی تو ان کی ماں عجمی تھیں، میں نے اس بارے میں ان کو طعنہ دے دیا انہوں نے جا کر یہ بات نبی کریم صلی اللہ علیہ وسلم سے کہہ دی۔ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے دریافت فرمایا کیا تم نے اس سے جھگڑا کیا ہے؟ میں نے عرض کیا جی ہاں۔ دریافت کیا تم نے اسے اس کی ماں کی وجہ سے طعنہ دیا ہے؟ میں نے عرض کیا جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے اندر ابھی جاہلیت کی بو باقی ہے۔ میں نے عرض کیا: یا رسول اللہ! اس بڑھاپے میں بھی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں یاد رکھو یہ ( غلام بھی ) تمہارے بھائی ہیں، اللہ تعالیٰ نے انہیں تمہاری ماتحتی میں دیا ہے، پس اللہ تعالیٰ جس کی ماتحتی میں بھی اس کے بھائی کو رکھے اسے چاہئے کہ جو وہ کھائے اسے بھی کھلائے اور جو وہ پہنے اسے بھی پہنائے اور اسے ایسا کام کرنے کے لیے نہ کہے، جو اس کے بس میں نہ ہو اگر اسے کوئی ایسا کام کرنے کے لیے کہنا ہی پڑے تو اس کام میں اس کی مدد کرے۔' WHERE id = 5822;
UPDATE hadiths SET urdu = 'ہم سے محمد بن صباح نے بیان کیا، کہا ہم سے اسماعیل بن زکریا نے بیان کیا، انہوں نے کہا کہ ہم سے برید بن عبداللہ بن ابی بردہ نے بیان کیا، ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے سنا کہ ایک شخص دوسرے شخص کی تعریف کر رہا ہے اور تعریف میں بہت مبالغہ سے کام لے رہا تھا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم نے اسے ہلاک کر دیا یا ( یہ فرمایا کہ ) تم نے اس شخص کی کمر کو توڑ دیا۔' WHERE id = 5832;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے ابوعوانہ نے، انہوں نے قتادہ سے، انہوں نے صفوان بن محرز سے کہ ایک شخص نے ابن عمر رضی اللہ عنہما سے پوچھا تم نے نبی کریم صلی اللہ علیہ وسلم سے کانا پھوسی کے بارے میں کیا سنا ہے؟ ( یعنی سرگوشی کے بارے میں ) انہوں نے کہا نبی کریم صلی اللہ علیہ وسلم فرماتے تھے ( قیامت کے دن تم مسلمانوں ) میں سے ایک شخص ( جو گنہگار ہو گا ) اپنے پروردگار سے نزدیک ہو جائے گا۔ پروردگار اپنا بازو اس پر رکھ دے گا اور فرمائے گا تو نے ( فلاں دن دنیا میں ) یہ یہ برے کام کئے تھے، وہ عرض کرے گا۔ بیشک ( پروردگار مجھ سے خطائیں ہوئی ہیں پر تو غفور رحیم ہے ) غرض ( سارے گناہوں کا ) اس سے ( پہلے ) اقرار کرا لے گا پھر فرمائے گا دیکھ میں نے دنیا میں تیرے گناہ چھپائے رکھے تو آج میں ان گناہوں کو بخش دیتا ہوں۔' WHERE id = 5842;
UPDATE hadiths SET urdu = 'ہم سے محمد بن صباح نے بیان کیا، کہا ہم سے اسماعیل بن زکریا نے بیان کیا، کہا ہم سے عاصم بن سلیمان احول نے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے پوچھا، کیا تم کو یہ بات معلوم ہے کہ ہم سے محمد بن صباح نے بیان کیا، کہا ہم سے اسماعیل بن زکریا نے بیان کیا، کہا ہم سے عاصم بن سلیمان احول نے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے پوچھا، کیا تم کو یہ بات معلوم ہے کہ' WHERE id = 5853;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا ہم سے جریر نے بیان کیا، ان سے منصور نے بیان کیا، ان سے ابووائل نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بلاشبہ سچ آدمی کو نیکی کی طرف بلاتا ہے اور نیکی جنت کی طرف لے جاتی ہے اور ایک شخص سچ بولتا رہتا ہے یہاں تک کہ وہ صدیق کا لقب اور مرتبہ حاصل کر لیتا ہے اور بلاشبہ جھوٹ برائی کی طرف لے جاتا ہے اور برائی جہنم کی طرف اور ایک شخص جھوٹ بولتا رہتا ہے، یہاں تک کہ وہ اللہ کے یہاں بہت جھوٹا لکھ دیا جاتا ہے۔“' WHERE id = 5863;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے عبداللہ بن دینار نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس شخص نے بھی اپنے کسی بھائی کو کہا کہ اے کافر! تو ان دونوں میں سے ایک کافر ہو گیا۔“' WHERE id = 5873;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں سعید بن مسیب نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”پہلوان وہ نہیں ہے جو کشتی لڑنے میں غالب ہو جائے بلکہ اصلی پہلوان تو وہ ہے جو غصہ کی حالت میں اپنے آپ پر قابو پائے بے قابو نہ ہو جائے۔“' WHERE id = 5883;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم سے نضر نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں سعید بن ابی بردہ نے، انہیں ان کے والد نے اور ان سے ان کے دادا نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم نے انہیں ( ابوموسیٰ اشعری رضی اللہ عنہ ) اور معاذ بن جبل کو ( یمن ) بھیجا تو ان سے فرمایا کہ ( لوگوں کے لیے ) آسانیاں پیدا کرنا، تنگی میں نہ ڈالنا، انہیں خوشخبری سنانا، دین سے نفرت نہ دلانا اور تم دونوں آپس میں اتفاق سے کام کرنا، ابوموسیٰ رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! ہم ایسی سر زمین میں جا رہے ہیں جہاں شہد سے شراب بنائی جاتی ہے اور اسے «بتع» کہا جاتا ہے اور جَو سے شراب بنائی جاتی ہے اور اسے «مزر‏.‏» کہا جاتا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر نشہ لانے والی چیز حرام ہے۔' WHERE id = 5893;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے روح بن عبادہ نے، کہا ہم سے حسین نے، ان سے یحییٰ بن ابی بکر نے، ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے عبداللہ بن عمرو رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میرے پاس تشریف لائے اور فرمایا، کیا یہ میری خبر صحیح ہے کہ تم رات بھر عبادت کرتے رہتے ہو اور دن میں روزے رکھتے ہو؟ میں نے کہا کہ جی ہاں یہ صحیح ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ایسا نہ کرو، عبادت بھی کرو اور سو بھی، روزے بھی رکھو اور بلا روزے بھی رہو، کیونکہ تمہارے جسم کا بھی تم پر حق ہے، تمہاری آنکھوں کا بھی تم پر حق ہے، تم سے ملاقات کے لیے آنے والوں کا بھی تم پر حق ہے، تمہاری بیوی کا بھی تم پر حق ہے، امید ہے کہ تمہاری عمر لمبی ہو گی، تمہارے لیے یہی کافی ہے کہ ہر مہینہ میں تین روزے رکھو، کیونکہ ہر نیکی کا بدلہ دس گناہ ملتا ہے، اس طرح زندگی بھر کا روزہ ہو گا۔ انہوں نے بیان کیا کہ میں نے سختی چاہی تو آپ نے میرے اوپر سختی کر دی۔ میں نے عرض کیا کہ میں اس سے زیادہ کی طاقت رکھتا ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ہر ہفتے تین روزہ رکھا کر، بیان کیا کہ میں نے اور سختی چاہی اور آپ نے میرے اوپر سختی کر دی۔ میں نے عرض کیا کہ میں اس سے بھی زیادہ کی طاقت رکھتا ہوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر اللہ کے نبی داؤد علیہ السلام جیسا روزہ رکھ۔ میں نے پوچھا، اللہ کے نبی داؤد علیہ السلام کا روزہ کیسا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ایک دن روزہ ایک دن افطار گویا آدھی عمر کے روزے۔' WHERE id = 5903;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اسود بن قیس نے، انہوں نے کہا کہ میں نے جندب بن عبداللہ بجلی سے سنا، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم چل رہے تھے کہ آپ کو پتھر سے ٹھوکر لگی اور آپ گر پڑے، اس سے آپ کی انگلی سے خون بہنے لگا، آپ صلی اللہ علیہ وسلم نے یہ شعر پڑھا ”تو تو اک انگلی ہے اور کیا ہے جو زخمی ہو گئی… کیا ہوا اگر راہ مولیٰ میں تو زخمی ہو گئی۔“' WHERE id = 5914;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا کہا ہم سے لیث بن سعد نے بیان، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ابوقعیس کے بھائی افلح ( میرے رضاعی چچا نے ) مجھ سے پردہ کا حکم نازل ہونے کے بعد اندر آنے کی اجازت چاہی، میں نے کہا کہ اللہ کی قسم جب تک نبی کریم صلی اللہ علیہ وسلم اجازت نہ دیں گے میں اندر آنے کی اجازت نہیں دوں گی۔ کیونکہ ابوقعیس کے بھائی نے مجھے دودھ نہیں پلایا بلکہ ابوقعیس کی بیوی نے دودھ پلایا ہے۔ پھر جب رسول اللہ صلی اللہ علیہ وسلم تشریف لائے تو میں نے عرض کیا: یا رسول اللہ! مرد نے تو مجھے دودھ نہیں پلایا تھا، دودھ تو ان کی بیوی نے پلایا تھا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں اندر آنے کی اجازت دے دو، کیونکہ وہ تمہارے چچا ہیں، تمہارے ہاتھ میں مٹی لگے۔ عروہ نے کہا کہ اسی وجہ سے عائشہ رضی اللہ عنہا کہتی تھیں کہ جتنے رشتے خون کی وجہ سے حرام ہوتے ہیں وہ رضاعت سے بھی حرام ہی سمجھو۔' WHERE id = 5924;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا ہم سے خالد بن حارث نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے واقد بن محمد بن زید نے بیان کیا، انہوں نے ان کے والد سے سنا اور انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، افسوس ( «ويلكم» یا «ويحكم» ) شعبہ نے بیان کیا کہ شک ان کے شیخ ( واقد بن محمد کو ) تھا۔ میرے بعد تم کافر نہ ہو جانا کہ ایک دوسرے کی گردن مارنے لگو۔ اور نضر نے شعبہ سے بیان کیا «ويحكم» اور عمر بن محمد نے اپنے والد سے «ويلكم» یا «ويحكم» کے لفظ نقل کئے ہیں۔' WHERE id = 5934;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”عہد توڑنے والے کے لیے قیامت میں ایک جھنڈا اٹھایا جائے گا اور پکارا جائے گا کہ یہ فلاں بن فلاں کی دغا بازی کا نشان ہے۔“' WHERE id = 5944;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ایوب سختیانی نے، ان سے محمد بن سیرین نے اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا ”میرے نام پر نام رکھو لیکن میری کنیت نہ رکھو۔“' WHERE id = 5954;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید بن عبداللہ بن ابی بردہ نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ میرے یہاں ایک بچہ پیدا ہوا تو میں اسے لے کر نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ نبی کریم صلی اللہ علیہ وسلم نے اس کا نام ابراہیم رکھا اور ایک کھجور اپنے دہان مبارک میں نرم کر کے اس کے منہ میں ڈالی اور اس کے لیے برکت کی دعا کی پھر اسے مجھے دے دیا۔ یہ ابوموسیٰ کی بڑی اولاد تھی۔' WHERE id = 5964;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، کہا ہم سے عبدالملک نے بیان کیا، ان سے عبداللہ بن حارث بن نوفل نے اور ان سے عباس بن عبدالمطلب رضی اللہ عنہ نے کہ انہوں نے عرض کیا کہ یا رسول اللہ! آپ نے جناب ابوطالب کو ان کی وفات کے بعد کوئی فائدہ پہنچایا، وہ آپ کی حفاظت کیا کرتے تھے اور آپ کے لیے لوگوں پر غصہ ہوا کرتے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں وہ دوزخ میں اس جگہ پر ہیں جہاں ٹخنوں تک آگ ہے اگر میں نہ ہوتا تو وہ دوزخ کے نیچے کے طبقے میں رہتے۔' WHERE id = 5974;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، ان سے ہند بن حارث نے بیان کیا کہ ام سلمہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ( رات میں ) بیدار ہوئے اور فرمایا ”سبحان اللہ! اللہ کی رحمت کے کتنے خزانے آج نازل کئے گئے ہیں اور کس طرح کے فتنے بھی اتارے گئے ہیں۔ کون ہے! جو ان حجرہ والیوں کو جگائے۔“ نبی کریم صلی اللہ علیہ وسلم کی مراد ازواج مطہرات سے تھی تاکہ وہ نماز پڑھ لیں کیونکہ بہت سی دنیا میں کپڑے پہننے والیاں آخرت میں ننگی ہوں گی۔ اور ابن ابی ثور نے بیان کیا، ان سے ابن عباس رضی اللہ عنہما نے اور ان سے عمر رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا، کیا آپ نے ازواج مطہرات کو طلاق دے دی ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے کہا اللہ اکبر!۔' WHERE id = 5984;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں سلیمان بن یسار نے خبر دی اور انہیں عبداللہ بن عباس رضی اللہ عنہما نے خبر دی، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فضل بن عباس رضی اللہ عنہما کو قربانی کے دن اپنی سواری پر اپنے پیچھے بٹھایا۔ وہ خوبصورت گورے مرد تھے۔ نبی کریم صلی اللہ علیہ وسلم لوگوں کو مسائل بتانے کے لیے کھڑے ہو گئے۔ اسی دوران میں قبیلہ خثعم کی ایک خوبصورت عورت بھی نبی کریم صلی اللہ علیہ وسلم سے مسئلہ پوچھنے آئی۔ فضل بھی اس عورت کو دیکھنے لگے۔ اس کا حسن و جمال ان کو بھلا معلوم ہوا۔ نبی کریم صلی اللہ علیہ وسلم نے مڑ کر دیکھا تو فضل اسے دیکھ رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے اپنا ہاتھ پیچھے لے جا کر فضل کی ٹھوڑی پکڑی اور ان کا چہرہ دوسری طرف کر دیا۔ پھر اس عورت نے کہا: یا رسول اللہ! حج کے بارے میں اللہ کا جو اپنے بندوں پر فریضہ ہے وہ میرے والد پر لاگو ہوتا ہے، جو بہت بوڑھے ہو چکے ہیں اور سواری پر سیدھے نہیں بیٹھ سکتے۔ کیا اگر میں ان کی طرف سے حج کر لوں تو ان کا حج ادا ہو جائے گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں ہو جائے گا۔' WHERE id = 5994;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، کہا مجھ کو یونس نے خبر دی، انہیں ابن شہاب نے کہا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ جب رسول اللہ صلی اللہ علیہ وسلم مدینہ منورہ ( ہجرت کر کے ) تشریف لائے تو ان کی عمر دس سال تھی۔ پھر میں نے نبی کریم صلی اللہ علیہ وسلم کی زندگی کے باقی دس سالوں میں آپ کی خدمت کی اور میں پردہ کے حکم کے متعلق سب سے زیادہ جانتا ہوں کہ کب نازل ہوا تھا۔ ابی بن کعب رضی اللہ عنہ مجھ سے اس کے بارے میں پوچھا کرتے تھے۔ پردہ کے حکم کا نزول سب سے پہلے اس رات ہوا جس میں رسول اللہ صلی اللہ علیہ وسلم نے زینب بنت جحش رضی اللہ عنہا سے نکاح کے بعد ان کے ساتھ پہلی خلوت کی تھی۔ نبی کریم صلی اللہ علیہ وسلم ان کے دولہا تھے اور آپ نے صحابہ کو دعوت ولیمہ پر بلایا تھا۔ کھانے سے فارغ ہو کر سب لوگ چلے گئے لیکن چند آدمی آپ کے پاس بیٹھے رہ گئے اور بہت دیر تک وہیں ٹھہرے رہے۔ نبی کریم صلی اللہ علیہ وسلم اٹھ کر باہر تشریف لے گئے اور میں بھی نبی کریم صلی اللہ علیہ وسلم کے ساتھ چلا گیا تاکہ وہ لوگ بھی چلے جائیں۔ نبی کریم چلتے رہے اور میں بھی نبی کریم صلی اللہ علیہ وسلم کے ساتھ چلتا رہا اور سمجھا کہ وہ لوگ اب چلے گئے ہیں۔ اس لیے واپس تشریف لائے اور میں بھی نبی کریم صلی اللہ علیہ وسلم کے ساتھ واپس آیا لیکن آپ جب زینب رضی اللہ عنہا کے حجرے میں داخل ہوئے تو وہ لوگ ابھی بیٹھے ہوئے تھے اور ابھی تک واپس نہیں گئے تھے۔ نبی کریم صلی اللہ علیہ وسلم دوبارہ وہاں سے لوٹ گئے اور میں بھی آپ کے ساتھ لوٹ گیا۔ جب آپ عائشہ رضی اللہ عنہا کے حجرہ کی چوکھٹ تک پہنچے تو آپ نے سمجھا کہ وہ لوگ نکل چکے ہوں گے۔ پھر آپ لوٹ کر آئے اور میں بھی آپ کے ساتھ لوٹ آیا تو واقعی وہ لوگ جا چکے تھے۔ پھر پردہ کی آیت نازل ہوئی اور نبی کریم صلی اللہ علیہ وسلم نے میرے اور اپنے درمیان پردہ لٹکا لیا۔' WHERE id = 6004;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، کہا ہم سے ابن ابی حازم نے ان سے ان کے والد نے اور ان سے سہل رضی اللہ عنہ نے کہ ہم جمعہ کے دن خوش ہوا کرتے تھے۔ میں نے عرض کی کس لیے؟ فرمایا کہ ہماری ایک بڑھیا تھیں جو مقام بضاعہ جایا کرتی تھیں۔ ابن سلمہ نے کہا کہ بضاعہ مدینہ منورہ کا کھجور کا ایک باغ تھا۔ پھر وہ وہاں سے چقندر لایا کرتی تھیں اور اسے ہانڈی میں ڈالتی تھیں اور جَو کے کچھ دانے پیس کر ( اس میں ملاتی تھیں ) جب ہم جمعہ کی نماز پڑھ کر واپس ہوتے تو انہیں سلام کرنے آتے اور وہ یہ چقندر کی جڑ میں آٹا ملی ہوئی دعوت ہمارے سامنے رکھتی تھیں ہم اس وجہ سے جمعہ کے دن خوش ہوا کرتے تھے اور قیلولہ یا دوپہر کا کھانا ہم جمعہ کے بعد کرتے تھے۔' WHERE id = 6014;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، انہیں عبداللہ بن ابی بکر بن انس نے خبر دی، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب اہل کتاب تمہیں سلام کریں تو تم اس کے جواب میں صرف «وعليكم» کہو۔“' WHERE id = 6024;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا کہا ہم سے اعمش نے بیان کیا، کہا ہم سے زید بن وہب نے بیان کیا ( کہا کہ ) واللہ ہم سے ابوذر رضی اللہ عنہ نے مقام ربذہ میں بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ رات کے وقت مدینہ منورہ کی کالی پتھروں والی زمین پر چل رہا تھا کہ احد پہاڑ دکھائی دیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے ابوذر! مجھے پسند نہیں کہ اگر احد پہاڑ کے برابر بھی میرے پاس سونا ہو اور مجھ پر ایک رات بھی اس طرح گزر جائے یا تین رات کہ اس میں سے ایک دینار بھی میرے پاس باقی بچے۔ سوائے اس کے جو میں قرض کی ادائیگی کے لیے محفوظ رکھ لوں میں اس سارے سونے کو اللہ کی مخلوق میں اس اس طرح تقسیم کر دوں گا۔ ابوذر رضی اللہ عنہ نے اس کی کیفیت ہمیں اپنے ہاتھ سے لپ بھر کر دکھائی۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے ابوذر! میں نے عرض کیا «لبيك وسعديك‏.‏» یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ زیادہ جمع کرنے والے ہی ( ثواب کی حیثیت سے ) کم حاصل کرنے والے ہوں گے۔ سوائے اس کے جو اللہ کے بندوں پر مال اس اس طرح یعنی کثرت کے ساتھ خرچ کرے۔ پھر فرمایا یہیں ٹھہرے رہو ابوذر! یہاں سے اس وقت تک نہ ہٹنا جب تک میں واپس نہ آ جاؤں۔ پھر آپ صلی اللہ علیہ وسلم تشریف لے گئے اور نظروں سے اوجھل ہو گئے۔ اس کے بعد میں نے آواز سنی اور مجھے خطرہ ہوا کہ کہیں نبی کریم صلی اللہ علیہ وسلم کو کوئی پریشانی نہ پیش آ گئی ہو۔ اس لیے میں نے ( نبی کریم صلی اللہ علیہ وسلم کو دیکھنے کے لیے ) جانا چاہا لیکن فوراً ہی نبی کریم صلی اللہ علیہ وسلم کا یہ ارشاد یاد آیا کہ یہاں سے نہ ہٹنا۔ چنانچہ میں وہیں رک گیا ( جب آپ تشریف لائے تو ) میں نے عرض کی۔ میں نے آواز سنی تھی اور مجھے خطرہ ہو گیا تھا کہ کہیں آپ کو کوئی پریشانی نہ پیش آ جائے پھر مجھے آپ کا ارشاد یاد آیا اس لیے میں یہیں ٹھہر گیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا یہ جبرائیل علیہ السلام تھے۔ میرے پاس آئے تھے اور مجھے خبر دی ہے کہ میری امت کا جو شخص بھی اس حال میں مرے گا کہ اللہ کے ساتھ کسی چیز کو شریک نہ ٹھہراتا ہو تو وہ جنت میں جائے گا۔ میں نے عرض کیا: یا رسول اللہ! اگرچہ اس نے زنا اور چوری کی ہو؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں اگر اس نے زنا اور چوری بھی کی ہو۔ ( اعمش نے بیان کیا کہ ) میں نے زید بن وہب سے کہا کہ مجھے معلوم ہوا ہے کہ اس حدیث کے راوی ابودرداء رضی اللہ عنہ ہیں؟ زید نے فرمایا میں گواہی دیتا ہوں کہ یہ حدیث مجھ سے ابوذر رضی اللہ عنہ نے مقام ربذہ میں بیان کی تھی۔ اعمش نے بیان کیا کہ مجھ سے ابوصالح نے حدیث بیان کی اور ان سے ابو الدرداء رضی اللہ عنہ نے اسی طرح بیان کیا اور ابوشہاب نے اعمش سے بیان کیا۔' WHERE id = 6034;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن جعفر نے بیان کیا، کہا ہم سے یزید بن ہارون نے بیان کیا، ان سے شعبہ نے، ان سے مغیرہ بن مقسم نے، ان سے ابراہیم نخعی نے اور ان سے علقمہ بن قیس نے کہ آپ ملک شام میں پہنچے ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا کہ اور مجھ سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے مغیرہ نے اور ان سے ابراہیم نے بیان کیا کہ علقمہ ملک شام گئے اور مسجد میں جا کر دو رکعت نماز پڑھی پھر یہ دعا کی اے اللہ! مجھے ایک ہم نشین عطا فرما۔ چنانچہ وہ ابودرداء رضی اللہ عنہ کی مجلس میں جا بیٹھے۔ ابودرداء رضی اللہ عنہ نے دریافت کیا۔ تمہارا تعلق کہاں سے ہے؟ کہا کہ اہل کوفہ سے، پوچھا کیا تمہارے یہاں ( نفاق اور منافقین کے ) بھیدوں کے جاننے والے وہ صحابی نہیں ہیں جن کے سوا کوئی اور ان سے واقف نہیں ہے؟ ان کا اشارہ حذیفہ رضی اللہ عنہ کی طرف تھا۔ کیا تمہارے یہاں وہ نہیں ہیں ( یا یوں کہا کہ ) تمہارے وہ جنہیں اللہ تعالیٰ نے اپنے رسول صلی اللہ علیہ وسلم کی زبانی شیطان سے پناہ دی تھی؟ اشارہ عمار رضی اللہ عنہ کی طرف تھا۔ کیا تمہارے یہاں مسواک اور گدے والے نہیں ہیں؟ ان کا اشارہ ابن مسعود رضی اللہ عنہ کی طرف تھا۔ عبداللہ بن مسعود رضی اللہ عنہ سورۃ «والليل إذا يغشى‏» کس طرح پڑھتے تھے۔ علقمہ رضی اللہ عنہ نے کہا کہ وہ «والذكر والأنثى‏» پڑھتے تھے۔ ابودرداء رضی اللہ عنہ نے اس پر کہا کہ یہ لوگ کوفہ والے اپنے مسلسل عمل سے قریب تھا کہ مجھے شبہ میں ڈال دیتے حالانکہ میں نے نبی کریم صلی اللہ علیہ وسلم سے خود اسے سنا تھا۔' WHERE id = 6044;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، ہم سے شعبہ نے بیان کیا، ان سے عبدالعزیز بن صہیب اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نماز کی تکبیر کہی گئی اور ایک صحابی رسول صلی اللہ علیہ وسلم سے سرگوشی کرتے رہے، پھر وہ دیر تک سرگوشی کرتے رہے یہاں تک کہ آپ کے صحابہ سونے لگے اس کے بعد آپ اٹھے اور نماز پڑھائی۔' WHERE id = 6056;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے اسحاق نے بیان کیا وہ سعید کے بیٹے ہیں، ان سے سعید نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں اپنے ہاتھوں سے ایک گھر بنایا تاکہ بارش سے حفاظت رہے اور دھوپ سے سایہ حاصل ہو اللہ کی مخلوق میں سے کسی نے اس کام میں میری مدد نہیں کی۔ معلوم ہوا کہ ضرورت کے لائق گھر بنانا درست ہے۔' WHERE id = 6066;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے عبدالملک بن عمیر نے، ان سے ربعی بن حراش نے اور ان سے حذیفہ بن یمان رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب اپنے بستر پر لیٹتے تو یہ کہتے «باسمك أموت وأحيا» ”تیرے ہی نام کے ساتھ میں مردہ اور زندہ رہتا ہوں“ اور جب بیدار ہوتے تو کہتے «الحمد لله الذي أحيانا بعد ما أماتنا وإليه النشور» ”اسی اللہ کے لیے تمام تعریفیں ہیں جس نے ہمیں زندہ کیا۔ اس کے بعد کہ اس نے موت طاری کر دی تھی اور اسی کی طرف لوٹنا ہے۔“ قرآن شریف میں جو لفظ «ننشرها» ہے اس کا بھی یہی معنی ہے کہ ہم اس کو نکال کر اٹھاتے ہیں۔' WHERE id = 6076;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے عبدالعزیز بن صہیب نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب بیت الخلاء جاتے تو یہ دعا پڑھتے «اللهم إني أعوذ بك من الخبث والخبائث» ”اے اللہ! میں خبیث جنوں اور جنیوں کی برائی سے تیری پناہ مانگتا ہوں۔“' WHERE id = 6086;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عمرو بن مرہ نے، کہا میں نے عبداللہ بن ابی اوفی رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اگر کوئی شخص صدقہ لاتا تو نبی کریم صلی اللہ علیہ وسلم فرماتے کہ اے اللہ! فلاں کی آل اولاد پر اپنی رحمتیں نازل فرما۔ میرے والد صدقہ لائے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! ابی اوفی کی آل اولاد پر رحمتیں نازل فرما۔' WHERE id = 6096;
UPDATE hadiths SET urdu = 'ہم سے محمد بن محبوب نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جمعہ کے دن خطبہ دے رہے تھے کہ ایک آدمی کھڑا ہوا اور کہا کہ یا رسول اللہ! اللہ سے دعا فرما دیجئیے کہ ہمارے لیے بارش برسائے ( نبی کریم صلی اللہ علیہ وسلم نے دعا فرمائی ) اور آسمان پر بادل چھا گیا اور بارش برسنے لگی، یہ حال ہو گیا کہ ہمارے لیے گھر تک پہنچنا مشکل تھا۔ یہ بارش اگلے جمعہ تک ہوتی رہی پھر وہی صحابی یا کوئی دوسرے صحابی اس دوسرے جمعہ کو کھڑے ہوئے اور کہا کہ اللہ سے دعا فرمائیے کہ اب بارش بند کر دے ہم تو ڈوب گئے۔ نبی کریم صلی اللہ علیہ وسلم نے دعا کی کہ اے اللہ! ہمارے چاروں طرف بستیوں کو سیراب کر اور ہم پر بارش بند کر دے۔ چنانچہ بادل ٹکڑے ہو کر مدینہ کے چاروں طرف بستیوں میں چلا گیا اور مدینہ والوں پر بارش رک گئی۔' WHERE id = 6106;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حاتم بن اسماعیل نے بیان کیا، ان سے جعد بن عبدالرحمٰن نے بیان کیا کہ میں نے سائب بن یزید رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میری خالہ مجھے لے کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئیں اور عرض کیا: یا رسول اللہ! میرا یہ بھانجا بیمار ہے۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے میرے سر پر ہاتھ پھیرا اور میرے لیے برکت کی دعا کی۔ پھر آپ نے وضو کیا اور میں نے آپ کے وضو کا پانی پیا۔ اس کے بعد میں آپ کی پشت کی طرف کھڑا ہو گیا اور میں نے مہر نبوت دیکھی جو دونوں شانوں کے درمیان میں تھی جیسے چھپر کھٹ کی گھنڈی ہوتی ہے یا حجلہ کا انڈہ۔' WHERE id = 6116;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر حوضی نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ صحابہ نے رسول اللہ صلی اللہ علیہ وسلم سے سوالات کئے اور جب بہت زیادہ کئے تو نبی کریم صلی اللہ علیہ وسلم کو ناگواری ہوئی، پھر آپ صلی اللہ علیہ وسلم ممبر پر تشریف لائے اور فرمایا کہ آج تم مجھ سے جو بات پوچھو گے میں بتاؤں گا۔ اس وقت میں نے دائیں بائیں دیکھا تو تمام صحابہ سر اپنے کپڑوں میں لپیٹے ہوئے رو رہے تھے، ایک صاحب جن کا اگر کسی سے جھگڑا ہوتا تو انہیں ان کے باپ کے سوا کسی اور کی طرف ( طعنہ کے طور پر ) منسوب کیا جاتا تھا۔ انہوں نے پوچھا: یا رسول اللہ! میرے باپ کون ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ حذافہ۔ اس کے بعد عمر رضی اللہ عنہ اٹھے اور عرض کیا ہم اللہ سے راضی ہیں کہ ہمارا رب ہے، اسلام سے کہ وہ دین ہے، محمد صلی اللہ علیہ وسلم سے کہ وہ سچے رسول ہیں، ہم فتنوں سے اللہ کی پناہ مانگتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، آج کی طرح خیر و شر کے معاملہ میں میں نے کوئی دن نہیں دیکھا، میرے سامنے جنت اور دوزخ کی تصویر لائی گئی اور میں نے انہیں دیوار کے اوپر دیکھا۔ قتادہ اس حدیث کو بیان کرتے وقت ( سورۃ المائدہ کی ) اس آیت کا ذکر کیا کرتے تھے «يا أيها الذين آمنوا لا تسألوا عن أشياء إن تبد لكم تسؤكم‏» ”اے ایمان والو! ایسی چیزوں کے متعلق نہ سوال کرو کہ اگر تمہارے سامنے ان کا جواب ظاہر ہو جائے تو تم کو برا لگے۔“' WHERE id = 6126;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا «اللهم حبب إلينا المدينة،‏‏‏‏ كما حببت إلينا مكة أو أشد،‏‏‏‏ وانقل حماها إلى الجحفة،‏‏‏‏ اللهم بارك لنا في مدنا وصاعنا» ”اے اللہ! ہمارے دل میں مدینہ کی ایسی ہی محبت پیدا کر دے جیسی تو نے مکہ کی محبت ہمارے دل میں پیدا کی ہے بلکہ اس سے بھی زیادہ اور اس کے بخار کو جحفہ میں منتقل کر دے، اے اللہ! ہمارے لیے ہمارے مد اور صاع میں برکت عطا فرما۔“' WHERE id = 6136;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، انہوں نے کہا ہم سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم جب کسی غزوہ یا حج یا عمرہ سے واپس ہوتے تو زمین سے ہر بلند چیز پر چڑھتے وقت تین تکبیریں کہا کرتے تھے۔ پھر دعا کرتے «لا إله إلا الله،‏‏‏‏ وحده لا شريك له،‏‏‏‏ له الملك وله الحمد،‏‏‏‏ وهو على كل شيء قدير. آيبون تائبون عابدون،‏‏‏‏ لربنا حامدون. صدق الله وعده. ونصر عبده،‏‏‏‏ وهزم الأحزاب وحده» ”اللہ کے سوا کوئی معبود نہیں، وہ تنہا ہے اس کا کوئی شریک نہیں، اس کے لیے بادشاہی ہے اور اسی کے لیے تمام تعریفیں ہیں اور وہ ہر چیز پر قدرت رکھنے والا ہے۔ لوٹتے ہیں ہم توبہ کرتے ہوئے اپنے رب کی عبادت کرتے ہوئے اور حمد بیان کرتے ہوئے۔ اللہ نے اپنا وعدہ سچ کر دکھایا، اپنے بندہ کی مدد کی اور تنہا تمام لشکر کو شکست دی۔“' WHERE id = 6147;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے ہشام نے بیان کیا، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ یہود نبی کریم صلی اللہ علیہ وسلم کو سلام کرتے تو کہتے «السام عليك‏.‏» آپ کو موت آئے۔ عائشہ رضی اللہ عنہا ان کا مقصد سمجھ گئیں اور جواب دیا کہ «عليكم السام واللعنة‏.‏» تمہیں موت آئے اور تم پر لعنت ہو۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ٹھہرو عائشہ! اللہ تمام امور میں نرمی کو پسند کرتا ہے۔ عائشہ رضی اللہ عنہا نے عرض کیا: اے اللہ کے نبی! کیا آپ نے نہیں سنا یہ لوگ کیا کہتے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تم نے نہیں سنا کہ میں انہیں کس طرح جواب دیتا ہوں۔ میں کہتا ہوں «وعليكم» ۔' WHERE id = 6157;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے سمی نے بیان کیا، ان سے ابوصالح نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے «سبحان الله وبحمده‏.‏» دن میں سو مرتبہ کہا، اس کے گناہ معاف کر دئیے جاتے ہیں، خواہ سمندر کی جھاگ کے برابر ہی کیوں نہ ہوں۔“' WHERE id = 6167;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد نے اور ان سے سہل رضی اللہ عنہ نے بیان کیا کہ میں نے آپ کو یہ فرماتے ہوئے سنا کہ جنت میں ایک کوڑے جتنی جگہ دنیا اور اس میں جو کچھ ہے سب سے بہتر ہے اور اللہ کے راستے میں صبح کو یا شام کو تھوڑا سا چلنا بھی «الدنيا وما فيها» سے بہتر ہے۔' WHERE id = 6177;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھ سے اسماعیل بن ابراہیم بن عقبہ نے بیان کیا، ان سے موسیٰ بن عقبہ نے کہا کہ ابن شہاب نے بیان کیا کہ مجھ سے عروہ بن زبیر نے بیان کیا اور انہیں مسور بن مخرمہ رضی اللہ عنہ نے خبر دی کہ عمرو بن عوف رضی اللہ عنہ جو بنی عامر بن عدی کے حلیف تھے اور بدر کی لڑائی میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے، انہوں نے انہیں خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے ابوعبیدہ بن الجراح رضی اللہ عنہ کو بحرین وہاں کا جزیہ لانے کے لیے بھیجا، نبی کریم صلی اللہ علیہ وسلم نے بحرین والوں سے صلح کر لی تھی اور ان پر علاء بن الحضرمی کو امیر مقرر کیا تھا۔ جب ابوعبیدہ رضی اللہ عنہ بحرین سے جزیہ کا مال لے کر آئے تو انصار نے ان کے آنے کے متعلق سنا اور صبح کی نماز نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھی اور جب نبی کریم صلی اللہ علیہ وسلم انہیں دیکھ کر مسکرائے اور فرمایا میرا خیال ہے کہ ابوعبیدہ کے آنے کے متعلق تم نے سن لیا ہے اور یہ بھی کہ وہ کچھ لے کر آئے ہیں؟ انصار نے عرض کیا: جی ہاں، یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تمہیں خوشخبری ہو تم اس کی امید رکھو جو تمہیں خوش کر دے گی، اللہ کی قسم! فقر و محتاجی وہ چیز نہیں ہے جس سے میں تمہارے متعلق ڈرتا ہوں بلکہ میں تو اس سے ڈرتا ہوں کہ دنیا تم پر بھی اسی طرح کشادہ کر دی جائے گی، جس طرح ان لوگوں پر کر دی گئی تھی جو تم سے پہلے تھے اور تم بھی اس کے لیے ایک دوسرے سے آگے بڑھنے کی اسی طرح کوشش کرو گے جس طرح وہ کرتے تھے اور تمہیں بھی اسی طرح غافل کر دے گی جس طرح ان کو غافل کیا تھا۔' WHERE id = 6187;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن یوسف نے بیان کیا، کہا ہم کو ابوبکر بن عیاش نے خبر دی، انہیں ابوحصین (عثمان بن عاصم) نے، انہیں ابوصالح ذکوان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”دینار و درہم کے بندے، عمدہ ریشمی چادروں کے بندے، سیاہ کملی کے بندے، تباہ ہو گئے کہ اگر انہیں دیا جائے تو وہ خوش ہو جاتے ہیں اور اگر نہ دیا جائے تو ناراض رہتے ہیں۔“' WHERE id = 6197;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن شبیب نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، ان سے یونس نے اور لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب زہری نے، ان سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے کہ ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر میرے پاس احد پہاڑ کے برابر بھی سونا ہو تو مجھے اس میں خوشی ہو گی کہ تین دن بھی مجھ پر اس حال میں نہ گزرنے پائیں کہ اس میں سے میرے پاس کچھ بھی باقی بچے۔ البتہ اگر کسی کا قرض دور کرنے کے لیے کچھ رکھ چھوڑوں تو یہ اور بات ہے۔' WHERE id = 6207;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم بن عبدالرحمٰن بغوی نے بیان کیا، کہا ہم سے اسحاق ازرق نے بیان کیا، ان سے مسعر بن کدام نے، ان سے ہلال نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے گھرانہ نے اگر کبھی ایک دن میں دو مرتبہ کھانا کھایا تو ضرور اس میں ایک وقت صرف کھجوریں ہوتی تھیں۔' WHERE id = 6217;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عرعرہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سعد بن ابراہیم نے، ان سے ابوسلمہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے پوچھا گیا کون سا عمل اللہ کے نزدیک زیادہ پسندیدہ ہے؟ فرمایا کہ جس پر ہمیشگی کی جائے، خواہ وہ تھوڑی ہی ہو اور فرمایا نیک کام کرنے میں اتنی ہی تکلیف اٹھاؤ جتنی طاقت ہے ( جو ہمیشہ نبھ سکے ) ۔' WHERE id = 6227;
UPDATE hadiths SET urdu = 'مجھ سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے ابرہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہے اسے چاہئے کہ اچھی بات کہے ورنہ خاموش رہے اور جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہے وہ اپنے پڑوسی کو تکلیف نہ پہنچائے اور جو کوئی اللہ اور آخرت کے دن پر ایمان رکھتا ہو وہ اپنے مہمان کی عزت کرے۔“' WHERE id = 6237;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، انہوں نے کہا ہم سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے سعید بن مسیب نے بیان کیا کہ ابوہریرہ رضی اللہ عنہ بیان کیا کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر تمہیں وہ معلوم ہو جائے جو میں جانتا ہوں تو تم ہنستے کم اور روتے زیادہ۔“' WHERE id = 6247;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے ماجشون نے بیان کیا، ان سے عبدالرحمٰن بن ابی صعصعہ نے، ان سے ان کے والد نے اور انہوں نے ابو سعید خدری رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ لوگوں پر ایک ایسا دور آئے گا جب ایک مسلمان کا سب سے بہتر مال بھیڑیں ہوں گی وہ انہیں لے کر پہاڑ کی چوٹیوں اور بارش کی جگہوں پر چلا جائے گا، اس دن وہ اپنے دین کو لے کر فسادوں سے ڈر کر وہاں سے بھاگ جائے گا۔' WHERE id = 6257;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن یوسف نے بیان کیا، کہا ہم کو ابوبکر بن عیاش نے خبر دی، انہیں ابوحصین نے، انہیں ابوصالح نے، انہیں ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں اور قیامت ان دو کی طرح بھیجے گئے ہیں۔ آپ کی مراد دو انگلیوں سے تھی۔“ ابوبکر بن عیاش کے ساتھ اس حدیث کو اسرائیل نے بھی ابوحصین سے روایت کیا ہے۔' WHERE id = 6267;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب تم میں سے کوئی مرتا ہے تو صبح و شام ( جب تک وہ برزخ میں ہے ) اس کے رہنے کی جگہ اسے ہر روز دکھائی جاتی ہے یا دوزخ ہو یا جنت اور کہا جاتا ہے کہ یہ تیرے رہنے کی جگہ ہے یہاں تک کہ تو اٹھایا جائے ( یعنی قیامت کے دن تک ) ۔“' WHERE id = 6277;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے سعید بن جبیر نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا کہ آپ منبر پر خطبہ میں فرما رہے تھے کہ تم اللہ تعالیٰ سے اس حال میں ملو گے کہ ننگے پاؤں، ننگے جسم اور بغیر ختنہ ہو گے۔' WHERE id = 6287;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا اس آیت کے بارے میں «ونزعنا ما في صدورهم من غل‏» کہا کہ ہم سے سعید نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے ابوالمتوکل ناجی نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مومنین جہنم سے چھٹکارا پا جائیں گے لیکن دوزخ و جنت کے درمیان ایک پل پر انہیں روک لیا جائے گا اور پھر ایک کے دوسرے پر ان مظالم کا بدلہ لیا جائے گا جو دنیا میں ان کے درمیان آپس میں ہوئے تھے اور جب کانٹ چھانٹ کر لی جائے گی اور صفائی ہو جائے گی تب انہیں جنت میں داخل ہونے کی اجازت ملے گی۔ پس اس ذات کی قسم جس کے ہاتھ میں محمد ( صلی اللہ علیہ وسلم ) کی جان ہے! جنتیوں میں سے ہر کوئی جنت میں اپنے گھر کو دنیا کے اپنے گھر کے مقابلہ میں زیادہ بہتر طریقے پر پہچان لے گا۔“' WHERE id = 6297;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اہل جنت سے کہا جائے گا کہ اے اہل جنت! ہمیشہ ( تمہیں یہیں ) رہنا ہے، تمہیں موت نہیں آئے گی اور اہل دوزخ سے کہا جائے گا کہ اے دوزخ والو! ہمیشہ ( تم کو یہیں ) رہنا ہے، تم کو موت نہیں آئے گی۔“' WHERE id = 6307;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، کہا ہم سے عبدالعزیز بن ابی حازم نے بیان کیا، ان سے ان کے والد حازم نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جنت والے ( اپنے اوپر کے درجوں کے ) بالاخانوں کو اس طرح دیکھیں گے جیسے تم آسمان میں ستاروں کو دیکھتے ہو۔“' WHERE id = 6317;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے ابوعوانہ نے، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ قیامت کے دن لوگوں کو جمع کرے گا۔ اس وقت لوگ کہیں گے کہ اگر ہم اپنے رب کے حضور میں کسی کی شفاعت لے جائیں تو نفع بخش ثابت ہو سکتی ہے۔ ممکن ہے ہم اپنی اس حالت سے نجات پا جائیں۔ چنانچہ لوگ آدم علیہ السلام کے پاس آئیں گے اور عرض کریں گے آپ ہی وہ بزرگ نبی ہیں جنہیں اللہ تعالیٰ نے اپنے ہاتھ سے بنایا اور آپ کے اندر اپنی چھپائی ہوئی روح پھونکی اور فرشتوں کو حکم دیا تو انہوں نے آپ کو سجدہ کیا، آپ ہمارے رب کے حضور میں ہماری شفاعت کریں۔ وہ کہیں گے کہ میں تو اس لائق نہیں ہوں، پھر وہ اپنی لغزش یاد کریں گے اور کہیں گے کہ نوح کے پاس جاؤ، وہ سب سے پہلے رسول ہیں جنہیں اللہ تعالیٰ نے بھیجا۔ لوگ نوح علیہ السلام کے پاس آئیں گے لیکن وہ بھی یہی جواب دیں گے کہ میں اس لائق نہیں ہوں۔ وہ اپنی لغزش کا ذکر کریں گے اور کہیں کہ تم ابراہیم کے پاس جاؤ جنہیں اللہ تعالیٰ نے اپنا خلیل بنایا تھا۔ لوگ ان کے پاس آئیں گے لیکن یہ بھی یہی کہیں گے کہ میں اس لائق نہیں ہوں، اپنی خطا کا ذکر کریں گے اور کہیں گے کہ تم لوگ موسیٰ کے پاس جاؤ جن سے اللہ تعالیٰ نے کلام کیا تھا۔ لوگ موسیٰ علیہ السلام کے پاس جائیں گے لیکن وہ بھی یہی جواب دیں گے کہ میں اس لائق نہیں ہوں، اپنی خطا کا ذکر کریں گے اور کہیں گے کہ عیسیٰ علیہ السلام کے پاس جاؤ۔ لوگ عیسیٰ علیہ السلام کے پاس جائیں گے، لیکن یہ بھی کہیں گے کہ میں اس لائق نہیں ہوں، محمد صلی اللہ علیہ وسلم کے پاس جاؤ کیونکہ ان کے تمام اگلے پچھلے گناہ معاف کر دئیے گئے ہیں۔ چنانچہ لوگ میرے پاس آئیں گے۔ اس وقت میں اپنے رب سے ( شفاعت کی ) اجازت چاہوں گا اور سجدہ میں گر جاؤں گا۔ اللہ تعالیٰ جتنی دیر تک چاہے گا مجھے سجدہ میں رہنے دے گا۔ پھر کہا جائے گا کہ اپنا سر اٹھا لو، مانگو دیا جائے گا، کہو سنا جائے گا، شفاعت کرو، شفاعت قبول کی جائے گی۔ میں اپنے رب کی اس وقت ایسی حمد بیان کروں گا کہ جو اللہ تعالیٰ مجھے سکھائے گا۔ پھر شفاعت کروں گا اور میرے لیے حد مقرر کر دی جائے گی اور میں لوگوں کو جہنم سے نکال کر جنت میں داخل کر دوں گا اور اسی طرح سجدہ میں گر جاؤں گا، تیسری یا چوتھی مرتبہ جہنم میں صرف وہی لوگ باقی رہ جائیں گے جنہیں قرآن نے روکا ہے ( یعنی جن کے جہنم میں ہمیشہ رہنے کا ذکر قرآن میں صراحت کے ساتھ ہے ) قتادہ رحمہ اللہ اس موقع پر کہا کرتے کہ اس سے وہ لوگ مراد ہیں جن پر جہنم میں ہمیشہ رہنا واجب ہو گیا ہے۔' WHERE id = 6327;
UPDATE hadiths SET urdu = '(دوسری سند) اور مجھ سے عمرو بن علی نے بیان کیا، کہا ہم سے محمد بن جعفر نے، کہا ہم سے شعبہ نے، ان سے مغیرہ نے، کہا کہ میں نے ابووائل سے سنا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں اپنے حوض پر تم سے پہلے ہی موجود رہوں گا اور تم میں سے کچھ لوگ میرے سامنے لائے جائیں گے پھر انہیں میرے سامنے سے ہٹا دیا جائے گا تو میں کہوں گا کہ اے میرے رب! یہ میرے ساتھی ہیں لیکن مجھ سے کہا جائے گا کہ آپ نہیں جانتے کہ انہوں نے آپ کے بعد دین میں کیا کیا نئی چیزیں ایجاد کر لی تھیں۔ اس روایت کی متابعت عاصم نے ابووائل سے کی، ان سے حذیفہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے بیان فرمایا۔' WHERE id = 6337;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، انہوں نے کہا ہم سے ابن وہب نے بیان کیا، انہوں نے کہا کہ مجھ سے یونس نے خبر دی، انہیں ابن شہاب نے، انہیں ابن مسیب نے، وہ نبی کریم صلی اللہ علیہ وسلم کے صحابہ سے روایت کرتے تھے کہ آپ صلی اللہ علیہ وسلم نے فرمایا ”حوض پر میرے صحابہ کی ایک جماعت آئے گی۔ پھر انہیں اس سے دور کر دیا جائے گا۔ میں عرض کروں گا میرے رب! یہ تو میرے صحابہ ہیں۔ اللہ تعالیٰ فرمائے گا کہ تمہیں معلوم نہیں کہ انہوں نے تمہارے بعد کیا کیا نئی چیزیں ایجاد کر لی تھیں، یہ الٹے پاؤں ( اسلام سے ) واپس لوٹ گئے تھے۔“' WHERE id = 6347;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے یزید رشک نے بیان کیا، انہوں نے مطرف بن عبداللہ بن شخیر سے سنا، وہ عمران بن حصین رضی اللہ عنہما سے بیان کرتے تھے، انہوں نے کہا کہ ایک صاحب نے ( یعنی خود انہوں نے ) عرض کیا: یا رسول اللہ! کیا جنت کے لوگ جہنمیوں میں سے پہچانے جا چکے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہاں“ انہوں نے کہا کہ پھر عمل کرنے والے کیوں عمل کریں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہر شخص وہی عمل کرتا ہے جس کے لیے وہ پیدا کیا گیا ہے یا جس کے لیے اسے سہولت دی گئی ہے۔' WHERE id = 6357;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے منصور بن معتمر نے، ان سے عبداللہ بن مرہ نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے نذر ماننے سے منع کیا تھا اور فرمایا تھا کہ نذر کسی چیز کو نہیں لوٹاتی، نذر صرف بخیل کے دل سے پیسہ نکالتی ہے۔' WHERE id = 6368;
UPDATE hadiths SET urdu = 'ہم سے علی بن حفص اور بشر بن محمد نے بیان کیا، ان دونوں نے کہا کہ عبداللہ نے ہمیں خبر دی، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سالم نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ابن صیاد سے فرمایا کہ میں نے تیرے لیے ایک بات دل میں چھپا رکھی ہے ( بتا وہ کیا ہے؟ ) اس نے کہا کہ ”دھواں“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بدبخت! اپنی حیثیت سے آگے نہ بڑھ۔ عمر رضی اللہ عنہ نے عرض کیا: آپ مجھے اجازت دیں تو میں اس کی گردن مار دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے چھوڑ دو، اگر یہ وہی ( دجال ) ہوا تو تم اس پر قابو نہیں پا سکتے اور اگر یہ وہ نہ ہوا تو اسے قتل کرنے میں تمہارے لیے کوئی بھلائی نہیں۔' WHERE id = 6378;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، ان سے سفیان نے، ان سے موسیٰ بن عقبہ نے اور ان سے سالم نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی قسم بس اتنی تھی کہ نہیں! دلوں کے پھیرنے والے اللہ کی قسم۔' WHERE id = 6388;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے ابوالاحوص نے بیان کیا، ان سے ابواسحاق نے، ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ریشم کا ایک ٹکڑا ہدیہ کے طور پر آیا تو لوگ اسے دست بدست اپنے ہاتھوں میں لینے لگے اور اس کی خوبصورتی اور نرمی پر حیرت کرنے لگے۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ تمہیں اس پر حیرت ہے؟ صحابہ نے عرض کی جی ہاں، یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، سعد رضی اللہ عنہ کے رومال جنت میں اس سے بھی اچھے ہیں۔ شعبہ اور اسرائیل نے ابواسحاق سے الفاظ ”اس ذات کی قسم جس کے ہاتھ میں میری جان ہے“ کا ذکر نہیں کیا۔' WHERE id = 6399;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا ہم کو معمر نے خبر دی، انہوں نے کہا ہم سے زہری نے بیان کیا، انہیں حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے قسم کھائی اور کہا کہ ”لات و عزیٰ کی قسم“ تو اسے پھر کلمہ «لا إله إلا الله» کہہ لینا چاہئے اور جو شخص اپنے ساتھی سے کہے کہ آؤ جوا کھیلیں تو اسے چاہئے کہ ( اس کے کفارہ میں ) صدقہ کرے۔' WHERE id = 6409;
UPDATE hadiths SET urdu = 'ہم سے اویسی نے بیان کیا، کہا ہم سے ابراہیم نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے (دوسری سند) اور ہم سے حجاج نے بیان کیا، کہا ہم سے عبداللہ بن عمر نمیری نے بیان کیا، کہا ہم سے یونس نے بیان کیا، کہا کہ میں نے زہری سے سنا، کہا کہ میں نے عروہ بن زبیر، سعید بن مسیب، علقمہ بن وقاص اور عبیداللہ بن عبداللہ رضی اللہ عنہما سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ صدیقہ رضی اللہ عنہا کی بات کے متعلق سنا کہ جب تہمت لگانے والے نے ان پر تہمت لگائی تھی اور اللہ تعالیٰ نے ان کو اس سے بری قرار دیا تھا۔ اور ہر شخص نے مجھ سے پوری بات کا کوئی ایک حصہ ہی بیان کا۔ پھر نبی کریم صلی اللہ علیہ وسلم کھڑے ہوئے اور عبداللہ بن ابی کے بارے میں مدد چاہی۔ پھر اسید بن حضیر رضی اللہ عنہ کھڑے ہوئے اور سعد بن عبادہ رضی اللہ عنہ سے کہا کہ اللہ کی قسم! ( «لعمر الله» ) ہم ضرور اسے قتل کر دیں گے ( مفصل حدیث پیچھے گزر چکی ہے ) ۔' WHERE id = 6420;
UPDATE hadiths SET urdu = 'ہم سے امام حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے عمرو بن دینار نے بیان کیا، کہا مجھ کو سعید بن جبیر نے خبر دی، کہا کہ میں نے ابن عباس رضی اللہ عنہما سے پوچھا تو انہوں نے بیان کیا کہ ہم سے ابی بن کعب رضی اللہ عنہ نے بیان کیا، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آیت «لا تؤاخذني بما نسيت ولا ترهقني من أمري عسرا‏» کے متعلق کہ پہلی مرتبہ اعتراض موسیٰ علیہ السلام سے بھول کر ہوا تھا۔' WHERE id = 6430;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے سلیمان بن بلال نے بیان کیا، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اپنی بیویوں کے ساتھ ایلاء کیا (یعنی قسم کھائی کہ آپ ان کے یہاں ایک مہینہ تک نہیں جائیں گے) اور نبی کریم صلی اللہ علیہ وسلم کے پاؤں میں موچ آ گئی تھی۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم اپنے بالا خانہ میں انتیس دن تک قیام پذیر رہے پھر وہاں سے اترے، لوگوں نے کہا یا رسول اللہ! آپ نے ایلاء ایک مہینے کے لیے کیا تھا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ مہینہ انتیس دن کا ہے۔' WHERE id = 6441;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”نذر انسان کو کوئی ایسی چیز نہیں دیتی جو اس کے مقدر میں نہ ہو، البتہ اللہ تعالیٰ اس کے ذریعہ بخیل سے اس کا مال نکلواتا ہے اور اس طرح وہ چیزیں صدقہ کر دیتا ہے جس کی اس سے پہلے اس کی امید نہیں کی جا سکتی تھی۔“' WHERE id = 6451;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے، کہا ہم سے ایوب نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم خطبہ دے رہے تھے کہ ایک شخص کو کھڑے دیکھا۔ نبی کریم صلی اللہ علیہ وسلم نے اس کے متعلق پوچھا تو لوگوں نے بتایا کہ یہ ابواسرائیل نامی ہیں۔ انہوں نے نذر مانی ہے کہ کھڑے ہی رہیں گے، بیٹھیں گے نہیں، نہ کسی چیز کے سایہ میں بیٹھیں گے اور نہ کسی سے بات کریں گے اور روزہ رکھیں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ان سے کہو کہ بات کریں، سایہ کے نیچے بیٹھیں اٹھیں اور اپنا روزہ پورا کر لیں۔ عبدالوہاب نے بیان کیا کہ ہم سے ایوب نے بیان کیا، ان سے عکرمہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے۔' WHERE id = 6461;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے خبر دی، انہیں اسحاق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اے اللہ! ان کے «كيل» پیمانے میں ان کے صاع اور ان کے مد میں برکت عطا فرما۔“' WHERE id = 6471;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے عبداللہ بن طاؤس نے بیان کیا، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”بدگمانی سے بچتے رہو، کیونکہ گمان ( بدظنی ) سب سے جھوٹی بات ہے۔ آپس میں ایک دوسرے کی برائی کی تلاش میں نہ لگے رہو نہ ایک دوسرے سے بغض رکھو اور نہ پیٹھ پیچھے کسی کی برائی کرو، بلکہ اللہ کے بندے بھائی بھائی بن کر رہو۔“' WHERE id = 6481;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے، کہا ہم سے ابوقیس عبدالرحمٰن بن ثروان نے، انہوں نے ہزیل بن شرحبیل سے سنا، بیان کیا کہ ابوموسیٰ رضی اللہ عنہ سے بیٹی، پوتی اور بہن کی میراث کے بارے میں پوچھا گیا تو انہوں نے کہا کہ بیٹی کو آدھا ملے گا اور بہن کو آدھا ملے گا اور تو ابن مسعود رضی اللہ عنہ کے یہاں جا، شاید وہ بھی یہی بتائیں گے۔ پھر ابن مسعود رضی اللہ عنہ سے پوچھا گیا اور ابوموسیٰ رضی اللہ عنہ کی بات بھی پہنچائی گئی تو انہوں نے کہا کہ میں اگر ایسا فتویٰ دوں تو گمراہ ہو چکا اور ٹھیک راستے سے بھٹک گیا۔ میں تو اس میں وہی فیصلہ کروں گا جو رسول اللہ صلی اللہ علیہ وسلم نے کیا تھا کہ بیٹی کو آدھا ملے گا، پوتی کو چھٹا حصہ ملے گا، اس طرح دو تہائی پوری ہو جائے گی اور پھر جو باقی بچے گا وہ بہن کو ملے گا۔ پھر ابوموسیٰ رضی اللہ عنہ کے پاس آئے اور ابن مسعود رضی اللہ عنہ کی بات ان تک پہنچائی تو انہوں نے کہا کہ جب تک یہ عالم تم میں موجود ہیں مجھ سے مسائل نہ پوچھا کرو۔' WHERE id = 6492;
UPDATE hadiths SET urdu = 'ہم سے امیہ بن بسطام نے بیان کیا، انہوں نے کہا ہم سے یزید بن زریع نے بیان کیا، ان سے روح نے بیان کیا، ان سے عبداللہ بن طاؤس نے، ان سے ان کے والد نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میراث اس کے وارثوں تک پہنچا دو اور جو کچھ اس میں سے بچ رہے وہ قریبی عزیز مرد کا حق ہے۔“' WHERE id = 6502;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ولاء کے تعلق کو بیچنے، اس کو ہبہ کرنے سے منع فرمایا ہے۔' WHERE id = 6512;
UPDATE hadiths SET urdu = 'ہم سے اصبغ بن الفرج نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، کہا کہ مجھ کو عمرو نے خبر دی، انہیں جعفر بن ربیعہ نے، انہیں عراک نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اپنے باپ کا کوئی انکار نہ کرے کیونکہ جو اپنے باپ سے منہ موڑتا ہے ( اور اپنے کو دوسرے کا بیٹا ظاہر کرتا ہے تو ) یہ کفر ہے۔“' WHERE id = 6523;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا ہم سے خالد بن الحارث نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے ابوحصین نے، انہوں نے کہا کہ میں نے عمیر بن سعید نخعی سے سنا، کہا کہ میں نے علی بن ابی طالب رضی اللہ عنہ سے سنا، انہوں نے کہا کہ میں نہیں پسند کروں گا کہ حد میں کسی کو ایسی سزا دوں کہ وہ مر جائے اور پھر مجھے اس کا رنج ہو، سوا شرابی کے کہ اگر وہ مر جائے تو میں اس کی دیت ادا کر دوں گا کیونکہ رسول اللہ صلی اللہ علیہ وسلم نے اس کی کوئی حد مقرر نہیں کی تھی۔' WHERE id = 6533;
UPDATE hadiths SET urdu = 'ہم سے سعید بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عروہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ایک مخزومی عورت کا معاملہ جس نے چوری کی تھی، قریش کے لوگوں کے لیے اہمیت اختیار کر گیا اور انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم سے اس معاملہ میں کون بات کر سکتا ہے اسامہ رضی اللہ عنہ کے سوا، جو نبی کریم صلی اللہ علیہ وسلم کو بہت پیارے ہیں اور کوئی آپ سے سفارش کی ہمت نہیں کر سکتا؟ چنانچہ اسامہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے بات کی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کیا تم اللہ کی حدوں میں سفارش کرنے آئے ہو۔“ پھر آپ صلی اللہ علیہ وسلم کھڑے ہوئے اور خطبہ دیا اور فرمایا ”اے لوگو! تم سے پہلے کے لوگ اس لیے گمراہ ہو گئے کہ جب ان میں کوئی بڑا آدمی چوری کرتا تو اسے چھوڑ دیتے لیکن اگر کمزور چوری کرتا تو اس پر حد قائم کرتے تھے اور اللہ کی قسم! اگر فاطمہ بنت محمد نے بھی چوری کی ہوتی تو محمد ( صلی اللہ علیہ وسلم ) اس کا ہاتھ ضرور کاٹ ڈالتے۔' WHERE id = 6543;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن المنذر نے بیان کیا، کہا ہم سے ابوضمرہ نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک چور کا ہاتھ ایک ڈھال پر کاٹا تھا جس کی قیمت تین درہم تھی، اس روایت کی متابعت محمد بن اسحاق نے کی اور لیث نے بیان کیا کہ مجھ سے نافع نے ( «ثمنه» کے بجائے ) لفظ «قيمته» کہا۔' WHERE id = 6553;
UPDATE hadiths SET urdu = 'ہمیں داؤد بن شبیب نے خبر دی، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے، کہا ہم کو انس رضی اللہ عنہ نے خبر دی ہے کہ میں تم سے ایک ایسی حدیث بیان کروں گا کہ میرے بعد کوئی اسے نہیں بیان کرے گا۔ میں نے یہ حدیث نبی کریم صلی اللہ علیہ وسلم سے سنی ہے۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے سنا کہ قیامت اس وقت تک قائم نہیں ہو گی یا یوں فرمایا کہ قیامت کی نشانیوں میں سے یہ ہے کہ علم دین دنیا سے اٹھ جائے گا اور جہالت پھیل جائے گی، شراب بکثرت پی جانے لگے گی اور زنا پھیل جائے گا۔ مرد کم ہو جائیں گے اور عورتوں کی کثرت ہو گی۔ حالت یہاں تک پہنچ جائے گی کہ پچاس عورتوں پر ایک ہی خبر لینے والا مرد رہ جائے گا۔' WHERE id = 6563;
UPDATE hadiths SET urdu = 'مجھ سے محمود نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ بن عبدالرحمٰن نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے کہ قبیلہ اسلم کے ایک صاحب ( ماعز بن مالک ) نبی کریم صلی اللہ علیہ وسلم کے پاس آئے اور زنا کا اقرار کیا۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے ان کی طرف سے اپنا منہ پھیر لیا۔ پھر جب انہوں نے چار مرتبہ اپنے لیے گواہی دی تو نبی کریم صلی اللہ علیہ وسلم نے ان سے پوچھا کیا تم دیوانے ہو گئے ہو؟ انہوں نے کہا کہ نہیں۔ پھر آپ نے پوچھا کیا تمہارا نکاح ہو چکا ہے؟ انہوں نے کہا کہ ہاں۔ چنانچہ آپ کے حکم سے انہیں عیدگاہ میں رجم کیا گیا۔ جب ان پر پتھر پڑے تو وہ بھاگ پڑے لیکن انہیں پکڑ لیا گیا اور رجم کیا گیا یہاں تک کہ وہ مر گئے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے ان کے حق میں کلمہ خیر فرمایا اور ان کا جنازہ ادا کیا اور ان کی تعریف کی جس کے وہ مستحق تھے۔' WHERE id = 6574;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، کہا ہم سے شیبانی نے بیان کیا میں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے رجم کے بارے میں پوچھا تو انہوں نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے رجم کیا تھا، میں نے پوچھا سورۃ النور سے پہلے یا اس کے بعد، انہوں نے بتلایا کہ مجھے معلوم نہیں۔ اس روایت کی متابعت علی بن مسہر، خالد بن عبداللہ المحاربی اور عبیدہ بن حمید نے شیبانی سے کی ہے اور بعض نے ( سورۃ النور کے بجائے ) سورۃ المائدہ کا ذکر کیا ہے لیکن پہلی روایت صحیح ہے۔' WHERE id = 6589;
UPDATE hadiths SET urdu = 'مجھ سے عیاش بن الولید نے بیان کیا، کہا ہم سے عبدالاعلیٰ نے بیان کیا، کہا ہم سے معمر نے بیان کیا، ان سے زہری نے، ان سے سالم نے، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں اس پر مار پڑتی کہ جب غلہ کے ڈھیر یوں ہی خریدیں، بن ناپے اور تولے اس کو اسی جگہ دوسرے کے ہاتھ بیچ ڈالیں ہاں وہ غلہ اٹھا کر اپنے ٹھکانے لے جائیں پھر بیچیں تو کچھ سزا نہ ہوتی۔' WHERE id = 6600;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سب سے پہلے ( قیامت کے دن ) لوگوں کے درمیان خون خرابے کے فیصلہ جات کئے جائیں گے۔“' WHERE id = 6611;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ایک یہودی نے ایک لڑکی کا سر دو پتھروں کے درمیان رکھ کر کچل دیا پھر اس لڑکی سے پوچھا گیا کہ یہ کس نے کیا ہے؟ فلاں نے، فلاں نے؟ آخر جب اس یہودی کا نام لیا گیا ( تو لڑکی نے سر کے اشارہ سے ہاں کہا ) پھر یہودی کو نبی کریم صلی اللہ علیہ وسلم کے یہاں لایا گیا اور اس سے پوچھ گچھ کی جاتی رہی یہاں تک کہ اس نے جرم کا اقرار کر لیا چنانچہ کا سر بھی پتھروں سے کچلا گیا۔' WHERE id = 6622;
UPDATE hadiths SET urdu = 'ہم سے عمر بن علی فلاس نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے موسیٰ بن ابی عائشہ نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے منہ میں ( مرض الوفات کے موقع پر ) آپ کی مرضی کے خلاف ہم نے دوا ڈالی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میرے حلق میں دوا نہ ڈالو لیکن ہم نے سمجھا کہ مریض ہونے کی وجہ سے دوا پینے سے نفرت کر رہے ہیں لیکن جب آپ کو ہوش ہوا تو فرمایا کہ تم جتنے لوگ گھر میں ہو سب کے حلق میں زبردستی دوا ڈالی جائے سوا عباس رضی اللہ عنہ کے کہ وہ اس وقت موجود نہیں تھے۔' WHERE id = 6632;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ہم سے یحییٰ نے، ان سے سفیان نے، ان سے موسیٰ بن ابی عائشہ نے بیان کیا، ان سے عبیداللہ بن عبداللہ نے کہ عائشہ رضی اللہ عنہا نے کہا، ہم نے نبی کریم صلی اللہ علیہ وسلم کے مرض میں آپ کے منہ میں زبردستی دوا ڈالی۔ حالانکہ نبی کریم صلی اللہ علیہ وسلم اشارہ کرتے رہے کہ دوا نہ ڈالی جائے لیکن ہم نے سمجھا کہ مریض کو دوا سے جو نفرت ہوتی ہے ( اس کی وجہ سے نبی کریم صلی اللہ علیہ وسلم فرما رہے ہیں ) پھر جب آپ کو افاقہ ہوا تو فرمایا۔ میں نے تمہیں نہیں کہا تھا کہ دوا نہ ڈالو۔ بیان کیا کہ ہم نے عرض کیا کہ آپ نے دوا سے ناگواری کی وجہ سے ایسا کیا ہو گا؟ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے ہر ایک کے منہ میں دوا ڈالی جائے اور میں دیکھتا رہوں گا سوائے عباس کے کیونکہ وہ اس وقت وہاں موجود ہی نہ تھے۔' WHERE id = 6643;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے ابن وہب نے بیان کیا، کہا ہم سے یونس نے بیان کیا، ان سے ابن شہاب نے، ان سے ابن المسیب اور ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ بنی ہذیل کی دو عورتیں آپس میں لڑیں اور ایک نے دوسری عورت پر پتھر پھینک مارا جس سے وہ عورت اپنے پیٹ کے بچے ( جنین ) سمیت مر گئی۔ پھر ( مقتولہ کے رشتہ دار ) مقدمہ رسول اللہ صلی اللہ علیہ وسلم کے دربار میں لے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فیصلہ کیا کہ پیٹ کے بچے کا خون بہا ایک غلام یا کنیز دینی ہو گی اور عورت کے خون بہا کو قاتل عورت کے عاقلہ ( عورت کے باپ کی طرف سے رشتہ دار عصبہ ) کے ذمہ واجب قرار دیا۔' WHERE id = 6655;
UPDATE hadiths SET urdu = 'ہم سے محمد بن حسین بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے عبیداللہ بن موسیٰ کوفی نے بیان کیا، انہوں نے کہا ہم کو شیبان نحوی نے خبر دی، انہوں نے فراش بن یحییٰ سے، انہوں نے عامر شعبی سے، انہوں نے عبداللہ بن عمرو بن عاص رضی اللہ عنہما سے، انہوں نے کہا کہ ایک گنوار ( نام نامعلوم ) نبی کریم صلی اللہ علیہ وسلم کے پاس آیا کہنے لگا: یا رسول اللہ! بڑے بڑے گناہ کون سے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے ساتھ شرک کرنا۔“ اس نے پوچھا پھر کون سا گناہ؟ آپ نے فرمایا ”ماں باپ کو ستانا۔“ پوچھا: پھر کون سا گناہ؟ آپ نے فرمایا ” «غموس‏ ‏‏.‏» قسم کھانا۔“ عبداللہ بن عمرو رضی اللہ عنہما نے کہا میں نے عرض کیا: یا رسول اللہ! «غموس‏ ‏‏.‏» قسم کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”جان بوجھ کر کسی مسلمان کا مال مار لینے کے لیے جھوٹی قسم کھانا۔“' WHERE id = 6665;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا مجھ سے ابن وہب نے، کہا کہ مجھ سے عمر بن محمد بن زید بن عبداللہ بن عمر نے، کہا ان سے ان کے والد نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے اور انہوں نے حروریہ کا ذکر کیا اور کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ وہ اسلام سے اس طرح باہر ہو جائیں گے جس طرح تیر کمان سے باہر ہو جاتا ہے۔' WHERE id = 6676;
UPDATE hadiths SET urdu = 'ہم سے سعید بن سلیمان نے بیان کیا، کہا ہم سے عباد نے، ان سے اسماعیل نے، انہوں نے قیس سے سنا، انہوں نے سعید بن زید رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے اپنے آپ کو اس حال میں پایا کہ اسلام لانے کی وجہ سے ( مکہ معظمہ میں ) عمر رضی اللہ عنہ نے مجھے باندھ دیا تھا اور اب جو کچھ تم نے عثمان رضی اللہ عنہ کے ساتھ کیا ہے اس پر اگر احد پہاڑ ٹکڑے ٹکڑے ہو جائے تو اسے ایسا ہی ہونا چاہئے۔' WHERE id = 6686;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، انہوں نے کہا ہم سے سعید بن سلیمان واسطی نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا، کہا ہم کو عبیداللہ بن ابی بکر بن انس نے خبر دی اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اپنے بھائی کی مدد کرو خواہ وہ ظالم ہو یا مظلوم۔“ ایک صحابی نے عرض کیا: یا رسول اللہ! جب وہ مظلوم ہو تو میں اس کی مدد کروں گا لیکن آپ کا کیا خیال ہے جب وہ ظالم ہو گا پھر میں اس کی مدد کیسے کروں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس وقت تم اسے ظلم سے روکنا کیونکہ یہی اس کی مدد ہے۔' WHERE id = 6696;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ ایک صحابی نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا کہ وہ خرید و فروخت میں دھوکہ کھا جاتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب تم کچھ خریدا کرو تو کہہ دیا کرو کہ اس میں کوئی دھوکہ نہ ہونا چاہئے۔' WHERE id = 6707;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم سے شعیب نے بیان کیا ‘ ان سے زہری نے ‘ ان سے عامر بن سعد بن ابی وقاص نے کہ انہوں نے اسامہ بن زید رضی اللہ عنہما سے سنا ‘ وہ سعد بن ابی وقاص رضی اللہ عنہ سے حدیث نقل کر رہے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے طاعون کا ذکر کیا اور فرمایا کہ یہ ایک عذاب ہے جس کے ذریعہ بعض امتوں کو عذاب دیا گیا تھا اس کے بعد اس کا کچھ حصہ باقی رہ گیا ہے اور وہ کبھی چلا جاتا ہے اور کبھی واپس آ جاتا ہے۔ پس جو شخص کسی سر زمین پر اس کے پھیلنے کے متعلق سنے تو وہاں نہ جائے لیکن اگر کوئی کسی جگہ ہو اور وہاں یہ وبا پھوٹ پڑے تو وہاں سے بھاگے بھی نہیں۔' WHERE id = 6717;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا ‘ کہا ہم سے زہیر نے بیان کیا ‘ کہا ہم سے یحییٰ نے جو سعید کے بیٹے ہیں ‘ کہا کہ میں نے ابوسلمہ رضی اللہ عنہ سے سنا ‘ کہا کہ میں نے ابوقتادہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( اچھے ) خواب اللہ کی طرف سے ہوتے ہیں اور برے خواب شیطان کی طرف سے ہوتے ہیں۔“' WHERE id = 6727;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن مختار نے بیان کیا، انہوں نے کہا ہم سے ثابت بنانی نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے مجھے خواب میں دیکھا تو اس نے واقعی دیکھا کیونکہ شیطان میری صورت میں نہیں آ سکتا اور مومن کا خواب نبوت کے چھیالیس حصوں میں سے ایک جزو ہوتا ہے۔“' WHERE id = 6737;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے ابوسلمہ نے اور ان سے ابوقتادہ انصاری رضی اللہ عنہ نے جو نبی کریم صلی اللہ علیہ وسلم کے صحابی اور آپ کے شہسواروں میں سے تھے انہوں نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھے خواب اللہ کی طرف سے ہوتے ہیں اور برے شیطان کی طرف سے پس تم میں جو کوئی برا خواب دیکھے جو اسے ناپسند ہو تو اس چاہئے کہ اپنی بائیں طرف تھوکے اور اس سے اللہ کی پناہ مانگے وہ اسے ہرگز نقصان نہیں پہنچا سکے گا۔' WHERE id = 6747;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن صباح نے بیان کیا، انہوں نے کہا ہم سے معتمر نے بیان کیا، انہوں نے کہا میں نے عوف سے سنا، ان سے محمد بن سیرین نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب قیامت قریب ہو گی تو مومن کا خواب جھوٹا نہیں ہو گا اور مومن کا خواب نبوت کے چھیالیس حصوں میں سے ایک حصہ ہے۔“ محمد بن سیرین رحمہ اللہ ( جو کہ علم تعبیر کے بہت بڑے عالم تھے ) نے کہا کہ نبوت کا حصہ جھوٹ نہیں ہو سکتا۔ ابوہریرہ رضی اللہ عنہ کہتے تھے کہ خواب تین طرح کے ہیں۔ دل کے خیالات، شیطان کا ڈرانا اور اللہ کی طرف سے خوشخبری۔ پس اگر کوئی شخص خواب میں بری چیز دیکھتا ہے تو اسے چاہئیے کہ اس کا ذکر کسی سے نہ کرے اور کھڑا ہو کر نماز پڑھنے لگے۔ محمد بن سیرین نے کہا کہ ابوہریرہ رضی اللہ عنہ خواب میں طوق کو ناپسند کرتے تھے اور قید دیکھنے کو اچھا سمجھتے تھے اور کہا گیا ہے کہ قید سے مراد دین میں ثابت قدمی ہے۔ اور قتادہ، یونس، ہشام اور ابوہلال نے ابن سیرین سے نقل کیا ہے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔ اور بعض نے یہ ساری روایت حدیث میں شمار کی ہے لیکن عوف کی روایت زیادہ واضح ہے اور یونس نے کہا کہ قید کے بارے میں روایت کو میں نبی کریم صلی اللہ علیہ وسلم کی حدیث ہی سمجھتا ہوں۔ ابوعبداللہ امام بخاری رحمہ اللہ نے کہا کہ طوق ہمیشہ گردنوں ہی میں ہوتے ہیں۔' WHERE id = 6758;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں حمزہ بن عبداللہ بن عمر نے خبر دی کہ عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے بیان کیا کہ میں سویا ہوا تھا کہ دودھ کا ایک پیالہ میرے پاس لایا گیا اور اس میں سے اتنا پیا کہ سیرابی کو میں نے ہر رگ و پے میں پایا۔ پھر میں نے اپنا بچا ہوا دودھ عمر کو دے دیا۔ لوگوں نے پوچھا: اے اللہ کے رسول! آپ نے اس کی تعبیر کیا کی؟ فرمایا کہ علم اس کی تعبیر ہے۔' WHERE id = 6768;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان نے، ان سے ایوب نے، ان سے عکرمہ نے، ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے ایسا خواب بیان کیا جو اس نے دیکھا نہ ہو تو اسے دو جَو کے دو دانوں کو قیامت کے دن جوڑنے کے لیے کہا جائے گا اور وہ اسے ہرگز نہیں کر سکے گا ( اس لیے مار کھاتا رہے گا ) اور جو شخص دوسرے لوگوں کی بات سننے کے لیے کان لگائے جو اسے پسند نہیں کرتے یا اس سے بھاگتے ہیں تو قیامت کے دن اس کے کانوں میں سیسہ پگھلا کر ڈالا جائے گا اور جو کوئی تصویر بنائے گا اسے عذاب دیا جائے گا اور اس پر زور دیا جائے گا کہ اس میں روح بھی ڈالے جو وہ نہیں کر سکے گا۔ اور سفیان نے کہا کہ ہم سے ایوب نے یہ حدیث موصولاً بیان کی اور قتیبہ بن سعید نے بیان کیا، ہم سے ابوعوانہ نے، ان سے قتادہ نے، ان سے عکرمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ جو اپنے خواب کے سلسلے میں جھوٹ بولے۔ اور شعبہ نے کہا، ان سے ابوہاشم الرمانی نے، انہوں نے عکرمہ سے سنا اور ان سے ابوہریرہ رضی اللہ عنہ نے ( کا قول موقوفاً ) جو شخص مورت بنائے، جو شخص جھوٹا خواب بیان کرے، جو شخص کان لگا کر دوسروں کی باتیں سنے۔ ہم سے اسحاق واسطی نے بیان کیا، کہا ہم سے خالد طحان نے بیان کیا، ان سے خالد حذاء نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جو کسی کی بات کان لگا کر سننے کے پیچھے لگا اور جس نے غلط خواب بیان کیا اور جس نے تصویر بنائی ( ایسی ہی حدیث نقل کی موقوفاً ابن عباس سے ) خالد حذاء کے ساتھ اس حدیث کو ہشام بن حسان فردوسی نے بھی عکرمہ سے، انہوں نے ابن عباس رضی اللہ عنہما سے موقوفاً روایت کیا۔' WHERE id = 6780;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے بیان کیا، ان سے جعد ابی عثمان نے بیان کیا، ان سے ابورجاء العطاردی نے بیان کیا، انہوں نے کہا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا، ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس نے اپنے امیر کی کوئی ناپسند چیز دیکھی تو اسے چاہے کہ صبر کرے اس لیے کہ جس نے جماعت سے ایک بالشت بھر جدائی اختیار کی اور اسی حال میں مرا تو وہ جاہلیت کی سی موت مرے گا۔“' WHERE id = 6792;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے، ان سے زبیر بن عدی نے بیان کیا کہ، ہم انس بن مالک رضی اللہ عنہ کے پاس آئے اور ان سے حجاج کے طرز عمل کی شکایت کی، انہوں نے کہا کہ صبر کرو کیونکہ تم پر جو دور بھی آتا ہے تو اس کے بعد آنے والا دور اس سے بھی برا ہو گا یہاں تک کہ تم اپنے رب سے جا ملو۔ میں نے یہ تمہارے نبی صلی اللہ علیہ وسلم سے سنا ہے۔' WHERE id = 6804;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، کہا ہم سے قرہ بن خالد نے بیان کیا، کہا ہم سے ابن سیرین نے بیان کیا، ان سے عبدالرحمٰن بن ابی بکرہ نے بیان کیا اور ایک دوسرے شخص ( حمید بن عبدالرحمٰن ) سے بھی سنا جو میری نظر میں عبدالرحمٰن بن ابی بکرہ سے اچھے ہیں اور ان سے ابوبکرہ رضی اللہ عنہ نے بیان کیا کہ رسول صلی اللہ علیہ وسلم نے لوگوں کو یوم النحر کو خطبہ دیا اور فرمایا ”تمہیں معلوم ہے یہ کون سا دن ہے؟“ لوگوں نے کہا کہ اللہ اور اس کے رسول کو زیادہ علم ہے۔ بیان کیا کہ ( اس کے بعد نبی کریم صلی اللہ علیہ وسلم کی خاموشی سے ) ہم یہ سمجھے کہ آپ صلی اللہ علیہ وسلم اس کا کوئی اور نام رکھیں گے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا ”کیا یہ قربانی کا دن ( یوم النحر ) نہیں ہے؟“ ہم نے عرض کیا: کیوں نہیں، یا رسول اللہ! آپ نے پھر پوچھا ”یہ کون سا شہر ہے؟ کیا یہ البلدہ ( مکہ مکرمہ ) نہیں ہے؟“ ہم نے عرض کیا: کیوں نہیں، یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پھر تمہارا خون، تمہارے مال، تمہاری عزت اور تمہاری کھال تم پر اسی طرح حرمت والے ہیں جس طرح اس دن کی حرمت اس مہینے اور اس شہر میں ہے۔ کیا میں نے پہنچا دیا؟“ ہم نے کہا جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے اللہ! گواہ رہنا۔ پس میرا یہ پیغام موجود لوگ غیر موجود لوگوں کو پہنچا دیں کیونکہ بہت سے پہنچانے والے اس پیغام کو اس تک پہنچائیں گے جو اس کو زیادہ محفوظ رکھنے والا ہو گا۔“ چنانچہ ایسا ہی ہوا اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے بعد کافر نہ ہو جانا کہ بعض بعض کی گردن مارنے لگو۔“ پھر جب وہ دن آیا جب عبداللہ عمرو بن حضرمی کو جاریہ بن قدامہ نے ایک مکان میں گھیر کر جلا دیا تو جاریہ نے اپنے لشکر والوں سے کہا زرا ابوبکرہ کو تو جھانکو وہ کس خیال میں ہے۔ انہوں نے کہا یہ ابوبکرہ موجود ہیں تم کو دیکھ رہے ہیں۔ عبدالرحمٰن بن ابی بکرہ کہتے ہیں مجھ سے میری والدہ ہالہ بنت غلیظ نے کہا کہ ابوبکرہ نے کہا اگر یہ لوگ ( تین جاریہ کے لشکر والے ) میرے گھر میں بھی گھس آئیں اور مجھ کو مارنے لگیں تو میں ان پر ایک بانس کی چھڑی بھی نہیں چلاؤں گا۔' WHERE id = 6814;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے خبر دی، انہیں عبدالرحمٰن بن عبداللہ بن ابی صعصعہ نے، انہیں ان کے والد نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”وہ وقت قریب ہے کہ مسلمان کا بہترین مال وہ بکریاں ہوں گی جنہیں وہ لے کر پہاڑی کی چوٹیوں اور بارش برسنے کی جگہوں پر چلا جائے گا۔ وہ فتنوں سے اپنے دین کی حفاظت کے لیے وہاں بھاگ کر آ جائے گا۔“' WHERE id = 6824;
UPDATE hadiths SET urdu = 'ہم سے بشر بن خالد نے بیان کیا، کہا ہم کو جعفر نے خبر دی، انہیں شعبہ نے، انہیں سلیمان نے کہ میں نے ابووائل سے سنا، انہوں نے کہا کہ اسامہ رضی اللہ عنہ سے کہا گیا کہ آپ ( عثمان بن عفان رضی اللہ عنہ ) سے گفتگو کیوں نہیں کرتے ( کہ عام مسلمانوں کی شکایات کا خیال رکھیں ) انہوں نے کہا کہ میں نے ( خلوت میں ) ان سے گفتگو کی ہے لیکن ( فتنہ کے ) دروازہ کو کھولے بغیر کہ اس طرح میں سب سے پہلے اس دروازہ کو کھولنے والا ہوں گا میں ایسا آدمی نہیں ہوں کہ کسی شخص سے جب وہ دو آدمیوں پر امیر بنا دیا جائے یہ کہوں کہ تو سب سے بہتر ہے۔ جبکہ میں رسول اللہ صلی اللہ علیہ وسلم سے سن چکا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک شخص کو ( قیامت کے دن ) لایا جائے گا اور اسے آگ میں ڈال دیا جائے گا۔ پھر وہ اس میں اس طرح چکی پیسے گا جیسے گدھا پیستا ہے۔ پھر دوزخ کے لوگ اس کے چاروں طرف جمع ہو جائیں گے اور کہیں گے، اے فلاں! کیا تم نیکیوں کا حکم کرتے اور برائیوں سے روکا نہیں کرتے تھے؟ وہ شخص کہے گا کہ میں اچھی بات کے لیے کہتا تو ضرور تھا لیکن خود نہیں کرتا تھا اور بری بات سے روکتا بھی تھا لیکن خود کرتا تھا۔' WHERE id = 6834;
UPDATE hadiths SET urdu = 'ہم سے خلاد نے بیان کیا، انہوں نے کہا ہم سے مسعر نے بیان کیا، ان سے حبیب بن ابی ثابت نے بیان کیا، ان سے ابوالشعثاء نے بیان کیا اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں نفاق تھا آج تو ایمان کے بعد کفر اختیار کرنا ہے۔' WHERE id = 6846;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، انہوں نے کہا ہم سے شیبان نے بیان کیا، ان سے یحییٰ نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دجال آئے گا اور مدینہ کے ایک کنارے قیام کرے گا، پھر مدینہ تین مرتبہ کانپے گا اور اس کے نتیجے میں ہر کافر اور منافق نکل کر اس کی طرف چلا جائے گا۔“' WHERE id = 6856;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے یزید بن ہارون نے بیان کیا، انہوں نے کہا ہم کو شعبہ نے خبر دی، انہیں قتادہ نے، انہیں انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”دجال مدینہ تک آئے گا تو یہاں فرشتوں کو اس کی حفاظت کرتے ہوئے پائے گا چنانچہ نہ دجال اس کے قریب آ سکتا ہے اور نہ طاعون، ان شاءاللہ۔“' WHERE id = 6866;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم سے فرمایا ”مسلمان کے لیے امیر کی بات سننا اور اس کی اطاعت کرنا ضروری ہے، ان چیزوں میں بھی جنہیں وہ پسند کرے اور ان میں بھی جنہیں وہ ناپسند کرے، جب تک اسے معصیت کا حکم نہ دیا جائے۔ پھر جب اسے معصیت کا حکم دیا جائے تو نہ سننا باقی رہتا ہے نہ اطاعت کرنا۔“' WHERE id = 6876;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، کہا ہم کو عبدالصمد نے خبر دی، کہا ہم سے شعبہ نے، کہا ہم سے ثابت البنانی نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کہ وہ اپنے گھر کی ایک عورت سے کہہ رہے تھے فلانی کو پہچانتی ہو؟ انہوں نے کہا کہ ہاں۔ بتلایا کہ نبی کریم صلی اللہ علیہ وسلم اس کے پاس سے گزرے اور وہ ایک قبر کے پاس رو رہی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ سے ڈر اور صبر کر۔ اس عورت نے جواب دیا۔ آپ میرے پاس سے چلے جاؤ، میری مصیبت آپ پر نہیں پڑی ہے۔ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم وہاں سے ہٹ گئے اور چلے گئے۔ پھر ایک صاحب ادھر سے گزرے اور ان سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم نے تم سے کیا کہا تھا؟ اس عورت نے کہا کہ میں نے انہیں پہچانا نہیں۔ ان صاحب نے کہا کہ وہ رسول اللہ صلی اللہ علیہ وسلم تھے۔ پھر وہ عورت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی۔ انہوں نے آپ کے یہاں کوئی دربان نہیں پایا پھر عرض کیا: یا رسول اللہ! میں نے آپ کو پہچانا نہیں ( تھا ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ صبر تو صدمہ کے شروع میں ہی ہوتا ہے۔' WHERE id = 6886;
UPDATE hadiths SET urdu = 'اور زہری سے روایت ہے انہوں نے بیان کیا کہ مجھ سے سالم بن عبداللہ نے بیان کیا، ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ میں نے عمر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مجھے عطا کرتے تھے تو میں کہتا کہ آپ اسے دے دیں جو اس کا مجھ سے زیادہ ضرورت مند ہو، پھر آپ صلی اللہ علیہ وسلم نے مجھے ایک مرتبہ مال دیا اور میں نے کہا کہ آپ اسے ایسے شخص کو دے دیں جو اس کا مجھ سے زیادہ ضرورت مند ہو تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے لے لو اور اس کے مالک بننے کے بعد اس کا صدقہ کر دو۔ یہ مال جب تمہیں اس طرح ملے کہ تم اس کے خواہشمند نہ ہو اور نہ اسے تم نے مانگا ہو تو اسے لے لیا کرو اور جو اس طرح نہ ملے اس کے پیچھے نہ پڑا کرو۔' WHERE id = 6896;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے زہری نے، انہوں نے عروہ سے سنا، انہیں ابوحمید ساعدی رضی اللہ عنہ نے خبر دی، انہوں نے بیان کیا کہ بنی اسد کے ایک شخص کو صدقہ کی وصولی کے لیے رسول اللہ صلی اللہ علیہ وسلم نے تحصیلدار بنایا، ان کا نام ابن الاتیتہ تھا۔ جب وہ لوٹ کر آئے تو انہوں نے کہا کہ یہ آپ لوگوں کا ہے اور یہ مجھے ہدیہ میں دیا گیا ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم منبر پر کھڑے ہوئے، سفیان ہی نے یہ روایت بھی کی کہ ”پھر آپ منبر پر چڑھے“ پھر اللہ کی حمد و ثنا بیان کی اور فرمایا کہ اس عامل کا کیا حال ہو گا جسے ہم تحصیل کے لیے بھیجتے ہیں پھر وہ آتا ہے اور کہتا ہے کہ یہ مال تمہارا ہے اور یہ میرا ہے۔ کیوں نہ وہ اپنے باپ یا ماں کے گھر بیٹھا رہا اور دیکھا ہوتا کہ اسے ہدیہ دیا جاتا ہے یا نہیں۔ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے، عامل جو چیز بھی ( ہدیہ کے طور پر ) لے گا اسے قیامت کے دن اپنی گردن پر اٹھائے ہوئے آئے گا۔ اگر اونٹ ہو گا تو وہ اپنی آواز نکالتا آئے گا، اگر گائے ہو گی تو وہ اپنی آواز نکالتی آئے گی، بکری ہو گی تو وہ بولتی آئے گی، پھر آپ نے اپنے ہاتھ اٹھائے۔ یہاں تک کہ ہم نے آپ کے دونوں بغلوں کی سفیدی دیکھی اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے پہنچا دیا! تین مرتبہ یہی فرمایا۔ سفیان بن عیینہ نے بیان کیا کہ یہ حدیث ہم سے زہری نے بیان کی اور ہشام نے اپنے والد سے روایت کی، ان سے ابوحمید رضی اللہ عنہ نے بیان کیا کہ میرے دونوں کانوں نے سنا اور دونوں آنکھوں نے دیکھا اور زید بن ثابت صحابی رضی اللہ عنہ سے بھی پوچھ کیونکہ انہوں نے بھی یہ حدیث میرے ساتھ سنی ہے۔ سفیان نے کہا زہری نے یہ لفظ نہیں کہا کہ میرے کانوں نے سنا۔ امام بخاری رحمہ اللہ نے کہا حدیث میں «خوار‏» کا لفظ ہے یعنی گائے کی آواز یا «جؤار» کا لفظ جو لفظ «تجأرون» سے نکلا ہے جو سورۃ مومنون میں ہے یعنی گائے کی آواز نکالتے ہوں گے۔' WHERE id = 6906;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن مسلم نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا، انہوں نے کہا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک لشکر بھیجا اور اس کا امیر اسامہ بن زید رضی اللہ عنہما کو بنایا لیکن ان کی سرداری پر طعن کیا گیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اگر آج تم ان کی امارت کو مطعون قرار دیتے ہو تو تم نے اس سے پہلے اس کے والد ( زید رضی اللہ عنہ ) کی امارت کو بھی مطعون قرار دیا تھا اور اللہ کی قسم! وہ امارت کے لیے سزاوار تھے اور وہ مجھے تمام لوگوں میں سب سے زیادہ عزیز تھے اور یہ ( اسامہ رضی اللہ عنہ ) ان کے بعد سب سے زیادہ مجھے عزیز ہے۔' WHERE id = 6917;
UPDATE hadiths SET urdu = 'ہم سے عمر بن علی نے بیان کیا، انہوں نے کہا ہم سے خالد بن حارث نے بیان کیا، انہوں نے کہا ہم سے حمید نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم سردی میں صبح کے وقت باہر نکلے اور مہاجرین اور انصار خندق کھود رہے تھے، پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے اللہ! خیر تو آخرت ہی کی خیر ہے۔ پس انصار و مہاجرین کی مغفرت کر دے۔“ اس کا جواب لوگوں نے دیا کہ ہم وہ ہیں جنہوں نے محمد صلی اللہ علیہ وسلم سے جہاد پر بیعت کی ہے ہمیشہ کے لیے جب تک وہ زندہ ہیں۔' WHERE id = 6929;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی انہیں زہری نے (دوسری سند) اور لیث نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، کہا مجھ کو ابوادریس خولانی نے خبر دی، انہوں نے عبادہ بن صامت رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم مجلس میں موجود تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مجھ سے بیعت کرو کہ اللہ کے ساتھ کسی کو شریک نہیں ٹھہراؤ گے، چوری نہیں کرو گے، زنا نہیں کرو گے، اپنی اولاد کو قتل نہیں کرو گے اور اپنی طرف سے گھڑ کر کسی پر بہتان نہیں لگاؤ گے اور نیک کام میں نافرمانی نہیں کرو گے۔ پس جو کوئی تم میں سے اس وعدے کو پورا کرے اس کا ثواب اللہ کے یہاں اسے ملے گا اور جو کوئی ان کاموں میں سے کسی برے کام کو کرے گا اس کی سزا اسے دنیا میں ہی مل جائے گی تو یہ اس کے لیے کفارہ ہو گا اور جو کوئی ان میں سے کسی برائی کا کام کرے گا اور اللہ اسے چھپا لے گا تو اس کا معاملہ اللہ کے حوالہ ہے۔ چاہے تو اس کی سزا دے اور چاہے اسے معاف کر دے۔“ چنانچہ ہم نے اس پر نبی کریم صلی اللہ علیہ وسلم سے بیعت کی۔ بیعت اقرار کو کہتے ہیں جو خلیفہ اسلام کے ہاتھ پر ہاتھ رکھ کر کیا جائے یا پھر کسی نیک صالح انسان کے ہاتھ پر ہو۔' WHERE id = 6941;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبدالرحمٰن بن عبداللہ بن کعب بن مالک نے کہ عبداللہ بن کعب بن مالک، کعب بن مالک رضی اللہ عنہ کے نابینا ہو جانے کے زمانے میں ان کے سب لڑکوں میں یہی راستے میں ان کے ساتھ چلتے تھے، ( انہوں ) نے بیان کیا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا، انہوں نے کہا کہ جب وہ غزوہ تبوک میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نہیں جا سکتے تھے، پھر انہوں نے اپنا پورا واقعہ بیان کیا اور نبی کریم صلی اللہ علیہ وسلم نے مسلمانوں کو ہم سے گفتگو کرنے سے روک دیا تھا تو ہم پچاس دن اسی حالت میں رہے، پھر نبی کریم صلی اللہ علیہ وسلم نے اعلان کیا کہ اللہ نے ہماری توبہ قبول کر لی ہے۔' WHERE id = 6952;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں ابی عبید نے جن کا نام سعد بن عبید ہے، عبدالرحمٰن بن ازہر کے مولیٰ کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص تم میں سے موت کی آرزو نہ کرے، اگر وہ نیک ہے تو ممکن ہے نیکی میں اور زیادہ ہو اور اگر برا ہے تو ممکن ہے اس سے توبہ کر لے۔“' WHERE id = 6962;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، انہوں نے کہا ہم سے وہیب نے بیان کیا، ان سے عمرو بن یحییٰ نے، ان سے عباد بن تمیم نے اور ان سے عبداللہ بن زید رضی اللہ عنہ نے بیان کیا کہ اگر ہجرت نہ ہوتی تو میں انصار کا ایک فرد ہوتا اور اگر لوگ کسی وادی یا گھاٹی میں چلیں تو میں انصار کی وادی یا گھاٹی میں چلوں گا۔ اس روایت کی متابعت ابوالتیاح نے کی، ان سے انس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے۔ اس میں بھی درے کا ذکر ہے۔' WHERE id = 6972;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے خالد بن مہران نے بیان کیا، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہر امت میں ایک امانت دار ہوتا ہے اور اس امت کے امانت دار ابوعبیدہ ابن الجراح رضی اللہ عنہ ہیں۔“' WHERE id = 6982;
UPDATE hadiths SET urdu = 'ہم سے محمد بن الولید نے بیان کیا، کہا ہم سے محمد بن جعفر نے، کہا ہم سے شعبہ نے، ان سے توبہ بن کیسان العنبری نے بیان کیا کہ مجھ سے شعبی نے کہا کہ تم نے دیکھا امام حسن بصری نبی کریم صلی اللہ علیہ وسلم سے کتنی حدیث ( مرسلاً ) روایت کرتے ہیں۔ میں ابن عمر رضی اللہ عنہما کی خدمت میں تقریباً اڑھائی سال رہا لیکن میں نے ان کو نبی کریم صلی اللہ علیہ وسلم سے اس حدیث کے سوا اور کوئی حدیث بیان کرتے نہیں سنا۔ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے صحابہ میں سے کئی اصحاب جن میں سعد رضی اللہ عنہ بھی تھے ( دستر خوان پر بیٹھے ہوئے تھے ) لوگوں نے گوشت کھانے کے لیے ہاتھ بڑھایا تو ازواج مطہرات میں سے ایک زوجہ مطہرہ ام المؤمنین میمونہ رضی اللہ عنہا نے آگاہ کیا کہ یہ سانڈے کا گوشت ہے۔ سب لوگ کھانے سے رک گئے، پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کھاؤ ( آپ صلی اللہ علیہ وسلم نے «كلوا» فرمایا یا «اطعموا» ) اس لیے کہ حلال ہے یا فرمایا کہ اس کھانے میں کوئی حرج نہیں البتہ یہ جانور میری خوراک نہیں ہے، مجھ کو اس کے کھانے سے ایک قسم کی نفرت آتی ہے۔' WHERE id = 6993;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم کو عمرو بن مرہ نے خبر دی، کہا میں نے مرۃ الہمدانی سے سنا، بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ سب سے اچھی بات کتاب اللہ اور سب سے اچھا طریقہ صلی اللہ علیہ وسلم کا طریقہ ہے اور سب سے بری نئی بات ( بدعت ) پیدا کرنا ہے ( دین میں ) اور بلاشبہ جس کا تم سے وعدہ کیا جاتا ہے وہ آ کر رہے گی اور تم پروردگار سے بچ کر کہیں نہیں جا سکتے۔' WHERE id = 7003;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، کہا ہم سے ابواسامہ حماد بن اسامہ نے بیان کیا، ان سے برید بن ابی بردہ نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے کچھ چیزوں کے متعلق پوچھا گیا جنہیں آپ نے ناپسند کیا جب لوگوں نے بہت زیادہ پوچھنا شروع کر دیا تو آپ صلی اللہ علیہ وسلم ناراض ہوئے اور فرمایا: پوچھو! اس پر ایک صحابی کھڑا ہوا اور پوچھا: یا رسول اللہ! میرے والد کون ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے والد حذافہ ہیں۔ پھر دوسرا صحابی کھڑا ہوا اور پوچھا میرے والد کون ہیں؟ فرمایا کہ تمہارے والد شیبہ کے مولیٰ سالم ہیں۔ پھر جب عمر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کے چہرہ پر غصہ کے آثار محسوس کئے تو عرض کیا ہم اللہ عزوجل کی بارگاہ میں آپ کو غصہ دلانے سے توبہ کرتے ہیں۔' WHERE id = 7015;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے مسلم نے، ان سے مسروق نے، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے کوئی کام کیا جس سے بعض لوگوں نے پرہیز کرنا اختیار کیا۔ جب نبی کریم صلی اللہ علیہ وسلم کو اس کی خبر پہنچی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان لوگوں کا کیا حال ہو گا جو ایسی چیز سے پرہیز کرتے ہیں جو میں کرتا ہوں، واللہ! میں ان سے زیادہ اللہ کے متعلق علم رکھتا ہوں اور ان سے زیادہ خشیت رکھتا ہوں۔' WHERE id = 7025;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسماعیل نے، ان سے قیس نے، ان سے مغیرہ بن شعبہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میری امت کا ایک گروہ ہمیشہ غالب رہے گا ( اس میں علمی و دینی غلبہ بھی داخل ہے ) یہاں تک کہ قیامت آ جائے گی اور وہ غالب ہی رہیں گے۔“' WHERE id = 7035;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، کہا ہم سے معمر بن راشد نے بیان کیا، ان سے زہری نے، ان سے عبیداللہ بن عبداللہ نے، ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں عبدالرحمٰن بن عوف رضی اللہ عنہ کو ( قرآن مجید ) پڑھایا کرتا تھا۔ جب وہ آخری حج آیا جو عمر رضی اللہ عنہ نے کیا تھا تو عبدالرحمٰن نے منیٰ میں مجھ سے کہا کاش تم امیرالمؤمنین کو آج دیکھتے جب ان کے پاس ایک شخص آیا اور کہا کہ فلاں شخص کہتا ہے کہ اگر امیرالمؤمنین کا انتقال ہو جائے تو ہم فلاں سے بیعت کر لیں گے۔ یہ سن کر عمر رضی اللہ عنہ نے کہا کہ میں آج سہ پہر کو کھڑے ہو کر لوگوں کو خطبہ سناؤں گا اور ان کو ڈراؤں کا جو ( عام مسلمانوں کے حق کو ) غصب کرنا چاہتے ہیں اور خود اپنی رائے سے امیر منتخب کرنے کا ارادہ رکھتے ہیں۔ میں نے عرض کیا کہ آپ ایسا نہ کریں کیونکہ موسم حج میں ہر طرح کے ناواقف اور معمولی لوگ جمع ہو جاتے ہیں۔ یہ سب کثرت سے آپ کی مجلس میں جمع ہو جائیں گے اور مجھے ڈر ہے کہ وہ آپ کی بات کا صحیح مطلب نہ سمجھ کر کچھ اور معنیٰ نہ کر لیں اور اسے منہ در منہ اڑاتے پھریں۔ اس لیے ابھی توقف کیجئے۔ جب آپ مدینے پہنچیں جو دار الہجرت اور دار السنہ ہے تو وہاں آپ کے مخاطب رسول اللہ صلی اللہ علیہ وسلم کے صحابہ، مہاجرین و انصار خالص ایسے ہی لوگ ملیں گے وہ آپ کی بات کو یاد رکھیں گے اور اس کا مطلب بھی ٹھیک بیان کریں گے۔ اس پر امیرالمؤمنین نے کہا کہ واللہ! میں مدینہ پہنچ کر جو پہلا خطبہ دوں گا اس میں اس کا بیان کروں گا۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ پھر ہم مدینے آئے تو عمر رضی اللہ عنہ جمعہ کے دن دوپہر ڈھلے برآمد ہوئے اور خطبہ سنایا۔ انہوں نے کہا: اللہ تعالیٰ نے محمد صلی اللہ علیہ وسلم کو سچا رسول بنا کر بھیجا اور آپ پر قرآن اتارا، اس قرآن میں رجم کی آیت بھی تھی۔' WHERE id = 7046;
UPDATE hadiths SET urdu = 'ہم سے عمر بن علی نے بیان کیا، انہوں نے کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، انہوں نے کہا ہم سے مالک نے بیان کیا، ان سے خبیب بن عبدالرحمٰن نے بیان کیا، ان سے حفص بن عاصم نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میرے حجرہ اور میرے منبر کے درمیان کی زمین جنت کے باغوں میں سے ایک باغ ہے اور میرا یہ منبر میرے حوض پر ہو گا۔“' WHERE id = 7057;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ اور مجھ سے محمد بن سلام بیکندی نے بیان کیا، کہا ہم کو عتاب بن بشیر نے خبر دی، انہیں اسحاق ابن ابی راشد نے، انہیں زہری نے، انہیں زین العابدین علی بن حسین رضی اللہ عنہ نے خبر دی اور انہیں ان کے والد حسین بن علی رضی اللہ عنہ نے خبر دی کہ علی بن ابی طالب رضی اللہ عنہ نے بیان کیا کہ ان کے اور فاطمہ بنت رسول اللہ علیم السلام والصلٰوۃ کے گھر ایک رات نبی کریم صلی اللہ علیہ وسلم تشریف لائے اور فرمایا کہ تم لوگ تہجد کی نماز نہیں پڑھتے۔ علی رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! ہماری جانیں اللہ کے ہاتھ میں ہیں پس جب وہ ہمیں اٹھانا چاہے تو ہم کو اٹھا دے گا۔ جوں ہی میں نے نبی کریم صلی اللہ علیہ وسلم سے یہ کہا تو آپ پیٹھ موڑ کر واپس جانے لگے اور کوئی جواب نہیں دیا لیکن واپس جاتے ہوئے آپ اپنی ران پر ہاتھ مار رہے تھے اور کہہ رہے تھے «وكان الإنسان أكثر شىء جدلا‏» ”اور انسان بڑا ہی جھگڑالو ہے“ اگر کوئی تمہارے پاس رات میں آئے تو «طارق» کہلائے گا اور قرآن میں جو «والطارق» کا لفظ آیا ہے اس سے مراد ستارہ ہے اور «ثاقب» بمعنی چمکتا ہوا۔ عرب لوگ آگ جلانے والے سے کہتے ہیں «ثقب نارك» یعنی آگ روشن کر۔ اس سے لفظ «ثاقب» ہے۔' WHERE id = 7068;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عبداللہ بن وہب نے بیان کیا، کہا مجھے یونس نے خبر دی، انہیں ابن شہاب نے کہا کہ مجھ کو عطاء بن ابی رباح نے خبر دی، انہیں جابر بن عبداللہ رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جو شخص کچی لہسن یا پیاز کھائے وہ ہم سے دور رہے یا ( یہ فرمایا کہ ) ہماری مسجد سے دور رہے اور اپنے گھر میں بیٹھا رہے ( یہاں تک کہ وہ بو رفع ہو جائے ) اور آپ کے پاس ایک طباق لایا گیا جس میں سبزیاں تھیں۔ نبی کریم صلی اللہ علیہ وسلم نے اس میں بو محسوس کی، پھر آپ کو اس میں رکھی ہوئی سبزیوں کے متعلق بتایا گیا تو آپ نے اپنے بعض صحابی کی طرف جو آپ کے ساتھ تھے اشارہ کر کے فرمایا کہ ان کے پاس لے جاؤ لیکن جب ان صحابی نے اسے دیکھا تو انہوں نے بھی اسے کھانا پسند نہیں کیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر ان سے فرمایا کہ تم کھا لو کیونکہ میں جس سے سرگوشی کرتا ہوں تم اس سے نہیں کرتے۔ ( آپ کی مراد فرشتوں سے تھی ) سعید بن کثیر بن عفیر نے جو امام بخاری رحمہ اللہ کے شیخ ہیں، عبداللہ بن وہب سے اس حدیث میں یوں روایت کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس ہانڈی لائی گئی جس میں ترکاریاں تھیں اور لیث و ابوصفوان عبداللہ بن سعید اموی نے بھی اس حدیث کو یونس سے روایت کیا لیکن انہوں نے ہانڈی کا قصہ نہیں بیان کیا، اب میں نہیں جانتا کہ ہانڈی کا قصہ حدیث میں داخل ہے یا زہری نے بڑھا دیا ہے۔' WHERE id = 7079;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے، کہا کہ مجھ سے عروہ بن مسیب اور علقمہ بن وقاص اور عبیداللہ بن عبداللہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے کہ جب تہمت لگانے والوں نے ان پر تہمت لگائی تھی اور رسول اللہ صلی اللہ علیہ وسلم نے علی بن ابی طالب، اسامہ بن زید رضی اللہ عنہما کو بلایا کیونکہ اس معاملہ میں وحی اس وقت تک نہیں آئی تھی اور نبی کریم صلی اللہ علیہ وسلم اپنی اہل خانہ کو جدا کرنے کے سلسلہ میں ان سے مشورہ لینا چاہتے تھے تو اسامہ رضی اللہ عنہ نے وہی مشورہ دیا جو انہیں معلوم تھا یعنی نبی کریم صلی اللہ علیہ وسلم کی اہل خانہ کی برات کا لیکن علی رضی اللہ عنہ نے کہا کہ اللہ تعالیٰ نے آپ پر کوئی پابندی تو عائد نہیں کی ہے اور اس کے سوا اور بہت سی عورتیں ہیں، باندی سے آپ دریافت فرما لیں، وہ آپ سے صحیح بات بتا دے گی۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے پوچھا کہ کیا تم نے کوئی ایسی بات دیکھی ہے جس سے شبہ ہوتا ہے۔ انہوں نے کہا کہ میں نے اس کے سوا اور کچھ نہیں دیکھا کہ وہ کم عمر لڑکی ہیں، آٹا گوندھ کر بھی سو جاتی ہیں اور پڑوس کی بکری آ کر اسے کھا جاتی ہے، اس کے بعد نبی کریم صلی اللہ علیہ وسلم منبر پر کھڑے ہوئے اور فرمایا، اے مسلمانو! میرے معاملے میں اس سے کون نمٹے گا جس کی اذیتیں اب میرے اہل خانہ تک پہنچ گئی ہیں۔ اللہ کی قسم! میں نے ان کے بارے میں بھلائی کے سوا اور کچھ نہیں جانا ہے۔ پھر آپ صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا کی پاک دامنی کا قصہ بیان کیا اور ابواسامہ نے ہشام بن عروہ سے بیان کیا۔' WHERE id = 7089;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا ہم سے سلیمان بن بلال نے بیان کیا، انہوں نے کہا مجھ سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”غیب کی پانچ کنجیاں ہیں، جنہیں اللہ کے سوا اور کوئی نہیں جانتا۔ اللہ کے سوا اور کوئی نہیں جانتا کہ رحم مادر میں کیا ہے، اللہ کے سوا اور کوئی نہیں جانتا کہ کل کیا ہو گا، اللہ کے سوا اور کوئی نہیں جانتا کہ بارش کب آئے گی، اللہ کے سوا اور کوئی نہیں جانتا کہ کس جگہ کوئی مرے گا اور اللہ کے سوا کوئی نہیں جانتا کہ قیامت کب قائم ہو گی۔“' WHERE id = 7099;
UPDATE hadiths SET urdu = 'مجھ سے سعید بن سلیمان نے بیان کیا، ان سے عبداللہ ابن مبارک نے بیان کیا، ان سے موسیٰ بن عقبہ نے، ان سے سالم بن عبداللہ بن عمر نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم قسم اس طرح کھاتے ”قسم اس کی جو دلوں کا پھیر دینے والا ہے۔“' WHERE id = 7110;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا ہم سے ورقاء نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اپنے باپ دادوں کی قسم نہ کھایا کرو، اگر کسی کو قسم کھانی ہی ہو تو اللہ کے نام کی قسم کھائے ورنہ خاموش رہے۔“' WHERE id = 7120;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کی کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کا ہاتھ بھرا ہوا ہے، اسے رات دن کی بخشش بھی کم نہیں کرتی، آپ صلی اللہ علیہ وسلم نے فرمایا کیا تمہیں معلوم ہے کہ جب اس نے آسمان و زمین پیدا کئے ہیں اس نے کتنا خرچ کیا ہے اس نے بھی اس میں کوئی کمی نہیں پیدا کی جو اس کے ہاتھ میں ہے اور فرمایا کہ اس کا عرش پانی پر ہے اور اس کے دوسرے ہاتھ میں ترازو ہے، جسے وہ جھکاتا اور اٹھاتا رہتا ہے۔' WHERE id = 7130;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا مجھ سے محمد بن فلیح نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے بیان کیا، انہوں نے کہا مجھ سے ہلال نے بیان کیا، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو اللہ اور اس کے رسول پر ایمان لایا، نماز قائم کی، رمضان کے روزے رکھے تو اللہ پر حق ہے کہ اسے جنت میں داخل کرے۔ خواہ اس نے ہجرت کی ہو یا وہیں مقیم رہا ہو جہاں اس کی پیدائش ہوئی تھی۔“ صحابہ نے کہا: یا رسول اللہ! کیا ہم اس کی اطلاع لوگوں کو نہ دے دیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جنت میں سو درجے ہیں جنہیں اللہ تعالیٰ نے اپنے راستے میں جہاد کرنے والوں کے لیے تیار کیا ہے، ہر دو درجوں کے درمیان اتنا فاصلہ ہے جتنا آسمان و زمین کے درمیان ہے۔ پس جب تم اللہ سے سوال کرو تو فردوس کا سوال کرو کیونکہ وہ درمیانہ درجے کی جنت ہے اور بلند ترین اور اس کے اوپر رحمان کا عرش ہے اور اسی سے جنت کی نہریں نکلتی ہیں۔' WHERE id = 7141;
UPDATE hadiths SET urdu = 'ہم سے یوسف بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے عاصم بن یوسف الیربوعی نے بیان کیا، ان سے ابوشہاب نے بیان کیا، ان سے اسماعیل بن ابی خالد نے بیان کیا، ان سے قیس بن ابی حازم نے بیان کیا اور ان سے جریر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم اپنے رب کو صاف صاف دیکھو گے۔' WHERE id = 7152;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے ابوصالح سمان نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تین آدمی ایسے ہیں جن سے اللہ تعالیٰ قیامت کے دن بات نہیں کرے گا اور نہ ان کی طرف رحمت سے دیکھے گا۔ ایک وہ جس نے کسی سامان کے متعلق قسم کھائی کہ اسے اس نے اتنے میں خریدا ہے، حالانکہ وہ جھوٹا ہے۔ دوسرا وہ شخص جس نے عصر کے بعد جھوٹی قسم اس لیے کھائی کہ کسی مسلمان کا مال ناحق مار لے اور تیسرا وہ شخص جس نے ضرورت سے فالتو پانی مانگنے والے کو نہیں دیا تو اللہ تعالیٰ قیامت کے دن اس سے کہے گا کہ جس طرح تو نے اس زائد ضرورت، فالتو چیز سے دوسرے کو روکا جسے تیرے ہاتھوں نے بنایا بھی نہیں تھا، میں بھی تجھے اپنا فضل نہیں دوں گا۔' WHERE id = 7162;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن جعفر نے بیان کیا، کہا ہم سے وکیع بن جراح نے بیان کیا، ان سے اعمش نے، ان سے ابراہیم نخعی نے، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ مدینہ کے ایک کھیت میں جا رہا تھا اور آپ صلی اللہ علیہ وسلم ایک کھجور کی چھڑی پر ٹیکا لیتے جاتے تھے۔ پھر آپ یہودیوں کی ایک جماعت سے گزرے تو ان میں سے بعض نے بعض سے کہا کہ ان سے روح کے متعلق پوچھو اور بعض نے کہا کہ اس کے متعلق مت پوچھو۔ آخر انہوں نے پوچھا تو آپ چھڑی پر ٹیک لگا کر کھڑے ہو گئے اور میں آپ کے پیچھے تھا۔ میں نے سمجھ لیا کہ آپ پر وحی نازل ہو رہی ہے۔ چنانچہ آپ نے یہ آیت پڑھی «ويسألونك عن الروح قل الروح من أمر ربي وما أوتيتم من العلم إلا قليلا» ”اور لوگ آپ سے روح کے متعلق پوچھتے ہیں، کہہ دیجئیے کہ روح میرے رب کے امر «مٰن» سے اور تمہیں علم بہت تھوڑا دیا گیا ہے۔“ اس پر بعض یہودیوں نے اپنے ساتھیوں سے کہا کہ ہم نے کہا نہ تھا کہ مت پوچھو۔' WHERE id = 7172;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان نے بیان کیا، انہوں نے کہا ہم سے فلیح بن سلیمان نے، انہوں نے کہا ہم سے ہلال بن علی نے، ان سے عطاء بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مومن کی مثال کھیت کے نرم پودے کی سی ہے کہ جدھر ہوا چلتی ہے تو اس کے پتے ادھر جھک جاتے ہیں اور جب ہوا رک جاتی ہے تو پتے بھی برابر ہو جاتے ہیں۔ اسی طرح مومن آزمائشوں میں بچایا جاتا ہے لیکن کافر کی مثال شمشاد کے سخت درخت جیسی ہے کہ ایک حالت پر کھڑا رہتا ہے یہاں تک کہ اللہ جب چاہتا ہے اسے اکھاڑ دیتا ہے۔“' WHERE id = 7182;
UPDATE hadiths SET urdu = 'ہم سے محمد بن العلاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کے پاس کوئی مانگنے والا آتا یا کوئی ضرورت مند آتا تو آپ صلی اللہ علیہ وسلم فرماتے کہ اس کی سفارش کرو تاکہ تمہیں بھی ثواب ملے، اللہ اپنے رسول کی زبان پر وہی جاری کرتا ہے جو چاہتا ہے۔' WHERE id = 7192;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے مالک نے، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تمہارے پاس رات اور دن کے فرشتے یکے بعد دیگرے آتے ہیں اور عصر اور فجر کی نمازیوں میں دو وقت کے فرشتے اکٹھے ہوتے ہیں۔ پھر جب وہ فرشتے اوپر جاتے ہیں جنہوں نے رات تمہارے ساتھ گزاری ہے تو اللہ تعالیٰ ان سے پوچھتا ہے حالانکہ وہ بندوں کے احوال کا سب سے زیادہ جاننے والا ہے کہ تم نے میرے بندوں کو کس حال میں چھوڑ ا؟ وہ جواب دیتے ہیں کہ ہم نے انہیں اس حال میں چھوڑا کہ وہ نماز پڑھ رہے تھے اور جب ہم ان کے پاس گئے جب بھی وہ نماز پڑھ رہے تھے۔“' WHERE id = 7202;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن اسد نے بیان کیا کہا، ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام بن منبہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ فرماتا ہے کہ جنت میں، میں نے اپنے نیک بندوں کے لیے وہ چیزیں تیار کر رکھی ہیں جنہیں نہ آنکھوں نے دیکھا، نہ کانوں نے سنا اور نہ کسی انسان کے دل میں ان کا خیال گزرا۔“' WHERE id = 7213;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن ابی الاسود نے بیان کیا، انہوں نے کہا ہم سے معتمر نے بیان کیا، انہوں نے کہا میں نے اپنے والد سے سنا، انہوں نے کہا ہم سے قتادہ نے بیان کیا، ان سے عقبہ بن عبدالغافر نے اور ان سے ابوسعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے پچھلی امتوں میں سے ایک شخص کا ذکر کیا۔ اس کے متعلق آپ صلی اللہ علیہ وسلم نے ایک کلمہ فرمایا یعنی اللہ نے اسے مال و اولاد سب کچھ دیا تھا۔ جب اس کے مرنے کا وقت قریب آیا تو اس نے اپنے لڑکوں سے پوچھا کہ میں تمہارے لیے کیسا باپ ثابت ہوا۔ انہوں نے کہا کہ بہترین باپ، اس پر اس نے کہا کہ لیکن تمہارے باپ نے اللہ کے ہاں کوئی نیکی نہیں بھیجی ہے اور اگر کہیں اللہ نے مجھے پکڑ پایا تو سخت عذاب کرے گا تو دیکھو جب میں مر جاؤں تو مجھے جلا دینا، یہاں تک کہ جب میں کوئلہ ہو جاؤں تو اسے خوب پیس لینا اور جس دن تیز آندھی آئے اس میں میری یہ راکھ اڑا دینا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس پر اس نے اپنے بیٹوں سے پختہ وعدہ لیا اور اللہ کی قسم کہ ان کے لڑکوں نے ایسا ہی کیا، جلا کر راکھ کر ڈالا، پھر انہوں نے اس کی راکھ کو تیز ہوا کے دن اڑا دیا۔ پھر اللہ تعالیٰ نے «كن‏» کا لفظ فرمایا کہ ہو جا تو وہ فوراً ایک مرد بن گیا جو کھڑا ہوا تھا۔ اللہ تعالیٰ نے فرمایا، اے میرے بندے! تجھے کس بات نے اس پر آمادہ کیا کہ تو نے یہ کام کرایا۔ اس نے کہا کہ تیرے خوف نے۔ بیان کیا کہ اللہ تعالیٰ نے اس کو کوئی سزا نہیں دی بلکہ اس پر رحم کیا۔ پھر میں نے یہ بات ابوعثمان نہدی سے بیان کی تو انہوں نے کہا کہ میں نے اسے سلیمان فارسی سے سنا، البتہ انہوں نے یہ لفظ زیادہ کئے کہ «أذروني في البحر‏.‏» یعنی میری راکھ کو دریا میں ڈال دینا یا کچھ ایسا ہی بیان کیا۔ ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے بیان کیا اور اس نے «لم يبتئر‏.‏» کے الفاظ کہے اور خلیفہ بن خیاط ( امام بخاری رحمہ اللہ کے شیخ ) نے کہا ہم سے معتمر نے بیان کیا پھر یہی حدیث نقل کی۔ اس میں «لم يبتئر‏.‏» ہے۔ قتادہ نے اس کے معنی یہ کئے ہیں یعنی کوئی نیکی آخرت کے لیے ذخیرہ نہیں کی۔' WHERE id = 7223;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا مجھ سے عبداللہ بن وہب نے بیان کیا، انہوں نے کہا کہ مجھے امام مالک نے بیان کیا، ان سے زید بن اسلم نے بیان کیا، ان سے عطاء بن یسار نے بیان کیا اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ جنت والوں سے کہے گا: اے جنت والو! وہ بولیں گے حاضر تیری خدمت کے لیے مستعد، ساری بھلائی تیرے دونوں ہاتھوں میں ہے۔ اللہ تعالیٰ پوچھے گا: کیا تم خوش ہو؟ وہ جواب دیں گے کیوں نہیں ہم خوش ہوں گے، اے رب! اور تو نے ہمیں وہ چیزیں عطا کی ہیں جو کسی مخلوق کو نہیں عطا کیں۔ اللہ تعالیٰ فرمائے گا کیا میں تمہیں اس سے افضل انعام نہ دوں؟ جنتی پوچھیں گے: اے رب! اس سے افضل کیا چیز ہو سکتی ہے اللہ تعالیٰ فرمائے گا کہ میں اپنی خوشی تم پر اتارتا ہوں اور اب کبھی تم سے ناراض نہیں ہوں گا۔“' WHERE id = 7233;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”رشک صرف دو آدمیوں پر کیا جا سکتا ہے، ایک اس پر جسے اللہ نے قرآن کا علم دیا اور وہ اس کی تلاوت رات دن کرتا ہے تو ایک دیکھنے والا کہتا ہے کہ کاش مجھے بھی اسی جیسا قرآن کا علم ہوتا تو میں بھی اس کی طرح تلاوت کرتا رہتا اور دوسرا وہ شخص ہے جسے اللہ نے مال دیا اور وہ اسے اس کے حق میں خرچ کرتا ہے جسے دیکھنے والا کہتا ہے کہ کاش مجھے بھی اللہ اتنا مال دیتا تو میں بھی اسی طرح خرچ کرتا جیسے یہ کرتا ہے۔“' WHERE id = 7243;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی سریح نے بیان کیا، کہا ہم کو شبابہ نے خبر دی، کہا ہم سے شعبہ نے بیان کیا، ان سے معاویہ بن قرہ نے، ان سے عبداللہ بن مغفل مزنی رضی اللہ عنہ نے بیان کیا کہ میں نے فتح مکہ کے دن رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ آپ اپنی ایک اونٹنی پر سوار تھے اور سورۃ الفتح پڑھ رہے تھے یا سورۃ الفتح میں سے کچھ آیات پڑھ رہے تھے۔ انہوں نے بیان کیا کہ پھر آپ نے اس میں ترجیع کی۔ شعبہ نے کہا یہ حدیث بیان کر کے معاویہ نے اس طرح آواز دہرا کر قرآت کی جیسے عبداللہ بن مغفل کیا کرتے تھے اور معاویہ نے کہا اگر مجھ کو اس کا خیال نہ ہوتا کہ لوگ تمہارے پاس جمع ہو کر ہجوم کریں گے تو میں اسی طرح آواز دہرا کر قرآت کرتا جس طرح عبداللہ بن مغفل نے نبی کریم صلی اللہ علیہ وسلم کی طرح آواز دہرانے کو نقل کیا تھا۔ شعبہ نے کہا میں نے معاویہ سے پوچھا ابن مغفل کیوں کر آواز دہراتے تھے؟ انہوں نے کہا آآآ تین تین بار مد کے ساتھ آواز دہراتے تھے۔' WHERE id = 7255;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے، کہا مجھ سے عروہ بن زبیر نے بیان کیا، ان سے مسور بن مخرمہ اور عبدالرحمٰن بن عبدالقاری نے، ان دونوں نے عمر بن خطاب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے ہشام بن حکیم رضی اللہ عنہ کو رسول اللہ صلی اللہ علیہ وسلم کی زندگی میں سورۃ الفرقان پڑھتے سنا۔ میں نے دیکھا کہ وہ قرآن مجید بہت سے ایسے طریقوں سے پڑھ رہے تھے جو نبی کریم صلی اللہ علیہ وسلم نے ہمیں نہیں پڑھائے تھے۔ قریب تھا کہ نماز ہی میں ان پر میں ہلہ کر دوں لیکن میں نے صبر سے کام لیا اور جب انہوں نے سلام پھیرا تو میں نے ان کی گردن میں اپنی چادر کا پھندا لگا دیا اور ان سے کہا تمہیں یہ سورت اس طرح کس نے پڑھائی جسے میں نے ابھی تم سے سنا۔ انہوں نے کہا کہ مجھے اس طرح رسول اللہ صلی اللہ علیہ وسلم نے پڑھائی ہے۔ میں نے کہا تم جھوٹے ہو، مجھے خود نبی کریم صلی اللہ علیہ وسلم نے اس سے مختلف قرآت سکھائی ہے جو تم پڑھ رہے تھے۔ چنانچہ میں انہیں کھینچتا ہوا نبی کریم صلی اللہ علیہ وسلم کے پاس لے گیا اور عرض کیا کہ میں نے اس شخص کو سورۃ الفرقان اس طرح پڑھتے سنا جو آپ نے مجھے نہیں سکھائی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں چھوڑ دو۔ ہشام! تم پڑھ کر سناؤ۔ انہوں نے وہی قرآت پڑھی جو میں ان سے سن چکا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسی طرح یہ سورت نازل ہوئی ہے۔ اے عمر! اب تم پڑھو! میں نے اس قرآت کے مطابق پڑھا جو آپ صلی اللہ علیہ وسلم نے مجھے سکھائی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس طرح بھی نازل ہوئی ہے۔ یہ قرآن عرب کی سات بولیوں پر اتارا گیا ہے۔ پس تمہیں جس قرآت میں سہولت ہو پڑھو۔' WHERE id = 7265;
